ents/DevisEnvoiApp\";\nimport ContractEmailPage from \"./components/ContractEmailPage\";\nimport RentalApp from \"./components/rental/RentalApp\";\nimport DeliveryApp from \"./components/delivery/DeliveryApp\";\nimport MobileHome from \"./components/mobile/MobileHome\";\n\nimport AbonnementsApp from \"./components/AbonnementsApp\";\nimport FormsApp from \"./components/FormsApp\";\nimport GlobalSettingsApp from \"./components/GlobalSettingsApp\";\nimport PartnersApp from \"./components/PartnersApp\";\nimport DjClientApp from \"./components/DjClientApp\";\nimport AgendaPrestationApp from \"./components/AgendaPrestationApp\";\nimport VenueApp from \"./components/VenueApp\";\nimport PublicVenuesApp from \"./components/PublicVenuesApp\";\n\nconst SmartHomePage = () => {\n  const savedUser = localStorage.getItem('user');\n  let interfaceType = 'desktop';\n  try {\n    const u = JSON.parse(savedUser);\n    interfaceType = u?.interface_type || (u?.role === 'location' ? 'mobile' : 'desktop');\n  } catch(e) {}\n  if (interfaceType === 'mobile') return <MobileHome />;\n  return <HomePage />;\n};\n\n\nfunction App() {\n  return (\n    <ErrorBoundary>\n      <div className=\"App min-h-screen bg-gradient-to-br from-orange-50 via-white to-amber-50\">\n        <BrowserRouter>\n          <AuthProvider>\n            <Routes>\n              {/* Page de connexion - publique */}\n              <Route path=\"/login\" element={<LoginPage />} />\n              \n              <Route path=\"/contracts/html-preview/:id\" element={\n                <ErrorBoundary>\n                  <ContractHtmlPreview />\n                </ErrorBoundary>\n              } />\n              \n              {/* Page d'accueil - protégée */}\n              <Route path=\"/\" element={\n                <ProtectedRoute>\n                  <SmartHomePage />\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/contracts2\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <Contracts2App />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n\n              <Route path=\"/contracts2/send-email\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <ContractEmailPage />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/location/*\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <LocationApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/rental/*\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <RentalApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/delivery/*\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <DeliveryApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              \n              <Route path=\"/crm\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <CRMApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/billetterie\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <BilletterieApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/dj-client\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <DjClientApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n\n              <Route path=\"/venues\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <VenueApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n\n              <Route path=\"/abonnements\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <AbonnementsApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/dj-profiles\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <DjProfilesApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/settings\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <Settings />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/devis\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <DevisEnvoiApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n\n              <Route path=\"/agenda-prestation\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <AgendaPrestationApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n              \n              <Route path=\"/formulaires\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <FormsApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n\n              <Route path=\"/parametres\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <GlobalSettingsApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n\n              <Route path=\"/partenaires\" element={\n                <ProtectedRoute>\n                  <>\n                    <Navigation />\n                    <ErrorBoundary>\n                      <PartnersApp />\n                    </ErrorBoundary>\n                  </>\n                </ProtectedRoute>\n              } />\n\n              <Route path=\"/lieux-reception\" element={\n                <ErrorBoundary>\n                  <PublicVenuesApp />\n                </ErrorBoundary>\n              } />\n\n               <Route path=\"/:slug\" element={\n                 <ErrorBoundary>\n                   <DjClientApp isPublic={true} />\n                 </ErrorBoundary>\n               } />\n            </Routes>\n          </AuthProvider>\n        </BrowserRouter>\n        <Toaster position=\"top-right\" />\n      </div>\n    </ErrorBoundary>\n  );\n}\n\nexport default App;\n","import React, { useState, useEffect } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport axios from 'axios';\nimport { toast } from 'sonner';\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from './ui/card';\nimport { Button } from './ui/button';\nimport { Input } from './ui/input';\nimport { Label } from './ui/label';\nimport { Badge } from './ui/badge';\nimport { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from './ui/select';\nimport { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from './ui/table';\nimport { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from './ui/dialog';\nimport { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from './ui/alert-dialog';\nimport { Textarea } from './ui/textarea';\nimport { jsPDF } from 'jspdf';\nimport autoTable from 'jspdf-autotable';\nimport { \n  Plus, Edit, Trash2, ArrowLeft, CreditCard, Calendar, \n  AlertTriangle, CheckCircle, PauseCircle, XCircle,\n  Euro, TrendingUp, Clock, Bell, Settings, Tag, FolderOpen, Download\n} from 'lucide-react';\n\nimport API_BASE_URL from '../utils/apiUrl';\nconst API = API_BASE_URL + '/api';\n\n// Configuration axios avec token\naxios.interceptors.request.use((config) => {\n  const token = localStorage.getItem('access_token');\n  if (token) {\n    config.headers.Authorization = `Bearer ${token}`;\n  }\n  return config;\n});\n\nfunction AbonnementsApp() {\n  const navigate = useNavigate();\n  const [subscriptions, setSubscriptions] = useState([]);\n  const [categories, setCategories] = useState([]);\n  const [stats, setStats] = useState({\n    active_count: 0,\n    total_monthly: 0,\n    total_annual: 0,\n    renewals_soon: 0\n  });\n  const [isLoading, setIsLoading] = useState(false);\n  const [showForm, setShowForm] = useState(false);\n  const [editingSubscription, setEditingSubscription] = useState(null);\n  const [showCategoryDialog, setShowCategoryDialog] = useState(false);\n  const [newCategoryName, setNewCategoryName] = useState('');\n  const [confirmDialog, setConfirmDialog] = useState({ open: false, subscription: null });\n  const [filterStatus, setFilterStatus] = useState('all');\n  const [filterCategory, setFilterCategory] = useState('all');\n\n  const [formData, setFormData] = useState({\n    name: '',\n    category: '',\n    provider: '',\n    amount_ht: '',\n    amount_ttc: '',\n    tva_rate: '20',\n    frequency: 'mensuel',\n    status: 'actif',\n    start_date: '',\n    renewal_date: '',\n    renewal_day: '',\n    payment_method: '',\n    payment_account: '',\n    contract_number: '',\n    notes: ''\n  });\n\n  useEffect(() => {\n    fetchData();\n  }, []);\n\n  const fetchData = async () => {\n    setIsLoading(true);\n    try {\n      const [subsRes, catsRes, statsRes] = await Promise.all([\n        axios.get(`${API}/subscriptions`),\n        axios.get(`${API}/subscriptions/categories`),\n        axios.get(`${API}/subscriptions/stats`)\n      ]);\n      setSubscriptions(subsRes.data || []);\n      setCategories(catsRes.data || []);\n      setStats(statsRes.data || {});\n    } catch (error) {\n      console.error('Error fetching data:', error);\n      toast.error('Erreur lors du chargement des données');\n    } finally {\n      setIsLoading(false);\n    }\n  };\n\n  // Calcul TTC à partir du HT\n  const calculateTTC = (ht, tvaRate) => {\n    const htValue = parseFloat(ht) || 0;\n    const tva = parseFloat(tvaRate) || 0;\n    return (htValue * (1 + tva / 100)).toFixed(2);\n  };\n\n  // Calcul HT à partir du TTC\n  const calculateHT = (ttc, tvaRate) => {\n    const ttcValue = parseFloat(ttc) || 0;\n    const tva = parseFloat(tvaRate) || 0;\n    return (ttcValue / (1 + tva / 100)).toFixed(2);\n  };\n\n  // Gestion du changement de montant HT\n  const handleHTChange = (value) => {\n    const newTTC = calculateTTC(value, formData.tva_rate);\n    setFormData({ ...formData, amount_ht: value, amount_ttc: newTTC });\n  };\n\n  // Gestion du changement de montant TTC\n  const handleTTCChange = (value) => {\n    const newHT = calculateHT(value, formData.tva_rate);\n    setFormData({ ...formData, amount_ttc: value, amount_ht: newHT });\n  };\n\n  // Gestion du changement de taux TVA (recalcule le TTC à partir du HT)\n  const handleTVAChange = (value) => {\n    const newTTC = calculateTTC(formData.amount_ht, value);\n    setFormData({ ...formData, tva_rate: value, amount_ttc: newTTC });\n  };\n\n  const handleSubmit = async (e) => {\n    e.preventDefault();\n    setIsLoading(true);\n\n    try {\n      const payload = {\n        ...formData,\n        amount_ht: parseFloat(formData.amount_ht) || 0,\n        tva_rate: parseFloat(formData.tva_rate) || 0,\n        amount_ttc: parseFloat(calculateTTC(formData.amount_ht, formData.tva_rate)),\n        start_date: formData.start_date || null,\n        // Pour mensuel: utiliser renewal_day, sinon renewal_date\n        renewal_date: formData.frequency !== 'mensuel' && formData.renewal_date ? formData.renewal_date : null,\n        renewal_day: formData.frequency === 'mensuel' && formData.renewal_day ? parseInt(formData.renewal_day) : null\n      };\n\n      if (editingSubscription) {\n        await axios.put(`${API}/subscriptions/${editingSubscription.id}`, payload);\n        toast.success('Abonnement mis à jour');\n      } else {\n        await axios.post(`${API}/subscriptions`, payload);\n        toast.success('Abonnement créé');\n      }\n\n      resetForm();\n      fetchData();\n    } catch (error) {\n      console.error('Error saving subscription:', error);\n      toast.error('Erreur lors de la sauvegarde');\n    } finally {\n      setIsLoading(false);\n    }\n  };\n\n  const handleEdit = (subscription) => {\n    setEditingSubscription(subscription);\n    setFormData({\n      name: subscription.name || '',\n      category: subscription.category || '',\n      provider: subscription.provider || '',\n      amount_ht: subscription.amount_ht?.toString() || '',\n      amount_ttc: subscription.amount_ttc?.toString() || '',\n      tva_rate: subscription.tva_rate?.toString() || '20',\n      frequency: subscription.frequency || 'mensuel',\n      status: subscription.status || 'actif',\n      start_date: subscription.start_date ? subscription.start_date.split('T')[0] : '',\n      renewal_date: subscription.renewal_date ? subscription.renewal_date.split('T')[0] : '',\n      renewal_day: subscription.renewal_day?.toString() || '',\n      payment_method: subscription.payment_method || '',\n      payment_account: subscription.payment_account || '',\n      contract_number: subscription.contract_number || '',\n      notes: subscription.notes || ''\n    });\n    setShowForm(true);\n  };\n\n  const handleDelete = async () => {\n    if (!confirmDialog.subscription) return;\n\n    try {\n      await axios.delete(`${API}/subscriptions/${confirmDialog.subscription.id}`);\n      toast.success('Abonnement supprimé');\n      setConfirmDialog({ open: false, subscription: null });\n      fetchData();\n    } catch (error) {\n      console.error('Error deleting subscription:', error);\n      toast.error('Erreur lors de la suppression');\n    }\n  };\n\n  const handleAddCategory = async () => {\n    if (!newCategoryName.trim()) return;\n\n    try {\n      await axios.post(`${API}/subscriptions/categories`, { name: newCategoryName.trim() });\n      toast.success('Catégorie ajoutée');\n      setNewCategoryName('');\n      setShowCategoryDialog(false);\n      fetchData();\n    } catch (error) {\n      console.error('Error adding category:', error);\n      toast.error('Erreur lors de l\\'ajout');\n    }\n  };\n\n  const resetForm = () => {\n    setFormData({\n      name: '',\n      category: '',\n      provider: '',\n      amount_ht: '',\n      amount_ttc: '',\n      tva_rate: '20',\n      frequency: 'mensuel',\n      status: 'actif',\n      start_date: '',\n      renewal_date: '',\n      renewal_day: '',\n      payment_method: '',\n      payment_account: '',\n      contract_number: '',\n      notes: ''\n    });\n    setEditingSubscription(null);\n    setShowForm(false);\n  };\n\n  const getStatusBadge = (status) => {\n    switch (status) {\n      case 'actif':\n        return <Badge className=\"bg-green-500 hover:bg-green-500\"><CheckCircle className=\"w-3 h-3 mr-1\" /> Actif</Badge>;\n      case 'suspendu':\n        return <Badge className=\"bg-yellow-500 hover:bg-yellow-500\"><PauseCircle className=\"w-3 h-3 mr-1\" /> Suspendu</Badge>;\n      case 'resilie':\n        return <Badge className=\"bg-red-500 hover:bg-red-500\"><XCircle className=\"w-3 h-3 mr-1\" /> Résilié</Badge>;\n      default:\n        return <Badge variant=\"outline\">{status}</Badge>;\n    }\n  };\n\n  const getFrequencyLabel = (frequency) => {\n    switch (frequency) {\n      case 'mensuel': return '/mois';\n      case 'trimestriel': return '/trim.';\n      case 'annuel': return '/an';\n      default: return '';\n    }\n  };\n\n  const isRenewalSoon = (sub) => {\n    const today = new Date();\n    \n    if (sub.frequency === 'mensuel' && sub.renewal_day) {\n      // Pour mensuel, calculer la prochaine date de renouvellement\n      const currentDay = today.getDate();\n      const renewalDay = sub.renewal_day;\n      let daysUntil;\n      \n      if (renewalDay >= currentDay) {\n        daysUntil = renewalDay - currentDay;\n      } else {\n        // Prochain mois\n        const daysInMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();\n        daysUntil = (daysInMonth - currentDay) + renewalDay;\n      }\n      \n      return daysUntil <= 7; // Alerte si dans les 7 prochains jours pour mensuel\n    } else if (sub.renewal_date) {\n      // Pour trimestriel/annuel\n      const renewal = new Date(sub.renewal_date);\n      const diffDays = Math.ceil((renewal - today) / (1000 * 60 * 60 * 24));\n      return diffDays >= 0 && diffDays <= 30;\n    }\n    \n    return false;\n  };\n\n  const getRenewalDisplay = (sub) => {\n    if (sub.frequency === 'mensuel' && sub.renewal_day) {\n      return `Le ${sub.renewal_day === 1 ? '1er' : sub.renewal_day} du mois`;\n    } else if (sub.renewal_date) {\n      return new Date(sub.renewal_date).toLocaleDateString('fr-FR');\n    }\n    return null;\n  };\n\n  const filteredSubscriptions = subscriptions.filter(sub => {\n    if (filterStatus !== 'all' && sub.status !== filterStatus) return false;\n    if (filterCategory !== 'all' && sub.category !== filterCategory) return false;\n    return true;\n  });\n\n  // Grouper les abonnements par catégorie\n  const groupedSubscriptions = filteredSubscriptions.reduce((acc, sub) => {\n    const category = sub.category || 'Sans catégorie';\n    if (!acc[category]) {\n      acc[category] = [];\n    }\n    acc[category].push(sub);\n    return acc;\n  }, {});\n\n  // Trier les catégories par ordre alphabétique\n  const sortedCategories = Object.keys(groupedSubscriptions).sort();\n\n  const exportToPDF = () => {\n    const doc = new jsPDF();\n    \n    // Titre\n    doc.setFontSize(18);\n    doc.text(\"Liste des Abonnements\", 14, 22);\n    \n    // Stats rapides\n    doc.setFontSize(11);\n    doc.setTextColor(100);\n    doc.text(`Total mensuel HT: ${stats.total_monthly?.toFixed(2)} euros`, 14, 30);\n    doc.text(`Total annuel HT: ${stats.total_annual?.toFixed(2)} euros`, 14, 36);\n    doc.text(`Abonnements actifs: ${stats.active_count}`, 100, 30);\n    \n    // Préparation des données pour le tableau\n    const tableColumn = [\"Nom\", \"Categorie\", \"Fournisseur\", \"Montant TTC\", \"Freq.\", \"Statut\", \"Renouv.\"];\n    const tableRows = [];\n    \n    filteredSubscriptions.forEach(sub => {\n      const subData = [\n        sub.name,\n        sub.category || '-',\n        sub.provider || '-',\n        `${sub.amount_ttc?.toFixed(2)} €`,\n        sub.frequency,\n        sub.status,\n        getRenewalDisplay(sub) || '-'\n      ];\n      tableRows.push(subData);\n    });\n    \n    autoTable(doc, {\n      head: [tableColumn],\n      body: tableRows,\n      startY: 45,\n      styles: { fontSize: 9 },\n      headStyles: { fillColor: [41, 128, 185] },\n      alternateRowStyles: { fillColor: [245, 245, 245] }\n    });\n    \n    doc.save(`abonnements_${new Date().toISOString().split('T')[0]}.pdf`);\n    toast.success(\"PDF exporté avec succès\");\n  };\n\n  return (\n    <div className=\"min-h-screen bg-gradient-to-br from-slate-50 to-blue-50\">\n      {/* Header */}\n      <div className=\"bg-gradient-to-r from-slate-800 to-slate-700 text-white shadow-lg\">\n        <div className=\"max-w-7xl mx-auto px-6 py-4\">\n          <div className=\"flex items-center justify-between\">\n            <div className=\"flex items-center gap-4\">\n              <Button \n                variant=\"ghost\" \n                className=\"text-white hover:bg-slate-600\"\n                onClick={() => navigate('/')}\n              >\n                <ArrowLeft className=\"w-5 h-5\" />\n              </Button>\n              <div>\n                <h1 className=\"text-2xl font-bold flex items-center gap-2\">\n                  <CreditCard className=\"w-7 h-7\" />\n                  Gestion des Abonnements\n                </h1>\n                <p className=\"text-slate-300 text-sm\">Suivez tous vos abonnements et charges récurrentes</p>\n              </div>\n            </div>\n            <div className=\"flex gap-2\">\n              <Button \n                variant=\"outline\" \n                className=\"bg-transparent border-slate-500 text-white hover:bg-slate-600\"\n                onClick={exportToPDF}\n              >\n                <Download className=\"w-4 h-4 mr-2\" />\n                Exporter PDF\n              </Button>\n              <Button \n                variant=\"outline\" \n                className=\"bg-transparent border-slate-500 text-white hover:bg-slate-600\"\n                onClick={() => setShowCategoryDialog(true)}\n              >\n                <Tag className=\"w-4 h-4 mr-2\" />\n                Catégories\n              </Button>\n              <Button \n                className=\"bg-blue-600 hover:bg-blue-700\"\n                onClick={() => { resetForm(); setShowForm(true); }}\n              >\n                <Plus className=\"w-4 h-4 mr-2\" />\n                Nouvel abonnement\n              </Button>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <div className=\"max-w-7xl mx-auto px-6 py-6\">\n        {/* Stats Cards */}\n        <div className=\"grid grid-cols-1 md:grid-cols-3 gap-4 mb-6\">\n          <Card className=\"bg-gradient-to-br from-green-500 to-green-600 text-white border-0\">\n            <CardContent className=\"py-4\">\n              <div className=\"flex items-center justify-between\">\n                <div>\n                  <p className=\"text-green-100 text-sm\">Coût mensuel HT</p>\n                  <p className=\"text-3xl font-bold\">{stats.total_monthly?.toFixed(2)} €</p>\n                  <p className=\"text-green-200 text-xs mt-0.5\">{(stats.total_monthly * 1.2)?.toFixed(2)} € TTC</p>\n                </div>\n                <Euro className=\"w-10 h-10 text-green-200\" />\n              </div>\n            </CardContent>\n          </Card>\n\n          <Card className=\"bg-gradient-to-br from-purple-500 to-purple-600 text-white border-0\">\n            <CardContent className=\"py-4\">\n              <div className=\"flex items-center justify-between\">\n                <div>\n                  <p className=\"text-purple-100 text-sm\">Coût annuel HT</p>\n                  <p className=\"text-3xl font-bold\">{stats.total_annual?.toFixed(2)} €</p>\n                </div>\n                <TrendingUp className=\"w-10 h-10 text-purple-200\" />\n              </div>\n            </CardContent>\n          </Card>\n\n          <Card className={`border-0 ${stats.renewals_soon > 0 ? 'bg-gradient-to-br from-orange-500 to-red-500 text-white' : 'bg-gradient-to-br from-slate-400 to-slate-500 text-white'}`}>\n            <CardContent className=\"py-4\">\n              <div className=\"flex items-center justify-between\">\n                <div>\n                  <p className={stats.renewals_soon > 0 ? 'text-orange-100' : 'text-slate-200'} style={{fontSize: '0.875rem'}}>Renouvellements annuels</p>\n                  <p className=\"text-3xl font-bold\">{stats.renewals_soon}</p>\n                  <p className={stats.renewals_soon > 0 ? 'text-orange-100' : 'text-slate-200'} style={{fontSize: '0.75rem'}}>dans les 30 jours</p>\n                </div>\n                <Bell className={`w-10 h-10 ${stats.renewals_soon > 0 ? 'text-orange-200' : 'text-slate-300'}`} />\n              </div>\n            </CardContent>\n          </Card>\n        </div>\n\n        {/* Filters */}\n        <Card className=\"mb-6\">\n          <CardContent className=\"py-4\">\n            <div className=\"flex flex-wrap gap-4 items-center\">\n              <div className=\"flex items-center gap-2\">\n                <Label className=\"text-sm text-gray-600\">Statut :</Label>\n                <Select value={filterStatus} onValueChange={setFilterStatus}>\n                  <SelectTrigger className=\"w-[150px]\">\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value=\"all\">Tous</SelectItem>\n                    <SelectItem value=\"actif\">Actif</SelectItem>\n                    <SelectItem value=\"suspendu\">Suspendu</SelectItem>\n                    <SelectItem value=\"resilie\">Résilié</SelectItem>\n                  </SelectContent>\n                </Select>\n              </div>\n\n              <div className=\"flex items-center gap-2\">\n                <Label className=\"text-sm text-gray-600\">Catégorie :</Label>\n                <Select value={filterCategory} onValueChange={setFilterCategory}>\n                  <SelectTrigger className=\"w-[200px]\">\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value=\"all\">Toutes</SelectItem>\n                    {categories.map(cat => (\n                      <SelectItem key={cat.id} value={cat.name}>{cat.name}</SelectItem>\n                    ))}\n                  </SelectContent>\n                </Select>\n              </div>\n\n              <div className=\"ml-auto text-sm text-gray-500\">\n                {filteredSubscriptions.length} abonnement(s)\n              </div>\n            </div>\n          </CardContent>\n        </Card>\n\n        {/* Subscriptions grouped by category */}\n        {filteredSubscriptions.length === 0 ? (\n          <Card>\n            <CardContent className=\"py-12\">\n              <div className=\"text-center\">\n                <CreditCard className=\"w-16 h-16 mx-auto text-gray-300 mb-4\" />\n                <p className=\"text-gray-500 text-lg\">Aucun abonnement trouvé</p>\n                <p className=\"text-gray-400 text-sm mt-2\">\n                  Cliquez sur \"Nouvel abonnement\" pour en ajouter un\n                </p>\n              </div>\n            </CardContent>\n          </Card>\n        ) : (\n          <div className=\"space-y-4\">\n            {sortedCategories.map(category => (\n              <Card key={category} className=\"overflow-hidden\">\n                <CardHeader className=\"bg-gradient-to-r from-slate-100 to-slate-50 py-3 border-b\">\n                  <div className=\"flex items-center justify-between\">\n                    <CardTitle className=\"text-base flex items-center gap-2\">\n                      <FolderOpen className=\"w-5 h-5 text-slate-600\" />\n                      {category}\n                    </CardTitle>\n                    <Badge variant=\"secondary\" className=\"text-xs\">\n                      {groupedSubscriptions[category].length} abonnement{groupedSubscriptions[category].length > 1 ? 's' : ''}\n                    </Badge>\n                  </div>\n                </CardHeader>\n                <CardContent className=\"p-0\">\n                  <Table>\n                    <TableHeader>\n                      <TableRow className=\"bg-slate-50/50\">\n                        <TableHead>Nom</TableHead>\n                        <TableHead>Fournisseur</TableHead>\n                        <TableHead className=\"text-right\">Montant TTC</TableHead>\n                        <TableHead>Fréquence</TableHead>\n                        <TableHead>Statut</TableHead>\n                        <TableHead>Renouvellement</TableHead>\n                        <TableHead>Actions</TableHead>\n                      </TableRow>\n                    </TableHeader>\n                    <TableBody>\n                      {groupedSubscriptions[category].map(sub => (\n                        <TableRow key={sub.id} className={sub.status === 'resilie' ? 'opacity-50' : ''}>\n                          <TableCell className=\"font-semibold\">{sub.name}</TableCell>\n                          <TableCell className=\"text-gray-600\">{sub.provider || '-'}</TableCell>\n                          <TableCell className=\"text-right font-semibold text-green-600\">\n                            {sub.amount_ttc?.toFixed(2)} €\n                            <span className=\"text-gray-400 text-xs ml-1\">{getFrequencyLabel(sub.frequency)}</span>\n                          </TableCell>\n                          <TableCell>\n                            {sub.frequency === 'mensuel' && 'Mensuel'}\n                            {sub.frequency === 'trimestriel' && 'Trimestriel'}\n                            {sub.frequency === 'annuel' && 'Annuel'}\n                          </TableCell>\n                          <TableCell>{getStatusBadge(sub.status)}</TableCell>\n                          <TableCell>\n                            {getRenewalDisplay(sub) ? (\n                              <div className=\"flex items-center gap-1\">\n                                {isRenewalSoon(sub) && (\n                                  <AlertTriangle className=\"w-4 h-4 text-orange-500\" />\n                                )}\n                                <span className={isRenewalSoon(sub) ? 'text-orange-600 font-medium' : ''}>\n                                  {getRenewalDisplay(sub)}\n                                </span>\n                              </div>\n                            ) : '-'}\n                          </TableCell>\n                          <TableCell>\n                            <div className=\"flex gap-2\">\n                              <Button \n                                variant=\"outline\" \n                                size=\"sm\" \n                                onClick={() => handleEdit(sub)}\n                              >\n                                <Edit className=\"w-4 h-4\" />\n                              </Button>\n                              <Button \n                                variant=\"destructive\" \n                                size=\"sm\"\n                                onClick={() => setConfirmDialog({ open: true, subscription: sub })}\n                              >\n                                <Trash2 className=\"w-4 h-4\" />\n                              </Button>\n                            </div>\n                          </TableCell>\n                        </TableRow>\n                      ))}\n                    </TableBody>\n                  </Table>\n                </CardContent>\n              </Card>\n            ))}\n          </div>\n        )}\n      </div>\n\n      {/* Form Dialog */}\n      <Dialog open={showForm} onOpenChange={(open) => !open && resetForm()}>\n        <DialogContent className=\"max-w-2xl max-h-[90vh] overflow-y-auto\">\n          <DialogHeader>\n            <DialogTitle>\n              {editingSubscription ? 'Modifier l\\'abonnement' : 'Nouvel abonnement'}\n            </DialogTitle>\n            <DialogDescription>\n              {editingSubscription \n                ? 'Modifiez les informations de l\\'abonnement'\n                : 'Ajoutez un nouvel abonnement ou charge récurrente'}\n            </DialogDescription>\n          </DialogHeader>\n\n          <form onSubmit={handleSubmit} className=\"space-y-4\">\n            <div className=\"grid grid-cols-2 gap-4\">\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"name\">Nom *</Label>\n                <Input\n                  id=\"name\"\n                  value={formData.name}\n                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}\n                  placeholder=\"Ex: Tidal, EDF, Loyer...\"\n                  required\n                />\n              </div>\n\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"category\">Catégorie *</Label>\n                <Select \n                  value={formData.category} \n                  onValueChange={(value) => setFormData({ ...formData, category: value })}\n                  required\n                >\n                  <SelectTrigger>\n                    <SelectValue placeholder=\"Sélectionner...\" />\n                  </SelectTrigger>\n                  <SelectContent>\n                    {categories.map(cat => (\n                      <SelectItem key={cat.id} value={cat.name}>{cat.name}</SelectItem>\n                    ))}\n                  </SelectContent>\n                </Select>\n              </div>\n            </div>\n\n            <div className=\"grid grid-cols-2 gap-4\">\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"provider\">Fournisseur</Label>\n                <Input\n                  id=\"provider\"\n                  value={formData.provider}\n                  onChange={(e) => setFormData({ ...formData, provider: e.target.value })}\n                  placeholder=\"Nom du prestataire\"\n                />\n              </div>\n\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"contract_number\">N° Contrat / Référence</Label>\n                <Input\n                  id=\"contract_number\"\n                  value={formData.contract_number}\n                  onChange={(e) => setFormData({ ...formData, contract_number: e.target.value })}\n                  placeholder=\"Référence client\"\n                />\n              </div>\n            </div>\n\n            <div className=\"grid grid-cols-3 gap-4\">\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"amount_ht\">Montant HT *</Label>\n                <div className=\"relative\">\n                  <Input\n                    id=\"amount_ht\"\n                    type=\"number\"\n                    step=\"0.01\"\n                    min=\"0\"\n                    value={formData.amount_ht}\n                    onChange={(e) => handleHTChange(e.target.value)}\n                    placeholder=\"0.00\"\n                    required\n                  />\n                  <span className=\"absolute right-3 top-1/2 -translate-y-1/2 text-gray-400\">€</span>\n                </div>\n              </div>\n\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"tva_rate\">TVA</Label>\n                <Select \n                  value={formData.tva_rate} \n                  onValueChange={handleTVAChange}\n                >\n                  <SelectTrigger>\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value=\"0\">0% (Exonéré)</SelectItem>\n                    <SelectItem value=\"5.5\">5.5%</SelectItem>\n                    <SelectItem value=\"10\">10%</SelectItem>\n                    <SelectItem value=\"20\">20%</SelectItem>\n                  </SelectContent>\n                </Select>\n              </div>\n\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"amount_ttc\">Montant TTC *</Label>\n                <div className=\"relative\">\n                  <Input\n                    id=\"amount_ttc\"\n                    type=\"number\"\n                    step=\"0.01\"\n                    min=\"0\"\n                    value={formData.amount_ttc}\n                    onChange={(e) => handleTTCChange(e.target.value)}\n                    placeholder=\"0.00\"\n                    className=\"text-green-600 font-semibold\"\n                    required\n                  />\n                  <span className=\"absolute right-3 top-1/2 -translate-y-1/2 text-gray-400\">€</span>\n                </div>\n              </div>\n            </div>\n\n            <div className=\"grid grid-cols-2 gap-4\">\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"frequency\">Fréquence *</Label>\n                <Select \n                  value={formData.frequency} \n                  onValueChange={(value) => setFormData({ ...formData, frequency: value })}\n                >\n                  <SelectTrigger>\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value=\"mensuel\">Mensuel</SelectItem>\n                    <SelectItem value=\"trimestriel\">Trimestriel</SelectItem>\n                    <SelectItem value=\"annuel\">Annuel</SelectItem>\n                  </SelectContent>\n                </Select>\n              </div>\n\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"status\">Statut *</Label>\n                <Select \n                  value={formData.status} \n                  onValueChange={(value) => setFormData({ ...formData, status: value })}\n                >\n                  <SelectTrigger>\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value=\"actif\">Actif</SelectItem>\n                    <SelectItem value=\"suspendu\">Suspendu</SelectItem>\n                    <SelectItem value=\"resilie\">Résilié</SelectItem>\n                  </SelectContent>\n                </Select>\n              </div>\n            </div>\n\n            <div className=\"grid grid-cols-2 gap-4\">\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"start_date\">Date de souscription</Label>\n                <Input\n                  id=\"start_date\"\n                  type=\"date\"\n                  value={formData.start_date}\n                  onChange={(e) => setFormData({ ...formData, start_date: e.target.value })}\n                />\n              </div>\n\n              <div className=\"space-y-2\">\n                {formData.frequency === 'mensuel' ? (\n                  <>\n                    <Label htmlFor=\"renewal_day\">Jour de prélèvement</Label>\n                    <Select \n                      value={formData.renewal_day} \n                      onValueChange={(value) => setFormData({ ...formData, renewal_day: value })}\n                    >\n                      <SelectTrigger>\n                        <SelectValue placeholder=\"Sélectionner le jour...\" />\n                      </SelectTrigger>\n                      <SelectContent>\n                        {Array.from({ length: 31 }, (_, i) => i + 1).map(day => (\n                          <SelectItem key={day} value={day.toString()}>\n                            {day === 1 ? '1er' : day} du mois\n                          </SelectItem>\n                        ))}\n                      </SelectContent>\n                    </Select>\n                  </>\n                ) : (\n                  <>\n                    <Label htmlFor=\"renewal_date\">Date de renouvellement</Label>\n                    <Input\n                      id=\"renewal_date\"\n                      type=\"date\"\n                      value={formData.renewal_date}\n                      onChange={(e) => setFormData({ ...formData, renewal_date: e.target.value })}\n                    />\n                  </>\n                )}\n              </div>\n            </div>\n\n            <div className=\"space-y-2\">\n              <Label htmlFor=\"payment_method\">Moyen de paiement</Label>\n              <Select \n                value={formData.payment_method} \n                onValueChange={(value) => setFormData({ ...formData, payment_method: value, payment_account: '' })}\n              >\n                <SelectTrigger>\n                  <SelectValue placeholder=\"Sélectionner...\" />\n                </SelectTrigger>\n                <SelectContent>\n                  <SelectItem value=\"prelevement\">Prélèvement automatique</SelectItem>\n                  <SelectItem value=\"cb\">Carte bancaire</SelectItem>\n                  <SelectItem value=\"virement\">Virement</SelectItem>\n                  <SelectItem value=\"especes\">Espèces</SelectItem>\n                </SelectContent>\n              </Select>\n            </div>\n\n            {(formData.payment_method === 'prelevement' || formData.payment_method === 'virement') && (\n              <div className=\"space-y-2\">\n                <Label htmlFor=\"payment_account\">Compte bancaire</Label>\n                <Input\n                  id=\"payment_account\"\n                  value={formData.payment_account || ''}\n                  onChange={(e) => setFormData({ ...formData, payment_account: e.target.value })}\n                  placeholder={formData.payment_method === 'prelevement' ? \"Ex: Compte pro LCL, Compte perso...\" : \"Ex: Compte épargne, Compte courant...\"}\n                />\n              </div>\n            )}\n\n            <div className=\"space-y-2\">\n              <Label htmlFor=\"notes\">Notes</Label>\n              <Textarea\n                id=\"notes\"\n                value={formData.notes}\n                onChange={(e) => setFormData({ ...formData, notes: e.target.value })}\n                placeholder=\"Informations complémentaires...\"\n                rows={3}\n              />\n            </div>\n\n            <DialogFooter>\n              <Button type=\"button\" variant=\"outline\" onClick={resetForm}>\n                Annuler\n              </Button>\n              <Button type=\"submit\" disabled={isLoading}>\n                {isLoading ? 'Enregistrement...' : (editingSubscription ? 'Mettre à jour' : 'Créer')}\n              </Button>\n            </DialogFooter>\n          </form>\n        </DialogContent>\n      </Dialog>\n\n      {/* Category Dialog */}\n      <Dialog open={showCategoryDialog} onOpenChange={setShowCategoryDialog}>\n        <DialogContent>\n          <DialogHeader>\n            <DialogTitle>Gérer les catégories</DialogTitle>\n            <DialogDescription>\n              Ajoutez des catégories personnalisées pour vos abonnements\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"space-y-4\">\n            <div className=\"flex gap-2\">\n              <Input\n                value={newCategoryName}\n                onChange={(e) => setNewCategoryName(e.target.value)}\n                placeholder=\"Nouvelle catégorie...\"\n              />\n              <Button onClick={handleAddCategory} disabled={!newCategoryName.trim()}>\n                <Plus className=\"w-4 h-4\" />\n              </Button>\n            </div>\n\n            <div className=\"space-y-2\">\n              <Label className=\"text-sm text-gray-600\">Catégories existantes :</Label>\n              <div className=\"flex flex-wrap gap-2\">\n                {categories.map(cat => (\n                  <Badge \n                    key={cat.id} \n                    variant={cat.is_default ? 'secondary' : 'outline'}\n                    className=\"py-1\"\n                  >\n                    {cat.name}\n                    {cat.is_default && <span className=\"ml-1 text-xs\">(défaut)</span>}\n                  </Badge>\n                ))}\n              </div>\n            </div>\n          </div>\n\n          <DialogFooter>\n            <Button variant=\"outline\" onClick={() => setShowCategoryDialog(false)}>\n              Fermer\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n\n      {/* Delete Confirmation */}\n      <AlertDialog open={confirmDialog.open} onOpenChange={(open) => !open && setConfirmDialog({ open: false, subscription: null })}>\n        <AlertDialogContent>\n          <AlertDialogHeader>\n            <AlertDialogTitle className=\"text-red-600 flex items-center gap-2\">\n              <Trash2 className=\"w-5 h-5\" />\n              Supprimer l'abonnement\n            </AlertDialogTitle>\n            <AlertDialogDescription>\n              Êtes-vous sûr de vouloir supprimer l'abonnement \"{confirmDialog.subscription?.name}\" ?\n              Cette action est irréversible.\n            </AlertDialogDescription>\n          </AlertDialogHeader>\n          <AlertDialogFooter>\n            <AlertDialogCancel>Annuler</AlertDialogCancel>\n            <AlertDialogAction onClick={handleDelete} className=\"bg-red-600 hover:bg-red-700\">\n              Supprimer\n            </AlertDialogAction>\n          </AlertDialogFooter>\n        </AlertDialogContent>\n      </AlertDialog>\n    </div>\n  );\n}\n\nexport default AbonnementsApp;\n","import React, { useState, useEffect, useRef } from 'react';\nimport { Calendar, dateFnsLocalizer, Views } from 'react-big-calendar';\nimport { format, parse, startOfWeek, getDay } from 'date-fns';\nimport { fr } from 'date-fns/locale';\nimport 'react-big-calendar/lib/css/react-big-calendar.css';\nimport axios from 'axios';\nimport { Trash2, Shield, CalendarDays, Loader2, X, User, Tag, Key, Info, HelpCircle, RotateCw, Plus, MapPin, Edit, Phone } from 'lucide-react';\nimport { toast } from 'sonner';\nimport API_BASE_URL from '../utils/apiUrl';\n\nconst locales = {\n  'fr': fr,\n};\n\nconst localizer = dateFnsLocalizer({\n  format,\n  parse,\n  startOfWeek,\n  getDay,\n  locales,\n});\n\nconst API = `${API_BASE_URL}/api`;\n\nconst CustomToolbar = (toolbar) => {\n  const goToBack = () => toolbar.onNavigate('PREV');\n  const goToNext = () => toolbar.onNavigate('NEXT');\n  const goToToday = () => toolbar.onNavigate('TODAY');\n\n  return (\n    <div className=\"flex flex-wrap items-center justify-between gap-4 mb-6\">\n      <div className=\"flex items-center gap-1 bg-white rounded-lg border p-1 shadow-sm\">\n        <button className=\"px-4 py-1.5 text-sm font-medium hover:bg-gray-100 rounded-md transition\" onClick={goToToday}>Aujourd'hui</button>\n        <button className=\"px-3 py-1.5 text-sm font-medium hover:bg-gray-100 rounded-md transition\" onClick={goToBack}>&lt;</button>\n        <button className=\"px-3 py-1.5 text-sm font-medium hover:bg-gray-100 rounded-md transition\" onClick={goToNext}>&gt;</button>\n      </div>\n      <div className=\"text-lg font-bold text-slate-800 capitalize\">\n        {toolbar.label}\n      </div>\n      <div className=\"flex items-center gap-1 bg-white rounded-lg border p-1 shadow-sm\">\n        {['month', 'agenda'].map(v => (\n          <button \n            key={v}\n            className={`px-4 py-1.5 text-sm font-medium rounded-md transition capitalize ${toolbar.view === v ? 'bg-indigo-100 text-indigo-700' : 'hover:bg-gray-100 text-gray-600'}`}\n            onClick={() => toolbar.onView(v)}\n          >\n            {v === 'month' ? 'Mois' : 'Planning'}\n          </button>\n        ))}\n      </div>\n    </div>\n  );\n};\n\nexport default function AgendaPrestationApp() {\n  const [events, setEvents] = useState([]);\n  const [djs, setDjs] = useState([]);\n  const [loading, setLoading] = useState(true);\n  const [settings, setSettings] = useState({ hidden_djs: [], deleted_djs: [], deleted_events: [] });\n  const [showConfirmDelete, setShowConfirmDelete] = useState(null);\n  const [selectedEvent, setSelectedEvent] = useState(null);\n  \n  const [undoableEvent, setUndoableEvent] = useState(null);\n  const [undoSeconds, setUndoSeconds] = useState(5);\n  const undoRef = useRef(null);\n  const timerRef = useRef(null);\n  \n  const [calendarView, setCalendarView] = useState('month');\n  const [calendarDate, setCalendarDate] = useState(new Date());\n\n  // State variables for manually added options and events\n  const [addEventDate, setAddEventDate] = useState(null);\n  const [addEventType, setAddEventType] = useState('option'); // 'option' or 'event'\n  const [customEventForm, setCustomEventForm] = useState({ title: '', clientName: '', clientPhone: '', djId: '', eventType: '', customEventTypeInput: '', details: '', location: '' });\n\n  const getEventTypesList = (djId) => {\n    const baseTypes = [\"Mariage\", \"Anniversaire\", \"Comité d'entreprise\", \"Soirée privée\", \"Événement professionnel\"];\n    const dj = djs.find(d => d.id === djId);\n    if (dj && (dj.name?.toLowerCase().includes(\"r'key\") || dj.name?.toLowerCase().includes(\"rkey\"))) {\n      baseTypes.push(\"Show Hypnose\", \"Intervention hypnose\");\n    }\n    return baseTypes;\n  };\n  const [editingCustomEventId, setEditingCustomEventId] = useState(null);\n  const [recurrence, setRecurrence] = useState('none'); // 'none', 'daily', 'weekly', 'monthly'\n  const [recurrenceEndType, setRecurrenceEndType] = useState('count'); // 'count', 'date'\n  const [recurrenceEndDate, setRecurrenceEndDate] = useState('');\n  const [recurrenceCount, setRecurrenceCount] = useState(5);\n  const [deleteRecurringEvent, setDeleteRecurringEvent] = useState(null);\n  const [syncingAll, setSyncingAll] = useState(false);\n  const [gcalStatus, setGcalStatus] = useState(null);\n\n  const handleSyncAllGoogle = async () => {\n    try {\n      setSyncingAll(true);\n      const token = localStorage.getItem('access_token');\n      const response = await axios.post(`${API}/agenda/sync-all-google`, {}, {\n        headers: token ? { 'Authorization': `Bearer ${token}` } : {}\n      });\n      if (response.data?.success) {\n        if (response.data.failedCalendars && response.data.failedCalendars.length > 0) {\n          toast.warning(\n            `Synchronisé, mais ${response.data.failedCalendars.length} agenda(s) non accessible(s). Veuillez vérifier que vous avez partagé les agendas des DJs avec le compte : ${gcalStatus?.serviceAccountEmail || \"de service associé\"}.`,\n            { duration: 12000 }\n          );\n        } else {\n          toast.success(response.data.message || \"Synchronisation terminée avec succès!\");\n        }\n      } else {\n        toast.error(\"Échec de la synchronisation.\");\n      }\n    } catch (error) {\n      console.error(\"Error triggering auto sync :\", error);\n      const errMsg = error.response?.data?.error || \"Erreur lors de la synchronisation.\";\n      toast.error(errMsg);\n    } finally {\n      setSyncingAll(false);\n    }\n  };\n\n  useEffect(() => {\n    fetchData();\n  }, []);\n\n  const fetchData = async () => {\n    try {\n      setLoading(true);\n      \n      const [settingsRes, djsRes, contractsRes, reservationsRes, customEventsRes, googleStatusRes] = await Promise.all([\n        axios.get(`${API}/agenda-settings`),\n        axios.get(`${API}/location/djs`),\n        axios.get(`${API}/contracts2`),\n        axios.get(`${API}/location/reservations`),\n        axios.get(`${API}/agenda-custom-events`).catch(() => ({ data: [] })),\n        axios.get(`${API}/location/google-calendar-status`).catch((err) => {\n          console.warn(\"Failed to fetch google calendar status:\", err);\n          return { data: { initialized: false, serviceAccountEmail: null } };\n        })\n      ]);\n\n      if (googleStatusRes && googleStatusRes.data) {\n        setGcalStatus(googleStatusRes.data);\n      }\n\n      const loadedSettings = {\n        hidden_djs: settingsRes.data.hidden_djs || [],\n        deleted_djs: settingsRes.data.deleted_djs || [],\n        deleted_events: settingsRes.data.deleted_events || []\n      };\n      setSettings(loadedSettings);\n      \n      const locationDjs = djsRes.data || [];\n      const officialDjMap = new Map();\n      \n      const normalize = (str) => {\n        if (!str) return \"\";\n        return String(str).toLowerCase().normalize(\"NFD\").replace(/[\\u0300-\\u036f]/g, \"\").trim();\n      };\n      \n      const nameToOfficialId = new Map();\n      \n      locationDjs.forEach(d => {\n        const id = String(d.id);\n        const name = typeof d.name === 'string' ? d.name : (d.nom_artistique || String(d.name || d.id || 'DJ Inconnu'));\n        officialDjMap.set(id, { ...d, id, name, active: true });\n        \n        const cleanName = normalize(name);\n        nameToOfficialId.set(cleanName, id);\n        \n        const firstWord = cleanName.split(/[\\s-]/)[0];\n        if (firstWord && !nameToOfficialId.has(firstWord)) {\n          nameToOfficialId.set(firstWord, id);\n        }\n      });\n      // Mappings de rattrapage\n      const joelId = nameToOfficialId.get(normalize(\"Joël R'Key\"));\n      if (joelId) nameToOfficialId.set(\"joel\", joelId);\n      \n      const stefanId = nameToOfficialId.get(normalize(\"Stefan Edison\"));\n      if (stefanId) nameToOfficialId.set(\"stephane\", stefanId);\n\n      const allContracts = (contractsRes.data || []).filter(c => !['deleted', 'trash', 'draft', 'cancelled'].includes(c.status));\n      \n      const parsedEvents = [];\n      const eventSignatures = new Set();\n      \n      allContracts.forEach(c => {\n        let rawDjId = typeof c.dj_profile === 'string' ? c.dj_profile : (c.dj_profile_data?.id || c.dj_profile?.id);\n        let rawDjName = c.dj_profile_data?.nom_artistique || (typeof c.dj_profile === 'string' ? c.dj_profile : c.dj_profile?.nom_artistique || c.dj_profile?.name || \"\");\n        \n        let targetId = String(rawDjId || \"\");\n        \n        let officialId = null;\n        if (officialDjMap.has(targetId)) {\n          officialId = targetId;\n        } else {\n          let cleanName = normalize(rawDjName);\n          if (nameToOfficialId.has(cleanName)) {\n            officialId = nameToOfficialId.get(cleanName);\n          } else {\n            let firstWord = cleanName.split(/[\\s-]/)[0];\n            if (nameToOfficialId.has(firstWord)) {\n              officialId = nameToOfficialId.get(firstWord);\n            }\n          }\n        }\n        \n        // Uniquement les DJs officiels\n        if (!officialId) return;\n\n        let assignedDj = officialDjMap.get(officialId);\n\n        let dateStr = c.client_info?.event_date || c.created_at;\n        if (!dateStr) return;\n        \n        let eventDate = new Date(dateStr);\n        if (isNaN(eventDate)) return;\n\n        let type = c.client_info?.event_type || 'Événement';\n        if (type && typeof type === 'string' && type.toLowerCase() === 'custom') {\n          type = c.client_info?.custom_event_type || 'Événement Personnalisé';\n        }\n        if (typeof type !== 'string') type = 'Événement';\n        \n        let client = c.client_info?.name || c.client_name || '';\n        if (typeof client !== 'string') {\n          client = client.name || client.nom || 'Client Inconnu';\n        }\n        \n        let title = String(`${type} - ${client}`.trim());\n        if (title === '-') title = 'Événement sans nom';\n\n        let optionsDetails = '';\n        if (c.selected_options && Array.isArray(c.selected_options)) {\n          const opts = c.selected_options.map(o => typeof o === 'string' ? o : o.name).filter(Boolean);\n          if (opts.length > 0) {\n            optionsDetails = `\\nOptions: ${opts.join(', ')}`;\n          }\n        } else if (c.requested_options && Array.isArray(c.requested_options)) {\n          const opts = c.requested_options.map(o => typeof o === 'string' ? o : o.name).filter(Boolean);\n          if (opts.length > 0) {\n            optionsDetails = `\\nOptions: ${opts.join(', ')}`;\n          }\n        }\n        \n        let fullTitle = `${title}${optionsDetails}`;\n        \n        // Prevent duplicate mapping if somehow necessary, but contracts are unique by ID\n        let signature = `${officialId}_${eventDate.toISOString().split('T')[0]}_contract_${c.id}`;\n        if (eventSignatures.has(signature)) return;\n        eventSignatures.add(signature);\n\n        parsedEvents.push({\n          id: `contract_${c.id}`,\n          title: fullTitle,\n          cleanTitle: title,\n          start: eventDate,\n          end: eventDate,\n          allDay: true,\n          djId: officialId,\n          djName: assignedDj.name,\n          clientName: client,\n          clientPhone: c.client_info?.phone || c.phone || '',\n          clientPhone2: c.client_info?.phone2 || '',\n          eventType: type,\n          status: String(c.status),\n          type: 'Contrat Prestation',\n          details: optionsDetails ? optionsDetails.trim() : '',\n          location: c.client_info?.event_location || ''\n        });\n      });\n\n      // Désactivation de l'affichage des réservations matériel [Matériel] sur l'agenda prestation\n      const djReservations = [];\n\n      djReservations.forEach(r => {\n        let officialId = null;\n        let cleanName = normalize(r.dj_name || '');\n        if (nameToOfficialId.has(cleanName)) {\n          officialId = nameToOfficialId.get(cleanName);\n        } else {\n          let firstWord = cleanName.split(/[\\s-]/)[0];\n          if (nameToOfficialId.has(firstWord)) {\n            officialId = nameToOfficialId.get(firstWord);\n          }\n        }\n        \n        if (!officialId) return;\n        \n        let assignedDj = officialDjMap.get(officialId);\n        \n        let startDate;\n        let endDate;\n        try {\n          const partsS = r.start_date.split('-');\n          const partsE = r.end_date.split('-');\n          startDate = new Date(parseInt(partsS[0], 10), parseInt(partsS[1], 10) - 1, parseInt(partsS[2], 10));\n          // Set end date to 23:59:59 to make it inclusive in react-big-calendar\n          endDate = new Date(parseInt(partsE[0], 10), parseInt(partsE[1], 10) - 1, parseInt(partsE[2], 10), 23, 59, 59, 999);\n        } catch (e) {\n          return;\n        }\n        if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) return;\n        \n        const itemsList = r.equipment_items || r.items || [];\n        const itemRefs = [];\n        if (Array.isArray(itemsList)) {\n          itemsList.forEach(item => {\n            const ref = item.reference || '';\n            if (ref && !itemRefs.includes(ref)) {\n              itemRefs.push(ref);\n            }\n          });\n        }\n        \n        let refsText = itemRefs.join('/');\n        \n        let equipmentOpts = '';\n        if (Array.isArray(itemsList) && itemsList.length > 0) {\n          const equips = itemsList.map(item => {\n            const name = item.equipment_name || item.name || '';\n            const qty = item.quantity || 1;\n            const ref = item.reference || '';\n            return `${name}${ref ? ` [${ref}]` : ''} (x${qty})`;\n          }).filter(Boolean);\n          if (equips.length > 0) {\n            equipmentOpts = `\\nMatériel: ${equips.join(', ')}`;\n          }\n        } else if (r.equipment && Array.isArray(r.equipment)) {\n          const equips = r.equipment.map(e => typeof e === 'string' ? e : e.name).filter(Boolean);\n          if (equips.length > 0) {\n            equipmentOpts = `\\nMatériel: ${equips.join(', ')}`;\n          }\n        }\n\n        let pubTitle = r.event_name || r.event || 'Réservation DJ';\n        let fullTitle = `[Matériel] ${refsText ? `${refsText} - ` : ''}${pubTitle}${equipmentOpts}`;\n\n        let signature = `${officialId}_${startDate.toISOString().split('T')[0]}_reservation_${r.id}`;\n        if (eventSignatures.has(signature)) return;\n        eventSignatures.add(signature);\n\n        parsedEvents.push({\n          id: `res_${r.id}`,\n          title: fullTitle,\n          cleanTitle: pubTitle,\n          start: startDate,\n          end: endDate,\n          allDay: true,\n          djId: officialId,\n          djName: assignedDj.name,\n          clientName: r.client_name || r.client?.name || r.user_name || 'Client Réservation',\n          eventType: 'Réservation Matériel',\n          status: 'reservation',\n          type: 'Réservation Matériel',\n          details: refsText ? `Référence: ${refsText}${equipmentOpts ? ` | ${equipmentOpts.trim()}` : ''}` : (equipmentOpts ? equipmentOpts.trim() : '')\n        });\n      });\n\n      // Parse custom manual events and options\n      const customEventsList = customEventsRes?.data || [];\n      customEventsList.forEach(item => {\n        let eventDate = new Date(item.date);\n        if (isNaN(eventDate)) return;\n\n        parsedEvents.push({\n          id: `custom_${item._id || item.id}`,\n          title: item.title,\n          cleanTitle: item.title,\n          start: eventDate,\n          end: eventDate,\n          allDay: true,\n          djId: item.isOption ? 'option_black' : (item.djId || \"\"),\n          djName: item.isOption ? 'Option' : (item.djName || 'Non assigné'),\n          clientName: item.clientName || '',\n          clientPhone: item.clientPhone || '',\n          eventType: item.eventType || (item.isOption ? 'Option' : 'Événement'),\n          status: item.isOption ? 'option' : 'custom_event',\n          type: item.isOption ? 'Option Soirée' : 'Événement Manuel',\n          details: item.details || '',\n          location: item.location || '',\n          isOption: !!item.isOption,\n          recurrenceId: item.recurrenceId || null\n        });\n      });\n\n      const availableDjs = Array.from(officialDjMap.values()).filter(d => !loadedSettings.deleted_djs.includes(d.id));\n      setDjs(availableDjs);\n\n      const filteredEvents = parsedEvents\n        .filter(e => e.isOption || !loadedSettings.deleted_djs.includes(e.djId))\n        .filter(e => !loadedSettings.deleted_events.includes(e.id));\n      setEvents(filteredEvents);\n\n    } catch (error) {\n      console.error(\"Error fetching agenda data:\", error);\n      toast.error(\"Erreur lors du chargement des données.\");\n    } finally {\n      setLoading(false);\n    }\n  };\n\n  const handleToggleDj = async (djId) => {\n    try {\n      const newHidden = settings.hidden_djs.includes(djId)\n        ? settings.hidden_djs.filter(id => id !== djId)\n        : [...settings.hidden_djs, djId];\n        \n      const newSettings = { ...settings, hidden_djs: newHidden };\n      setSettings(newSettings);\n      \n      await axios.put(`${API}/agenda-settings`, newSettings);\n    } catch (error) {\n      toast.error(\"Erreur de sauvegarde\");\n    }\n  };\n\n  const handleDeleteDj = async (djId) => {\n    try {\n      const newDeleted = [...settings.deleted_djs, djId];\n      const newSettings = { ...settings, deleted_djs: newDeleted };\n      setSettings(newSettings);\n      \n      setDjs(djs.filter(d => d.id !== djId));\n      setShowConfirmDelete(null);\n      \n      await axios.put(`${API}/agenda-settings`, newSettings);\n      toast.success(\"Agenda supprimé\");\n    } catch (error) {\n      toast.error(\"Erreur lors de la suppression\");\n    }\n  };\n\n  const handleDeleteEvent = async (event, deleteAllSeries = false) => {\n    setSelectedEvent(null);\n    \n    if (event.id && event.id.startsWith('custom_')) {\n      const customId = event.id.replace('custom_', '');\n      \n      if (event.recurrenceId && !deleteAllSeries && deleteRecurringEvent === null) {\n        setDeleteRecurringEvent(event);\n        return;\n      }\n\n      try {\n        setLoading(true);\n        const url = deleteAllSeries \n          ? `${API}/agenda-custom-events/${customId}?deleteAllSeries=true`\n          : `${API}/agenda-custom-events/${customId}`;\n          \n        await axios.delete(url);\n        \n        if (deleteAllSeries && event.recurrenceId) {\n          setEvents(prev => prev.filter(e => e.recurrenceId !== event.recurrenceId));\n          toast.success(\"Toute la série d'événements a été supprimée !\");\n        } else {\n          setEvents(prev => prev.filter(e => e.id !== event.id));\n          toast.success(\"Option/Événement supprimé avec succès !\");\n        }\n        setDeleteRecurringEvent(null);\n      } catch (err) {\n        console.error(\"Error deleting custom event:\", err);\n        toast.error(\"Erreur lors de la suppression définitive.\");\n      } finally {\n        setLoading(false);\n      }\n      return;\n    }\n\n    if (undoRef.current) {\n      commitDeletion(undoRef.current);\n    }\n    \n    undoRef.current = event;\n    setUndoableEvent(event);\n    setUndoSeconds(5);\n    \n    setEvents(prev => prev.filter(e => e.id !== event.id));\n    \n    if (timerRef.current) clearInterval(timerRef.current);\n    \n    timerRef.current = setInterval(() => {\n      setUndoSeconds(prev => {\n        if (prev <= 1) {\n          clearInterval(timerRef.current);\n          commitDeletion(undoRef.current);\n          setUndoableEvent(null);\n          undoRef.current = null;\n          return 0;\n        }\n        return prev - 1;\n      });\n    }, 1000);\n  };\n\n  const handleSaveCustomEvent = async (e) => {\n    e.preventDefault();\n    if (!customEventForm.title || !customEventForm.title.trim()) {\n      toast.error(\"Veuillez saisir un titre / nom d'événement.\");\n      return;\n    }\n    if (addEventType === 'event' && !customEventForm.djId) {\n      toast.error(\"Veuillez attribuer un DJ.\");\n      return;\n    }\n\n    const payload = {\n      title: customEventForm.title.trim(),\n      date: format(addEventDate, 'yyyy-MM-dd'),\n      isOption: addEventType === 'option',\n      djId: customEventForm.djId || null,\n      djName: customEventForm.djId ? djs.find(d => d.id === customEventForm.djId)?.name : '',\n      clientName: addEventType === 'event' ? customEventForm.clientName.trim() : '',\n      clientPhone: (customEventForm.clientPhone || '').trim(),\n      eventType: addEventType === 'event' ? (customEventForm.eventType === 'custom' ? (customEventForm.customEventTypeInput || '').trim() : customEventForm.eventType.trim()) : 'Option',\n      details: customEventForm.details.trim(),\n      location: (customEventForm.location || '').trim(),\n      recurrence: !editingCustomEventId ? recurrence : 'none',\n      recurrenceEndType: !editingCustomEventId ? recurrenceEndType : 'count',\n      recurrenceEndDate: !editingCustomEventId ? recurrenceEndDate : '',\n      recurrenceCount: !editingCustomEventId ? Number(recurrenceCount) : 5\n    };\n\n    try {\n      setLoading(true);\n      if (editingCustomEventId) {\n        const res = await axios.put(`${API}/agenda-custom-events/${editingCustomEventId}`, payload);\n        if (res.data.success) {\n          toast.success(\"Événement / Option modifié avec succès !\");\n          setCustomEventForm({ title: '', clientName: '', clientPhone: '', djId: '', eventType: '', customEventTypeInput: '', details: '', location: '' });\n          setAddEventDate(null);\n          setEditingCustomEventId(null);\n          setRecurrence('none');\n          setRecurrenceEndType('count');\n          setRecurrenceEndDate('');\n          setRecurrenceCount(5);\n          await fetchData();\n        } else {\n          toast.error(\"Erreur lors de la modification.\");\n        }\n      } else {\n        const res = await axios.post(`${API}/agenda-custom-events`, payload);\n        if (res.data.success) {\n          toast.success(addEventType === 'option' ? \"Option de soirée enregistrée avec succès !\" : \"Événement enregistré avec succès !\");\n          setCustomEventForm({ title: '', clientName: '', clientPhone: '', djId: '', eventType: '', customEventTypeInput: '', details: '', location: '' });\n          setAddEventDate(null);\n          setRecurrence('none');\n          setRecurrenceEndType('count');\n          setRecurrenceEndDate('');\n          setRecurrenceCount(5);\n          await fetchData();\n        } else {\n          toast.error(\"Erreur lors de l'enregistrement.\");\n        }\n      }\n    } catch (err) {\n      console.error(\"Error saving custom event:\", err);\n      toast.error(\"Une erreur s'est produite lors de la communication de l'API.\");\n    } finally {\n      setLoading(false);\n    }\n  };\n\n  const handleUndoDelete = () => {\n    if (timerRef.current) {\n      clearInterval(timerRef.current);\n    }\n    if (undoRef.current) {\n      const restored = undoRef.current;\n      setEvents(prev => [...prev, restored]);\n      toast.success(\"Suppression annulée !\");\n    }\n    setUndoableEvent(null);\n    undoRef.current = null;\n  };\n\n  const commitDeletion = async (eventToDelete) => {\n    if (!eventToDelete) return;\n    try {\n      const updatedDeletedEvents = [...(settings.deleted_events || []), eventToDelete.id];\n      const updatedSettings = { ...settings, deleted_events: updatedDeletedEvents };\n      setSettings(updatedSettings);\n      \n      await axios.put(`${API}/agenda-settings`, updatedSettings);\n      toast.info(\"L'événement a été retiré de l'agenda.\");\n    } catch (err) {\n      console.error(\"Error committing event deletion:\", err);\n      toast.error(\"Erreur technique lors de la suppression définitive.\");\n    }\n  };\n\n  useEffect(() => {\n    return () => {\n      if (timerRef.current) clearInterval(timerRef.current);\n    };\n  }, []);\n\n  const eventStyleGetter = (event) => {\n    if (event.isOption) {\n      return {\n        style: {\n          backgroundColor: '#000000',\n          borderRadius: '4px',\n          opacity: 0.95,\n          color: '#ffffff',\n          border: '1px solid #111111',\n          display: 'block',\n          fontSize: '12px',\n          fontWeight: '600',\n          letterSpacing: '0.2px',\n          padding: '4px 8px',\n          whiteSpace: 'pre-wrap',\n          lineHeight: '1.4'\n        }\n      };\n    }\n    if (settings.hidden_djs.includes(event.djId)) {\n      return { style: { display: 'none' } };\n    }\n    const dj = djs.find(d => d.id === event.djId);\n    const backgroundColor = dj?.color || '#3174ad';\n    return {\n      style: {\n        backgroundColor,\n        borderRadius: '4px',\n        opacity: 0.9,\n        color: '#fff',\n        border: '0px',\n        display: 'block',\n        fontSize: '12px',\n        fontWeight: '500',\n        letterSpacing: '0.2px',\n        padding: '4px 8px',\n        whiteSpace: 'pre-wrap',\n        lineHeight: '1.4'\n      }\n    };\n  };\n\n  const displayedEvents = events.filter(e => e.isOption || !settings.hidden_djs.includes(e.djId));\n\n  return (\n    <div className=\"w-full flex-col h-screen bg-slate-50 text-left items-stretch overflow-hidden flex\">\n      <div className=\"flex-1 flex flex-col min-h-0 w-full\">\n        <header className=\"bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0 w-full\">\n          <div className=\"flex items-center gap-3\">\n            <div className=\"w-10 h-10 rounded-xl bg-red-100 flex items-center justify-center text-red-600\">\n              <CalendarDays className=\"w-6 h-6\" />\n            </div>\n            <div>\n              <h1 className=\"text-xl font-bold text-slate-800\">Agenda Prestation</h1>\n              <p className=\"text-sm text-slate-500\">Vue globale des événements signés</p>\n            </div>\n          </div>\n          <div className=\"flex items-center gap-2\">\n            <button\n              onClick={handleSyncAllGoogle}\n              disabled={syncingAll || loading}\n              className=\"flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white font-semibold rounded-lg text-sm transition shadow-sm disabled:opacity-50\"\n              title=\"Synchroniser tous les événements actifs avec les Google Agendas de chaque DJ\"\n            >\n              {syncingAll ? (\n                <Loader2 className=\"w-4 h-4 animate-spin\" />\n              ) : (\n                <CalendarDays className=\"w-4 h-4\" />\n              )}\n              <span>Synchroniser Google Agenda</span>\n            </button>\n            <button\n              onClick={fetchData}\n              disabled={loading}\n              className=\"flex items-center gap-2 px-4 py-2 bg-indigo-50 hover:bg-indigo-100 active:bg-indigo-200 border border-indigo-150 disabled:opacity-50 text-indigo-700 font-semibold rounded-lg text-sm transition shadow-sm\"\n            >\n              <RotateCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />\n              <span>Actualiser</span>\n            </button>\n          </div>\n        </header>\n\n        <div className=\"flex-1 flex overflow-hidden p-6 gap-6\">\n          {/* Sidebar DJs */}\n          <div className=\"w-64 shrink-0 bg-white border border-slate-200 rounded-xl shadow-sm flex flex-col overflow-hidden\">\n            <div className=\"p-4 border-b border-slate-100 bg-slate-50\">\n              <h2 className=\"font-semibold text-slate-700 flex items-center gap-2\">\n                <Shield className=\"w-4 h-4\" /> Agendas DJs\n              </h2>\n            </div>\n            <div className=\"flex-1 overflow-y-auto p-2\">\n              {loading ? (\n                <div className=\"flex justify-center p-6\"><Loader2 className=\"w-6 h-6 animate-spin text-slate-300\" /></div>\n              ) : djs.length === 0 ? (\n                <div className=\"p-4 text-center text-sm text-slate-500 italic\">Aucun agenda disponible</div>\n              ) : (\n                <div className=\"space-y-1\">\n                  {djs.map(dj => (\n                    <div key={dj.id} className=\"group flex items-center justify-between p-2 rounded-lg hover:bg-slate-50 transition\">\n                      <label className=\"flex items-center gap-3 cursor-pointer flex-1 overflow-hidden\">\n                        <input \n                          type=\"checkbox\" \n                          checked={!settings.hidden_djs.includes(dj.id)} \n                          onChange={() => handleToggleDj(dj.id)}\n                          className=\"w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500 border-gray-300\" \n                        />\n                        <div className=\"w-3 h-3 rounded-full flex-shrink-0\" style={{ backgroundColor: dj.color || '#ccc' }}></div>\n                        <span className=\"text-sm font-medium text-slate-700 truncate\">{dj.name}</span>\n                      </label>\n                      <button \n                        onClick={() => setShowConfirmDelete(dj.id)}\n                        className=\"opacity-0 group-hover:opacity-100 p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded transition flex-shrink-0\"\n                        title=\"Supprimer l'agenda\"\n                      >\n                        <Trash2 className=\"w-4 h-4\" />\n                      </button>\n                    </div>\n                  ))}\n                </div>\n              )}\n            </div>\n\n            {/* Google Calendar Status Helper Box */}\n            {gcalStatus && gcalStatus.serviceAccountEmail && (\n              <div className=\"p-4 border-t border-slate-100 bg-slate-50/70 text-xs text-slate-600 space-y-2 shrink-0\">\n                <div className=\"flex items-center gap-1.5 font-bold text-slate-700\">\n                  <span className=\"w-2 h-2 rounded-full bg-emerald-500 block animate-pulse\"></span>\n                  Google Calendar connecté\n                </div>\n                <p className=\"leading-relaxed\">\n                  Pour que l'agenda de chaque DJ se synchronise, vous <strong>devez partager son agenda Google</strong> avec ce compte :\n                </p>\n                <div className=\"p-2 bg-white border border-slate-200 rounded font-mono text-[10px] break-all select-all flex items-center justify-between text-indigo-600 font-semibold shadow-xs\">\n                  <span>{gcalStatus.serviceAccountEmail}</span>\n                </div>\n                <p className=\"text-[10px] text-slate-500 leading-tight\">\n                  Autorisation requise pour l'ajout : <span className=\"font-semibold text-slate-600\">\"Modifier les événements\" (droit d'écriture)</span>.\n                </p>\n              </div>\n            )}\n          </div>\n\n          {/* Calendar View */}\n          <div className=\"flex-1 bg-white border border-slate-200 rounded-xl shadow-sm p-4 overflow-hidden flex flex-col\">\n             {loading ? (\n                <div className=\"flex-1 flex items-center justify-center\">\n                  <div className=\"flex flex-col items-center gap-3\">\n                    <Loader2 className=\"w-10 h-10 animate-spin text-indigo-600\" />\n                    <p className=\"text-slate-500 font-medium text-sm\">Chargement du calendrier...</p>\n                  </div>\n                </div>\n             ) : (\n                <div className=\"flex-1\">\n                  <Calendar\n                    localizer={localizer}\n                    events={displayedEvents}\n                    startAccessor=\"start\"\n                    endAccessor=\"end\"\n                    style={{ height: '100%' }}\n                    view={calendarView}\n                    date={calendarDate}\n                    onView={setCalendarView}\n                    onNavigate={setCalendarDate}\n                    onDrillDown={(newDate) => {\n                      setCalendarDate(newDate);\n                      setCalendarView('agenda');\n                    }}\n                    onSelectEvent={(event) => {\n                      setSelectedEvent(event);\n                    }}\n                    length={calendarView === 'agenda' ? 1 : undefined}\n                    messages={{\n                      next: \"Suivant\",\n                      previous: \"Précédent\",\n                      today: \"Aujourd'hui\",\n                      month: \"Mois\",\n                      week: \"Semaine\",\n                      day: \"Jour\",\n                      agenda: \"Mode Liste\",\n                      noEventsInRange: \"Aucun événement sur cette période.\",\n                      showMore: total => `+ ${total} de plus`\n                    }}\n                    culture=\"fr\"\n                    eventPropGetter={eventStyleGetter}\n                    components={{\n                      toolbar: CustomToolbar,\n                      month: {\n                        dateHeader: ({ date, label }) => {\n                          return (\n                            <div className=\"flex items-center justify-between w-full px-2 py-0.5 shrink-0 select-none\">\n                              <span className=\"text-sm font-semibold text-slate-700\">{label}</span>\n                              <button\n                                type=\"button\"\n                                onClick={(e) => {\n                                  e.preventDefault();\n                                  e.stopPropagation();\n                                  setAddEventDate(date);\n                                  setAddEventType('option');\n                                  setCustomEventForm({ title: '', clientName: '', djId: '', eventType: '', customEventTypeInput: '', details: '' });\n                                }}\n                                className=\"w-5 h-5 rounded-full bg-slate-100 hover:bg-slate-900 hover:text-white border border-slate-300 hover:border-slate-900 flex items-center justify-center text-slate-600 transition-colors shrink-0 text-xs font-bold cursor-pointer\"\n                                title=\"Ajouter une option de soirée ou un événement\"\n                              >\n                                <Plus className=\"w-3 h-3\" />\n                              </button>\n                            </div>\n                          );\n                        }\n                      }\n                    }}\n                    popup\n                    dayLayoutAlgorithm=\"no-overlap\"\n                    views={['month', 'agenda']}\n                  />\n                </div>\n             )}\n          </div>\n        </div>\n      </div>\n\n      {showConfirmDelete && (\n        <div className=\"fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4\">\n          <div className=\"bg-white rounded-xl shadow-xl max-w-sm w-full p-6 animate-in zoom-in-95 duration-200\">\n            <h3 className=\"text-lg font-bold text-slate-900 mb-2\">Confirmer la suppression</h3>\n            <p className=\"text-slate-600 mb-6 text-sm\">\n              Êtes-vous sûr de vouloir masquer et supprimer cet agenda DJ de cette vue ? Il ne s'affichera plus ici. \n              (L'artiste ne sera pas supprimé des autres applications).\n            </p>\n            <div className=\"flex justify-end gap-3\">\n              <button \n                onClick={() => setShowConfirmDelete(null)}\n                className=\"px-4 py-2 font-medium bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg transition\"\n              >\n                Annuler\n              </button>\n              <button \n                onClick={() => handleDeleteDj(showConfirmDelete)}\n                className=\"px-4 py-2 font-medium bg-red-600 hover:bg-red-700 text-white rounded-lg transition\"\n              >\n                Supprimer\n              </button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {selectedEvent && (\n        <div className=\"fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4\">\n          <div className=\"bg-white rounded-xl shadow-xl max-w-md w-full overflow-hidden animate-in zoom-in-95 duration-200\">\n            {/* Header */}\n            <div className=\"p-4 bg-slate-50 border-b flex items-center justify-between\">\n              <span className=\"text-xs font-bold uppercase tracking-wider text-slate-500 bg-slate-200/60 px-2.5 py-1 rounded-md\">\n                {selectedEvent.type || 'Événement'}\n              </span>\n              <button \n                onClick={() => setSelectedEvent(null)}\n                className=\"text-slate-400 hover:text-slate-600 hover:bg-slate-100 p-1 rounded-lg transition\"\n              >\n                <X className=\"w-5 h-5\" />\n              </button>\n            </div>\n            \n            {/* Content */}\n            <div className=\"p-6 space-y-4\">\n              <div>\n                <h3 className=\"text-lg font-bold text-slate-950 leading-tight\">\n                  {selectedEvent.cleanTitle || selectedEvent.title}\n                </h3>\n                <p className=\"text-sm text-slate-500 mt-1 flex items-center gap-1.5 font-medium\">\n                  <CalendarDays className=\"w-4 h-4 text-indigo-500\" />\n                  {format(selectedEvent.start, 'dd MMMM yyyy', { locale: fr })}\n                </p>\n              </div>\n\n              <div className=\"border-t border-slate-100 pt-4 space-y-3\">\n                <div className=\"flex items-center gap-2.5 text-sm\">\n                  <User className=\"w-4.5 h-4.5 text-slate-400\" />\n                  <span className=\"text-slate-500\">Client :</span>\n                  <span className=\"font-semibold text-slate-800\">{selectedEvent.clientName || 'Inconnu'}</span>\n                </div>\n\n                {(selectedEvent.clientPhone || selectedEvent.clientPhone2) && (\n                  <div className=\"flex items-center gap-2.5 text-sm\">\n                    <Phone className=\"w-4.5 h-4.5 text-indigo-500\" />\n                    <span className=\"text-slate-500\">Téléphone :</span>\n                    <div className=\"flex flex-wrap gap-x-2 text-indigo-600 font-semibold\">\n                      {selectedEvent.clientPhone && (\n                        <a href={`tel:${selectedEvent.clientPhone}`} className=\"hover:underline\">\n                          {selectedEvent.clientPhone}\n                        </a>\n                      )}\n                      {selectedEvent.clientPhone && selectedEvent.clientPhone2 && <span className=\"text-slate-300\">/</span>}\n                      {selectedEvent.clientPhone2 && (\n                        <a href={`tel:${selectedEvent.clientPhone2}`} className=\"hover:underline\">\n                          {selectedEvent.clientPhone2}\n                        </a>\n                      )}\n                    </div>\n                  </div>\n                )}\n                \n                <div className=\"flex items-center gap-2.5 text-sm\">\n                  <Shield className=\"w-4.5 h-4.5 text-slate-400\" />\n                  <span className=\"text-slate-500\">DJ assigné :</span>\n                  <span className=\"font-semibold text-slate-800\">{selectedEvent.djName}</span>\n                </div>\n\n                {selectedEvent.location && (\n                  <div className=\"flex items-center gap-2.5 text-sm\">\n                    <MapPin className=\"w-4.5 h-4.5 text-slate-400\" />\n                    <span className=\"text-slate-500\">Lieu :</span>\n                    <span className=\"font-semibold text-slate-800\">{selectedEvent.location}</span>\n                  </div>\n                )}\n\n                {selectedEvent.details && (\n                  <div className=\"bg-slate-50 border border-slate-100 p-3 rounded-lg text-xs leading-relaxed text-slate-700 whitespace-pre-wrap\">\n                    <span className=\"font-bold text-slate-400 block uppercase tracking-wider text-[10px] mb-1\">Détails de la prestation / Matériel</span>\n                    {selectedEvent.details}\n                  </div>\n                )}\n              </div>\n            </div>\n\n            {/* Footer with actions */}\n            <div className=\"p-4 bg-slate-50 border-t flex flex-col sm:flex-row justify-between gap-3\">\n              <div className=\"flex flex-wrap gap-2\">\n                <button \n                  onClick={() => {\n                    if (window.confirm(\"Masquer définitivement cet événement du planning de prestation ? (Le contrat d'origine ou la réservation ne seront pas modifiés)\")) {\n                      handleDeleteEvent(selectedEvent);\n                    }\n                  }}\n                  className=\"flex items-center justify-center gap-1.5 px-3 py-2 bg-red-50 hover:bg-red-100 border border-red-200 text-red-650 hover:text-red-700 rounded-lg text-sm font-semibold transition\"\n                  title=\"Supprime cet événement uniquement de la vue Prestation\"\n                >\n                  <Trash2 className=\"w-4 h-4\" />\n                  Masquer\n                </button>\n\n                {selectedEvent.id && selectedEvent.id.startsWith('custom_') && (\n                  <button \n                    onClick={() => {\n                      setCustomEventForm({\n                        title: selectedEvent.cleanTitle || selectedEvent.title || '',\n                        clientName: selectedEvent.clientName || '',\n                        clientPhone: selectedEvent.clientPhone || '',\n                        djId: selectedEvent.djId === 'option_black' ? '' : (selectedEvent.djId || ''),\n                        eventType: (selectedEvent.eventType && !getEventTypesList(selectedEvent.djId).includes(selectedEvent.eventType)) ? 'custom' : (selectedEvent.eventType || ''),\n                        customEventTypeInput: (selectedEvent.eventType && !getEventTypesList(selectedEvent.djId).includes(selectedEvent.eventType)) ? selectedEvent.eventType : '',\n                        details: selectedEvent.details || '',\n                        location: selectedEvent.location || ''\n                      });\n                      setAddEventDate(selectedEvent.start);\n                      setAddEventType(selectedEvent.isOption ? 'option' : 'event');\n                      setEditingCustomEventId(selectedEvent.id.replace('custom_', ''));\n                      setSelectedEvent(null);\n                    }}\n                    className=\"flex items-center justify-center gap-1.5 px-3 py-2 bg-blue-50 hover:bg-blue-100 border border-blue-200 text-blue-650 hover:text-blue-700 rounded-lg text-sm font-semibold transition animate-shake\"\n                  >\n                    <Edit className=\"w-4 h-4\" />\n                    Modifier\n                  </button>\n                )}\n              </div>\n              \n              <button \n                onClick={() => setSelectedEvent(null)}\n                className=\"px-4 py-2 bg-slate-250 hover:bg-slate-350 text-slate-800 rounded-lg text-sm font-semibold transition\"\n              >\n                Fermer\n              </button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {undoableEvent && (\n        <div className=\"fixed bottom-6 right-6 md:right-1/2 md:translate-x-1/2 z-50 bg-slate-900 border border-slate-800 text-white px-5 py-4 rounded-xl shadow-2xl flex items-center justify-between gap-4 animate-in fade-in slide-in-from-bottom-5 duration-300 min-w-[320px] max-w-md\">\n          <div className=\"flex-1 text-sm font-medium text-left\">\n            <div>Événement masqué avec succès</div>\n            <div className=\"text-xs text-slate-350 mt-1 truncate max-w-[240px]\">{undoableEvent.cleanTitle || undoableEvent.title}</div>\n          </div>\n          <button \n            onClick={handleUndoDelete}\n            className=\"text-xs font-bold uppercase text-indigo-400 hover:text-indigo-300 px-3 py-1.5 bg-slate-800 hover:bg-slate-750 border border-slate-750 rounded-lg transition-all\"\n          >\n            Annuler ({undoSeconds}s)\n          </button>\n        </div>\n      )}\n\n      {addEventDate && (\n        <div className=\"fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4\">\n          <div className=\"bg-white rounded-xl shadow-2xl max-w-md w-full overflow-hidden animate-in zoom-in-95 duration-200\">\n            {/* Header */}\n            <div className=\"p-4 bg-slate-50 border-b flex items-center justify-between\">\n              <h3 className=\"text-sm font-bold uppercase tracking-wider text-slate-700 flex items-center gap-1.5\">\n                <CalendarDays className=\"w-4.5 h-4.5 text-indigo-500\" />\n                <span>{editingCustomEventId ? \"Modifier l'événement du\" : \"Planifier pour le\"} {format(addEventDate, 'dd MMMM yyyy', { locale: fr })}</span>\n              </h3>\n              <button \n                type=\"button\"\n                onClick={() => {\n                  setAddEventDate(null);\n                  setEditingCustomEventId(null);\n                  setCustomEventForm({ title: '', clientName: '', clientPhone: '', djId: '', eventType: '', customEventTypeInput: '', details: '', location: '' });\n                  setRecurrence('none');\n                  setRecurrenceEndType('count');\n                  setRecurrenceEndDate('');\n                  setRecurrenceCount(5);\n                }}\n                className=\"text-slate-400 hover:text-slate-600 hover:bg-slate-100 p-1 rounded-lg transition\"\n              >\n                <X className=\"w-5 h-5\" />\n              </button>\n            </div>\n            \n            {/* Form */}\n            <form onSubmit={handleSaveCustomEvent} className=\"p-6 space-y-4\">\n              {/* Date Input */}\n              <div className=\"mb-4\">\n                <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Date de l'événement *</label>\n                <input\n                  type=\"date\"\n                  required\n                  value={addEventDate ? format(addEventDate, 'yyyy-MM-dd') : ''}\n                  onChange={(e) => {\n                    if (e.target.value) {\n                      setAddEventDate(new Date(e.target.value));\n                    }\n                  }}\n                  className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 bg-white shadow-sm\"\n                />\n              </div>\n\n              {/* Selector / Switcher */}\n              <div className=\"grid grid-cols-2 gap-2 p-1 bg-slate-100 rounded-lg mb-6\">\n                <button\n                  type=\"button\"\n                  onClick={() => setAddEventType('option')}\n                  className={`py-2 text-sm font-semibold rounded-md transition-all flex items-center justify-center gap-1.5 cursor-pointer ${addEventType === 'option' ? 'bg-black text-white shadow-sm' : 'text-slate-600 hover:bg-slate-50'}`}\n                >\n                  <Tag className=\"w-4 h-4\" />\n                  Option de soirée\n                </button>\n                <button\n                  type=\"button\"\n                  onClick={() => setAddEventType('event')}\n                  className={`py-2 text-sm font-semibold rounded-md transition-all flex items-center justify-center gap-1.5 cursor-pointer ${addEventType === 'event' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-600 hover:bg-slate-50'}`}\n                >\n                  <User className=\"w-4 h-4\" />\n                  Événement Manuel\n                </button>\n              </div>\n\n              {addEventType === 'option' ? (\n                // OPTION FORM\n                <div className=\"space-y-4\">\n                  <div className=\"text-xs bg-slate-50 border border-slate-150 text-slate-650 p-3 rounded-lg leading-relaxed\">\n                    Les <strong>options de soirée</strong> sont marquées en <strong>noir et blanc</strong> et s'affichent par défaut pour tout le monde pour bloquer une date ou noter une possibilité.\n                  </div>\n                  \n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Titre de l'option / Client *</label>\n                    <input\n                      type=\"text\"\n                      required\n                      placeholder=\"Ex: Option Mariage Dupuis ou Option Soirée Privée\"\n                      value={customEventForm.title}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, title: e.target.value }))}\n                      className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-gray-900 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                    />\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Attribuer un DJ (Optionnel)</label>\n                    {djs.length === 0 ? (\n                      <div className=\"text-xs text-red-500 italic\">Aucun DJ disponible.</div>\n                    ) : (\n                      <select\n                        value={customEventForm.djId}\n                        onChange={(e) => setCustomEventForm(prev => ({ ...prev, djId: e.target.value }))}\n                        className=\"w-full px-3 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-gray-900 focus:border-transparent text-sm text-slate-900 bg-white shadow-sm\"\n                      >\n                        <option value=\"\">-- Sélectionnez un DJ (pour synchronisation) --</option>\n                        {djs.map(dj => (\n                          <option key={dj.id} value={dj.id}>\n                            {dj.name}\n                          </option>\n                        ))}\n                      </select>\n                    )}\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Téléphone du client</label>\n                    <input\n                      type=\"text\"\n                      placeholder=\"Ex: 06 12 34 56 78\"\n                      value={customEventForm.clientPhone}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, clientPhone: e.target.value }))}\n                      className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-gray-900 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                    />\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Lieu de l'événement</label>\n                    <input\n                      type=\"text\"\n                      placeholder=\"Ex: Château de Versailles, Villebon...\"\n                      value={customEventForm.location}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, location: e.target.value }))}\n                      className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-gray-900 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                    />\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Détails / Notes optionnelles</label>\n                    <textarea\n                      placeholder=\"Notes ou remarques particulières...\"\n                      rows={3}\n                      value={customEventForm.details}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, details: e.target.value }))}\n                      className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-gray-900 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm resize-none\"\n                    />\n                  </div>\n                </div>\n              ) : (\n                // EVENT FORM\n                <div className=\"space-y-4\">\n                  <div className=\"text-xs bg-indigo-50/50 border border-indigo-100 text-indigo-700 p-3 rounded-lg leading-relaxed\">\n                    Les <strong>événements manuels</strong> vous permettent d'enregistrer une prestation directement dans l'agenda sans générer de contrat et d'attribuer un DJ.\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Nom de l'événement *</label>\n                    <input\n                      type=\"text\"\n                      required\n                      placeholder=\"Ex: Soirée Entreprise Décathlon ou Mariage Julie\"\n                      value={customEventForm.title}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, title: e.target.value }))}\n                      className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                    />\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Attribuer un DJ / Artiste *</label>\n                    {djs.length === 0 ? (\n                      <div className=\"text-xs text-red-500 italic\">Aucun DJ disponible. Veuillez d'abord en configurer un.</div>\n                    ) : (\n                      <select\n                        required\n                        value={customEventForm.djId}\n                        onChange={(e) => setCustomEventForm(prev => ({ ...prev, djId: e.target.value }))}\n                        className=\"w-full px-3 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 bg-white shadow-sm\"\n                      >\n                        <option value=\"\">-- Sélectionnez un DJ --</option>\n                        {djs.map(dj => (\n                          <option key={dj.id} value={dj.id}>\n                            {dj.name}\n                          </option>\n                        ))}\n                      </select>\n                    )}\n                  </div>\n\n                  <div className=\"grid grid-cols-2 gap-4\">\n                    <div>\n                      <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Nom du client</label>\n                      <input\n                        type=\"text\"\n                        placeholder=\"Dupuis\"\n                        value={customEventForm.clientName}\n                        onChange={(e) => setCustomEventForm(prev => ({ ...prev, clientName: e.target.value }))}\n                        className=\"w-full px-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                      />\n                    </div>\n                    <div className={customEventForm.eventType === 'custom' ? \"space-y-4\" : \"\"}>\n                      <div>\n                        <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Type de soirée</label>\n                        <select\n                          value={customEventForm.eventType}\n                          onChange={(e) => setCustomEventForm(prev => ({ ...prev, eventType: e.target.value, customEventTypeInput: e.target.value !== 'custom' ? '' : prev.customEventTypeInput }))}\n                          className=\"w-full px-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 bg-white shadow-sm\"\n                        >\n                          <option value=\"\">-- Sélectionnez un type --</option>\n                          {getEventTypesList(customEventForm.djId).map(type => (\n                            <option key={type} value={type}>{type}</option>\n                          ))}\n                          <option value=\"custom\">Type personnalisé</option>\n                        </select>\n                      </div>\n                      \n                      {customEventForm.eventType === 'custom' && (\n                        <div className=\"mt-4 animate-in fade-in slide-in-from-top-2 duration-150\">\n                          <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Type d'événement personnalisé</label>\n                          <input\n                            type=\"text\"\n                            placeholder=\"Ex: Festival, Soirée étudiante...\"\n                            value={customEventForm.customEventTypeInput || ''}\n                            onChange={(e) => setCustomEventForm(prev => ({ ...prev, customEventTypeInput: e.target.value }))}\n                            className=\"w-full px-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                          />\n                        </div>\n                      )}\n                    </div>\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Lieu de l'événement</label>\n                    <input\n                      type=\"text\"\n                      placeholder=\"Ex: Château de Versailles, Villebon...\"\n                      value={customEventForm.location}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, location: e.target.value }))}\n                      className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                    />\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Téléphone du client</label>\n                    <input\n                      type=\"text\"\n                      placeholder=\"Ex: 06 12 34 56 78\"\n                      value={customEventForm.clientPhone}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, clientPhone: e.target.value }))}\n                      className=\"w-full px-3.5 py-2.5 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm\"\n                    />\n                  </div>\n\n                  <div>\n                    <label className=\"block text-xs font-bold text-slate-700 uppercase tracking-wider mb-1.5\">Détails de l'événement</label>\n                    <textarea\n                      placeholder=\"Remarques techniques, horaires, etc...\"\n                      rows={2}\n                      value={customEventForm.details}\n                      onChange={(e) => setCustomEventForm(prev => ({ ...prev, details: e.target.value }))}\n                      className=\"w-full px-3.5 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm text-slate-900 placeholder:text-gray-400 bg-white shadow-sm resize-none\"\n                    />\n                  </div>\n                </div>\n              )}\n\n              {!editingCustomEventId && (\n                <div className=\"border-t pt-4 space-y-4\">\n                  <div className=\"flex items-center gap-2\">\n                    <span className=\"text-xs font-bold text-slate-700 uppercase tracking-wider\">Récurrence</span>\n                  </div>\n\n                  <div className=\"grid grid-cols-2 gap-4\">\n                    <div>\n                      <label className=\"block text-xs font-medium text-slate-600 mb-1\">Fréquence</label>\n                      <select\n                        value={recurrence}\n                        onChange={(e) => {\n                          setRecurrence(e.target.value);\n                          if (e.target.value !== 'none' && !recurrenceEndDate && addEventDate) {\n                            const defaultEnd = new Date(addEventDate);\n                            defaultEnd.setMonth(defaultEnd.getMonth() + 1);\n                            const yyyy = defaultEnd.getFullYear();\n                            const mm = String(defaultEnd.getMonth() + 1).padStart(2, '0');\n                            const dd = String(defaultEnd.getDate()).padStart(2, '0');\n                            setRecurrenceEndDate(`${yyyy}-${mm}-${dd}`);\n                          }\n                        }}\n                        className=\"w-full px-3 py-2 rounded-lg border border-slate-205 outline-none text-sm text-slate-900 bg-white shadow-sm cursor-pointer\"\n                      >\n                        <option value=\"none\">Aucune</option>\n                        <option value=\"daily\">Quotidienne (Tous les jours)</option>\n                        <option value=\"weekly\">Hebdomadaire (Toutes les semaines)</option>\n                        <option value=\"monthly\">Mensuelle (Tous les mois)</option>\n                      </select>\n                    </div>\n\n                    {recurrence !== 'none' && (\n                      <div>\n                        <label className=\"block text-xs font-medium text-slate-600 mb-1\">Finir par</label>\n                        <select\n                          value={recurrenceEndType}\n                          onChange={(e) => setRecurrenceEndType(e.target.value)}\n                          className=\"w-full px-3 py-2 rounded-lg border border-slate-205 outline-none text-sm text-slate-900 bg-white shadow-sm cursor-pointer\"\n                        >\n                          <option value=\"count\">Nombre de fois</option>\n                          <option value=\"date\">Une date précise</option>\n                        </select>\n                      </div>\n                    )}\n                  </div>\n\n                  {recurrence !== 'none' && (\n                    <div className=\"animate-in fade-in slide-in-from-top-2 duration-150\">\n                      {recurrenceEndType === 'count' ? (\n                        <div>\n                          <label className=\"block text-xs font-medium text-slate-600 mb-1\">Nombre de répétitions</label>\n                          <div className=\"flex items-center gap-3\">\n                            <input\n                              type=\"number\"\n                              min={1}\n                              max={100}\n                              value={recurrenceCount}\n                              onChange={(e) => setRecurrenceCount(Math.min(100, Math.max(1, parseInt(e.target.value) || 1)))}\n                              className=\"w-24 px-3 py-2 rounded-lg border border-slate-205 outline-none text-sm text-slate-900 bg-white shadow-sm\"\n                            />\n                            <span className=\"text-xs text-slate-500\">occurrences au total (max 100)</span>\n                          </div>\n                        </div>\n                      ) : (\n                        <div>\n                          <label className=\"block text-xs font-medium text-slate-600 mb-1\">Date de fin</label>\n                          <input\n                            type=\"date\"\n                            value={recurrenceEndDate}\n                            onChange={(e) => setRecurrenceEndDate(e.target.value)}\n                            className=\"w-full px-3 py-2 rounded-lg border border-slate-205 outline-none text-sm text-slate-900 bg-white shadow-sm\"\n                          />\n                        </div>\n                      )}\n                    </div>\n                  )}\n                </div>\n              )}\n\n              {/* Action buttons */}\n              <div className=\"pt-4 border-t flex justify-end gap-3 shrink-0\">\n                <button\n                  type=\"button\"\n                  onClick={() => {\n                    setAddEventDate(null);\n                    setEditingCustomEventId(null);\n                    setCustomEventForm({ title: '', clientName: '', clientPhone: '', djId: '', eventType: '', customEventTypeInput: '', details: '', location: '' });\n                    setRecurrence('none');\n                    setRecurrenceEndType('count');\n                    setRecurrenceEndDate('');\n                    setRecurrenceCount(5);\n                  }}\n                  className=\"px-4 py-2 text-sm font-semibold text-slate-700 bg-slate-100 hover:bg-slate-200 rounded-lg transition\"\n                >\n                  Annuler\n                </button>\n                <button\n                  type=\"submit\"\n                  className={`px-5 py-2 text-sm font-semibold rounded-lg text-white transition flex items-center justify-center gap-1.5 shadow-md ${addEventType === 'option' ? 'bg-black hover:bg-slate-900' : 'bg-indigo-600 hover:bg-indigo-700'}`}\n                >\n                  {editingCustomEventId ? <Edit className=\"w-4 h-4\" /> : <Plus className=\"w-4 h-4\" />}\n                  <span>{editingCustomEventId ? \"Modifier\" : \"Enregistrer\"} {addEventType === 'option' ? \"l'option\" : \"l'événement\"}</span>\n                </button>\n              </div>\n            </form>\n          </div>\n        </div>\n      )}\n\n      {deleteRecurringEvent && (\n        <div className=\"fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4\">\n          <div className=\"bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in zoom-in-95 duration-200 text-center\">\n            <div className=\"w-12 h-12 bg-red-50 text-red-650 rounded-full flex items-center justify-center mx-auto mb-4\">\n              <Trash2 className=\"w-6 h-6\" />\n            </div>\n            <h3 className=\"text-base font-bold text-slate-900 mb-2\">Événement récurrent</h3>\n            <p className=\"text-sm text-slate-500 mb-6 leading-relaxed\">\n              Cet événement fait partie d'une série récurrente. Que souhaitez-vous supprimer ?\n            </p>\n            <div className=\"space-y-2\">\n              <button\n                type=\"button\"\n                onClick={() => handleDeleteEvent(deleteRecurringEvent, false)}\n                className=\"w-full py-2.5 bg-slate-100 hover:bg-slate-200 text-slate-800 rounded-lg text-sm font-semibold transition cursor-pointer\"\n              >\n                Supprimer uniquement cet événement\n              </button>\n              <button\n                type=\"button\"\n                onClick={() => handleDeleteEvent(deleteRecurringEvent, true)}\n                className=\"w-full py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-lg text-sm font-semibold transition shadow-sm cursor-pointer\"\n              >\n                Supprimer toute la série\n              </button>\n              <button\n                type=\"button\"\n                onClick={() => setDeleteRecurringEvent(null)}\n                className=\"w-full py-2.5 text-slate-500 hover:text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-medium transition cursor-pointer\"\n              >\n                Annuler\n              </button>\n            </div>\n          </div>\n        </div>\n      )}\n    </div>\n  );\n}\n","import React, { useState, useEffect, useRef } from \"react\";\nimport axios from \"../services/axiosConfig\";\nimport { Button } from \"./ui/button\";\nimport { Input } from \"./ui/input\";\nimport { Label } from \"./ui/label\";\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from \"./ui/card\";\nimport { Badge } from \"./ui/badge\";\nimport { Textarea } from \"./ui/textarea\";\nimport { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from \"./ui/select\";\nimport { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from \"./ui/dialog\";\nimport { Ticket, Plus, Edit, Trash2, Calendar, MapPin, Clock, ExternalLink, Code, Copy, Timer, Upload, Phone, Tag, X, Eye } from \"lucide-react\";\nimport { toast } from \"sonner\";\n\nimport API_BASE_URL from '../utils/apiUrl';\nconst BACKEND_URL = API_BASE_URL;\nconst API = `${BACKEND_URL}/api`;\n\n// Composant iframe aperçu avec auto-resize via postMessage\nconst BilletteriePreviewIframe = ({ type }) => {\n  const iframeRef = React.useRef(null);\n  const [height, setHeight] = React.useState(400);\n\n  React.useEffect(() => {\n    const handler = (e) => {\n      if (\n        iframeRef.current &&\n        e.source === iframeRef.current.contentWindow &&\n        e.data &&\n        e.data.type === 'rkey-widget-resize' &&\n        e.data.height > 50\n      ) {\n        setHeight(e.data.height);\n      }\n    };\n    window.addEventListener('message', handler);\n    return () => window.removeEventListener('message', handler);\n  }, []);\n\n  const src = type\n    ? `${BACKEND_URL}/api/widgets/billetterie.html?type=${type}`\n    : `${BACKEND_URL}/api/widgets/billetterie.html`;\n\n  return (\n    <iframe\n      ref={iframeRef}\n      src={src}\n      title=\"Aperçu du widget événements\"\n      className=\"w-full border-0 rounded-lg\"\n      style={{ height: `${height}px`, transition: 'height 0.3s ease' }}\n      scrolling=\"no\"\n      frameBorder=\"0\"\n      data-testid=\"billetterie-preview-iframe\"\n    />\n  );\n};\n\nfunction BilletterieApp() {\n  const [events, setEvents] = useState([]);\n  const [showEventDialog, setShowEventDialog] = useState(false);\n  const [showWidgetDialog, setShowWidgetDialog] = useState(false);\n  const [showPreviewDialog, setShowPreviewDialog] = useState(false);\n  const [previewType, setPreviewType] = useState(null);\n  const [editingEvent, setEditingEvent] = useState(null);\n  const [typeFilter, setTypeFilter] = useState(\"all\");\n  const [uploadingImage, setUploadingImage] = useState(false);\n  const fileInputRef = useRef(null);\n\n  const [eventForm, setEventForm] = useState({\n    titre: \"\",\n    type: \"dj\",\n    date: \"\",\n    date_fin: \"\",\n    heure: \"\",\n    duree: \"\",\n    lieu: \"\",\n    descriptif: \"\",\n    photo_url: \"\",\n    lien_reservation: \"\",\n    telephone_reservation: \"\",\n    etiquette: \"\"\n  });\n\n  useEffect(() => {\n    loadEvents();\n  }, []);\n\n  const loadEvents = async () => {\n    try {\n      const response = await axios.get(`${API}/billetterie/events`);\n      setEvents(response.data);\n    } catch (error) {\n      console.error(\"Error loading events:\", error);\n      toast.error(\"Erreur lors du chargement des événements\");\n    }\n  };\n\n  const handleSaveEvent = async () => {\n    if (!eventForm.titre.trim() || !eventForm.date || !eventForm.lieu.trim()) {\n      toast.error(\"Les champs titre, date de début et lieu sont requis\");\n      return;\n    }\n\n    try {\n      if (editingEvent) {\n        await axios.put(`${API}/billetterie/events/${editingEvent.id}`, {\n          ...editingEvent,\n          ...eventForm,\n          date_fin: eventForm.date_fin || null\n        });\n        toast.success(\"Événement mis à jour !\");\n      } else {\n        await axios.post(`${API}/billetterie/events`, {\n          ...eventForm,\n          date_fin: eventForm.date_fin || null\n        });\n        toast.success(\"Événement créé !\");\n      }\n      \n      loadEvents();\n      setShowEventDialog(false);\n      resetEventForm();\n    } catch (error) {\n      console.error(\"Error saving event:\", error);\n      toast.error(\"Erreur lors de la sauvegarde\");\n    }\n  };\n\n  const handleImageUpload = async (e) => {\n    const file = e.target.files?.[0];\n    if (!file) return;\n\n    // Vérifier le type\n    const allowedTypes = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];\n    if (!allowedTypes.includes(file.type)) {\n      toast.error(\"Type de fichier non autorisé. Utilisez JPG, PNG, WebP ou GIF.\");\n      return;\n    }\n\n    // Vérifier la taille (max 5MB)\n    if (file.size > 5 * 1024 * 1024) {\n      toast.error(\"L'image est trop volumineuse (max 5 Mo)\");\n      return;\n    }\n\n    try {\n      setUploadingImage(true);\n      const formData = new FormData();\n      formData.append('file', file);\n\n      const response = await axios.post(`${API}/billetterie/upload-image`, formData, {\n        headers: { 'Content-Type': 'multipart/form-data' }\n      });\n\n      if (response.data.success) {\n        setEventForm(prev => ({ ...prev, photo_url: response.data.image_url }));\n        toast.success(\"Image uploadée !\");\n      }\n    } catch (error) {\n      console.error(\"Error uploading image:\", error);\n      toast.error(\"Erreur lors de l'upload de l'image\");\n    } finally {\n      setUploadingImage(false);\n    }\n  };\n\n  const handleDeleteEvent = async (eventId) => {\n    if (!window.confirm(\"Supprimer cet événement ?\")) return;\n\n    try {\n      await axios.delete(`${API}/billetterie/events/${eventId}`);\n      toast.success(\"Événement supprimé\");\n      loadEvents();\n    } catch (error) {\n      console.error(\"Error deleting event:\", error);\n      toast.error(\"Erreur lors de la suppression\");\n    }\n  };\n\n  const resetEventForm = () => {\n    setEventForm({\n      titre: \"\",\n      type: \"dj\",\n      date: \"\",\n      date_fin: \"\",\n      heure: \"\",\n      duree: \"\",\n      lieu: \"\",\n      descriptif: \"\",\n      photo_url: \"\",\n      lien_reservation: \"\",\n      telephone_reservation: \"\",\n      etiquette: \"\"\n    });\n    setEditingEvent(null);\n  };\n\n  const openEditEvent = (event) => {\n    setEditingEvent(event);\n    setEventForm({\n      titre: event.titre,\n      type: event.type,\n      date: event.date,\n      date_fin: event.date_fin || \"\",\n      heure: event.heure || \"\",\n      duree: event.duree || \"\",\n      lieu: event.lieu,\n      descriptif: event.descriptif || \"\",\n      photo_url: event.photo_url || \"\",\n      lien_reservation: event.lien_reservation || \"\",\n      telephone_reservation: event.telephone_reservation || \"\",\n      etiquette: event.etiquette || \"\"\n    });\n    setShowEventDialog(true);\n  };\n\n  const duplicateEvent = (event) => {\n    // Créer une copie de l'événement sans l'ID (pour créer un nouvel événement)\n    setEditingEvent(null); // Important: null pour créer un nouvel événement\n    setEventForm({\n      titre: event.titre + \" (copie)\",\n      type: event.type,\n      date: \"\", // Vider la date pour forcer l'utilisateur à choisir une nouvelle date\n      date_fin: \"\",\n      heure: event.heure || \"\",\n      duree: event.duree || \"\",\n      lieu: event.lieu,\n      descriptif: event.descriptif || \"\",\n      photo_url: event.photo_url || \"\",\n      lien_reservation: event.lien_reservation || \"\",\n      telephone_reservation: event.telephone_reservation || \"\",\n      etiquette: event.etiquette || \"\"\n    });\n    setShowEventDialog(true);\n    toast.info(\"Événement dupliqué - Modifiez la date et les détails\");\n  };\n\n  // Fonction pour formater l'affichage de la date/période\n  const formatEventDate = (event, detailed = false) => {\n    const startDate = new Date(event.date);\n    const options = detailed \n      ? { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }\n      : { day: 'numeric', month: 'short', year: 'numeric' };\n    \n    if (event.date_fin) {\n      const endDate = new Date(event.date_fin);\n      if (detailed) {\n        return `Du ${startDate.toLocaleDateString('fr-FR', { day: 'numeric', month: 'long' })} au ${endDate.toLocaleDateString('fr-FR', options)}`;\n      }\n      return `${startDate.toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' })} - ${endDate.toLocaleDateString('fr-FR', options)}`;\n    }\n    return startDate.toLocaleDateString('fr-FR', options);\n  };\n\n  // Fonction pour obtenir l'URL complète de l'image\n  const getImageUrl = (photoUrl) => {\n    if (!photoUrl) return null;\n    if (photoUrl.startsWith('http') || photoUrl.startsWith('data:')) return photoUrl;\n    if (photoUrl.startsWith('/api') || photoUrl.startsWith('api')) {\n      return photoUrl.startsWith('/') ? photoUrl : `/${photoUrl}`;\n    }\n    return `${BACKEND_URL}${photoUrl}`;\n  };\n\n  const getTypeBadge = (type) => {\n    if (type === \"dj\") {\n      return <Badge className=\"bg-orange-500 hover:bg-orange-500 text-white\">🎵 DJ</Badge>;\n    } else if (type === \"formation\") {\n      return <Badge className=\"bg-green-500 hover:bg-green-500 text-white\">📚 Formation</Badge>;\n    } else {\n      return <Badge className=\"bg-purple-500 hover:bg-purple-500 text-white\">🎭 Hypnose</Badge>;\n    }\n  };\n\n  const filteredEvents = events.filter(event => {\n    if (typeFilter === \"all\") return true;\n    return event.type === typeFilter;\n  });\n\n  const futureEvents = filteredEvents.filter(event => {\n    const today = new Date();\n    today.setHours(0, 0, 0, 0);\n    // Un événement est \"à venir\" si sa date de fin (ou date unique) est >= aujourd'hui\n    const endDate = event.date_fin ? new Date(event.date_fin) : new Date(event.date);\n    return endDate >= today;\n  });\n\n  const pastEvents = filteredEvents.filter(event => {\n    const today = new Date();\n    today.setHours(0, 0, 0, 0);\n    const endDate = event.date_fin ? new Date(event.date_fin) : new Date(event.date);\n    return endDate < today;\n  });\n\n  const generateWidgetCode = (type = null) => {\n    let productionUrl = window.location.origin;\n    if (productionUrl.includes('ais-dev')) {\n        productionUrl = productionUrl.replace('ais-dev', 'ais-pre');\n    }\n    const widgetUrl = type \n      ? `${productionUrl}/api/widgets/billetterie.html?type=${type}`\n      : `${productionUrl}/api/widgets/billetterie.html`;\n    const uid = 'rkey-evt-' + (type || 'all') + '-' + Date.now().toString(36);\n    \n    const widgetCode = `<!-- Widget Événements R'Key Prod${type ? ` - ${type.toUpperCase()}` : ''} -->\n<div style=\"width:100%;position:relative;\">\n  <iframe id=\"${uid}\" src=\"${widgetUrl}\" \n    style=\"width:100%;border:none;min-height:400px;display:block;\" \n    scrolling=\"no\" frameborder=\"0\" allowtransparency=\"true\">\n  </iframe>\n</div>\n<script>\n(function(){\n  var f=document.getElementById('${uid}');\n  if(!f)return;\n  window.addEventListener('message',function(e){\n    if(e.source===f.contentWindow&&e.data&&e.data.type==='rkey-widget-resize'&&e.data.height>50){\n      f.style.height=e.data.height+'px';\n    }\n  });\n})();\n</script>`;\n\n    return widgetCode;\n  };\n\n  const [widgetType, setWidgetType] = useState(null);\n\n  const openWidgetDialog = (type = null) => {\n    setWidgetType(type);\n    setShowWidgetDialog(true);\n  };\n\n  const copyWidgetCode = () => {\n    const code = generateWidgetCode(widgetType);\n    navigator.clipboard.writeText(code);\n    toast.success(\"Code copié dans le presse-papier !\");\n  };\n\n  return (\n    <div className=\"min-h-screen bg-gradient-to-br from-gray-50 to-slate-100\">\n      <div className=\"container mx-auto py-8 px-4\">\n        <div className=\"mb-8\">\n          <h1 className=\"text-4xl font-bold text-gray-800 mb-2 flex items-center gap-3\">\n            📅 Événements\n          </h1>\n          <p className=\"text-gray-600\">Gérez vos événements et générez votre widget</p>\n        </div>\n\n        {/* Statistiques */}\n        <div className=\"grid grid-cols-1 md:grid-cols-3 gap-4 mb-6\">\n          <Card className=\"bg-gradient-to-br from-gray-700 to-gray-900 text-white\">\n            <CardContent className=\"pt-6\">\n              <div className=\"flex items-center justify-between\">\n                <div>\n                  <p className=\"text-sm opacity-90\">Événements à venir</p>\n                  <p className=\"text-3xl font-bold\">{futureEvents.length}</p>\n                </div>\n                <Ticket className=\"h-12 w-12 opacity-80\" />\n              </div>\n            </CardContent>\n          </Card>\n\n          <Card className=\"bg-gradient-to-br from-purple-500 to-pink-600 text-white\">\n            <CardContent className=\"pt-6\">\n              <div className=\"flex items-center justify-between\">\n                <div>\n                  <p className=\"text-sm opacity-90\">Événements passés</p>\n                  <p className=\"text-3xl font-bold\">{pastEvents.length}</p>\n                </div>\n                <Calendar className=\"h-12 w-12 opacity-80\" />\n              </div>\n            </CardContent>\n          </Card>\n\n          <Card className=\"bg-gradient-to-br from-blue-500 to-indigo-600 text-white\">\n            <CardContent className=\"pt-6\">\n              <div className=\"flex items-center justify-between\">\n                <div>\n                  <p className=\"text-sm opacity-90\">Total événements</p>\n                  <p className=\"text-3xl font-bold\">{events.length}</p>\n                </div>\n                <Ticket className=\"h-12 w-12 opacity-80\" />\n              </div>\n            </CardContent>\n          </Card>\n        </div>\n\n        {/* Actions */}\n        <Card className=\"mb-6\">\n          <CardContent className=\"pt-6\">\n            <div className=\"flex flex-col md:flex-row gap-4\">\n              <Select value={typeFilter} onValueChange={setTypeFilter}>\n                <SelectTrigger className=\"w-full md:w-48\">\n                  <SelectValue placeholder=\"Filtrer par type\" />\n                </SelectTrigger>\n                <SelectContent>\n                  <SelectItem value=\"all\">Tous les types</SelectItem>\n                  <SelectItem value=\"dj\">🎵 DJ</SelectItem>\n                  <SelectItem value=\"hypnose\">🎭 Hypnose</SelectItem>\n                  <SelectItem value=\"formation\">📚 Formation</SelectItem>\n                </SelectContent>\n              </Select>\n              \n              <div className=\"flex gap-2 flex-1 flex-wrap\">\n                <Button \n                  onClick={() => {\n                    resetEventForm();\n                    setShowEventDialog(true);\n                  }}\n                  className=\"bg-gradient-to-r from-gray-700 to-gray-900 hover:from-gray-800 hover:to-black\"\n                >\n                  <Plus className=\"mr-2 h-4 w-4\" />\n                  Nouvel événement\n                </Button>\n\n                <Button\n                  onClick={() => { setPreviewType(null); setShowPreviewDialog(true); }}\n                  variant=\"outline\"\n                  className=\"border-blue-400 text-blue-600 hover:bg-blue-50\"\n                  data-testid=\"preview-all-btn\"\n                >\n                  <Eye className=\"mr-2 h-4 w-4\" />\n                  Aperçu\n                </Button>\n                \n                <Button \n                  onClick={() => openWidgetDialog('dj')}\n                  variant=\"outline\"\n                  className=\"border-gray-700 text-gray-700 hover:bg-gray-100\"\n                >\n                  <Code className=\"mr-2 h-4 w-4\" />\n                  DJ\n                </Button>\n\n                <Button \n                  onClick={() => openWidgetDialog('hypnose')}\n                  variant=\"outline\"\n                  className=\"border-purple-600 text-purple-600 hover:bg-purple-50\"\n                >\n                  <Code className=\"mr-2 h-4 w-4\" />\n                  Hypnose\n                </Button>\n\n                <Button \n                  onClick={() => openWidgetDialog('formation')}\n                  variant=\"outline\"\n                  className=\"border-green-600 text-green-600 hover:bg-green-50\"\n                >\n                  <Code className=\"mr-2 h-4 w-4\" />\n                  Formation\n                </Button>\n              </div>\n            </div>\n          </CardContent>\n        </Card>\n\n        {/* Liste des événements à venir */}\n        {futureEvents.length > 0 && (\n          <div className=\"mb-8\">\n            <h2 className=\"text-2xl font-bold text-gray-800 mb-4\">Événements à venir</h2>\n            <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n              {futureEvents.map(event => (\n                <Card key={event.id} className=\"hover:shadow-lg transition-shadow relative\">\n                  {/* Étiquette/Badge en diagonale */}\n                  {event.etiquette && (\n                    <div className=\"absolute -top-2 -right-2 z-20 overflow-hidden\" style={{ width: '130px', height: '130px' }}>\n                      <div className=\"absolute bg-gradient-to-r from-red-500 to-pink-500 text-white text-[9px] font-bold py-1.5 text-center shadow-lg uppercase tracking-wider transform rotate-45\"\n                           style={{ width: '180px', top: '28px', right: '-42px' }}>\n                        {event.etiquette}\n                      </div>\n                    </div>\n                  )}\n                  \n                  {/* Image */}\n                  {event.photo_url && (\n                    <div className=\"relative overflow-hidden\">\n                      <img src={getImageUrl(event.photo_url)} alt={event.titre} className=\"w-full h-48 object-cover\" />\n                    </div>\n                  )}\n                  \n                  <CardContent className=\"pt-6\">\n                    <div className=\"flex items-start justify-between mb-3\">\n                      <div className=\"flex-1\">\n                        {getTypeBadge(event.type)}\n                        <h3 className=\"text-xl font-bold text-gray-800 mt-2\">{event.titre}</h3>\n                      </div>\n                      <div className=\"flex gap-2\">\n                        <Button\n                          variant=\"ghost\"\n                          size=\"sm\"\n                          onClick={() => duplicateEvent(event)}\n                          title=\"Dupliquer\"\n                        >\n                          <Copy className=\"h-4 w-4\" />\n                        </Button>\n                        <Button\n                          variant=\"ghost\"\n                          size=\"sm\"\n                          onClick={() => openEditEvent(event)}\n                          title=\"Modifier\"\n                        >\n                          <Edit className=\"h-4 w-4\" />\n                        </Button>\n                        <Button\n                          variant=\"ghost\"\n                          size=\"sm\"\n                          onClick={() => handleDeleteEvent(event.id)}\n                          className=\"text-red-600 hover:text-red-700\"\n                          title=\"Supprimer\"\n                        >\n                          <Trash2 className=\"h-4 w-4\" />\n                        </Button>\n                      </div>\n                    </div>\n\n                    <div className=\"space-y-2 text-sm text-gray-600 mb-4\">\n                      <div className=\"flex items-center gap-2\">\n                        <Calendar className=\"h-4 w-4\" />\n                        {formatEventDate(event, true)}\n                      </div>\n                      {event.heure && (\n                        <div className=\"flex items-center gap-2\">\n                          <Clock className=\"h-4 w-4\" />\n                          {event.heure}\n                        </div>\n                      )}\n                      {event.duree && (\n                        <div className=\"flex items-center gap-2\">\n                          <Timer className=\"h-4 w-4\" />\n                          {event.duree}\n                        </div>\n                      )}\n                      <div className=\"flex items-center gap-2\">\n                        <MapPin className=\"h-4 w-4\" />\n                        {event.lieu}\n                      </div>\n                    </div>\n\n                    {event.descriptif && (\n                      <p className=\"text-sm text-gray-700 mb-4 line-clamp-3\">{event.descriptif}</p>\n                    )}\n\n                    <div className=\"space-y-2\">\n                      {event.lien_reservation && (\n                        <Button \n                          onClick={() => window.open(event.lien_reservation, '_blank')}\n                          className=\"w-full bg-gray-800 hover:bg-gray-900\"\n                        >\n                          <ExternalLink className=\"mr-2 h-4 w-4\" />\n                          Réserver en ligne\n                        </Button>\n                      )}\n                      {event.telephone_reservation && (\n                        <Button \n                          onClick={() => window.open(`tel:${event.telephone_reservation}`, '_self')}\n                          className={`w-full ${!event.lien_reservation \n                            ? 'bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 text-white' \n                            : 'border-gray-600 text-gray-600 hover:bg-gray-50'}`}\n                          variant={event.lien_reservation ? \"outline\" : \"default\"}\n                        >\n                          <Phone className=\"mr-2 h-4 w-4\" />\n                          {event.telephone_reservation}\n                        </Button>\n                      )}\n                    </div>\n                  </CardContent>\n                </Card>\n              ))}\n            </div>\n          </div>\n        )}\n\n        {/* Liste des événements passés */}\n        {pastEvents.length > 0 && (\n          <div>\n            <h2 className=\"text-2xl font-bold text-gray-400 mb-4\">Événements passés</h2>\n            <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 opacity-60\">\n              {pastEvents.map(event => (\n                <Card key={event.id} className=\"hover:shadow-lg transition-shadow\">\n                  <CardContent className=\"pt-6\">\n                    <div className=\"flex items-start justify-between mb-3\">\n                      <div className=\"flex-1\">\n                        {getTypeBadge(event.type)}\n                        <h3 className=\"text-xl font-bold text-gray-800 mt-2\">{event.titre}</h3>\n                      </div>\n                      <div className=\"flex gap-2\">\n                        <Button\n                          variant=\"ghost\"\n                          size=\"sm\"\n                          onClick={() => duplicateEvent(event)}\n                          title=\"Dupliquer\"\n                        >\n                          <Copy className=\"h-4 w-4\" />\n                        </Button>\n                        <Button\n                          variant=\"ghost\"\n                          size=\"sm\"\n                          onClick={() => handleDeleteEvent(event.id)}\n                          className=\"text-red-600 hover:text-red-700\"\n                          title=\"Supprimer\"\n                        >\n                          <Trash2 className=\"h-4 w-4\" />\n                        </Button>\n                      </div>\n                    </div>\n\n                    <div className=\"space-y-2 text-sm text-gray-600\">\n                      <div className=\"flex items-center gap-2\">\n                        <Calendar className=\"h-4 w-4\" />\n                        {formatEventDate(event)}\n                      </div>\n                      <div className=\"flex items-center gap-2\">\n                        <MapPin className=\"h-4 w-4\" />\n                        {event.lieu}\n                      </div>\n                    </div>\n                  </CardContent>\n                </Card>\n              ))}\n            </div>\n          </div>\n        )}\n\n        {futureEvents.length === 0 && pastEvents.length === 0 && (\n          <Card>\n            <CardContent className=\"pt-6 text-center text-gray-500\">\n              <Ticket className=\"h-12 w-12 mx-auto mb-4 opacity-50\" />\n              <p>Aucun événement trouvé</p>\n            </CardContent>\n          </Card>\n        )}\n      </div>\n\n      {/* Dialog Événement */}\n      <Dialog open={showEventDialog} onOpenChange={setShowEventDialog}>\n        <DialogContent className=\"max-w-2xl max-h-[90vh] overflow-y-auto\">\n          <DialogHeader>\n            <DialogTitle>\n              {editingEvent ? \"Modifier l'événement\" : \"Nouvel événement\"}\n            </DialogTitle>\n            <DialogDescription>\n              Renseignez les informations de l'événement\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"space-y-4\">\n            <div>\n              <Label htmlFor=\"titre\">Titre de l'événement *</Label>\n              <Input\n                id=\"titre\"\n                value={eventForm.titre}\n                onChange={(e) => setEventForm(prev => ({ ...prev, titre: e.target.value }))}\n                placeholder=\"Ex: Show Hypnose à Colmar\"\n              />\n            </div>\n\n            <div>\n              <Label htmlFor=\"type\">Type d'événement *</Label>\n              <Select \n                value={eventForm.type} \n                onValueChange={(value) => setEventForm(prev => ({ ...prev, type: value, heure: value === 'formation' ? '' : prev.heure, duree: value === 'formation' ? '' : prev.duree }))}\n              >\n                <SelectTrigger>\n                  <SelectValue />\n                </SelectTrigger>\n                <SelectContent>\n                  <SelectItem value=\"dj\">🎵 Soirée DJ</SelectItem>\n                  <SelectItem value=\"hypnose\">🎭 Show Hypnose</SelectItem>\n                  <SelectItem value=\"formation\">📚 Formation</SelectItem>\n                </SelectContent>\n              </Select>\n            </div>\n\n            <div className=\"grid grid-cols-2 gap-4\">\n              <div>\n                <Label htmlFor=\"date\">Date de début *</Label>\n                <Input\n                  id=\"date\"\n                  type=\"date\"\n                  value={eventForm.date}\n                  onChange={(e) => setEventForm(prev => ({ ...prev, date: e.target.value }))}\n                />\n              </div>\n              <div>\n                <Label htmlFor=\"date_fin\">Date de fin (optionnel)</Label>\n                <Input\n                  id=\"date_fin\"\n                  type=\"date\"\n                  value={eventForm.date_fin}\n                  onChange={(e) => setEventForm(prev => ({ ...prev, date_fin: e.target.value }))}\n                />\n                <p className=\"text-xs text-gray-500 mt-1\">\n                  Pour une période (ex: tout l'été)\n                </p>\n              </div>\n            </div>\n\n            {/* Heure et Durée - masqués pour les formations */}\n            {eventForm.type !== 'formation' && (\n              <div className=\"grid grid-cols-2 gap-4\">\n                <div>\n                  <Label htmlFor=\"heure\">Heure</Label>\n                  <Input\n                    id=\"heure\"\n                    type=\"time\"\n                    value={eventForm.heure}\n                    onChange={(e) => setEventForm(prev => ({ ...prev, heure: e.target.value }))}\n                    placeholder=\"20:30\"\n                  />\n                </div>\n                <div>\n                  <Label htmlFor=\"duree\">Durée du show</Label>\n                  <Input\n                    id=\"duree\"\n                    value={eventForm.duree}\n                    onChange={(e) => setEventForm(prev => ({ ...prev, duree: e.target.value }))}\n                    placeholder=\"Ex: 1h30, 2h\"\n                  />\n                </div>\n              </div>\n            )}\n\n            <div>\n              <Label htmlFor=\"lieu\">Lieu *</Label>\n              <Input\n                id=\"lieu\"\n                value={eventForm.lieu}\n                onChange={(e) => setEventForm(prev => ({ ...prev, lieu: e.target.value }))}\n                placeholder=\"Ex: Salle des fêtes, Colmar\"\n              />\n            </div>\n\n            <div>\n              <Label htmlFor=\"descriptif\">Descriptif</Label>\n              <Textarea\n                id=\"descriptif\"\n                value={eventForm.descriptif}\n                onChange={(e) => setEventForm(prev => ({ ...prev, descriptif: e.target.value }))}\n                placeholder=\"Description de l'événement...\"\n                rows={4}\n              />\n            </div>\n\n            {/* Upload d'image */}\n            <div>\n              <Label>Photo de l'événement</Label>\n              <div className=\"mt-2 space-y-3\">\n                {eventForm.photo_url && (\n                  <div className=\"relative inline-block\">\n                    <img \n                      src={getImageUrl(eventForm.photo_url)} \n                      alt=\"Aperçu\" \n                      className=\"w-40 h-24 object-cover rounded-lg border\"\n                    />\n                    <Button\n                      type=\"button\"\n                      variant=\"ghost\"\n                      size=\"sm\"\n                      className=\"absolute -top-2 -right-2 h-6 w-6 p-0 bg-red-500 hover:bg-red-600 text-white rounded-full\"\n                      onClick={() => setEventForm(prev => ({ ...prev, photo_url: '' }))}\n                    >\n                      <X className=\"h-4 w-4\" />\n                    </Button>\n                  </div>\n                )}\n                <div className=\"flex gap-2\">\n                  <input\n                    ref={fileInputRef}\n                    type=\"file\"\n                    accept=\"image/jpeg,image/png,image/webp,image/gif\"\n                    onChange={handleImageUpload}\n                    className=\"hidden\"\n                  />\n                  <Button\n                    type=\"button\"\n                    variant=\"outline\"\n                    onClick={() => fileInputRef.current?.click()}\n                    disabled={uploadingImage}\n                  >\n                    <Upload className=\"mr-2 h-4 w-4\" />\n                    {uploadingImage ? 'Upload...' : 'Choisir une image'}\n                  </Button>\n                </div>\n                <p className=\"text-xs text-gray-500\">\n                  JPG, PNG, WebP ou GIF (max 5 Mo)\n                </p>\n              </div>\n            </div>\n\n            {/* Étiquette/Badge */}\n            <div>\n              <Label htmlFor=\"etiquette\">Étiquette (optionnel)</Label>\n              <div className=\"flex gap-2 mt-1\">\n                <Input\n                  id=\"etiquette\"\n                  value={eventForm.etiquette}\n                  onChange={(e) => setEventForm(prev => ({ ...prev, etiquette: e.target.value }))}\n                  placeholder=\"Ex: À ne pas louper, Gratuit, Nouveauté\"\n                />\n                <div className=\"flex gap-1 flex-shrink-0\">\n                  {['Gratuit', 'Nouveauté', 'Complet'].map(tag => (\n                    <Button\n                      key={tag}\n                      type=\"button\"\n                      variant=\"outline\"\n                      size=\"sm\"\n                      className=\"text-xs\"\n                      onClick={() => setEventForm(prev => ({ ...prev, etiquette: tag }))}\n                    >\n                      {tag}\n                    </Button>\n                  ))}\n                </div>\n              </div>\n              <p className=\"text-xs text-gray-500 mt-1\">\n                Affiché en ruban sur la carte de l'événement\n              </p>\n            </div>\n\n            <div>\n              <Label htmlFor=\"lien_reservation\">Lien de réservation</Label>\n              <Input\n                id=\"lien_reservation\"\n                value={eventForm.lien_reservation}\n                onChange={(e) => setEventForm(prev => ({ ...prev, lien_reservation: e.target.value }))}\n                placeholder=\"https://weezevent.com/...\"\n              />\n              <p className=\"text-xs text-gray-500 mt-1\">\n                Lien vers votre système de billetterie (Weezevent, etc.)\n              </p>\n            </div>\n\n            <div>\n              <Label htmlFor=\"telephone_reservation\">Téléphone de réservation</Label>\n              <Input\n                id=\"telephone_reservation\"\n                value={eventForm.telephone_reservation}\n                onChange={(e) => setEventForm(prev => ({ ...prev, telephone_reservation: e.target.value }))}\n                placeholder=\"07 83 55 36 74\"\n              />\n              <p className=\"text-xs text-gray-500 mt-1\">\n                Numéro de téléphone pour réserver (optionnel)\n              </p>\n            </div>\n          </div>\n\n          <DialogFooter>\n            <Button variant=\"outline\" onClick={() => setShowEventDialog(false)}>\n              Annuler\n            </Button>\n            <Button \n              onClick={handleSaveEvent}\n              className=\"bg-gradient-to-r from-gray-700 to-gray-900\"\n            >\n              {editingEvent ? \"Mettre à jour\" : \"Créer\"}\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n\n      {/* Dialog Widget */}\n      <Dialog open={showWidgetDialog} onOpenChange={setShowWidgetDialog}>\n        <DialogContent className=\"max-w-2xl max-h-[90vh] overflow-y-auto\">\n          <DialogHeader>\n            <DialogTitle>\n              {widgetType === 'hypnose' ? 'Widget Hypnose' : 'Widget DJ'}\n            </DialogTitle>\n            <DialogDescription>\n              {widgetType === 'hypnose' \n                ? 'Ce widget affichera uniquement vos événements Hypnose.'\n                : 'Ce widget affichera uniquement vos soirées DJ.'}\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"space-y-4\">\n            <div className=\"bg-gray-100 p-4 rounded-lg\">\n              <pre className=\"text-sm overflow-x-auto whitespace-pre-wrap font-mono\">\n                <code>{generateWidgetCode(widgetType)}</code>\n              </pre>\n            </div>\n\n            <div className=\"bg-blue-50 border border-blue-200 rounded-lg p-4\">\n              <h3 className=\"font-semibold text-sm mb-2\">Instructions :</h3>\n              <ol className=\"text-sm space-y-1 list-decimal list-inside\">\n                <li>Copiez le code ci-dessus</li>\n                <li>Collez-le dans un bloc \"Code HTML personnalisé\" sur votre site</li>\n                <li>Le widget s'affiche automatiquement avec vos événements</li>\n                <li>Les événements passés disparaissent automatiquement</li>\n              </ol>\n            </div>\n\n            <div className={`${widgetType === 'hypnose' ? 'bg-purple-50 border-purple-200' : widgetType === 'formation' ? 'bg-green-50 border-green-200' : 'bg-gray-50 border-gray-200'} border rounded-lg p-4`}>\n              <h3 className=\"font-semibold text-sm mb-2\">Options personnalisables :</h3>\n              <ul className=\"text-sm space-y-1 list-disc list-inside\">\n                <li><code className={`${widgetType === 'hypnose' ? 'bg-purple-100' : widgetType === 'formation' ? 'bg-green-100' : 'bg-gray-100'} px-1 rounded`}>data-height=\"800\"</code> → Hauteur du widget (en pixels)</li>\n                <li><code className={`${widgetType === 'hypnose' ? 'bg-purple-100' : widgetType === 'formation' ? 'bg-green-100' : 'bg-gray-100'} px-1 rounded`}>data-width=\"100%\"</code> → Largeur du widget</li>\n                <li><code className={`${widgetType === 'hypnose' ? 'bg-purple-100' : widgetType === 'formation' ? 'bg-green-100' : 'bg-gray-100'} px-1 rounded`}>data-resize=\"1\"</code> → Redimensionnement auto (1 = oui, 0 = non)</li>\n              </ul>\n            </div>\n          </div>\n\n          <DialogFooter>\n            <Button variant=\"outline\" onClick={() => setShowWidgetDialog(false)}>\n              Fermer\n            </Button>\n            <Button \n              onClick={copyWidgetCode}\n              className={widgetType === 'hypnose' ? 'bg-gradient-to-r from-purple-600 to-violet-600' : widgetType === 'formation' ? 'bg-gradient-to-r from-green-600 to-emerald-600' : 'bg-gradient-to-r from-gray-700 to-gray-900'}\n            >\n              <Code className=\"mr-2 h-4 w-4\" />\n              Copier le code\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n\n      {/* Dialog Aperçu */}\n      <Dialog open={showPreviewDialog} onOpenChange={setShowPreviewDialog}>\n        <DialogContent className=\"max-w-3xl max-h-[90vh] overflow-hidden\" data-testid=\"billetterie-preview-dialog\">\n          <DialogHeader>\n            <DialogTitle className=\"flex items-center gap-2\">\n              <Eye className=\"w-5 h-5 text-blue-500\" />\n              Aperçu du widget {previewType ? `- ${previewType.toUpperCase()}` : '- Tous'}\n            </DialogTitle>\n            <DialogDescription>\n              Rendu tel qu'il apparaîtra sur votre site\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"bg-gray-200 rounded-lg p-3 overflow-auto\" style={{ maxHeight: '65vh' }}>\n            <BilletteriePreviewIframe type={previewType} />\n          </div>\n\n          <DialogFooter className=\"flex-col sm:flex-row gap-2\">\n            <Button variant=\"outline\" onClick={() => setShowPreviewDialog(false)}>\n              Fermer\n            </Button>\n            <Button\n              onClick={() => {\n                setShowPreviewDialog(false);\n                openWidgetDialog(previewType);\n              }}\n              className=\"bg-gradient-to-r from-gray-700 to-gray-900\"\n            >\n              <Code className=\"mr-2 h-4 w-4\" />\n              Obtenir le code widget\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n    </div>\n  );\n}\n\nexport default BilletterieApp;\n","import React, { useState, useEffect } from \"react\";\nimport axios from \"../services/axiosConfig\";\nimport { Button } from \"./ui/button\";\nimport { Input } from \"./ui/input\";\nimport { Label } from \"./ui/label\";\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from \"./ui/card\";\nimport { Badge } from \"./ui/badge\";\nimport { Textarea } from \"./ui/textarea\";\nimport { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from \"./ui/select\";\nimport { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from \"./ui/dialog\";\nimport { Building2, Users, Calendar, Plus, Edit, Trash2, Check, X, Search, Phone, Mail, MapPin, FileText, UserPlus } from \"lucide-react\";\nimport { toast } from \"sonner\";\n\nimport API_BASE_URL from '../utils/apiUrl';\nconst BACKEND_URL = API_BASE_URL;\nconst API = `${BACKEND_URL}/api`;\n\n// Helpers to extract year and event type from notes (for legacy data)\nconst parseFromNotes = (notes) => {\n  if (!notes) return { year: \"\", type: \"\" };\n  let year = \"\";\n  let type = \"\";\n  \n  const dateMatch = notes.match(/Événement:\\s*(\\d{4}-\\d{2}-\\d{2})/i) || \n                    notes.match(/Événement:\\s*(\\d{2}\\/\\d{2}\\/(\\d{4}))/i) ||\n                    notes.match(/Événement:\\s*(20\\d{2})/i);\n  if (dateMatch) {\n    if (dateMatch[2]) {\n      year = dateMatch[2];\n    } else {\n      const yrMatch = dateMatch[1].match(/\\b(20\\d{2})\\b/);\n      if (yrMatch) year = yrMatch[1];\n    }\n  } else {\n    const yrMatch = notes.match(/\\b(20\\d{2})\\b/);\n    if (yrMatch) year = yrMatch[1];\n  }\n  \n  const typeMatch = notes.match(/Type:\\s*([^\\n]+)/i);\n  if (typeMatch) {\n    type = typeMatch[1].trim();\n  }\n  \n  return { year, type };\n};\n\nconst getCompanyYear = (company) => {\n  if (company.annee_prestation) return String(company.annee_prestation);\n  const parsed = parseFromNotes(company.notes);\n  return parsed.year ? String(parsed.year) : \"\";\n};\n\nconst getCompanyEventType = (company) => {\n  if (company.type_evenement) return company.type_evenement;\n  const parsed = parseFromNotes(company.notes);\n  return parsed.type || \"\";\n};\n\nconst getCompanyEventDate = (company) => {\n  if (company.date_evenement) {\n    if (/^\\d{4}-\\d{2}-\\d{2}$/.test(company.date_evenement)) {\n      return company.date_evenement;\n    }\n  }\n  if (!company.notes) return \"\";\n  const match = company.notes.match(/Événement:\\s*(\\d{4}-\\d{2}-\\d{2})/i);\n  if (match) return match[1];\n\n  const matchFr = company.notes.match(/Événement:\\s*(\\d{2})\\/(\\d{2})\\/(\\d{4})/i);\n  if (matchFr) return `${matchFr[3]}-${matchFr[2]}-${matchFr[1]}`;\n\n  return \"\";\n};\n\nconst getCompanyProvenance = (company) => {\n  if (company.provenance) return company.provenance;\n  if (company.notes) {\n    if (company.notes.includes(\"Importé depuis l'application Matériel\") || company.notes.toLowerCase().includes(\"location: \")) {\n      return \"location\";\n    }\n    if (company.notes.includes(\"Importé depuis le contrat\")) {\n      return \"contrat\";\n    }\n  }\n  return \"\";\n};\n\nfunction CRMApp() {\n  const [companies, setCompanies] = useState([]);\n  const [relances, setRelances] = useState([]);\n  const [searchTerm, setSearchTerm] = useState(\"\");\n  const [statusFilter, setStatusFilter] = useState(\"all\");\n  const [anneeFilter, setAnneeFilter] = useState(\"all\");\n  const [eventFilter, setEventFilter] = useState(\"all\");\n  const [startDateFilter, setStartDateFilter] = useState(\"\");\n  const [endDateFilter, setEndDateFilter] = useState(\"\");\n  const [showCompanyDialog, setShowCompanyDialog] = useState(false);\n  const [showRelanceDialog, setShowRelanceDialog] = useState(false);\n  const [showDetailDialog, setShowDetailDialog] = useState(false);\n  const [showExportDialog, setShowExportDialog] = useState(false);\n  const [selectedCompanyForDetail, setSelectedCompanyForDetail] = useState(null);\n  const [editingCompany, setEditingCompany] = useState(null);\n  const [selectedCompany, setSelectedCompany] = useState(null);\n  \n  const [companyForm, setCompanyForm] = useState({\n    nom: \"\",\n    type_client: \"Particulier\",\n    siret: \"\",\n    secteur: \"\",\n    adresse: \"\",\n    telephone: \"\",\n    email: \"\",\n    statut: \"prospect\",\n    contacts: [],\n    notes: \"\",\n    blacklist_tags: \"\",\n    annee_prestation: \"\",\n    type_evenement: \"\",\n    date_evenement: \"\"\n  });\n\n  const [typeFilter, setTypeFilter] = useState(\"all\");\n  const [isImporting, setIsImporting] = useState(false);\n\n  const [newContact, setNewContact] = useState({\n    nom: \"\",\n    fonction: \"\",\n    telephone: \"\",\n    email: \"\"\n  });\n\n  const [relanceForm, setRelanceForm] = useState({\n    date: \"\",\n    objet: \"\",\n    company_id: \"\"\n  });\n\n  useEffect(() => {\n    loadCompanies();\n    loadRelances();\n  }, []);\n\n  const loadCompanies = async () => {\n    try {\n      const response = await axios.get(`${API}/crm/companies`);\n      setCompanies(response.data);\n    } catch (error) {\n      console.error(\"Error loading companies:\", error);\n      toast.error(\"Erreur lors du chargement des entreprises\");\n    }\n  };\n\n  const loadRelances = async () => {\n    try {\n      const response = await axios.get(`${API}/crm/relances`);\n      setRelances(response.data);\n    } catch (error) {\n      console.error(\"Error loading relances:\", error);\n      toast.error(\"Erreur lors du chargement des relances\");\n    }\n  };\n\n  const handleSaveCompany = async () => {\n    if (!companyForm.nom.trim()) {\n      toast.error(\"Le nom de l'entreprise est requis\");\n      return;\n    }\n\n    try {\n      if (editingCompany) {\n        await axios.put(`${API}/crm/companies/${editingCompany.id}`, {\n          ...editingCompany,\n          ...companyForm\n        });\n        toast.success(\"Entreprise mise à jour !\");\n      } else {\n        await axios.post(`${API}/crm/companies`, companyForm);\n        toast.success(\"Entreprise créée !\");\n      }\n      \n      loadCompanies();\n      setShowCompanyDialog(false);\n      resetCompanyForm();\n    } catch (error) {\n      console.error(\"Error saving company:\", error);\n      toast.error(\"Erreur lors de la sauvegarde\");\n    }\n  };\n\n  const handleDeleteCompany = async (companyId) => {\n    if (!window.confirm(\"Êtes-vous sûr de vouloir supprimer cette entreprise ?\")) {\n      return;\n    }\n\n    try {\n      await axios.delete(`${API}/crm/companies/${companyId}`);\n      toast.success(\"Entreprise supprimée\");\n      loadCompanies();\n      loadRelances();\n      if (selectedCompany?.id === companyId) {\n        setSelectedCompany(null);\n      }\n    } catch (error) {\n      console.error(\"Error deleting company:\", error);\n      toast.error(\"Erreur lors de la suppression\");\n    }\n  };\n\n  const handleAddContact = () => {\n    if (!newContact.nom.trim()) {\n      toast.error(\"Le nom du contact est requis\");\n      return;\n    }\n\n    setCompanyForm(prev => ({\n      ...prev,\n      contacts: [...prev.contacts, { ...newContact }]\n    }));\n\n    setNewContact({ nom: \"\", fonction: \"\", telephone: \"\", email: \"\" });\n    toast.success(\"Contact ajouté\");\n  };\n\n  const handleRemoveContact = (index) => {\n    setCompanyForm(prev => ({\n      ...prev,\n      contacts: prev.contacts.filter((_, i) => i !== index)\n    }));\n  };\n\n  const handleSaveRelance = async () => {\n    if (!relanceForm.date || !relanceForm.objet.trim()) {\n      toast.error(\"La date et l'objet sont requis\");\n      return;\n    }\n\n    try {\n      await axios.post(`${API}/crm/relances`, {\n        ...relanceForm,\n        company_id: selectedCompany.id\n      });\n      \n      toast.success(\"Relance créée !\");\n      loadRelances();\n      setShowRelanceDialog(false);\n      setRelanceForm({ date: \"\", objet: \"\", company_id: \"\" });\n    } catch (error) {\n      console.error(\"Error saving relance:\", error);\n      toast.error(\"Erreur lors de la sauvegarde\");\n    }\n  };\n\n  const handleCompleteRelance = async (relanceId) => {\n    try {\n      await axios.patch(`${API}/crm/relances/${relanceId}/complete`);\n      toast.success(\"Relance marquée comme terminée\");\n      loadRelances();\n    } catch (error) {\n      console.error(\"Error completing relance:\", error);\n      toast.error(\"Erreur lors de la mise à jour\");\n    }\n  };\n\n  const handleDeleteRelance = async (relanceId) => {\n    if (!window.confirm(\"Supprimer cette relance ?\")) return;\n\n    try {\n      await axios.delete(`${API}/crm/relances/${relanceId}`);\n      toast.success(\"Relance supprimée\");\n      loadRelances();\n    } catch (error) {\n      console.error(\"Error deleting relance:\", error);\n      toast.error(\"Erreur lors de la suppression\");\n    }\n  };\n\n  const resetCompanyForm = () => {\n    setCompanyForm({\n      nom: \"\",\n      type_client: \"Particulier\",\n      siret: \"\",\n      secteur: \"\",\n      adresse: \"\",\n      telephone: \"\",\n      email: \"\",\n      statut: \"prospect\",\n      contacts: [],\n      notes: \"\",\n      blacklist_tags: \"\",\n      annee_prestation: \"\",\n      type_evenement: \"\",\n      date_evenement: \"\"\n    });\n    setEditingCompany(null);\n  };\n\n  const openEditCompany = (company) => {\n    setEditingCompany(company);\n    setCompanyForm({\n      nom: company.nom,\n      type_client: company.type_client || \"Entreprise\",\n      siret: company.siret || \"\",\n      secteur: company.secteur || \"\",\n      adresse: company.adresse || \"\",\n      telephone: company.telephone || \"\",\n      email: company.email || \"\",\n      statut: company.statut,\n      contacts: company.contacts || [],\n      notes: company.notes || \"\",\n      blacklist_tags: company.blacklist_tags || \"\",\n      annee_prestation: company.annee_prestation || \"\",\n      type_evenement: company.type_evenement || \"\",\n      date_evenement: company.date_evenement || getCompanyEventDate(company) || \"\"\n    });\n    setShowCompanyDialog(true);\n  };\n\n  const handleEditFromDetail = (company) => {\n    setShowDetailDialog(false);\n    openEditCompany(company);\n  };\n\n  const handleSiretFetch = async () => {\n    if (!companyForm.siret || companyForm.siret.trim().length < 9) {\n      toast.error(\"Veuillez saisir un SIRET ou SIREN valide\");\n      return;\n    }\n    \n    try {\n      toast.info(\"Recherche SIRENE en cours...\");\n      const response = await fetch(`https://recherche-entreprises.api.gouv.fr/search?q=${companyForm.siret}`);\n      const data = await response.json();\n      \n      if (data && data.results && data.results.length > 0) {\n        const result = data.results[0];\n        \n        const siege = result.siege || {};\n        const adresseComplete = siege.adresse || `${siege.numero_voie || ''} ${siege.type_voie || ''} ${siege.libelle_voie || ''}, ${siege.code_postal || ''} ${siege.libelle_commune || ''}`.trim();\n\n        setCompanyForm(prev => ({\n          ...prev,\n          nom: result.nom_complet || prev.nom,\n          adresse: adresseComplete !== ',' ? adresseComplete.replace(/ {2,}/g, ' ') : prev.adresse,\n          siret: siege.siren ? (siege.siret || siege.siren) : prev.siret,\n          secteur: result.activite_principale || prev.secteur\n        }));\n        \n        toast.success(\"Informations trouvées et appliquées !\");\n      } else {\n        toast.error(\"Aucune entreprise trouvée avec ce numéro\");\n      }\n    } catch (error) {\n      console.error(error);\n      toast.error(\"Erreur lors de la recherche SIRENE\");\n    }\n  };\n\n  const handleImportContacts = async () => {\n    setIsImporting(true);\n    try {\n      let newClientsAdded = 0;\n      \n      // 1. Fetch contracts\n      let contracts = [];\n      try {\n        const responseContracts = await axios.get(`${API}/contracts2`);\n        contracts = responseContracts.data || [];\n      } catch (err) {\n        console.error(\"Error fetching contracts:\", err);\n        toast.error(\"Erreur de chargement des contrats, l'import des contrats a été ignoré\");\n      }\n\n      // 2. Fetch Location Clients\n      let locationClients = [];\n      try {\n        const responseLoc = await axios.get(`${API}/location/clients`);\n        locationClients = responseLoc.data || [];\n      } catch (err) {\n        console.error(\"Error fetching location clients:\", err);\n        toast.error(\"Erreur de chargement des clients de location, cet import a été ignoré\");\n      }\n\n      // Local state copy to avoid inserting duplicates of items imported in the same execution\n      let currentCompanies = [...companies];\n\n      // Process DJ / Prestation Contracts\n      for (const contract of contracts) {\n        const clientInfo = contract.client_info || {};\n        \n        // Skip if no useful data\n        if (!clientInfo.name && !clientInfo.company && !clientInfo.email) continue;\n        \n        const emailLower = clientInfo.email ? clientInfo.email.toLowerCase().trim() : \"\";\n        const nameLower = clientInfo.name ? clientInfo.name.toLowerCase().trim() : \"\";\n        const companyLower = clientInfo.company ? clientInfo.company.toLowerCase().trim() : \"\";\n\n        // Check if exists\n        const exists = currentCompanies.some(c => {\n          const cEmail = c.email ? c.email.toLowerCase().trim() : \"\";\n          const cNom = c.nom ? c.nom.toLowerCase().trim() : \"\";\n          return (emailLower && cEmail === emailLower) || \n                 (nameLower && cNom === nameLower) || \n                 (companyLower && cNom === companyLower);\n        });\n        \n        if (!exists) {\n            // Add new client\n            const isCompany = !!clientInfo.company;\n            const eventDate = clientInfo.event_date || \"\";\n            let eventYear = \"\";\n            if (eventDate) {\n              const yrMatch = eventDate.match(/\\b(20\\d{2})\\b/);\n              if (yrMatch) eventYear = yrMatch[1];\n            }\n            const eventType = clientInfo.event_type || \"\";\n\n            const newClient = {\n                nom: clientInfo.company || clientInfo.name || \"Client Inconnu\",\n                type_client: isCompany ? \"Entreprise\" : \"Particulier\",\n                siret: \"\",\n                secteur: \"\",\n                adresse: clientInfo.address || \"\",\n                telephone: clientInfo.phone || \"\",\n                email: clientInfo.email || \"\",\n                statut: \"client\", // imported from signed/sent contracts mostly\n                contacts: isCompany && clientInfo.name ? [{ nom: clientInfo.name, telephone: clientInfo.phone, email: clientInfo.email, fonction: \"Contact\" }] : [],\n                notes: `Importé depuis le contrat \"${contract.id || 'inconnu'}\".\\nÉvénement: ${clientInfo.event_date || 'N/A'}\\nType: ${clientInfo.event_type || 'N/A'}`,\n                blacklist_tags: \"\",\n                annee_prestation: eventYear,\n                type_evenement: eventType,\n                date_evenement: eventDate\n            };\n            \n            const postResponse = await axios.post(`${API}/crm/companies`, newClient);\n            const addedClient = postResponse.data;\n            currentCompanies.push(addedClient);\n            newClientsAdded++;\n        }\n      }\n\n      // Process Location Clients\n      for (const locClient of locationClients) {\n        const rawName = locClient.name || \"\";\n        const rawCompany = locClient.company_name || \"\";\n        const rawEmail = locClient.email || \"\";\n\n        // Skip if no useful data\n        if (!rawName && !rawCompany && !rawEmail) continue;\n\n        const emailLower = rawEmail ? rawEmail.toLowerCase().trim() : \"\";\n        const nameLower = rawName ? rawName.toLowerCase().trim() : \"\";\n        const companyLower = rawCompany ? rawCompany.toLowerCase().trim() : \"\";\n\n        // Check if exists\n        const exists = currentCompanies.some(c => {\n          const cEmail = c.email ? c.email.toLowerCase().trim() : \"\";\n          const cNom = c.nom ? c.nom.toLowerCase().trim() : \"\";\n          return (emailLower && cEmail === emailLower) || \n                 (nameLower && cNom === nameLower) || \n                 (companyLower && cNom === companyLower);\n        });\n\n        if (!exists) {\n          // Determine type de client\n          let typeClient = \"Particulier\";\n          if (locClient.client_type === \"entreprise\" || locClient.client_type === \"association\") {\n            typeClient = locClient.client_type === \"entreprise\" ? \"Entreprise\" : \"Association\";\n          } else if (rawCompany) {\n            typeClient = \"Entreprise\";\n          }\n\n          const hasContactName = rawName && rawCompany && rawName.toLowerCase() !== rawCompany.toLowerCase();\n\n          const newClient = {\n            nom: rawCompany || rawName || \"Client Inconnu\",\n            type_client: typeClient,\n            siret: locClient.siret || \"\",\n            secteur: \"\",\n            adresse: locClient.address || \"\",\n            telephone: locClient.phone || \"\",\n            email: rawEmail,\n            statut: \"client\",\n            contacts: hasContactName ? [{ nom: rawName, telephone: locClient.phone, email: rawEmail, fonction: \"Contact principal\" }] : [],\n            notes: `Importé depuis l'application Matériel (Clients).\\nNotes de location: ${locClient.notes || 'N/A'}`,\n            blacklist_tags: \"\",\n            annee_prestation: \"\",\n            type_evenement: \"\"\n          };\n\n          const postResponse = await axios.post(`${API}/crm/companies`, newClient);\n          const addedClient = postResponse.data;\n          currentCompanies.push(addedClient);\n          newClientsAdded++;\n        }\n      }\n      \n      if (newClientsAdded > 0) {\n          toast.success(`${newClientsAdded} nouveau(x) contact(s) importé(s)`);\n          loadCompanies();\n      } else {\n          toast.info(\"Aucun nouveau contact à importer.\");\n      }\n    } catch (error) {\n      console.error(error);\n      toast.error(\"Erreur lors de l'import des contacts\");\n    } finally {\n      setIsImporting(false);\n    }\n  };\n\n  const getCompanyRelances = (companyId) => {\n    return relances.filter(r => r.company_id === companyId);\n  };\n\n  const getActiveRelances = (companyId) => {\n    return getCompanyRelances(companyId).filter(r => r.statut === \"active\");\n  };\n\n  const getCompletedRelances = (companyId) => {\n    return getCompanyRelances(companyId).filter(r => r.statut === \"terminee\");\n  };\n\n  const getTodayRelances = () => {\n    const today = new Date().toISOString().split('T')[0];\n    return relances.filter(r => r.statut === \"active\" && r.date === today);\n  };\n\n  const getUpcomingRelances = () => {\n    const today = new Date().toISOString().split('T')[0];\n    return relances.filter(r => r.statut === \"active\" && r.date >= today);\n  };\n\n  const filteredCompanies = companies.filter(company => {\n    const matchesSearch = (company.nom || \"\").toLowerCase().includes(searchTerm.toLowerCase()) ||\n                          (company.secteur && company.secteur.toLowerCase().includes(searchTerm.toLowerCase())) ||\n                          (company.blacklist_tags && company.blacklist_tags.toLowerCase().includes(searchTerm.toLowerCase()));\n    const matchesStatus = statusFilter === \"all\" || company.statut === statusFilter;\n    const matchesType = typeFilter === \"all\" || \n                        company.type_client === typeFilter || \n                        (!company.type_client && typeFilter === \"Entreprise\"); // Retro-compatibilité\n\n    const matchesAnnee = anneeFilter === \"all\" || getCompanyYear(company) === anneeFilter;\n    const matchesEvent = eventFilter === \"all\" || getCompanyEventType(company).toLowerCase() === eventFilter.toLowerCase();\n\n    // Filtre par date exacte d'événement\n    const evDate = getCompanyEventDate(company);\n    let matchesDateRange = true;\n    if (startDateFilter) {\n      if (!evDate || evDate < startDateFilter) matchesDateRange = false;\n    }\n    if (endDateFilter) {\n      if (!evDate || evDate > endDateFilter) matchesDateRange = false;\n    }\n\n    return matchesSearch && matchesStatus && matchesType && matchesAnnee && matchesEvent && matchesDateRange;\n  });\n\n  const getStatusBadge = (statut) => {\n    const styles = {\n      client: \"bg-green-100 text-green-800 hover:bg-green-100\",\n      demarche: \"bg-yellow-100 text-yellow-800 hover:bg-yellow-100\",\n      prospect: \"bg-blue-100 text-blue-800 hover:bg-blue-100\"\n    };\n    \n    const labels = {\n      client: \"🟢 Déjà client\",\n      demarche: \"🟡 Démarché\",\n      prospect: \"🔵 Prospect\"\n    };\n\n    return (\n      <Badge className={styles[statut] || \"\"}>\n        {labels[statut] || statut}\n      </Badge>\n    );\n  };\n\n  const getTypeBadge = (type) => {\n    if (!type) type = \"Entreprise\";\n    const styles = {\n      \"Particulier\": \"bg-indigo-100 text-indigo-800 hover:bg-indigo-100\",\n      \"Entreprise\": \"bg-slate-100 text-slate-800 hover:bg-slate-100\",\n      \"Association\": \"bg-purple-100 text-purple-800 hover:bg-purple-100\"\n    };\n    \n    return (\n      <Badge className={styles[type] || \"\"}>\n        {type}\n      </Badge>\n    );\n  };\n\n  const filterYears = Array.from(new Set(\n    companies.map(c => getCompanyYear(c)).filter(Boolean)\n  )).sort().reverse();\n\n  const filterEventTypes = Array.from(new Set(\n    companies.map(c => getCompanyEventType(c)).filter(Boolean)\n  )).sort();\n\n  const handleExportEmails = () => {\n    const mainEmails = filteredCompanies\n      .map(c => c.email?.trim())\n      .filter(email => email && email.includes(\"@\"));\n    \n    const contactEmails = filteredCompanies\n      .flatMap(c => (c.contacts || []).map(contact => contact.email?.trim()))\n      .filter(email => email && email.includes(\"@\"));\n\n    const allEmails = Array.from(new Set([...mainEmails, ...contactEmails]));\n    \n    if (allEmails.length === 0) {\n      toast.error(\"Aucune adresse email trouvée pour les clients filtrés.\");\n      return;\n    }\n    \n    setShowExportDialog(true);\n  };\n\n  const handleDownloadCSV = () => {\n    const headers = [\"Nom du Client\", \"Type de Client\", \"Statut\", \"Email Principal\", \"Téléphone Principal\", \"Adresse\", \"Date de prestation\", \"Type d'événement\", \"Année\"];\n    const rows = filteredCompanies.map(c => [\n      c.nom || \"\",\n      c.type_client || \"Particulier\",\n      c.statut || \"prospect\",\n      c.email || \"\",\n      c.telephone || \"\",\n      c.adresse || \"\",\n      getCompanyEventDate(c) || \"\",\n      getCompanyEventType(c) || \"\",\n      getCompanyYear(c) || \"\"\n    ]);\n\n    const csvContent = [\n      headers.join(\";\"),\n      ...rows.map(row => row.map(val => `\"${String(val).replace(/\"/g, '\"\"')}\"`).join(\";\"))\n    ].join(\"\\n\");\n\n    const blob = new Blob([\"\\uFEFF\" + csvContent], { type: \"text/csv;charset=utf-8;\" });\n    const url = URL.createObjectURL(blob);\n    const link = document.createElement(\"a\");\n    link.setAttribute(\"href\", url);\n    link.setAttribute(\"download\", `export_fichier_clients_${new Date().toISOString().split('T')[0]}.csv`);\n    document.body.appendChild(link);\n    link.click();\n    document.body.removeChild(link);\n    toast.success(\"Fichier CSV exporté avec succès !\");\n  };\n\n  return (\n    <div className=\"min-h-screen bg-gradient-to-br from-green-50 to-emerald-50\">\n      <div className=\"container mx-auto py-8 px-4\">\n        <div className=\"mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4\">\n          <div>\n            <h1 className=\"text-4xl font-bold text-gray-800 mb-2 flex items-center gap-3\">\n              📇 Fichier Client\n            </h1>\n            <p className=\"text-gray-600\">Base de données globale : particuliers, entreprises et associations</p>\n          </div>\n          <Button \n            onClick={handleImportContacts}\n            disabled={isImporting}\n            className=\"bg-blue-600 hover:bg-blue-700 text-white\"\n          >\n            <UserPlus className=\"mr-2 h-4 w-4\" />\n            {isImporting ? \"Importation...\" : \"Importer depuis contacts\"}\n          </Button>\n        </div>\n\n        {/* Statistiques (en lignes compactes) */}\n        <div className=\"flex flex-wrap items-center justify-between gap-6 bg-white border border-gray-250 shadow-sm rounded-xl px-6 py-4 mb-6\">\n          <div className=\"flex items-center gap-2\">\n            <span className=\"text-xl\">👥</span>\n            <div>\n              <span className=\"text-xs text-slate-500 block font-medium uppercase tracking-wider\">Total Clients</span>\n              <span className=\"text-lg font-bold text-slate-950\">{companies.length}</span>\n            </div>\n          </div>\n          <div className=\"h-8 w-px bg-slate-200 hidden md:block\"></div>\n          <div className=\"flex items-center gap-2\">\n            <span className=\"text-xl\">🔵</span>\n            <div>\n              <span className=\"text-xs text-slate-500 block font-medium uppercase tracking-wider\">Prospects</span>\n              <span className=\"text-lg font-bold text-slate-950\">\n                {companies.filter(c => c.statut === \"prospect\").length}\n              </span>\n            </div>\n          </div>\n          <div className=\"h-8 w-px bg-slate-200 hidden md:block\"></div>\n          <div className=\"flex items-center gap-2\">\n            <span className=\"text-xl\">📅</span>\n            <div>\n              <span className=\"text-xs text-slate-500 block font-medium uppercase tracking-wider\">Relances Aujourd'hui</span>\n              <span className=\"text-lg font-bold text-slate-950\">{getTodayRelances().length}</span>\n            </div>\n          </div>\n          <div className=\"h-8 w-px bg-slate-200 hidden md:block\"></div>\n          <div className=\"flex items-center gap-2\">\n            <span className=\"text-xl\">📋</span>\n            <div>\n              <span className=\"text-xs text-slate-500 block font-medium uppercase tracking-wider\">Relances À Venir</span>\n              <span className=\"text-lg font-bold text-slate-950\">{getUpcomingRelances().length}</span>\n            </div>\n          </div>\n        </div>\n\n        {/* Barre de recherche et filtres */}\n        <Card className=\"mb-6\">\n          <CardContent className=\"pt-6\">\n            <div className=\"space-y-4\">\n              {/* Row 1: Search + Date Range Filters */}\n              <div className=\"flex flex-col lg:flex-row gap-4 items-center\">\n                <div className=\"flex-1 w-full relative\">\n                  <Search className=\"absolute left-3 top-3 h-4 w-4 text-gray-400\" />\n                  <Input\n                    placeholder=\"Rechercher par nom, secteur, etc...\"\n                    value={searchTerm}\n                    onChange={(e) => setSearchTerm(e.target.value)}\n                    className=\"pl-10\"\n                  />\n                </div>\n                \n                <div className=\"flex flex-wrap items-center gap-2 w-full lg:w-auto\">\n                  <div className=\"flex items-center gap-1.5 min-w-[150px] w-full sm:w-auto\">\n                    <span className=\"text-xs text-slate-500 font-medium shrink-0\">Du</span>\n                    <Input \n                      type=\"date\" \n                      value={startDateFilter} \n                      onChange={(e) => setStartDateFilter(e.target.value)} \n                      className=\"h-9 text-xs\"\n                    />\n                  </div>\n                  <div className=\"flex items-center gap-1.5 min-w-[150px] w-full sm:w-auto\">\n                    <span className=\"text-xs text-slate-500 font-medium shrink-0\">Au</span>\n                    <Input \n                      type=\"date\" \n                      value={endDateFilter} \n                      onChange={(e) => setEndDateFilter(e.target.value)} \n                      className=\"h-9 text-xs\"\n                    />\n                  </div>\n                  {(startDateFilter || endDateFilter) && (\n                    <Button \n                      variant=\"ghost\" \n                      size=\"sm\" \n                      onClick={() => { setStartDateFilter(\"\"); setEndDateFilter(\"\"); }}\n                      className=\"text-red-550 hover:text-red-700 h-9 font-medium\"\n                    >\n                      Effacer dates\n                    </Button>\n                  )}\n                </div>\n              </div>\n\n              {/* Row 2: Select Dropdowns & Buttons */}\n              <div className=\"flex flex-col md:flex-row gap-4 flex-wrap items-center justify-between\">\n                <div className=\"flex flex-wrap gap-2 items-center w-full md:w-auto\">\n                  <Select value={anneeFilter} onValueChange={setAnneeFilter}>\n                    <SelectTrigger className=\"w-full sm:w-36\">\n                      <SelectValue placeholder=\"Année\" />\n                    </SelectTrigger>\n                    <SelectContent>\n                      <SelectItem value=\"all\">Toutes les années</SelectItem>\n                      {filterYears.map(year => (\n                        <SelectItem key={year} value={year}>{year}</SelectItem>\n                      ))}\n                    </SelectContent>\n                  </Select>\n\n                  <Select value={eventFilter} onValueChange={setEventFilter}>\n                    <SelectTrigger className=\"w-full sm:w-44\">\n                      <SelectValue placeholder=\"Type événement\" />\n                    </SelectTrigger>\n                    <SelectContent>\n                      <SelectItem value=\"all\">Tous événements</SelectItem>\n                      {filterEventTypes.map(type => (\n                        <SelectItem key={type} value={type.toLowerCase()}>{type}</SelectItem>\n                      ))}\n                    </SelectContent>\n                  </Select>\n\n                  <Select value={statusFilter} onValueChange={setStatusFilter}>\n                    <SelectTrigger className=\"w-full sm:w-36\">\n                      <SelectValue placeholder=\"Statut\" />\n                    </SelectTrigger>\n                    <SelectContent>\n                      <SelectItem value=\"all\">Tous statuts</SelectItem>\n                      <SelectItem value=\"client\">🟢 Déjà clients</SelectItem>\n                      <SelectItem value=\"demarche\">🟡 Démarchés</SelectItem>\n                      <SelectItem value=\"prospect\">Prospects</SelectItem>\n                    </SelectContent>\n                  </Select>\n\n                  <Select value={typeFilter} onValueChange={setTypeFilter}>\n                    <SelectTrigger className=\"w-full sm:w-36\">\n                      <SelectValue placeholder=\"Type de client\" />\n                    </SelectTrigger>\n                    <SelectContent>\n                      <SelectItem value=\"all\">Tous types</SelectItem>\n                      <SelectItem value=\"Particulier\">Particuliers</SelectItem>\n                      <SelectItem value=\"Entreprise\">Entreprises</SelectItem>\n                      <SelectItem value=\"Association\">Associations</SelectItem>\n                    </SelectContent>\n                  </Select>\n\n                  {(searchTerm || anneeFilter !== \"all\" || eventFilter !== \"all\" || statusFilter !== \"all\" || typeFilter !== \"all\" || startDateFilter || endDateFilter) && (\n                    <Button\n                      variant=\"outline\"\n                      onClick={() => {\n                        setSearchTerm(\"\");\n                        setAnneeFilter(\"all\");\n                        setEventFilter(\"all\");\n                        setStatusFilter(\"all\");\n                        setTypeFilter(\"all\");\n                        setStartDateFilter(\"\");\n                        setEndDateFilter(\"\");\n                      }}\n                      className=\"text-gray-500 hover:text-gray-800 text-xs h-9 sm:w-auto w-full\"\n                    >\n                      Réinitialiser\n                    </Button>\n                  )}\n                </div>\n\n                <div className=\"flex gap-2 w-full md:w-auto mt-2 md:mt-0 justify-end flex-wrap\">\n                  <Button \n                    onClick={handleExportEmails}\n                    variant=\"outline\"\n                    className=\"border-green-300 text-green-700 hover:bg-green-50 h-9\"\n                  >\n                    📥 Exporter les adresses mail ({filteredCompanies.length})\n                  </Button>\n\n                  <Button \n                    onClick={() => {\n                      resetCompanyForm();\n                      setShowCompanyDialog(true);\n                    }}\n                    className=\"bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-700 hover:to-emerald-700 h-9\"\n                  >\n                    <Plus className=\"mr-2 h-4 w-4\" />\n                    Nouveau Client\n                  </Button>\n                </div>\n              </div>\n            </div>\n          </CardContent>\n        </Card>\n\n        {/* Liste des entreprises (Lignes compactes) */}\n        <div className=\"bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden divide-y divide-slate-100\">\n          {/* Header de la liste */}\n          <div className=\"hidden md:flex items-center px-6 py-3 bg-slate-50 text-xs font-semibold uppercase tracking-wider text-slate-500\">\n            <div className=\"w-[35%]\">Nom du Client / Secteur</div>\n            <div className=\"w-[20%]\">Date & Type d'Événement</div>\n            <div className=\"w-[15%]\">Type de Client</div>\n            <div className=\"w-[15%]\">Statut</div>\n            <div className=\"w-[15%] text-right\">Actions</div>\n          </div>\n          \n          {filteredCompanies.length === 0 ? (\n            <div className=\"p-8 text-center text-gray-500\">\n              <Users className=\"h-12 w-12 mx-auto mb-4 opacity-50\" />\n              <p>Aucun client trouvé</p>\n            </div>\n          ) : (\n            filteredCompanies.map(company => {\n              const activeRelances = getActiveRelances(company.id);\n              return (\n                <div \n                  key={company.id} \n                  onClick={() => {\n                    setSelectedCompanyForDetail(company);\n                    setShowDetailDialog(true);\n                  }}\n                  className=\"px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 hover:bg-slate-50/80 cursor-pointer transition-colors\"\n                >\n                  {/* Nom / Secteur */}\n                  <div className=\"w-full md:w-[35%] flex items-center gap-3\">\n                    <span className=\"text-2xl shrink-0 select-none\">\n                      {company.type_client === \"Particulier\" ? \"👤\" : company.type_client === \"Association\" ? \"🤝\" : \"🏢\"}\n                    </span>\n                    <div className=\"min-w-0\">\n                      <h4 className=\"font-semibold text-slate-800 text-base truncate flex items-center gap-2 flex-wrap\">\n                        {company.nom}\n                        {activeRelances.length > 0 && (\n                          <span className=\"inline-flex items-center justify-center w-5 h-5 text-[10px] font-bold text-white bg-red-500 rounded-full\" title={`${activeRelances.length} relance(s) active(s)`}>\n                            {activeRelances.length}\n                          </span>\n                        )}\n                        {getCompanyProvenance(company) === \"location\" && (\n                          <Badge className=\"bg-blue-100 text-blue-800 hover:bg-blue-100 text-[10px] font-semibold py-0.5 px-2 border border-blue-200 uppercase tracking-tight\">\n                            📦 Location\n                          </Badge>\n                        )}\n                        {getCompanyProvenance(company) === \"contrat\" && (\n                          <Badge className=\"bg-purple-100 text-purple-800 hover:bg-purple-100 text-[10px] font-semibold py-0.5 px-2 border border-purple-200 uppercase tracking-tight\">\n                            🎵 Prestation\n                          </Badge>\n                        )}\n                      </h4>\n                      <p className=\"text-sm text-slate-400 truncate mt-0.5\">\n                        {company.secteur || \"Aucun secteur\"} {company.siret && `• SIRET: ${company.siret}`}\n                      </p>\n                    </div>\n                  </div>\n\n                  {/* Date & Type Événement */}\n                  <div className=\"w-full md:w-[20%] flex flex-col gap-1 items-start\">\n                    <div className=\"flex flex-wrap gap-1 items-center\">\n                      {getCompanyEventDate(company) ? (\n                        <Badge className=\"bg-emerald-100 text-emerald-800 hover:bg-emerald-100 border border-emerald-200 font-semibold text-xs\">\n                          📅 {new Date(getCompanyEventDate(company)).toLocaleDateString('fr-FR')}\n                        </Badge>\n                      ) : getCompanyYear(company) ? (\n                        <Badge className=\"bg-emerald-50 text-emerald-700 hover:bg-emerald-50 border border-emerald-100 font-medium text-xs\">\n                          📅 {getCompanyYear(company)}\n                        </Badge>\n                      ) : (\n                        <span className=\"text-gray-400 text-sm\">—</span>\n                      )}\n                    </div>\n                    {getCompanyEventType(company) ? (\n                      <Badge className=\"bg-amber-50 text-amber-850 hover:bg-amber-50 border border-amber-100 font-medium text-xs truncate max-w-[120px]\" title={getCompanyEventType(company)}>\n                        🎉 {getCompanyEventType(company)}\n                      </Badge>\n                    ) : null}\n                  </div>\n\n                  {/* Type */}\n                  <div className=\"w-full md:w-[15%]\">\n                    {getTypeBadge(company.type_client)}\n                  </div>\n\n                  {/* Statut */}\n                  <div className=\"w-full md:w-[15%]\">\n                    {getStatusBadge(company.statut)}\n                  </div>\n\n                  {/* Actions de ligne rapide */}\n                  <div className=\"w-full md:w-[15%] flex justify-start md:justify-end items-center gap-1\" onClick={(e) => e.stopPropagation()}>\n                    <Button\n                      variant=\"ghost\"\n                      size=\"sm\"\n                      onClick={() => {\n                        setSelectedCompanyForDetail(company);\n                        setShowDetailDialog(true);\n                      }}\n                      className=\"text-slate-550 hover:text-slate-800\"\n                      title=\"Afficher les détails\"\n                    >\n                      <FileText className=\"h-4 w-4\" />\n                    </Button>\n                    <Button\n                      variant=\"ghost\"\n                      size=\"sm\"\n                      onClick={() => openEditCompany(company)}\n                      className=\"text-slate-600 hover:text-blue-600\"\n                      title=\"Modifier\"\n                    >\n                      <Edit className=\"h-4 w-4\" />\n                    </Button>\n                    <Button\n                      variant=\"ghost\"\n                      size=\"sm\"\n                      onClick={() => handleDeleteCompany(company.id)}\n                      className=\"text-red-500 hover:text-red-700 hover:bg-red-50\"\n                      title=\"Supprimer\"\n                    >\n                      <Trash2 className=\"h-4 w-4\" />\n                    </Button>\n                  </div>\n                </div>\n              );\n            })\n          )}\n        </div>\n      </div>\n\n      {/* Dialog Entreprise */}\n      <Dialog open={showCompanyDialog} onOpenChange={setShowCompanyDialog}>\n        <DialogContent className=\"max-w-2xl max-h-[90vh] overflow-y-auto\">\n          <DialogHeader>\n            <DialogTitle>\n              {editingCompany ? \"Modifier le client\" : \"Nouveau client\"}\n            </DialogTitle>\n            <DialogDescription>\n              Renseignez les informations du client\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"space-y-4\">\n            <div className=\"grid grid-cols-2 gap-4\">\n              <div>\n                <Label htmlFor=\"type_client\">Type de client</Label>\n                <Select \n                  value={companyForm.type_client} \n                  onValueChange={(value) => setCompanyForm(prev => ({ ...prev, type_client: value }))}\n                >\n                  <SelectTrigger id=\"type_client\">\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value=\"Particulier\">👤 Particulier</SelectItem>\n                    <SelectItem value=\"Entreprise\">🏢 Entreprise</SelectItem>\n                    <SelectItem value=\"Association\">🤝 Association</SelectItem>\n                  </SelectContent>\n                </Select>\n              </div>\n\n              <div>\n                <Label htmlFor=\"statut\">Statut</Label>\n                <Select \n                  value={companyForm.statut} \n                  onValueChange={(value) => setCompanyForm(prev => ({ ...prev, statut: value }))}\n                >\n                  <SelectTrigger id=\"statut\">\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value=\"prospect\">🔵 Prospect</SelectItem>\n                    <SelectItem value=\"demarche\">🟡 Démarché</SelectItem>\n                    <SelectItem value=\"client\">🟢 Déjà client</SelectItem>\n                  </SelectContent>\n                </Select>\n              </div>\n            </div>\n\n            {(companyForm.type_client === \"Entreprise\" || companyForm.type_client === \"Association\") && (\n              <div className=\"flex gap-2 items-end\">\n                <div className=\"flex-1\">\n                  <Label htmlFor=\"siret\">Recherche SIRET / SIREN</Label>\n                  <Input\n                    id=\"siret\"\n                    value={companyForm.siret}\n                    onChange={(e) => setCompanyForm(prev => ({ ...prev, siret: e.target.value }))}\n                    placeholder=\"Entrez le SIRET ou SIREN\"\n                  />\n                </div>\n                <Button variant=\"secondary\" onClick={handleSiretFetch}>\n                  <Search className=\"h-4 w-4 mr-2\" /> Rechercher\n                </Button>\n              </div>\n            )}\n\n            <div>\n              <Label htmlFor=\"nom\">Nom / Raison Sociale *</Label>\n              <Input\n                id=\"nom\"\n                value={companyForm.nom}\n                onChange={(e) => setCompanyForm(prev => ({ ...prev, nom: e.target.value }))}\n                placeholder=\"Ex: Mairie de Colmar, Jean Dupont\"\n              />\n            </div>\n\n            <div>\n              <Label htmlFor=\"secteur\">Secteur / Activité</Label>\n              <Input\n                id=\"secteur\"\n                value={companyForm.secteur}\n                onChange={(e) => setCompanyForm(prev => ({ ...prev, secteur: e.target.value }))}\n                placeholder=\"Ex: CE, Mairie, Informatique...\"\n              />\n            </div>\n\n            <div className=\"grid grid-cols-1 md:grid-cols-3 gap-4\">\n              <div>\n                <Label htmlFor=\"date_evenement\">Date précise de l'événement</Label>\n                <Input\n                  id=\"date_evenement\"\n                  type=\"date\"\n                  value={companyForm.date_evenement || \"\"}\n                  onChange={(e) => {\n                    const newDate = e.target.value;\n                    setCompanyForm(prev => {\n                      const yr = newDate ? newDate.split('-')[0] : prev.annee_prestation;\n                      return { ...prev, date_evenement: newDate, annee_prestation: yr };\n                    });\n                  }}\n                />\n              </div>\n              <div>\n                <Label htmlFor=\"annee_prestation\">Année (Auto-remplie)</Label>\n                <Input\n                  id=\"annee_prestation\"\n                  value={companyForm.annee_prestation || \"\"}\n                  onChange={(e) => setCompanyForm(prev => ({ ...prev, annee_prestation: e.target.value }))}\n                  placeholder=\"Ex: 2026\"\n                />\n              </div>\n              <div>\n                <Label htmlFor=\"type_evenement\">Type d'événement</Label>\n                <Input\n                  id=\"type_evenement\"\n                  value={companyForm.type_evenement || \"\"}\n                  onChange={(e) => setCompanyForm(prev => ({ ...prev, type_evenement: e.target.value }))}\n                  placeholder=\"Ex: Mariage, Gala...\"\n                />\n              </div>\n            </div>\n\n            <div>\n              <Label htmlFor=\"adresse\">Adresse</Label>\n              <Input\n                id=\"adresse\"\n                value={companyForm.adresse}\n                onChange={(e) => setCompanyForm(prev => ({ ...prev, adresse: e.target.value }))}\n                placeholder=\"Adresse complète\"\n              />\n            </div>\n\n            <div className=\"grid grid-cols-2 gap-4\">\n              <div>\n                <Label htmlFor=\"telephone\">Téléphone</Label>\n                <Input\n                  id=\"telephone\"\n                  value={companyForm.telephone}\n                  onChange={(e) => setCompanyForm(prev => ({ ...prev, telephone: e.target.value }))}\n                  placeholder=\"03 89 XX XX XX\"\n                />\n              </div>\n              <div>\n                <Label htmlFor=\"email\">Email</Label>\n                <Input\n                  id=\"email\"\n                  type=\"email\"\n                  value={companyForm.email}\n                  onChange={(e) => setCompanyForm(prev => ({ ...prev, email: e.target.value }))}\n                  placeholder=\"contact@entreprise.fr\"\n                />\n              </div>\n            </div>\n\n            {/* Contacts */}\n            <div className=\"border-t pt-4\">\n              <Label className=\"text-base font-semibold mb-3 block\">👥 Contacts</Label>\n              \n              {companyForm.contacts.length > 0 && (\n                <div className=\"space-y-2 mb-4\">\n                  {companyForm.contacts.map((contact, idx) => (\n                    <div key={idx} className=\"bg-gray-50 p-3 rounded-lg flex justify-between items-start\">\n                      <div className=\"flex-1\">\n                        <p className=\"font-medium\">{contact.nom}</p>\n                        <p className=\"text-sm text-gray-600\">\n                          {contact.fonction && `${contact.fonction} • `}\n                          {contact.telephone && `${contact.telephone} • `}\n                          {contact.email}\n                        </p>\n                      </div>\n                      <Button\n                        size=\"sm\"\n                        variant=\"ghost\"\n                        onClick={() => handleRemoveContact(idx)}\n                        className=\"text-red-600\"\n                      >\n                        <X className=\"h-4 w-4\" />\n                      </Button>\n                    </div>\n                  ))}\n                </div>\n              )}\n\n              <div className=\"space-y-3 bg-blue-50 p-4 rounded-lg\">\n                <p className=\"text-sm font-medium\">Ajouter un contact</p>\n                <div className=\"grid grid-cols-2 gap-3\">\n                  <Input\n                    placeholder=\"Nom *\"\n                    value={newContact.nom}\n                    onChange={(e) => setNewContact(prev => ({ ...prev, nom: e.target.value }))}\n                  />\n                  <Input\n                    placeholder=\"Fonction\"\n                    value={newContact.fonction}\n                    onChange={(e) => setNewContact(prev => ({ ...prev, fonction: e.target.value }))}\n                  />\n                  <Input\n                    placeholder=\"Téléphone\"\n                    value={newContact.telephone}\n                    onChange={(e) => setNewContact(prev => ({ ...prev, telephone: e.target.value }))}\n                  />\n                  <Input\n                    placeholder=\"Email\"\n                    value={newContact.email}\n                    onChange={(e) => setNewContact(prev => ({ ...prev, email: e.target.value }))}\n                  />\n                </div>\n                <Button onClick={handleAddContact} size=\"sm\" variant=\"outline\" className=\"w-full\">\n                  <Plus className=\"mr-2 h-4 w-4\" />\n                  Ajouter ce contact\n                </Button>\n              </div>\n            </div>\n\n            <div>\n              <Label htmlFor=\"notes\">Notes</Label>\n              <Textarea\n                id=\"notes\"\n                value={companyForm.notes}\n                onChange={(e) => setCompanyForm(prev => ({ ...prev, notes: e.target.value }))}\n                placeholder=\"Notes libres (Préferences, etc.)...\"\n                rows={4}\n              />\n            </div>\n\n            <div>\n              <Label htmlFor=\"blacklist_tags\">Tags & Blacklist</Label>\n              <Input\n                id=\"blacklist_tags\"\n                value={companyForm.blacklist_tags}\n                onChange={(e) => setCompanyForm(prev => ({ ...prev, blacklist_tags: e.target.value }))}\n                placeholder=\"Ex: mauvais payeur, VIP, ne pas relancer...\"\n                className=\"border-red-200 focus:border-red-500\"\n              />\n            </div>\n          </div>\n\n          <DialogFooter>\n            <Button variant=\"outline\" onClick={() => setShowCompanyDialog(false)}>\n              Annuler\n            </Button>\n            <Button \n              onClick={handleSaveCompany}\n              className=\"bg-gradient-to-r from-green-600 to-emerald-600\"\n            >\n              {editingCompany ? \"Mettre à jour\" : \"Créer\"}\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n\n      {/* Dialog Relance */}\n      <Dialog open={showRelanceDialog} onOpenChange={setShowRelanceDialog}>\n        <DialogContent>\n          <DialogHeader>\n            <DialogTitle>Nouvelle relance</DialogTitle>\n            <DialogDescription>\n              Pour : {selectedCompany?.nom}\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"space-y-4\">\n            <div>\n              <Label htmlFor=\"relance_date\">Date prévue *</Label>\n              <Input\n                id=\"relance_date\"\n                type=\"date\"\n                value={relanceForm.date}\n                onChange={(e) => setRelanceForm(prev => ({ ...prev, date: e.target.value }))}\n              />\n            </div>\n\n            <div>\n              <Label htmlFor=\"relance_objet\">Objet de la relance *</Label>\n              <Input\n                id=\"relance_objet\"\n                value={relanceForm.objet}\n                onChange={(e) => setRelanceForm(prev => ({ ...prev, objet: e.target.value }))}\n                placeholder=\"Ex: Proposition Noël 2025\"\n              />\n            </div>\n          </div>\n\n          <DialogFooter>\n            <Button variant=\"outline\" onClick={() => setShowRelanceDialog(false)}>\n              Annuler\n            </Button>\n            <Button \n              onClick={handleSaveRelance}\n              className=\"bg-gradient-to-r from-green-600 to-emerald-600\"\n            >\n              Créer la relance\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n\n      {/* Dialog Détails Client */}\n      <Dialog open={showDetailDialog} onOpenChange={setShowDetailDialog}>\n        <DialogContent className=\"max-w-2xl max-h-[90vh] overflow-y-auto\">\n          {(() => {\n            const company = companies.find(c => c.id === selectedCompanyForDetail?.id) || selectedCompanyForDetail;\n            if (!company) return null;\n            \n            const activeRelancesList = getActiveRelances(company.id);\n            const completedRelancesList = getCompletedRelances(company.id);\n            \n            return (\n              <>\n                <DialogHeader className=\"border-b pb-4\">\n                  <div className=\"flex items-center gap-3\">\n                    <span className=\"text-3xl\">\n                      {company.type_client === \"Particulier\" ? \"👤\" : company.type_client === \"Association\" ? \"🤝\" : \"🏢\"}\n                    </span>\n                    <div>\n                      <DialogTitle className=\"text-2xl font-bold text-gray-800 flex items-center gap-2 flex-wrap\">\n                        {company.nom}\n                        {getStatusBadge(company.statut)}\n                      </DialogTitle>\n                      <DialogDescription className=\"text-sm text-gray-400 mt-1\">\n                        Créé le {new Date(company.created_at || company.id).toLocaleDateString('fr-FR')}\n                      </DialogDescription>\n                    </div>\n                  </div>\n                </DialogHeader>\n\n                <div className=\"space-y-6 py-4\">\n                  {/* Meta / Badges */}\n                  <div className=\"flex flex-wrap gap-2\">\n                    {getTypeBadge(company.type_client)}\n                    {getCompanyProvenance(company) === \"location\" && (\n                      <Badge className=\"bg-blue-100 text-blue-800 border-blue-200\">📦 Origine: Location Matériel</Badge>\n                    )}\n                    {getCompanyProvenance(company) === \"contrat\" && (\n                      <Badge className=\"bg-purple-100 text-purple-800 border-purple-200\">🎵 Origine: Contrat Prestation</Badge>\n                    )}\n                    {company.secteur && <Badge variant=\"outline\">Secteur: {company.secteur}</Badge>}\n                    {company.siret && <Badge variant=\"secondary\" className=\"bg-slate-100 text-slate-600 font-normal\">SIRET: {company.siret}</Badge>}\n                    {getCompanyEventDate(company) ? (\n                      <Badge className=\"bg-emerald-100 text-emerald-800 font-semibold\">📅 Événement le: {new Date(getCompanyEventDate(company)).toLocaleDateString('fr-FR')}</Badge>\n                    ) : getCompanyYear(company) ? (\n                      <Badge className=\"bg-emerald-100 text-emerald-800 font-semibold\">📅 Année: {getCompanyYear(company)}</Badge>\n                    ) : null}\n                    {getCompanyEventType(company) && <Badge className=\"bg-amber-100 text-amber-850 font-semibold\">🎉 Événement: {getCompanyEventType(company)}</Badge>}\n                    {company.blacklist_tags && <Badge variant=\"destructive\">{company.blacklist_tags}</Badge>}\n                  </div>\n\n                  {/* Coordonnées */}\n                  <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4 bg-slate-50 p-4 rounded-xl border border-slate-100\">\n                    {company.adresse && (\n                      <div className=\"flex items-start text-sm text-gray-700\">\n                        <MapPin className=\"h-5 w-5 mr-3 text-slate-400 shrink-0\" />\n                        <div>\n                          <p className=\"font-semibold text-gray-500 text-xs uppercase tracking-wider\">Adresse</p>\n                          <p className=\"mt-0.5\">{company.adresse}</p>\n                        </div>\n                      </div>\n                    )}\n                    {company.telephone && (\n                      <div className=\"flex items-start text-sm text-gray-700\">\n                        <Phone className=\"h-5 w-5 mr-3 text-slate-400 shrink-0\" />\n                        <div>\n                          <p className=\"font-semibold text-gray-500 text-xs uppercase tracking-wider\">Téléphone</p>\n                          <p className=\"mt-0.5\">{company.telephone}</p>\n                        </div>\n                      </div>\n                    )}\n                    {company.email && (\n                      <div className=\"flex items-start text-sm text-gray-700 md:col-span-2 border-t pt-3 mt-1\">\n                        <Mail className=\"h-5 w-5 mr-3 text-slate-400 shrink-0\" />\n                        <div>\n                          <p className=\"font-semibold text-gray-500 text-xs uppercase tracking-wider\">Email</p>\n                          <a href={`mailto:${company.email}`} className=\"mt-0.5 text-blue-600 hover:underline block\">{company.email}</a>\n                        </div>\n                      </div>\n                    )}\n                  </div>\n\n                  {/* Contacts */}\n                  {company.contacts && company.contacts.length > 0 && (\n                    <div>\n                      <h4 className=\"text-sm font-semibold uppercase tracking-wider text-slate-500 mb-3 flex items-center gap-1.5\">\n                        <Users className=\"w-4 h-4 text-emerald-600\" /> Contacts ({company.contacts.length})\n                      </h4>\n                      <div className=\"grid grid-cols-1 md:grid-cols-2 gap-3\">\n                        {company.contacts.map((contact, idx) => (\n                          <div key={idx} className=\"bg-white border rounded-lg p-3 shadow-xs\">\n                            <p className=\"font-semibold text-slate-800\">{contact.nom}</p>\n                            {contact.fonction && <p className=\"text-xs text-slate-400 font-medium\">{contact.fonction}</p>}\n                            <div className=\"mt-2 space-y-1 text-xs text-slate-600\">\n                              {contact.telephone && <p>📞 {contact.telephone}</p>}\n                              {contact.email && <p>✉️ <a href={`mailto:${contact.email}`} className=\"hover:underline text-blue-650\">{contact.email}</a></p>}\n                            </div>\n                          </div>\n                        ))}\n                      </div>\n                    </div>\n                  )}\n\n                  {/* Notes */}\n                  {company.notes && (\n                    <div>\n                      <h4 className=\"text-sm font-semibold uppercase tracking-wider text-slate-500 mb-2 flex items-center gap-1.5\">\n                        <FileText className=\"w-4 h-4 text-amber-500\" /> Notes & Détails\n                      </h4>\n                      <div className=\"bg-yellow-50/70 border border-yellow-105 p-4 rounded-xl\">\n                        <p className=\"text-sm text-gray-700 whitespace-pre-wrap leading-relaxed\">{company.notes}</p>\n                      </div>\n                    </div>\n                  )}\n\n                  {/* Relances actives */}\n                  <div>\n                    <div className=\"flex items-center justify-between mb-3 border-b pb-2\">\n                      <h4 className=\"text-sm font-semibold uppercase tracking-wider text-slate-500 flex items-center gap-1.5\">\n                        <Calendar className=\"w-4 h-4 text-blue-500\" /> Relances Actives ({activeRelancesList.length})\n                      </h4>\n                      <Button\n                        size=\"sm\"\n                        variant=\"ghost\"\n                        onClick={() => {\n                          setSelectedCompany(company);\n                          setRelanceForm({ date: \"\", objet: \"\", company_id: company.id });\n                          setShowRelanceDialog(true);\n                        }}\n                        className=\"text-blue-600 hover:text-blue-700 text-xs h-7 px-2\"\n                      >\n                        <Plus className=\"h-3.5 w-3.5 mr-1\" /> Ajouter\n                      </Button>\n                    </div>\n\n                    {activeRelancesList.length === 0 ? (\n                      <p className=\"text-sm text-gray-400 italic\">Aucune relance active planifiée.</p>\n                    ) : (\n                      <div className=\"space-y-2\">\n                        {activeRelancesList.map(relance => (\n                          <div key={relance.id} className=\"bg-blue-50/50 hover:bg-blue-50 border border-blue-100 p-3 rounded-lg flex items-center justify-between\">\n                            <div className=\"flex-1 min-w-0 pr-3\">\n                              <p className=\"text-sm font-medium text-blue-900 truncate\">\n                                {relance.objet}\n                              </p>\n                              <p className=\"text-xs text-blue-500 mt-0.5\">\n                                Planifié pour le : {new Date(relance.date).toLocaleDateString('fr-FR')}\n                              </p>\n                            </div>\n                            <div className=\"flex gap-1\">\n                              <Button\n                                size=\"sm\"\n                                variant=\"ghost\"\n                                onClick={() => handleCompleteRelance(relance.id)}\n                                className=\"text-green-600 hover:text-green-700 hover:bg-green-100/50 h-8 w-8 p-0\"\n                                title=\"Terminer la relance\"\n                              >\n                                <Check className=\"h-4 w-4\" />\n                              </Button>\n                              <Button\n                                size=\"sm\"\n                                variant=\"ghost\"\n                                onClick={() => handleDeleteRelance(relance.id)}\n                                className=\"text-red-600 hover:text-red-700 hover:bg-red-100/50 h-8 w-8 p-0\"\n                                title=\"Supprimer la relance\"\n                              >\n                                <X className=\"h-4 w-4\" />\n                              </Button>\n                            </div>\n                          </div>\n                        ))}\n                      </div>\n                    )}\n                  </div>\n\n                  {/* Historique des relances */}\n                  {completedRelancesList.length > 0 && (\n                    <div>\n                      <h4 className=\"text-sm font-semibold uppercase tracking-wider text-slate-500 mb-2.5\">\n                        📋 Historique des relances ({completedRelancesList.length})\n                      </h4>\n                      <div className=\"space-y-1.5 max-h-40 overflow-y-auto pr-1\">\n                        {completedRelancesList.map(relance => (\n                          <div key={relance.id} className=\"text-sm text-gray-500 pl-4 relative before:absolute before:left-1 before:top-[8px] before:w-1.5 before:h-1.5 before:bg-green-500 before:rounded-full\">\n                            <strong>{new Date(relance.date).toLocaleDateString('fr-FR')}</strong> : {relance.objet}\n                          </div>\n                        ))}\n                      </div>\n                    </div>\n                  )}\n                </div>\n\n                <DialogFooter className=\"border-t pt-4\">\n                  <div className=\"flex justify-between items-center w-full gap-4\">\n                    <Button\n                      variant=\"destructive\"\n                      onClick={() => {\n                        setShowDetailDialog(false);\n                        handleDeleteCompany(company.id);\n                      }}\n                      className=\"gap-1.5\"\n                    >\n                      <Trash2 className=\"w-4 h-4\" /> Supprimer\n                    </Button>\n                    <div className=\"flex gap-2\">\n                      <Button variant=\"outline\" onClick={() => setShowDetailDialog(false)}>\n                        Fermer\n                      </Button>\n                      <Button \n                        onClick={() => handleEditFromDetail(company)}\n                        className=\"bg-blue-600 hover:bg-blue-700 text-white gap-1.5\"\n                      >\n                        <Edit className=\"w-4 h-4\" /> Modifier\n                      </Button>\n                    </div>\n                  </div>\n                </DialogFooter>\n              </>\n            );\n          })()}\n        </DialogContent>\n      </Dialog>\n\n      {/* Dialog Exportation d'Emails */}\n      <Dialog open={showExportDialog} onOpenChange={setShowExportDialog}>\n        <DialogContent className=\"max-w-md\">\n          <DialogHeader className=\"border-b pb-3\">\n            <DialogTitle className=\"text-xl font-bold flex items-center gap-2\">\n              📥 Exporter les adresses email\n            </DialogTitle>\n            <DialogDescription>\n              Générez une liste des adresses email pour vos newsletters ou campagnes de communication.\n            </DialogDescription>\n          </DialogHeader>\n\n          {(() => {\n            const mainEmails = filteredCompanies\n              .map(c => c.email?.trim())\n              .filter(email => email && email.includes(\"@\"));\n            \n            const contactEmails = filteredCompanies\n              .flatMap(c => (c.contacts || []).map(contact => contact.email?.trim()))\n              .filter(email => email && email.includes(\"@\"));\n\n            const allEmails = Array.from(new Set([...mainEmails, ...contactEmails]));\n            const emailStringList = allEmails.join(\", \");\n\n            return (\n              <div className=\"space-y-4 py-3\">\n                <div className=\"bg-blue-50 p-3 rounded-lg border border-blue-100 text-sm text-blue-800\">\n                  <p className=\"font-semibold\">Filtres actifs :</p>\n                  <p className=\"text-xs text-blue-600 mt-1\">\n                    {startDateFilter && endDateFilter ? `Événements du ${new Date(startDateFilter).toLocaleDateString('fr-FR')} au ${new Date(endDateFilter).toLocaleDateString('fr-FR')}` : \n                     startDateFilter ? `Événements après le ${new Date(startDateFilter).toLocaleDateString('fr-FR')}` : \n                     endDateFilter ? `Événements avant le ${new Date(endDateFilter).toLocaleDateString('fr-FR')}` : \"Tous les événements\"}\n                  </p>\n                  <p className=\"font-medium mt-2\">📊 {allEmails.length} adresse(s) email unique(s) trouvée(s)</p>\n                </div>\n\n                <div className=\"space-y-2\">\n                  <Label className=\"text-slate-700 text-xs font-semibold uppercase tracking-wider block\">Liste brute (Séparateur: Virgule)</Label>\n                  <Textarea \n                    value={emailStringList}\n                    readOnly\n                    rows={6}\n                    className=\"font-mono text-xs bg-slate-50 border-slate-200 focus:ring-0 focus:border-slate-300 resize-none select-all\"\n                  />\n                  <p className=\"text-[10px] text-slate-450 italic\">Idéal pour copier-coller dans le champ Cci/Bcc de votre client mail.</p>\n                </div>\n\n                <div className=\"flex flex-col gap-2 pt-2 border-t\">\n                  <Button \n                    onClick={() => {\n                      navigator.clipboard.writeText(emailStringList);\n                      toast.success(\"Adresses email copiées dans le presse-papiers !\");\n                    }}\n                    className=\"bg-emerald-600 hover:bg-emerald-700 text-white w-full gap-2\"\n                  >\n                    📋 Copier dans le presse-papiers\n                  </Button>\n                  <Button \n                    onClick={handleDownloadCSV}\n                    variant=\"outline\" \n                    className=\"w-full gap-2 text-blue-700 border-blue-200 hover:bg-blue-50\"\n                  >\n                    ⬇️ Télécharger le fichier CSV complet\n                  </Button>\n                  <Button \n                    variant=\"ghost\" \n                    onClick={() => setShowExportDialog(false)} \n                    className=\"w-full text-slate-500 hover:text-slate-700\"\n                  >\n                    Fermer\n                  </Button>\n                </div>\n              </div>\n            );\n          })()}\n        </DialogContent>\n      </Dialog>\n    </div>\n  );\n}\n\nexport default CRMApp;\n","import React, { useState, useEffect, useRef } from 'react';\nimport { useLocation, useNavigate } from 'react-router-dom';\nimport { Button } from './ui/button';\nimport { Input } from './ui/input';\nimport { Textarea } from './ui/textarea';\nimport { Card, CardContent, CardHeader, CardTitle } from './ui/card';\nimport { Label } from './ui/label';\nimport { Checkbox } from './ui/checkbox';\nimport { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from './ui/dialog';\nimport { toast } from 'sonner';\nimport { \n  Send, \n  ArrowLeft, \n  Plus, \n  Trash2, \n  Edit, \n  Save,\n  Star,\n  Loader2,\n  FileText,\n  Mail,\n  XCircle\n} from 'lucide-react';\nimport ReactQuill from 'react-quill';\nimport 'react-quill/dist/quill.snow.css';\nimport apiService from '../services/api';\nimport VariableInsertMenu, { VARIABLES } from './VariableInsertMenu';\nimport { useEmailSignature } from '../hooks/useEmailSignature';\n\n// Quill editor modules configuration\nconst quillModules = {\n  toolbar: [\n    [{ 'header': [1, 2, 3, false] }],\n    ['bold', 'italic', 'underline'],\n    [{ 'color': [] }, { 'background': [] }],\n    [{ 'list': 'ordered'}, { 'list': 'bullet' }],\n    [{ 'align': [] }],\n    ['image'],\n    ['clean']\n  ]\n};\n\nconst quillFormats = [\n  'header',\n  'bold', 'italic', 'underline',\n  'color', 'background',\n  'list', 'bullet',\n  'align',\n  'image'\n];\n\n// Hardcoded signature removed - now loaded from Global Settings via useEmailSignature hook\n\nconst ContractEmailPage = () => {\n  const { signatureHtml } = useEmailSignature();\n  const location = useLocation();\n  const navigate = useNavigate();\n  const contractData = location.state?.contractData;\n  const contractHTML = location.state?.contractHTML;\n  const contractHTMLs = location.state?.contractHTMLs;\n\n  // Email states\n  const [recipientEmail, setRecipientEmail] = useState(\"\");\n  const [emailSubject, setEmailSubject] = useState(\"\");\n  const [emailBody, setEmailBody] = useState('');\n  const [sendingEmail, setSendingEmail] = useState(false);\n  const [emailSignature, setEmailSignature] = useState('');\n\n  // Template states\n  const [templates, setTemplates] = useState([]);\n  const [showTemplateDialog, setShowTemplateDialog] = useState(false);\n  const [editingTemplate, setEditingTemplate] = useState(null);\n  const [templateForm, setTemplateForm] = useState({ name: '', subject: '', body: '', is_default: false });\n  const [savingTemplate, setSavingTemplate] = useState(false);\n  const subjectInputRef = useRef(null);\n\n  // Derive selectedSubmission from contract data for variable replacement\n  const selectedSubmission = contractData ? {\n    nom: contractData.client_info?.name || '',\n    email: contractData.client_info?.email || '',\n    telephone: contractData.client_info?.phone || '',\n    entreprise: contractData.client_info?.company || '',\n    date_evenement: contractData.client_info?.event_date ? (() => {\n      const parts = contractData.client_info.event_date.split('-');\n      return parts.length === 3 ? `${parts[2]}-${parts[1]}-${parts[0]}` : contractData.client_info.event_date;\n    })() : '',\n    type_evenement: contractData.client_info?.event_type || '',\n  } : null;\n\n  // Insert variable at cursor in email body (ReactQuill)\n  const handleInsertVariable = (variable) => {\n    const quill = document.querySelector('.ql-editor');\n    if (quill) {\n      const sel = window.getSelection();\n      if (sel.rangeCount > 0 && quill.contains(sel.anchorNode)) {\n        const range = sel.getRangeAt(0);\n        const textNode = document.createTextNode(variable);\n        range.deleteContents();\n        range.insertNode(textNode);\n        range.setStartAfter(textNode);\n        range.collapse(true);\n        sel.removeAllRanges();\n        sel.addRange(range);\n        setEmailBody(quill.innerHTML);\n      } else {\n        setEmailBody(prev => prev ? prev.replace(/<\\/p>(?![\\s\\S]*<\\/p>)/, `${variable}</p>`) : `<p>${variable}</p>`);\n      }\n    } else {\n      setEmailBody(prev => prev ? prev.replace(/<\\/p>(?![\\s\\S]*<\\/p>)/, `${variable}</p>`) : `<p>${variable}</p>`);\n    }\n  };\n\n  // Insert variable at cursor in email subject\n  const handleInsertSubjectVariable = (variable) => {\n    const input = subjectInputRef.current;\n    if (input) {\n      const start = input.selectionStart || 0;\n      const end = input.selectionEnd || 0;\n      const current = emailSubject || '';\n      const newVal = current.slice(0, start) + variable + current.slice(end);\n      setEmailSubject(newVal);\n      setTimeout(() => {\n        input.focus();\n        input.setSelectionRange(start + variable.length, start + variable.length);\n      }, 0);\n    } else {\n      setEmailSubject(prev => prev + variable);\n    }\n  };\n\n  // Replace variables in text with actual values\n  const replaceVariables = (text, data) => {\n    if (!text || !data) return text;\n    let result = text;\n    VARIABLES.forEach(v => {\n      const field = v.key.replace(/[{}]/g, '');\n      const value = data[field] || '';\n      result = result.split(v.key).join(value);\n    });\n    return result;\n  };\n\n  // Initialize form with contract data\n  useEffect(() => {\n    if (contractData) {\n      console.log(\"Contract Data received:\", contractData);\n      console.log(\"Event date from contractData:\", contractData.client_info?.event_date);\n      setRecipientEmail(contractData.client_info?.email || \"\");\n    }\n  }, [contractData]);\n\n  // Fetch templates and apply signature from hook\n  useEffect(() => {\n    const init = async () => {\n      // Fetch templates\n      try {\n        const response = await apiService.get('/contract-emails/templates');\n        setTemplates(response.data.templates || []);\n        const defaultTemplate = response.data.templates?.find(t => t.is_default);\n        if (defaultTemplate) {\n          setEmailSubject(defaultTemplate.subject);\n          setEmailBody(defaultTemplate.body + signatureHtml);\n        } else {\n          setEmailBody(signatureHtml);\n        }\n      } catch (error) {\n        console.error('Error fetching templates:', error);\n        setEmailBody(signatureHtml);\n      }\n    };\n    init();\n  }, [signatureHtml]);\n\n  const fetchTemplates = async () => {\n    try {\n      const response = await apiService.get('/contract-emails/templates');\n      setTemplates(response.data.templates || []);\n    } catch (error) {\n      console.error('Error fetching templates:', error);\n    }\n  };\n\n  const applyTemplate = (template) => {\n    setEmailSubject(template.subject);\n    setEmailBody(template.body + emailSignature);\n    toast.success(`Template \"${template.name}\" appliqué`);\n  };\n\n  const openTemplateDialog = (template = null) => {\n    if (template) {\n      // Mode édition : utiliser les valeurs du template existant\n      setEditingTemplate(template);\n      setTemplateForm({\n        name: template.name,\n        subject: template.subject,\n        body: template.body,\n        is_default: template.is_default\n      });\n    } else {\n      // Mode création : utiliser l'objet et le corps actuels du formulaire\n      setEditingTemplate(null);\n      setTemplateForm({ \n        name: '', \n        subject: emailSubject, \n        body: emailBody, \n        is_default: false \n      });\n    }\n    setShowTemplateDialog(true);\n  };\n\n  const saveTemplate = async () => {\n    if (!templateForm.name) {\n      toast.error('Veuillez saisir un nom pour le template');\n      return;\n    }\n    \n    // Vérifier qu'il y a du contenu à sauvegarder\n    if (!templateForm.subject && !templateForm.body) {\n      toast.error('Le template doit avoir un objet ou un corps de message');\n      return;\n    }\n\n    try {\n      setSavingTemplate(true);\n      if (editingTemplate) {\n        await apiService.put(`/contract-emails/templates/${editingTemplate.id}`, templateForm);\n        toast.success('Template mis à jour');\n      } else {\n        await apiService.post('/contract-emails/templates', templateForm);\n        toast.success('Template créé');\n      }\n      fetchTemplates();\n      setShowTemplateDialog(false);\n    } catch (error) {\n      console.error('Error saving template:', error);\n      toast.error('Erreur lors de l\\'enregistrement');\n    } finally {\n      setSavingTemplate(false);\n    }\n  };\n\n  const deleteTemplate = async (templateId) => {\n    if (!window.confirm('Supprimer ce template ?')) return;\n    \n    try {\n      await apiService.delete(`/contract-emails/templates/${templateId}`);\n      toast.success('Template supprimé');\n      fetchTemplates();\n    } catch (error) {\n      console.error('Error deleting template:', error);\n      toast.error('Erreur lors de la suppression');\n    }\n  };\n\n  const sendEmail = async () => {\n    if (!recipientEmail) {\n      toast.error('Veuillez saisir l\\'email du destinataire');\n      return;\n    }\n    if (!emailSubject) {\n      toast.error('Veuillez saisir l\\'objet du mail');\n      return;\n    }\n    if (!contractHTML) {\n      toast.error('Données du contrat manquantes');\n      return;\n    }\n\n    try {\n      setSendingEmail(true);\n      toast.info(\"Génération et envoi du contrat en cours...\", { duration: 3000 });\n\n      // Format event date from contract data (DDMMYYYY)\n      // The event date is in contractData.client_info.event_date\n      let eventDateFormatted = '';\n      const eventDate = contractData?.client_info?.event_date;\n      console.log(\"Contract data:\", contractData);\n      console.log(\"Event date from contractData:\", eventDate);\n      \n      if (eventDate && eventDate.trim() !== '') {\n        try {\n          // Parse YYYY-MM-DD format directly to avoid timezone issues\n          const parts = eventDate.split('-');\n          if (parts.length === 3) {\n            const year = parts[0];\n            const month = parts[1];\n            const day = parts[2];\n            eventDateFormatted = `${day}${month}${year}`;\n          } else {\n            // Fallback to Date parsing\n            const date = new Date(eventDate);\n            if (!isNaN(date.getTime())) {\n              const day = String(date.getDate()).padStart(2, '0');\n              const month = String(date.getMonth() + 1).padStart(2, '0');\n              const year = date.getFullYear();\n              eventDateFormatted = `${day}${month}${year}`;\n            }\n          }\n        } catch (e) {\n          console.error(\"Error parsing event date:\", e);\n        }\n      }\n      \n      // If still empty, use current date as fallback\n      if (!eventDateFormatted) {\n        const now = new Date();\n        const day = String(now.getDate()).padStart(2, '0');\n        const month = String(now.getMonth() + 1).padStart(2, '0');\n        const year = now.getFullYear();\n        eventDateFormatted = `${day}${month}${year}`;\n        console.log(\"Using fallback current date:\", eventDateFormatted);\n      }\n      \n      console.log(\"Final eventDateFormatted:\", eventDateFormatted);\n      \n      const finalSubject = replaceVariables(emailSubject, selectedSubmission);\n      const finalBody = replaceVariables(emailBody, selectedSubmission);\n\n      toast.info(\"Génération du(des) PDF en cours...\", { duration: 5000 });\n      let pdfBase64 = '';\n      let pdfFilename = `contrat_RkeyProd_${eventDateFormatted}.pdf`;\n      let pdfs = [];\n\n      const generateSinglePdfBase64 = async (htmlToRender) => {\n        let tempContainer = null;\n        try {\n          if (!window.jspdf || !window.jspdf.jsPDF) {\n            throw new Error('jsPDF non disponible');\n          }\n          \n          const pdf = new window.jspdf.jsPDF({\n            orientation: 'portrait', unit: 'mm', format: 'a4', compress: true\n          });\n          const pageWidth = 210;\n          const margin = 10;\n          const availableWidth = pageWidth - (2 * margin);\n          const availableHeight = 297 - (2 * margin);\n          \n          tempContainer = document.createElement('div');\n          tempContainer.style.position = 'fixed';\n          tempContainer.style.top = '-9999px';\n          tempContainer.style.left = '-9999px';\n          tempContainer.style.width = '794px';\n          tempContainer.style.background = 'white';\n          tempContainer.style.padding = '20px';\n          tempContainer.innerHTML = htmlToRender;\n          document.body.appendChild(tempContainer);\n          \n          await new Promise(r => setTimeout(r, 1500));\n          \n          const allPages = tempContainer.querySelectorAll('[id^=\"pdf-page-\"]');\n          let pdfPageAdded = false;\n          \n          if (allPages.length > 0) {\n            for (let i = 0; i < allPages.length; i++) {\n              const pageEl = allPages[i];\n              if (pageEl && pageEl.innerHTML.trim()) {\n                if (pdfPageAdded) pdf.addPage();\n                try {\n                  const canvas = await window.html2canvas(pageEl, {\n                    scale: 1.4, useCORS: true, allowTaint: true,\n                    backgroundColor: '#ffffff', width: 794,\n                    height: Math.min(1123, pageEl.scrollHeight),\n                    logging: false, removeContainer: false\n                  });\n                  const imgData = canvas.toDataURL('image/jpeg', 0.88);\n                  const imgWidth = availableWidth;\n                  const imgHeight = (canvas.height * imgWidth) / canvas.width;\n                  if (imgHeight <= availableHeight) {\n                    pdf.addImage(imgData, 'JPEG', margin, margin, imgWidth, imgHeight, undefined, 'FAST');\n                  } else {\n                    const scaledHeight = availableHeight;\n                    const scaledWidth = (canvas.width * scaledHeight) / canvas.height;\n                    pdf.addImage(imgData, 'JPEG', margin, margin, scaledWidth, scaledHeight, undefined, 'FAST');\n                  }\n                  pdfPageAdded = true;\n                } catch (pageErr) {\n                  console.warn('Capture page error:', pageErr);\n                }\n              }\n            }\n          } else {\n            const canvas = await window.html2canvas(tempContainer, {\n              scale: 1.4, useCORS: true, allowTaint: true,\n              backgroundColor: '#ffffff', width: 794, logging: false\n            });\n            const imgData = canvas.toDataURL('image/jpeg', 0.88);\n            const imgWidth = availableWidth;\n            const imgHeight = (canvas.height * imgWidth) / canvas.width;\n            pdf.addImage(imgData, 'JPEG', margin, margin, imgWidth, Math.min(imgHeight, availableHeight), undefined, 'FAST');\n          }\n          \n          return pdf.output('datauristring').split(',')[1] || '';\n        } finally {\n          try { if (tempContainer && tempContainer.parentNode) tempContainer.parentNode.removeChild(tempContainer); } catch(e) {}\n        }\n      };\n\n      try {\n        if (contractHTMLs && Array.isArray(contractHTMLs)) {\n          for (let doc of contractHTMLs) {\n            const b64 = await generateSinglePdfBase64(doc.html);\n            if (b64) {\n              pdfs.push({\n                base64: b64,\n                filename: doc.filename\n              });\n            }\n          }\n        } else {\n          pdfBase64 = await generateSinglePdfBase64(contractHTML);\n        }\n      } catch (pdfError) {\n        console.error('PDF generation error:', pdfError);\n        toast.error(\"Erreur de génération PDF, envoi sans pièce jointe\");\n      }\n\n      const requestData = {\n        contract_html: contractHTML,\n        client_name: contractData?.client_info?.name || \"Client\",\n        event_date: eventDateFormatted,\n        recipient_email: recipientEmail,\n        email_subject: finalSubject,\n        email_body: finalBody,\n        pdf_base64: pdfBase64,\n        pdf_filename: pdfFilename,\n        pdfs: pdfs.length > 0 ? pdfs : null\n      };\n\n      const response = await apiService.post('/contract-emails/send', requestData);\n\n      if (response.data.success) {\n        // Mettre à jour le statut du contrat à \"sent\" (envoyé)\n        if (contractData?.id) {\n          try {\n            await apiService.put(`/contracts2/${contractData.id}/status`, { status: 'sent' });\n            console.log('Contract status updated to sent');\n          } catch (statusError) {\n            console.error('Error updating contract status:', statusError);\n            // On ne bloque pas l'envoi si la mise à jour du statut échoue\n          }\n        }\n        \n        toast.success(response.data.message);\n        // Navigate back to contracts\n        navigate('/contracts2');\n      }\n    } catch (error) {\n      console.error('Error sending email:', error);\n      const errorDetail = error.response?.data?.detail || error.message || 'Erreur lors de l\\'envoi de l\\'email';\n      toast.error(errorDetail);\n    } finally {\n      setSendingEmail(false);\n    }\n  };\n\n  // If no contract data, redirect back\n  if (!contractData || !contractHTML) {\n    return (\n      <div className=\"min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-6\">\n        <div className=\"max-w-4xl mx-auto\">\n          <Card>\n            <CardContent className=\"p-8 text-center\">\n              <FileText className=\"w-16 h-16 mx-auto text-gray-400 mb-4\" />\n              <h2 className=\"text-xl font-semibold mb-2\">Aucun contrat sélectionné</h2>\n              <p className=\"text-gray-500 mb-6\">Veuillez d'abord créer un contrat depuis l'application Contrats DJ.</p>\n              <Button onClick={() => navigate('/contracts2')}>\n                <ArrowLeft className=\"w-4 h-4 mr-2\" />\n                Retour aux contrats\n              </Button>\n            </CardContent>\n          </Card>\n        </div>\n      </div>\n    );\n  }\n\n  return (\n    <div className=\"min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-6\">\n      <div className=\"max-w-4xl mx-auto space-y-6\">\n        {/* Header */}\n        <div className=\"flex items-center justify-between\">\n          <Button \n            variant=\"outline\" \n            onClick={() => navigate(-1)}\n            className=\"gap-2\"\n          >\n            <ArrowLeft className=\"w-4 h-4\" />\n            Retour au contrat\n          </Button>\n        </div>\n\n        {/* Main Card */}\n        <Card>\n          <CardHeader className=\"border-b bg-gradient-to-r from-green-50 to-emerald-50\">\n            <CardTitle className=\"flex items-center gap-3 text-green-700\">\n              <div className=\"p-2 bg-green-100 rounded-lg\">\n                <Send className=\"w-6 h-6\" />\n              </div>\n              <div>\n                <h1 className=\"text-2xl\">Envoyer le contrat par email</h1>\n                <p className=\"text-sm font-normal text-green-600 mt-1\">\n                  Le contrat sera généré en PDF et envoyé en pièce jointe\n                </p>\n              </div>\n            </CardTitle>\n          </CardHeader>\n          \n          <CardContent className=\"p-6 space-y-6\">\n            {/* Contract Summary */}\n            <div className=\"bg-blue-50 border border-blue-200 rounded-lg p-4\">\n              <h3 className=\"font-semibold text-blue-800 mb-2 flex items-center gap-2\">\n                <FileText className=\"w-4 h-4\" />\n                Contrat à envoyer\n              </h3>\n              <div className=\"text-sm text-blue-700 space-y-1\">\n                <p><strong>Client :</strong> {contractData.client_info?.name || \"Non renseigné\"}</p>\n                <p><strong>Email :</strong> {contractData.client_info?.email || \"Non renseigné\"}</p>\n                {contractData.client_info?.event_date && (\n                  <p><strong>Date événement :</strong> {new Date(contractData.client_info.event_date).toLocaleDateString('fr-FR')}</p>\n                )}\n              </div>\n            </div>\n\n            {/* Email Configuration */}\n            <div className=\"space-y-4\">\n              <h3 className=\"font-semibold text-gray-800 flex items-center gap-2\">\n                <Mail className=\"w-5 h-5 text-gray-600\" />\n                Configuration de l'email\n              </h3>\n              \n              <div>\n                <Label htmlFor=\"recipient\">Email du destinataire *</Label>\n                <Input\n                  id=\"recipient\"\n                  type=\"email\"\n                  placeholder=\"\"\n                  value={recipientEmail}\n                  onChange={(e) => setRecipientEmail(e.target.value)}\n                  className=\"mt-1\"\n                />\n              </div>\n              \n              <div>\n                <div className=\"flex items-center justify-between\">\n                  <Label htmlFor=\"subject\">Objet du mail *</Label>\n                  <VariableInsertMenu onInsert={handleInsertSubjectVariable} submissionData={selectedSubmission} />\n                </div>\n                <Input\n                  id=\"subject\"\n                  placeholder=\"\"\n                  value={emailSubject}\n                  onChange={(e) => setEmailSubject(e.target.value)}\n                  className=\"mt-1\"\n                />\n              </div>\n              \n              <div>\n                <div className=\"flex items-center justify-between mb-1\">\n                  <Label>Corps du message</Label>\n                  <VariableInsertMenu onInsert={handleInsertVariable} submissionData={selectedSubmission} />\n                </div>\n                <div className=\"mt-1 bg-white rounded-md border\">\n                  <ReactQuill\n                    theme=\"snow\"\n                    value={emailBody}\n                    onChange={setEmailBody}\n                    modules={quillModules}\n                    formats={quillFormats}\n                    placeholder=\"\"\n                    style={{ minHeight: '200px' }}\n                  />\n                </div>\n              </div>\n\n              {/* PDF Filename Display */}\n              {contractData && (() => {\n                // Format event date for display - using client_info.event_date\n                const eventDate = contractData?.client_info?.event_date;\n                let dateStr = '';\n                \n                if (eventDate && eventDate.trim() !== '') {\n                  // Parse YYYY-MM-DD format directly to avoid timezone issues\n                  const parts = eventDate.split('-');\n                  if (parts.length === 3) {\n                    dateStr = `${parts[2]}${parts[1]}${parts[0]}`;\n                  } else {\n                    // Fallback to Date parsing\n                    try {\n                      const date = new Date(eventDate);\n                      if (!isNaN(date.getTime())) {\n                        const day = String(date.getDate()).padStart(2, '0');\n                        const month = String(date.getMonth() + 1).padStart(2, '0');\n                        const year = date.getFullYear();\n                        dateStr = `${day}${month}${year}`;\n                      }\n                    } catch (e) {\n                      console.error(\"Error parsing date for display:\", e);\n                    }\n                  }\n                }\n                \n                // Fallback to current date\n                if (!dateStr) {\n                  const now = new Date();\n                  dateStr = `${String(now.getDate()).padStart(2, '0')}${String(now.getMonth() + 1).padStart(2, '0')}${now.getFullYear()}`;\n                }\n                \n                return (\n                  <div className=\"bg-gray-100 border border-gray-300 rounded-lg p-3\">\n                    <p className=\"text-sm text-gray-700 flex items-center gap-2\">\n                      <FileText className=\"w-4 h-4 text-red-500\" />\n                      <strong>Pièce jointe :</strong> contrat_RkeyProd_{dateStr}.pdf\n                    </p>\n                  </div>\n                );\n              })()}\n            </div>\n\n            {/* Templates Section */}\n            <div className=\"border-t pt-6\">\n              <div className=\"flex items-center justify-between mb-4\">\n                <h3 className=\"font-semibold text-gray-800 flex items-center gap-2\">\n                  <Star className=\"w-5 h-5 text-amber-500\" />\n                  Templates Email\n                </h3>\n                <Button \n                  variant=\"outline\" \n                  size=\"sm\" \n                  onClick={() => openTemplateDialog()}\n                  disabled={!emailSubject && !emailBody}\n                >\n                  <Save className=\"w-4 h-4 mr-1\" />\n                  Enregistrer comme template\n                </Button>\n              </div>\n              \n              {templates.length === 0 ? (\n                <div className=\"text-center py-8 bg-gray-50 rounded-lg border-2 border-dashed\">\n                  <Star className=\"w-10 h-10 mx-auto text-gray-300 mb-2\" />\n                  <p className=\"text-gray-500\">Aucun template. Créez-en un pour gagner du temps !</p>\n                </div>\n              ) : (\n                <div className=\"space-y-2\">\n                  {templates.map((template) => (\n                    <div \n                      key={template.id}\n                      className=\"flex items-center justify-between p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors border\"\n                    >\n                      <div className=\"flex items-center gap-3\">\n                        {template.is_default && (\n                          <Star className=\"w-5 h-5 text-amber-500 fill-amber-500\" />\n                        )}\n                        <div>\n                          <span className=\"font-medium\">{template.name}</span>\n                          <p className=\"text-sm text-gray-500\">{template.subject}</p>\n                        </div>\n                      </div>\n                      <div className=\"flex items-center gap-2\">\n                        <Button \n                          variant=\"default\" \n                          size=\"sm\" \n                          onClick={() => applyTemplate(template)}\n                          className=\"bg-green-600 hover:bg-green-700\"\n                        >\n                          Utiliser\n                        </Button>\n                        <Button \n                          variant=\"ghost\" \n                          size=\"sm\" \n                          onClick={() => openTemplateDialog(template)}\n                        >\n                          <Edit className=\"w-4 h-4\" />\n                        </Button>\n                        <Button \n                          variant=\"ghost\" \n                          size=\"sm\" \n                          onClick={() => deleteTemplate(template.id)}\n                          className=\"text-red-600 hover:text-red-700 hover:bg-red-50\"\n                        >\n                          <Trash2 className=\"w-4 h-4\" />\n                        </Button>\n                      </div>\n                    </div>\n                  ))}\n                </div>\n              )}\n            </div>\n\n            {/* Action Buttons */}\n            <div className=\"flex justify-end gap-4 pt-6 border-t\">\n              <Button \n                variant=\"outline\" \n                onClick={() => navigate(-1)}\n                size=\"lg\"\n              >\n                Annuler\n              </Button>\n              <Button \n                onClick={sendEmail}\n                disabled={sendingEmail || !recipientEmail || !emailSubject}\n                className=\"bg-green-600 hover:bg-green-700\"\n                size=\"lg\"\n              >\n                {sendingEmail ? (\n                  <>\n                    <Loader2 className=\"w-5 h-5 mr-2 animate-spin\" />\n                    Envoi en cours...\n                  </>\n                ) : (\n                  <>\n                    <Send className=\"w-5 h-5 mr-2\" />\n                    Envoyer le contrat\n                  </>\n                )}\n              </Button>\n            </div>\n          </CardContent>\n        </Card>\n      </div>\n\n      {/* Template Dialog */}\n      <Dialog open={showTemplateDialog} onOpenChange={setShowTemplateDialog}>\n        <DialogContent>\n          <DialogHeader>\n            <DialogTitle>\n              {editingTemplate ? 'Modifier le Template' : 'Enregistrer comme template'}\n            </DialogTitle>\n          </DialogHeader>\n          <div className=\"space-y-4\">\n            <div>\n              <Label htmlFor=\"template-name\">Nom du template *</Label>\n              <Input\n                id=\"template-name\"\n                value={templateForm.name}\n                onChange={(e) => setTemplateForm({ ...templateForm, name: e.target.value })}\n                placeholder=\"\"\n                className=\"mt-1\"\n              />\n            </div>\n            \n            {/* Aperçu du contenu qui sera sauvegardé */}\n            <div className=\"bg-gray-50 rounded-lg p-3 space-y-2\">\n              <p className=\"text-sm font-medium text-gray-700\">Contenu qui sera sauvegardé :</p>\n              <div className=\"text-sm text-gray-600\">\n                <p><strong>Objet :</strong> {templateForm.subject || <span className=\"italic text-gray-400\">(vide)</span>}</p>\n                <p><strong>Corps :</strong> {templateForm.body ? \n                  <span className=\"text-green-600\">✓ Contenu HTML avec mise en forme</span> : \n                  <span className=\"italic text-gray-400\">(vide)</span>}\n                </p>\n              </div>\n            </div>\n            \n            <div className=\"flex items-center space-x-2\">\n              <Checkbox\n                id=\"template-default\"\n                checked={templateForm.is_default}\n                onCheckedChange={(checked) => setTemplateForm({ ...templateForm, is_default: checked })}\n              />\n              <Label htmlFor=\"template-default\" className=\"cursor-pointer\">\n                Définir comme template par défaut\n              </Label>\n            </div>\n          </div>\n          <DialogFooter>\n            <Button variant=\"outline\" onClick={() => setShowTemplateDialog(false)}>\n              Annuler\n            </Button>\n            <Button \n              onClick={saveTemplate} \n              disabled={savingTemplate}\n              className=\"bg-blue-600 hover:bg-blue-700\"\n            >\n              {savingTemplate ? (\n                <Loader2 className=\"w-4 h-4 animate-spin mr-2\" />\n              ) : (\n                <Save className=\"w-4 h-4 mr-2\" />\n              )}\n              Enregistrer\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n    </div>\n  );\n};\n\nexport default ContractEmailPage;\n","import React, { useState, useEffect } from 'react';\nimport { useParams } from 'react-router-dom';\nimport { isContractDirigeant } from './contracts2/calculations';\n\nconst ContractHtmlPreview = () => {\n  const { id } = useParams();\n  const [contract, setContract] = useState(null);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useEffect(() => {\n    loadContract();\n  }, [id]);\n\n  const loadContract = async () => {\n    try {\n      setLoading(true);\n      setError(null);\n      const token = localStorage.getItem('access_token');\n      const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n      const response = await fetch(`${(window.location.hostname === 'rkeyprodapp.fr' || window.location.hostname === 'www.rkeyprodapp.fr') ? window.location.origin : (process.env.REACT_APP_BACKEND_URL || window.location.origin)}/api/contracts2/${id}`, { headers });\n      if (!response.ok) {\n        throw new Error('Contrat non trouvé');\n      }\n      const contractData = await response.json();\n      setContract(contractData);\n    } catch (error) {\n      console.error('Failed to load contract:', error);\n      setError('Impossible de charger le contrat. Veuillez vérifier que l\\'ID est correct.');\n    } finally {\n      setLoading(false);\n    }\n  };\n\n  if (loading) {\n    return (\n      <div className=\"min-h-screen bg-white flex items-center justify-center\">\n        <div className=\"text-center\">\n          <div className=\"animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500 mx-auto mb-4\"></div>\n          <p className=\"text-gray-600\">Chargement du contrat...</p>\n        </div>\n      </div>\n    );\n  }\n\n  if (error) {\n    return (\n      <div className=\"min-h-screen bg-white flex items-center justify-center\">\n        <div className=\"text-center max-w-md mx-auto p-8\">\n          <div className=\"text-red-500 text-6xl mb-4\">⚠️</div>\n          <h2 className=\"text-2xl font-bold text-gray-900 mb-4\">Contrat non trouvé</h2>\n          <p className=\"text-gray-600 mb-6\">{error}</p>\n        </div>\n      </div>\n    );\n  }\n\n  if (!contract) {\n    return (\n      <div className=\"min-h-screen bg-white flex items-center justify-center\">\n        <div className=\"text-center\">\n          <p className=\"text-gray-600\">Contrat non disponible.</p>\n        </div>\n      </div>\n    );\n  }\n\n  const calculateContractTotal = () => {\n    const optionsTotal = (contract.selected_options || [])\n      .filter(option => option.selected)\n      .reduce((sum, option) => sum + option.price, 0);\n    return Math.max(0, contract.base_price + optionsTotal - (contract.discount_amount || 0));\n  };\n\n  const calculateContractDepositAmount = () => {\n    if (contract.no_deposit_required) {\n      return 0;\n    }\n    \n    if (contract.custom_deposit_amount > 0) {\n      return contract.custom_deposit_amount;\n    }\n    \n    const optionsTotal = (contract.selected_options || [])\n      .filter(option => option.selected)\n      .reduce((sum, option) => sum + option.price, 0);\n    \n    const isCompany = !!(contract.client_info?.company && contract.client_info.company.trim().length > 0);\n    const ratio = isCompany ? 0.3 : 0.5;\n    const deposit = (contract.base_price * ratio) + optionsTotal - (contract.discount_amount || 0);\n    \n    if (isContractDirigeant(contract)) {\n      return Math.max(0, deposit);\n    }\n    return Math.max(0, Math.round(deposit / 50) * 50);\n  };\n\n  return (\n    <div className=\"min-h-screen bg-white p-8\">\n      <div className=\"max-w-4xl mx-auto\">\n        {/* Header */}\n        <div className=\"border-b-2 border-orange-600 pb-6 mb-8\">\n          <div className=\"flex justify-between items-start\">\n            <div>\n              <h1 className=\"text-3xl font-bold text-orange-600 mb-2\">R'KEY PROD</h1>\n              <p className=\"text-sm font-semibold\">ANIMATION DJ - LOCATION SON & LUMIÈRE - SHOW</p>\n              <div className=\"text-xs mt-2\">\n                5 rue du Hohlandsbourg<br />\n                67390 Marckolsheim<br />\n                📞 07 83 55 36 74<br />\n                ✉ info@rkey-prod.fr<br />\n                SIRET: 99992355000019\n              </div>\n            </div>\n            <div className=\"text-right text-sm\">\n              <strong>Date:</strong> {new Date().toLocaleDateString('fr-FR')}<br />\n              <strong>N° Contrat:</strong> {contract.invoice_number || 'CTR-' + new Date().getFullYear() + '-' + String(Date.now()).slice(-3)}<br /><br />\n              <div className=\"text-xs\">\n                <strong>Prestataire:</strong><br />\n                {contract.dj_profile === 'stephane' ? 'Stéphane JACOBY (Stefan Edison)' : 'Joël RUTTKAY (Joël R\\'Key)'}<br />\n                📞 07 83 55 36 74<br />\n                ✉ {contract.dj_profile === 'stephane' ? 'stephane@rkey-prod.fr' : 'info@rkey-prod.fr'}<br />\n                {contract.dj_profile === 'stephane' ? 'SIRET: 42121827200019' : ''}\n              </div>\n            </div>\n          </div>\n        </div>\n\n        {/* Title */}\n        <h2 className=\"text-2xl font-bold text-center mb-8\">CONTRAT DE PRESTATION ARTISTIQUE</h2>\n\n        {/* Client Info */}\n        <div className=\"grid grid-cols-2 gap-6 mb-8\">\n          <div>\n            <h3 className=\"text-lg font-bold mb-4 bg-gray-100 p-3 border-l-4 border-orange-600\">INFORMATIONS CLIENT</h3>\n            <p className=\"mb-2\"><span className=\"font-semibold\">Nom:</span> {contract.client_info.name}</p>\n            {contract.client_info.company && <p className=\"mb-2\"><span className=\"font-semibold\">Entreprise:</span> {contract.client_info.company}</p>}\n            <p className=\"mb-2\"><span className=\"font-semibold\">Email:</span> {contract.client_info.email}</p>\n            <p className=\"mb-2\"><span className=\"font-semibold\">Téléphone:</span> {contract.client_info.phone || 'Non renseigné'}</p>\n            {contract.client_info.address && <p className=\"mb-2\"><span className=\"font-semibold\">Adresse:</span> {contract.client_info.address}</p>}\n          </div>\n          <div>\n            <h3 className=\"text-lg font-bold mb-4 bg-gray-100 p-3 border-l-4 border-orange-600\">DÉTAILS ÉVÉNEMENT</h3>\n            <p className=\"mb-2\"><span className=\"font-semibold\">Type:</span> {contract.client_info.event_type}</p>\n            <p className=\"mb-2\"><span className=\"font-semibold\">Date:</span> {new Date(contract.client_info.event_date).toLocaleDateString('fr-FR')}</p>\n            <p className=\"mb-2\"><span className=\"font-semibold\">Lieu:</span> {contract.client_info.event_location}</p>\n            {contract.client_info.guest_count && <p className=\"mb-2\"><span className=\"font-semibold\">Invités:</span> {contract.client_info.guest_count}</p>}\n            <p className=\"mb-2\"><span className=\"font-semibold\">Début:</span> {contract.client_info.start_time || 'À définir'}</p>\n            <p className=\"mb-2\"><span className=\"font-semibold\">Fin:</span> {contract.client_info.unlimited_time ? 'Sans limite' : (contract.client_info.end_time || 'À définir')}</p>\n          </div>\n        </div>\n\n        {/* Pricing Table */}\n        {contract.selected_options && contract.selected_options.filter(opt => opt.selected).length > 0 && (\n          <div className=\"mb-8\">\n            <h3 className=\"text-lg font-bold mb-4 bg-gray-100 p-3 border-l-4 border-orange-600\">GRILLE TARIFAIRE</h3>\n            <table className=\"w-full border-collapse border border-gray-300\">\n              <thead className=\"bg-gray-100\">\n                <tr>\n                  <th className=\"border border-gray-300 p-2 text-left\">Prestation</th>\n                  <th className=\"border border-gray-300 p-2 text-right\">Prix</th>\n                </tr>\n              </thead>\n              <tbody>\n                <tr>\n                  <td className=\"border border-gray-300 p-2\"><strong>Prestation artistique</strong></td>\n                  <td className=\"border border-gray-300 p-2 text-right font-bold\">{contract.base_price}€</td>\n                </tr>\n                {contract.selected_options.filter(opt => opt.selected).map((option, idx) => (\n                  <tr key={idx}>\n                    <td className=\"border border-gray-300 p-2\">+ {option.name}</td>\n                    <td className=\"border border-gray-300 p-2 text-right font-bold\">{option.price}€</td>\n                  </tr>\n                ))}\n                {contract.discount_amount > 0 && (\n                  <tr>\n                    <td className=\"border border-gray-300 p-2\">- Remise accordée sur acompte</td>\n                    <td className=\"border border-gray-300 p-2 text-right text-red-600 font-bold\">-{contract.discount_amount}€</td>\n                  </tr>\n                )}\n                <tr className=\"bg-gray-50\">\n                  <td className=\"border border-gray-300 p-2\"><strong>TOTAL</strong></td>\n                  <td className=\"border border-gray-300 p-2 text-right\"><strong>{calculateContractTotal()}€</strong><br /><small className=\"text-xs\">TVA non applicable, article 293 B du CGI</small></td>\n                </tr>\n              </tbody>\n            </table>\n          </div>\n        )}\n\n        {/* Payment Conditions */}\n        <div className=\"mb-8\">\n          <h3 className=\"text-lg font-bold mb-4 bg-gray-100 p-3 border-l-4 border-orange-600\">CONDITIONS DE PAIEMENT</h3>\n          <div className=\"p-4 bg-gray-50 rounded\">\n            {contract.no_deposit_required ? (\n              <div className=\"text-center\">\n                <strong>🤝 CLIENT DE CONFIANCE - AUCUN ACOMPTE REQUIS</strong><br />\n                <span className=\"text-2xl font-bold\">{calculateContractTotal()}€</span><br />\n                <small>Montant total à régler le jour de l'événement</small>\n              </div>\n            ) : (\n              (() => {\n                const isCompany = !!(contract.client_info?.company && contract.client_info.company.trim().length > 0);\n                return (\n                  <div className={isCompany ? \"flex justify-center\" : \"grid grid-cols-2 gap-4\"}>\n                    <div className=\"text-center\">\n                      <strong>Acompte à la signature</strong><br />\n                      <span className=\"text-2xl font-bold text-blue-600\">{calculateContractDepositAmount()}€</span>\n                    </div>\n                    {!isCompany && (\n                      <div className=\"text-center\">\n                        <strong>Solde le jour J</strong><br />\n                        <span className=\"text-2xl font-bold text-green-600\">{calculateContractTotal() - calculateContractDepositAmount()}€</span>\n                      </div>\n                    )}\n                  </div>\n                );\n              })()\n            )}\n          </div>\n        </div>\n\n        {/* Footer */}\n        <div className=\"text-center mt-12 pt-6 border-t border-gray-300\">\n          <p className=\"font-bold\">R'KEY PROD</p>\n          <p className=\"text-sm\">5 rue du Hohlandsbourg, 67390 Marckolsheim</p>\n          <p className=\"text-sm\">📞 07 83 55 36 74 - ✉ info@rkey-prod.fr</p>\n        </div>\n      </div>\n    </div>\n  );\n};\n\nexport default ContractHtmlPreview;\n","import React, { useState, useEffect, useMemo } from \"react\";\nimport { useNavigate } from \"react-router-dom\";\nimport axios from \"../services/axiosConfig\";\nimport { Button } from \"./ui/button\";\nimport { Input } from \"./ui/input\";\nimport { Label } from \"./ui/label\";\nimport { Card, CardContent, CardDescription, CardHeader, CardTitle } from \"./ui/card\";\nimport { Badge } from \"./ui/badge\";\nimport { Textarea } from \"./ui/textarea\";\nimport { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from \"./ui/select\";\nimport { Checkbox } from \"./ui/checkbox\";\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from \"./ui/tabs\";\nimport { Separator } from \"./ui/separator\";\nimport { X, Search, Users, FileSignature, FileText, Euro, Calendar, MapPin, User, Phone, Mail, Building, Download, Printer, Edit, Trash2, Plus, FileCheck, Archive, RotateCcw, Send, Settings, Save, XCircle, Copy, ArrowLeft, Utensils, Coffee, Soup, Minus, Paperclip, Upload, Loader2, Eye, AlertCircle } from \"lucide-react\";\nimport { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from \"./ui/dialog\";\nimport { toast } from \"sonner\";\nimport apiService from \"../services/api\";\nimport FormSubmissionsSelector from \"./FormSubmissionsSelector\";\n\n// Modules extraits pour la maintenabilité\nimport { fallbackPredefinedNotes, musicStyles, eventCategories, defaultHypnosisProgram, defaultCompanySettings } from \"./contracts2/constants\";\nimport { generateContractHTML } from \"./contracts2/htmlGenerator\";\nimport { generatePDFFromHTML as generatePDFFromHTMLImported, printContractWithSignature, generateContractAndGuide, getCompiledGuideBlob, previewContractPdf, getFormattedEventDate } from \"./contracts2/pdfGenerator\";\nimport { ConfigurationPage } from \"./contracts2/ConfigurationPage\";\nimport { ContractPreview } from \"./contracts2/ContractPreview\";\nimport { ContractHistory } from \"./contracts2/ContractHistory\";\nimport { SignaturePadModal } from \"./contracts2/SignaturePadModal\";\nimport ErrorBoundary from \"./ErrorBoundary\";\nimport { generateMandatHTML, generateArtisteHTML, generateEntrepriseHTML } from \"./contracts2/mandatHtmlGenerator\";\nimport { \n  calculateDepositAmount as calculateDepositAmountImported, \n  calculateRemainingBalance as calculateRemainingBalanceImported, \n  calculateCompanyMargeHT, \n  isArtistFreelance,\n  isContractDirigeant \n} from \"./contracts2/calculations\";\n\nimport API_BASE_URL from '../utils/apiUrl';\nconst BACKEND_URL = API_BASE_URL;\nconst API = `${BACKEND_URL}/api`;\n\nconst defaultArtistCgv = `Article 1 - Objet\nLe présent contrat définit les conditions d'engagement de l'Artiste DJ pour la prestation artistique musicale décrite ci-dessus.\n\nArticle 2 - Obligations de l'Artiste\nL'Artiste s'engage à assurer la prestation d'animation musicale incluant l'infrastructure technique (son et lumière festif) et la performance musicale, pour la durée et aux conditions décrites dans le présent contrat.\n\nArticle 3 - Obligations du Client\nLe Client s'engage à mettre à disposition les installations électriques nécessaires, à faciliter l'accès au lieu de prestation et à régler le montant convenu selon les modalités définies.\n\nArticle 4 - Annulation\nEn cas d'annulation par le client moins de 30 jours avant l'événement, le montant total reste dû à l'Artiste.\n\nArticle 5 - Clause de sous-traitance\nLe présent contrat lie le Client directement à l'Artiste DJ pour la prestation musicale. R'KEY PROD n'intervient qu'en tant que mandataire pour la recherche de l'artiste et ne saurait être tenu responsable de l'exécution de la prestation artistique.`;\n\nconst getCompanyProvenance = (company) => {\n  if (company.provenance) return company.provenance;\n  if (company.notes) {\n    if (company.notes.includes(\"Importé depuis l'application Matériel\") || company.notes.toLowerCase().includes(\"location: \")) {\n      return \"location\";\n    }\n    if (company.notes.includes(\"Importé depuis le contrat\")) {\n      return \"contrat\";\n    }\n  }\n  return \"\";\n};\n\nfunction Contracts2App() {\n  const navigate = useNavigate();\n  \n  const [error, setError] = useState(null);\n  \n  useEffect(() => {\n    const currentPath = window.location.pathname;\n    if (currentPath && !currentPath.includes('/contracts2')) {\n      console.warn('Unexpected path change detected:', currentPath);\n    }\n    const handlePopState = (event) => { console.log('PopState event:', event); };\n    window.addEventListener('popstate', handlePopState);\n    return () => window.removeEventListener('popstate', handlePopState);\n  }, []);\n  \n  const safeSetState = (setter, value) => {\n    try { setter(value); } catch (err) {\n      console.error('State update error:', err);\n      setError(err);\n      toast.error('Erreur dans l\\'application - rafraîchir si nécessaire');\n    }\n  };\n\n  if (error) {\n    return (\n      <div className=\"min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 flex items-center justify-center\">\n        <Card className=\"max-w-md mx-auto\">\n          <CardHeader><CardTitle className=\"text-red-600\">Erreur de l'application</CardTitle></CardHeader>\n          <CardContent>\n            <p className=\"text-gray-600 mb-4\">Une erreur s'est produite. Essayez de rafraîchir la page.</p>\n            <Button onClick={() => { setError(null); window.location.reload(); }} className=\"w-full\">Rafraîchir la page</Button>\n          </CardContent>\n        </Card>\n      </div>\n    );\n  }\n\n  // ═══════════════════════════════════════════════════\n  // STATE DECLARATIONS\n  // ═══════════════════════════════════════════════════\n\n  const [clientInfo, setClientInfo] = useState({\n    name: \"\", company: \"\", address: \"\", phone: \"\", phone2: \"\", email: \"\",\n    event_date: \"\", event_location: \"\", event_type: \"\", custom_event_type: \"\",\n    event_note: \"\", setup_date: \"\", setup_time: \"À définir\", start_time: \"\",\n    end_time: \"\", unlimited_time: false, guest_count: \"\", venue_id: \"\",\n    additional_events: []\n  });\n\n  const [venues, setVenues] = useState([]);\n  const [venueSearch, setVenueSearch] = useState(\"\");\n  const [isNewVenueDialogOpen, setIsNewVenueDialogOpen] = useState(false);\n  const [newVenueForm, setNewVenueForm] = useState({ name: \"\", department: \"\", city: \"\" });\n  const [isVenueDropdownOpen, setIsVenueDropdownOpen] = useState(false);\n\n  const [availableOptions, setAvailableOptions] = useState([]);\n  const [selectedOptions, setSelectedOptions] = useState([]);\n  const [cgvTemplates, setCgvTemplates] = useState({});\n  const [selectedCgvTemplate, setSelectedCgvTemplate] = useState(\"\");\n  const [cgvText, setCgvText] = useState(\"\");\n  const [artisteCgvText, setArtisteCgvText] = useState(defaultArtistCgv);\n  const [invoiceNumber, setInvoiceNumber] = useState(\"\");\n  const [artisteInvoiceNumber, setArtisteInvoiceNumber] = useState(\"\");\n  const [nextNumbers, setNextNumbers] = useState({ next_mandat_number: \"\", next_artiste_number: \"\" });\n  const [discountAmount, setDiscountAmount] = useState(0);\n  const [djProfiles, setDjProfiles] = useState({});\n  const [selectedDjProfile, setSelectedDjProfile] = useState(\"\");\n\n  // Artist notification email modal states\n  const [isArtistNotifOpen, setIsArtistNotifOpen] = useState(false);\n  const [notifContract, setNotifContract] = useState(null);\n  const [notifArtistProfile, setNotifArtistProfile] = useState(null);\n  const [notifTemplates, setNotifTemplates] = useState([]);\n  const [notifSelectedTemplateId, setNotifSelectedTemplateId] = useState(\"\");\n  const [notifEmailSubject, setNotifEmailSubject] = useState(\"\");\n  const [notifEmailBody, setNotifEmailBody] = useState(\"\");\n  const [notifRecipientEmail, setNotifRecipientEmail] = useState(\"\");\n  const [notifIsSending, setNotifIsSending] = useState(false);\n\n  const [basePrice, setBasePrice] = useState(0);\n  // ── CONTRATS 2: Mode Mandat/Agence ──\n  const [contractMode, setContractMode] = useState('entreprise'); // 'entreprise' ou 'mandataire' par défaut\n  const [cgvTitle, setCgvTitle] = useState(\"Conditions Générales de Vente\");\n  const [artisteCgvTitle, setArtisteCgvTitle] = useState(\"Conditions Générales de l'Artiste\");\n  const [fraisMandat, setFraisMandat] = useState(0);\n  const [cachetArtiste, setCachetArtiste] = useState(0);\n  const [freelanceCachetCap, setFreelanceCachetCap] = useState(800);\n  const [packSonorisation, setPackSonorisation] = useState(false);\n  const [packLumiere, setPackLumiere] = useState(false);\n  const [optionsTarifNotes, setOptionsTarifNotes] = useState(\"\");\n  const [contracts, setContracts] = useState([]);\n  const [importDocCategory, setImportDocCategory] = useState(\"Contrat Signé / Complémentaire\");\n  const [inlineUploadCategory, setInlineUploadCategory] = useState(\"Contrat Initial\");\n  const [historyUploadCategory, setHistoryUploadCategory] = useState(\"Contrat Initial\");\n  \n  // ── SCRIPT D'IMPORTATION DE VIEUX CONTRATS ──\n  const [isImportModalOpen, setIsImportModalOpen] = useState(false);\n  const [isImporting, setIsImporting] = useState(false);\n  const [importedFile, setImportedFile] = useState(null);\n  const [importReport, setImportReport] = useState(null);\n  const [importError, setImportError] = useState(null);\n  const [importTargetContractId, setImportTargetContractId] = useState(\"\");\n  const [importMatchedContract, setImportMatchedContract] = useState(null);\n  const [activeTab, setActiveTab] = useState(\"history\");\n  const [generatedContract, setGeneratedContract] = useState(null);\n  const [editingContract, setEditingContract] = useState(null);\n  const [showConfiguration, setShowConfiguration] = useState(false);\n  const [selectedNotes, setSelectedNotes] = useState([]);\n  const [selectedMusicStyles, setSelectedMusicStyles] = useState([]);\n  const [djNotes, setDjNotes] = useState(\"\");\n  const [blacklist, setBlacklist] = useState(\"\");\n  const [cateringNotes, setCateringNotes] = useState(\"\");\n  const [cateringDrinks, setCateringDrinks] = useState(false);\n  const [cateringHotMealNoTable, setCateringHotMealNoTable] = useState(false);\n  const [cateringHotMealNoTableQty, setCateringHotMealNoTableQty] = useState(0);\n  const [selectedEvents, setSelectedEvents] = useState([]);\n  const [customRepasEvents, setCustomRepasEvents] = useState([]);\n  const [customMusiqueEvents, setCustomMusiqueEvents] = useState([]);\n  const [newRepasEvent, setNewRepasEvent] = useState(\"\");\n  const [newMusiqueEvent, setNewMusiqueEvent] = useState(\"\");\n  const [newAnimationEvent, setNewAnimationEvent] = useState(\"\");\n  const [customAnimationEvents, setCustomAnimationEvents] = useState([]);\n  const [eventNotes, setEventNotes] = useState(\"\");\n  const [eventOrder, setEventOrder] = useState([]);\n  \n  const [hypnosisProgram, setHypnosisProgram] = useState(defaultHypnosisProgram);\n  const [customDepositAmount, setCustomDepositAmount] = useState(0);\n  const [noDepositRequired, setNoDepositRequired] = useState(false);\n  const [selectedRIB, setSelectedRIB] = useState(\"\");\n  const [depositPaid, setDepositPaid] = useState(false);\n  const [depositPaymentMethod, setDepositPaymentMethod] = useState(\"\");\n  const [depositPaidDate, setDepositPaidDate] = useState(\"\");\n  const [backgroundMusicAperitif, setBackgroundMusicAperitif] = useState(\"\");\n\n  const [companySettings, setCompanySettings] = useState(defaultCompanySettings);\n  \n  const [hasLimiteurSon, setHasLimiteurSon] = useState(false);\n  const [hasDetecteurFumee, setHasDetecteurFumee] = useState(false);\n  const [hasNoLimiteurNiDetecteur, setHasNoLimiteurNiDetecteur] = useState(false);\n  const [hasWifi, setHasWifi] = useState(false);\n  const [has4g5g, setHas4g5g] = useState(false);\n  \n  const [technicianContact, setTechnicianContact] = useState({ name: \"\", email: \"\", phone: \"\" });\n\n  const [deletedContracts, setDeletedContracts] = useState([]);\n  const [archivedContracts, setArchivedContracts] = useState([]);\n  const [showTrash, setShowTrash] = useState(false);\n  const [showArchive, setShowArchive] = useState(false);\n  const [previewDoc, setPreviewDoc] = useState(null);\n\n  const [showSignaturePad, setShowSignaturePad] = useState(false);\n  const [clientSignature, setClientSignature] = useState(null);\n  const [signaturePadRef, setSignaturePadRef] = useState(null);\n  const [signatureImages, setSignatureImages] = useState({});\n\n  const [predefinedNotes, setPredefinedNotes] = useState(fallbackPredefinedNotes);\n  const [pdfNotes, setPdfNotes] = useState([]);\n  const [selectedPdfNotes, setSelectedPdfNotes] = useState([]);\n\n  const [selectedSubmission, setSelectedSubmission] = useState(null);\n\n  const [showAttachmentsDialog, setShowAttachmentsDialog] = useState(false);\n  const [selectedContractForAttachments, setSelectedContractForAttachments] = useState(null);\n  const [uploadingAttachment, setUploadingAttachment] = useState(false);\n  const [previewPdfUrl, setPreviewPdfUrl] = useState(null);\n  const [previewPdfFilename, setPreviewPdfFilename] = useState(\"\");\n\n  const [crmCompanies, setCrmCompanies] = useState([]);\n  const [searchCrmQuery, setSearchCrmQuery] = useState(\"\");\n  const [showCrmDropdown, setShowCrmDropdown] = useState(false);\n\n  // Handle submission import → auto-fill client fields\n  const handleSubmissionSelect = (fields) => {\n    const updates = {};\n    if (fields.nom) updates.name = fields.nom;\n    if (fields.email) updates.email = fields.email;\n    if (fields.telephone) updates.phone = fields.telephone;\n    if (fields.entreprise) updates.company = fields.entreprise;\n    if (fields.date_evenement) {\n      const raw = fields.date_evenement;\n      // Try to parse to YYYY-MM-DD for the date input\n      let iso = null;\n      if (/^\\d{4}-\\d{2}-\\d{2}$/.test(raw)) { iso = raw; }\n      else {\n        const m = raw.match(/^(\\d{1,2})[/\\-.](\\d{1,2})[/\\-.](\\d{4})$/);\n        if (m) iso = `${m[3]}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`;\n        else { const d = new Date(raw); if (!isNaN(d.getTime())) iso = d.toISOString().split('T')[0]; }\n      }\n      if (iso) updates.event_date = iso;\n    }\n    if (fields.type_evenement) updates.event_type = fields.type_evenement;\n    setClientInfo(prev => ({ ...prev, ...updates }));\n    setSelectedSubmission(fields);\n  };\n\n  const handleClearSubmission = () => { setSelectedSubmission(null); };\n\n  // Format date JJ-MM-AAAA for display\n  const formatDateDisplay = (dateStr) => {\n    if (!dateStr) return '';\n    const iso = /^\\d{4}-\\d{2}-\\d{2}$/.test(dateStr) ? dateStr : null;\n    if (iso) { const [y, m, d] = iso.split('-'); return `${d}-${m}-${y}`; }\n    const m = dateStr.match(/^(\\d{1,2})[/\\-.](\\d{1,2})[/\\-.](\\d{4})$/);\n    if (m) return `${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}-${m[3]}`;\n    return dateStr;\n  };\n\n  // ═══════════════════════════════════════════════════\n  // HELPER FUNCTIONS\n  // ═══════════════════════════════════════════════════\n\n  const getProfileData = (profileKey) => {\n    const p = djProfiles[profileKey];\n    if (p) return p;\n    if (profileKey === 'joel') return { name: \"Joël RUTTKAY (Joël R'Key)\", nom_complet: \"Joël RUTTKAY\", nom_artistique: \"Joël R'Key\", email: \"info@rkey-prod.fr\", phone: \"07 83 55 36 74\", address: \"5 rue du Hohlandsbourg, 67390 Marckolsheim\", siret: \"99992355000019\", titre: \"Gérant de R'KEY PROD\", statut_artiste: \"dirigeant\", iban: \"\", bic: \"\" };\n    if (profileKey === 'stephane') return { name: \"Stéphane JACOBY (Stefan Edison)\", nom_complet: \"Stéphane JACOBY\", nom_artistique: \"Stefan Edison\", email: \"stephane@rkey-prod.fr\", phone: \"06 31 21 61 14\", address: \"5 rue du Hohlandsbourg, 67390 Marckolsheim\", siret: \"42121827200019\", titre: \"Animateur DJ\", statut_artiste: \"freelance\", iban: \"FR76 4061 8804 8700 0401 4272 395\", bic: \"\" };\n    return { name: \"\", nom_complet: \"\", nom_artistique: \"\", email: \"\", phone: \"\", address: \"\", siret: \"\", titre: \"Animateur DJ\", statut_artiste: \"dirigeant\", iban: \"\", bic: \"\" };\n  };\n\n  const resolveProfile = (contract) => {\n    const snapshot = contract.dj_profile_data && contract.dj_profile_data.name\n      ? contract.dj_profile_data\n      : getProfileData(contract.dj_profile);\n    const current = getProfileData(contract.dj_profile);\n    const merged = { ...current, ...snapshot, bic: snapshot.bic || current.bic || \"\" };\n\n    // Standardize \"fondateur\" or empty titles to \"Dirigeant\" / \"dirigeant\"\n    if (merged.titre && typeof merged.titre === 'string') {\n      if (merged.titre.toLowerCase().includes('fondateur')) {\n        merged.titre = merged.titre.replace(/fondateur/g, \"dirigeant\").replace(/Fondateur/g, \"Dirigeant\");\n      }\n    }\n    const isJoel = (merged.name || \"\").toLowerCase().includes(\"joël\") || (merged.name || \"\").toLowerCase().includes(\"joel\");\n    if (isJoel && (!merged.titre || merged.titre.toLowerCase() === 'animateur dj')) {\n      merged.titre = \"Dirigeant\";\n    }\n    return merged;\n  };\n\n  // Wrapper : appelle le HTML generator importé avec le contexte local\n  const generateContractHTMLLocal = (contract, clientSig = null, sigs = null, options = {}) => {\n    return generateContractHTML(contract, clientSig, sigs || signatureImages, companySettings, predefinedNotes, resolveProfile, options);\n  };\n\n  const animationEvents = useMemo(() => {\n    const baseAnimations = [...eventCategories.animations];\n    const profile = getProfileData(selectedDjProfile);\n    if (profile.nom_artistique?.toLowerCase().includes(\"r'key\") || profile.nom_artistique?.toLowerCase().includes(\"rkey\") || profile.titre?.includes(\"Gérant\")) {\n      baseAnimations.push(\"Show hypnose\");\n    }\n    return baseAnimations;\n  }, [selectedDjProfile, djProfiles]);\n\n  const eventTypesList = useMemo(() => {\n    const baseTypes = [\"Mariage\", \"Anniversaire\", \"Comité d'entreprise\", \"Soirée privée\", \"Événement professionnel\"];\n    const profile = getProfileData(selectedDjProfile);\n    if (profile.nom_artistique?.toLowerCase().includes(\"r'key\") || profile.nom_artistique?.toLowerCase().includes(\"rkey\") || profile.titre?.includes(\"Gérant\")) {\n      baseTypes.push(\"Show Hypnose\");\n      baseTypes.push(\"Intervention hypnose\");\n    }\n    return baseTypes;\n  }, [selectedDjProfile, djProfiles]);\n\n  const getNoteContent = (noteKey) => {\n    return predefinedNotes[noteKey] || { title: '', content: '' };\n  };\n\n  // ═══════════════════════════════════════════════════\n  // DATA LOADING\n  // ═══════════════════════════════════════════════════\n\n  useEffect(() => {\n    const loadSignatures = async () => {\n      try {\n        const signatures = await loadSignatureImages();\n        setSignatureImages(signatures);\n      } catch (error) { console.warn('Erreur lors du chargement des signatures:', error); }\n    };\n    loadSignatures();\n  }, []);\n\n  useEffect(() => {\n    loadOptions();\n    loadTechnicalNotes();\n    loadPdfNotes();\n    loadCgvTemplates();\n    loadDjProfiles();\n    loadContracts();\n    loadDeletedContracts();\n    loadArchivedContracts();\n    loadCompanySettings();\n    loadCrmCompanies();\n    fetchNextNumbers();\n    loadVenues();\n  }, []);\n\n  useEffect(() => {\n    const handleClickOutside = (e) => {\n      if (!e.target.closest('#crm-search-container')) {\n        setShowCrmDropdown(false);\n      }\n      if (!e.target.closest('#venue-select-container')) {\n        setIsVenueDropdownOpen(false);\n      }\n    };\n    document.addEventListener('mousedown', handleClickOutside);\n    return () => document.removeEventListener('mousedown', handleClickOutside);\n  }, []);\n\n  const loadCrmCompanies = async () => {\n    try {\n      const response = await axios.get(`${API}/crm/companies`);\n      setCrmCompanies(response.data || []);\n    } catch (error) {\n      console.error(\"Error loading CRM companies:\", error);\n    }\n  };\n\n  const handleSelectCrmCompany = (company) => {\n    let name = company.nom || \"\";\n    let compName = \"\";\n    \n    if (company.type_client !== \"Particulier\") {\n      compName = company.nom || \"\";\n      if (company.contacts && company.contacts.length > 0) {\n        name = company.contacts[0].nom || company.nom;\n      }\n    }\n    \n    setClientInfo(prev => ({\n      ...prev,\n      name: name,\n      company: compName,\n      email: company.email || (company.contacts && company.contacts[0]?.email) || \"\",\n      phone: company.telephone || (company.contacts && company.contacts[0]?.telephone) || \"\",\n      address: company.adresse || \"\"\n    }));\n    \n    setSearchCrmQuery(\"\");\n    setShowCrmDropdown(false);\n    toast.success(`Informations de ${company.nom} appliquées !`);\n  };\n\n  const filteredCrmCompanies = useMemo(() => {\n    if (!searchCrmQuery.trim()) return [];\n    const q = searchCrmQuery.toLowerCase();\n    return crmCompanies.filter(c => \n      (c.nom && c.nom.toLowerCase().includes(q)) || \n      (c.email && c.email.toLowerCase().includes(q)) ||\n      (c.telephone && c.telephone.includes(q)) ||\n      (c.secteur && c.secteur.toLowerCase().includes(q)) ||\n      (c.contacts && c.contacts.some(contact => contact.nom && contact.nom.toLowerCase().includes(q)))\n    );\n  }, [crmCompanies, searchCrmQuery]);\n\n  const loadVenues = async () => {\n    try {\n      const response = await axios.get(`${API}/venues`);\n      setVenues(response.data);\n    } catch (error) {\n      console.error('Erreur de chargement des lieux de réception:', error);\n    }\n  };\n\n  const handleQuickCreateVenue = async () => {\n    if (!newVenueForm.name || !newVenueForm.department || !newVenueForm.city) {\n      toast.error(\"Veuillez remplir tous les champs obligatoires.\");\n      return;\n    }\n    try {\n      const response = await axios.post(`${API}/venues`, {\n        ...newVenueForm,\n        is_complete: false\n      });\n      const createdVenue = response.data;\n      toast.success(\"Lieu de réception créé !\");\n      \n      setVenues(prev => [...prev, createdVenue]);\n      \n      handleClientInfoChange(\"event_location\", `${createdVenue.department} / ${createdVenue.city} / ${createdVenue.name}`);\n      setClientInfo(prev => ({\n        ...prev,\n        venue_id: createdVenue.id\n      }));\n      \n      setIsNewVenueDialogOpen(false);\n      setNewVenueForm({ name: \"\", department: \"\", city: \"\" });\n      setIsVenueDropdownOpen(false);\n    } catch (err) {\n      console.error(\"Error quick creating venue:\", err);\n      toast.error(\"Erreur lors de la création.\");\n    }\n  };\n\n  const loadOptions = async () => {\n    try {\n      const persistentOptions = await apiService.getMaterialOptions();\n      if (persistentOptions && persistentOptions.length > 0) {\n        const options = persistentOptions.map((opt) => ({ ...opt, selected: false }));\n        setAvailableOptions(options);\n        setSelectedOptions(options);\n      } else {\n        const response = await axios.get(`${API}/contract-options`);\n        const options = response.data.options.map((opt, index) => ({\n          ...opt, id: `option-${index}-${opt.name.replace(/\\s+/g, '-').toLowerCase()}`, selected: false\n        }));\n        setAvailableOptions(options);\n        setSelectedOptions(options);\n      }\n    } catch (error) {\n      toast.error(\"Erreur lors du chargement des options\");\n      console.error(\"Error loading options:\", error);\n    }\n  };\n\n  const loadTechnicalNotes = async () => {\n    try {\n      const notes = await apiService.getTechnicalNotes();\n      if (notes && notes.length > 0) {\n        const notesObj = {};\n        notes.forEach(note => { notesObj[note.key] = { title: note.title, content: note.content }; });\n        setPredefinedNotes(notesObj);\n      }\n    } catch (error) { console.error(\"Error loading technical notes:\", error); }\n  };\n\n  const fetchNextNumbers = async () => {\n    try {\n      const response = await axios.get(`${API}/contracts2/counters`);\n      setNextNumbers(response.data);\n    } catch (e) {\n      console.warn(\"Error loading counters:\", e);\n    }\n  };\n\n  const handleGenerateNumbers = async (type) => {\n    try {\n      const response = await axios.post(`${API}/contracts2/counters/increment`, { type });\n      const { mandat_number, artiste_number } = response.data;\n      \n      if (type === 'mandat') {\n        setInvoiceNumber(mandat_number);\n        toast.success(`Numéro de mandat généré : ${mandat_number}`);\n      } else if (type === 'artiste') {\n        setArtisteInvoiceNumber(artiste_number);\n        toast.success(`Numéro d'engagement d'artiste généré : ${artiste_number}`);\n      } else if (type === 'both') {\n        setInvoiceNumber(mandat_number);\n        setArtisteInvoiceNumber(artiste_number);\n        toast.success(`Numéros générés : Mandat ${mandat_number} & Artiste ${artiste_number}`);\n      }\n      \n      fetchNextNumbers();\n    } catch (error) {\n      console.error(\"Erreur génération numéros de contrat:\", error);\n      toast.error(\"Erreur lors de la génération des numéros séquentiels\");\n    }\n  };\n\n  const loadPdfNotes = async () => {\n    try {\n      const notes = await apiService.getContractPdfNotes();\n      setPdfNotes(notes || []);\n    } catch (error) { console.error(\"Error loading PDF notes:\", error); }\n  };\n\n  const loadCgvTemplates = async () => {\n    try {\n      const response = await apiService.getCgvTemplates();\n      setCgvTemplates(response.templates || {});\n    } catch (error) {\n      toast.error(\"Erreur lors du chargement des modèles CGV\");\n      console.error(\"Error loading CGV templates:\", error);\n    }\n  };\n\n  const loadDjProfiles = async () => {\n    try {\n      const response = await axios.get(`${API}/dj-profiles`);\n      const profiles = response.data.profiles;\n      setDjProfiles(profiles);\n      if (!selectedDjProfile && Object.keys(profiles).length > 0) {\n        const dirigeantKey = Object.keys(profiles).find(k => profiles[k].statut_artiste === 'dirigeant');\n        setSelectedDjProfile(dirigeantKey || Object.keys(profiles)[0]);\n      }\n    } catch (error) {\n      toast.error(\"Erreur lors du chargement des profils DJ\");\n      console.error(\"Error loading DJ profiles:\", error);\n    }\n  };\n\n  const loadCompanySettings = async () => {\n    try {\n      const token = localStorage.getItem('access_token');\n      const response = await fetch(`${API}/global-settings`, {\n        headers: { Authorization: `Bearer ${token}` },\n      });\n      if (response.ok) {\n        const data = await response.json();\n        setCompanySettings({\n          company_name: data.company_name || \"R'KEY PROD\",\n          bank_name: data.bank_name || \"Tiime\",\n          bank_iban: data.bank_iban || \"\",\n          bank_bic: data.bank_bic || \"\",\n          bank_titulaire: data.bank_titulaire || \"R'KEY PROD\",\n          artiste_cgv_text: data.artiste_cgv_text || \"\",\n        });\n        if (data.artiste_cgv_text) {\n          setArtisteCgvText(data.artiste_cgv_text);\n        }\n      }\n    } catch (error) { console.error(\"Error loading company settings:\", error); }\n  };\n\n  const loadSignatureImages 