ultKey].content || \"\");\n      }\n    }\n  }, [contractMode, cgvTemplates, editingContract]);\n\n  const loadContracts = async () => {\n    try {\n      const response = await axios.get(`${API}/contracts2`);\n      const activeContracts = response.data.filter(contract => !['deleted', 'archived', 'cancelled'].includes(contract.status));\n      setContracts(activeContracts);\n    } catch (error) { toast.error(\"Erreur lors du chargement des contrats\"); console.error(\"Error loading contracts:\", error); }\n  };\n\n  const loadDeletedContracts = async () => {\n    try { setDeletedContracts((await axios.get(`${API}/contracts2/trash`)).data); }\n    catch (error) { toast.error(\"Erreur lors du chargement de la corbeille\"); console.error(error); }\n  };\n\n  const loadArchivedContracts = async () => {\n    try { setArchivedContracts((await axios.get(`${API}/contracts2/archived`)).data); }\n    catch (error) { toast.error(\"Erreur lors du chargement des archives\"); console.error(error); }\n  };\n\n  const handleManageAttachments = (contract) => {\n    setSelectedContractForAttachments(contract);\n    setShowAttachmentsDialog(true);\n  };\n\n  const handleAttachmentUpload = async (e) => {\n    const files = Array.from(e.target.files);\n    if (files.length === 0) return;\n    \n    const allowedTypes = [\n      \"application/pdf\", \n      \"image/png\", \n      \"image/jpeg\", \n      \"image/jpg\", \n      \"image/heic\", \n      \"image/heif\"\n    ];\n\n    setUploadingAttachment(true);\n    const token = localStorage.getItem('access_token');\n    const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n\n    for (const file of files) {\n      const fileExt = file.name.split('.').pop().toLowerCase();\n      const isHeic = fileExt === 'heic' || fileExt === 'heif';\n      if (!allowedTypes.includes(file.type) && !isHeic) {\n        toast.error(`Format non supporté pour \"${file.name}\". PDF, PNG, JPG ou HEIC uniquement.`);\n        continue;\n      }\n\n      const formData = new FormData();\n      formData.append(\"file\", file);\n      formData.append(\"category\", historyUploadCategory);\n\n      try {\n        const response = await fetch(`${BACKEND_URL}/api/contracts2/${selectedContractForAttachments.id}/documents`, {\n          method: \"POST\",\n          headers,\n          body: formData\n        });\n\n        if (response.ok) {\n          const result = await response.json();\n          if (result.success) {\n            toast.success(`\"${file.name}\" a été ajouté avec succès !`);\n            \n            // local update in state\n            setSelectedContractForAttachments(prev => {\n              const updatedDocs = [...(prev.event_documents || []), result.document];\n              return { ...prev, event_documents: updatedDocs };\n            });\n          } else {\n            toast.error(`Erreur d'envoi pour \"${file.name}\"`);\n          }\n        } else {\n          const errRes = await response.json().catch(() => ({}));\n          toast.error(`Erreur pour \"${file.name}\" : ${errRes.error || 'Statut ' + response.status}`);\n        }\n      } catch (err) {\n        console.error(err);\n        toast.error(`Erreur réseau pour \"${file.name}\"`);\n      }\n    }\n    \n    setUploadingAttachment(false);\n    e.target.value = null; // reset input\n    \n    loadContracts();\n    loadArchivedContracts();\n  };\n\n  const handlePreviewAttachment = async (doc) => {\n    try {\n      const token = localStorage.getItem('access_token');\n      const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n      const response = await fetch(`${BACKEND_URL}/api/contracts2/${selectedContractForAttachments.id}/documents/${doc.id}?preview=true`, { headers });\n      if (!response.ok) throw new Error(\"Impossible de récupérer le document\");\n      const blob = await response.blob();\n      const url = window.URL.createObjectURL(blob);\n      setPreviewPdfUrl(url);\n      setPreviewPdfFilename(doc.filename);\n    } catch (err) {\n      console.error(err);\n      toast.error(\"Erreur lors de l'ouverture du document\");\n    }\n  };\n\n  const handleDeleteAttachment = async (docId) => {\n    if (!window.confirm(\"Voulez-vous vraiment supprimer cette pièce jointe ?\")) return;\n    \n    try {\n      const token = localStorage.getItem('access_token');\n      const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n      const response = await fetch(`${BACKEND_URL}/api/contracts2/${selectedContractForAttachments.id}/documents/${docId}`, {\n        method: \"DELETE\",\n        headers\n      });\n      \n      if (response.ok) {\n        toast.success(\"Pièce jointe supprimée !\");\n        setSelectedContractForAttachments(prev => ({\n          ...prev,\n          event_documents: (prev.event_documents || []).filter(a => a.id !== docId)\n        }));\n        \n        loadContracts();\n        loadArchivedContracts();\n      } else {\n        toast.error(\"Erreur lors de la suppression de la pièce jointe\");\n      }\n    } catch (err) {\n      console.error(err);\n      toast.error(\"Erreur réseau lors de la suppression\");\n    }\n  };\n\n  const handleInlineAttachmentUpload = async (e) => {\n    if (!editingContract) {\n      toast.error(\"Veuillez d'abord sauvegarder le contrat.\");\n      return;\n    }\n    const files = Array.from(e.target.files);\n    if (files.length === 0) return;\n    \n    const allowedTypes = [\n      \"application/pdf\", \n      \"image/png\", \n      \"image/jpeg\", \n      \"image/jpg\", \n      \"image/heic\", \n      \"image/heif\"\n    ];\n\n    setUploadingAttachment(true);\n    const token = localStorage.getItem('access_token');\n    const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n\n    for (const file of files) {\n      const fileExt = file.name.split('.').pop().toLowerCase();\n      const isHeic = fileExt === 'heic' || fileExt === 'heif';\n      if (!allowedTypes.includes(file.type) && !isHeic) {\n        toast.error(`Format non supporté pour \"${file.name}\". PDF, PNG, JPG ou HEIC uniquement.`);\n        continue;\n      }\n\n      const formData = new FormData();\n      formData.append(\"file\", file);\n      formData.append(\"category\", inlineUploadCategory);\n\n      try {\n        const response = await fetch(`${BACKEND_URL}/api/contracts2/${editingContract.id}/documents`, {\n          method: \"POST\",\n          headers,\n          body: formData\n        });\n\n        if (response.ok) {\n          const result = await response.json();\n          if (result.success) {\n            toast.success(`\"${file.name}\" a été ajouté avec succès !`);\n            \n            setEditingContract(prev => {\n              if (!prev) return prev;\n              const updatedDocs = [...(prev.event_documents || []), result.document];\n              return { ...prev, event_documents: updatedDocs };\n            });\n\n            setGeneratedContract(prev => {\n              if (!prev) return prev;\n              const updatedDocs = [...(prev.event_documents || []), result.document];\n              return { ...prev, event_documents: updatedDocs };\n            });\n\n            setContracts(prev => prev.map(c => {\n              if (c.id === editingContract.id) {\n                return { ...c, event_documents: [...(c.event_documents || []), result.document] };\n              }\n              return c;\n            }));\n          } else {\n            toast.error(`Erreur d'envoi pour \"${file.name}\"`);\n          }\n        } else {\n          const errRes = await response.json().catch(() => ({}));\n          toast.error(`Erreur pour \"${file.name}\" : ${errRes.error || 'Statut ' + response.status}`);\n        }\n      } catch (err) {\n        console.error(err);\n        toast.error(`Erreur réseau pour \"${file.name}\"`);\n      }\n    }\n    \n    setUploadingAttachment(false);\n    e.target.value = null; // reset input\n    \n    loadContracts();\n    loadArchivedContracts();\n  };\n\n  const handleInlineDeleteAttachment = async (docId) => {\n    if (!window.confirm(\"Voulez-vous vraiment supprimer cette pièce jointe ?\")) return;\n    \n    try {\n      const token = localStorage.getItem('access_token');\n      const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n      const response = await fetch(`${BACKEND_URL}/api/contracts2/${editingContract.id}/documents/${docId}`, {\n        method: \"DELETE\",\n        headers\n      });\n      \n      if (response.ok) {\n        toast.success(\"Pièce jointe supprimée !\");\n        \n        setEditingContract(prev => {\n          if (!prev) return prev;\n          return {\n            ...prev,\n            event_documents: (prev.event_documents || []).filter(a => a.id !== docId)\n          };\n        });\n\n        setGeneratedContract(prev => {\n          if (!prev) return prev;\n          return {\n            ...prev,\n            event_documents: (prev.event_documents || []).filter(a => a.id !== docId)\n          };\n        });\n\n        setContracts(prev => prev.map(c => {\n          if (c.id === editingContract.id) {\n            return {\n              ...c,\n              event_documents: (c.event_documents || []).filter(a => a.id !== docId)\n            };\n          }\n          return c;\n        }));\n        \n        loadContracts();\n        loadArchivedContracts();\n      } else {\n        toast.error(\"Erreur lors de la suppression de la pièce jointe\");\n      }\n    } catch (err) {\n      console.error(err);\n      toast.error(\"Erreur réseau lors de la suppression\");\n    }\n  };\n\n  const handleInlinePreviewAttachment = async (doc) => {\n    try {\n      const token = localStorage.getItem('access_token');\n      const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n      const response = await fetch(`${BACKEND_URL}/api/contracts2/${editingContract.id}/documents/${doc.id}?preview=true`, { headers });\n      if (!response.ok) throw new Error(\"Impossible de récupérer le document\");\n      const blob = await response.blob();\n      const url = window.URL.createObjectURL(blob);\n      setPreviewPdfUrl(url);\n      setPreviewPdfFilename(doc.filename);\n    } catch (err) {\n      console.error(err);\n      toast.error(\"Erreur lors de l'ouverture du document\");\n    }\n  };\n\n  const markContractAsSent = async (contractId) => {\n    try {\n      const response = await axios.put(`${API}/contracts2/${contractId}/status`, { status: 'sent' });\n      if (response.status === 200) {\n        setContracts(prev => prev.map(contract => contract.id === contractId ? { ...contract, status: 'sent' } : contract));\n        toast.success(\"Contrat marqué comme envoyé !\");\n      }\n    } catch (error) { console.error('Error marking contract as sent:', error); toast.error(\"Erreur lors de la mise à jour du statut\"); }\n  };\n\n  const handleNotifTemplateChange = (templateId, templateList = notifTemplates, contract = notifContract, artist = notifArtistProfile) => {\n    setNotifSelectedTemplateId(templateId);\n    const tpl = templateList.find(t => t.id === templateId);\n    if (tpl && contract && artist) {\n      const clientName = contract.client_info?.name || contract.client_name || \"Client\";\n      const artistName = artist.nom_artistique || artist.nom_complet || \"Artiste\";\n      const eventDate = contract.client_info?.event_date || contract.event_date || \"\";\n      const eventType = contract.client_info?.event_type || contract.event_type || \"\";\n      const eventLocation = contract.client_info?.event_location || contract.event_location || \"\";\n\n      let subject = tpl.subject || \"\";\n      let body = tpl.body || \"\";\n\n      const replacements = {\n        \"{{client_name}}\": clientName,\n        \"{{artist_name}}\": artistName,\n        \"{{event_date}}\": eventDate,\n        \"{{event_type}}\": eventType,\n        \"{{event_location}}\": eventLocation\n      };\n\n      Object.entries(replacements).forEach(([key, val]) => {\n        subject = subject.replaceAll(key, val);\n        body = body.replaceAll(key, val);\n      });\n\n      setNotifEmailSubject(subject);\n      setNotifEmailBody(body);\n    }\n  };\n\n  const openArtistNotificationDialog = async (contract, artistProfile) => {\n    try {\n      setNotifContract(contract);\n      setNotifArtistProfile(artistProfile);\n      setNotifRecipientEmail(artistProfile.email || \"\");\n      \n      const res = await axios.get(`${API}/freelance-email-templates`);\n      const list = res.data.templates || [];\n      setNotifTemplates(list);\n\n      if (list.length > 0) {\n        const defTpl = list.find(t => t.is_default) || list[0];\n        setNotifSelectedTemplateId(defTpl.id);\n        \n        const clientName = contract.client_info?.name || contract.client_name || \"Client\";\n        const artistName = artistProfile.nom_artistique || artistProfile.nom_complet || \"Artiste\";\n        const eventDate = contract.client_info?.event_date || contract.event_date || \"\";\n        const eventType = contract.client_info?.event_type || contract.event_type || \"\";\n        const eventLocation = contract.client_info?.event_location || contract.event_location || \"\";\n\n        let subject = defTpl.subject || \"\";\n        let body = defTpl.body || \"\";\n\n        const replacements = {\n          \"{{client_name}}\": clientName,\n          \"{{artist_name}}\": artistName,\n          \"{{event_date}}\": eventDate,\n          \"{{event_type}}\": eventType,\n          \"{{event_location}}\": eventLocation\n        };\n\n        Object.entries(replacements).forEach(([key, val]) => {\n          subject = subject.replaceAll(key, val);\n          body = body.replaceAll(key, val);\n        });\n\n        setNotifEmailSubject(subject);\n        setNotifEmailBody(body);\n      } else {\n        setNotifSelectedTemplateId(\"\");\n        setNotifEmailSubject(\"Prestation confirmée et signée\");\n        setNotifEmailBody(`Bonjour ${artistProfile.nom_artistique || \"Artiste\"},\\n\\nLe contrat a été signé.`);\n      }\n      \n      setIsArtistNotifOpen(true);\n    } catch (err) {\n      console.error(\"Error preparing artist notification:\", err);\n      toast.error(\"Erreur lors de la préparation de la notification email\");\n    }\n  };\n\n  const sendArtistNotification = async () => {\n    if (!notifRecipientEmail.trim() || !notifEmailSubject.trim() || !notifEmailBody.trim()) {\n      toast.error(\"Veuillez remplir le destinataire, l'objet et le message.\");\n      return;\n    }\n    try {\n      setNotifIsSending(true);\n      await axios.post(`${API}/contract-emails/send`, {\n        recipient_email: notifRecipientEmail.trim(),\n        email_subject: notifEmailSubject.trim(),\n        email_body: notifEmailBody\n      });\n      toast.success(\"Notification par email envoyée à l'artiste avec succès !\");\n      setIsArtistNotifOpen(false);\n      setNotifContract(null);\n      setNotifArtistProfile(null);\n    } catch (err) {\n      console.error(\"Error sending artist notification email:\", err);\n      toast.error(\"Erreur d'envoi. Veuillez vérifier la configuration SMTP et l'adresse email.\");\n    } finally {\n      setNotifIsSending(false);\n    }\n  };\n\n  const markContractAsSigned = async (contractId) => {\n    try { \n      await axios.put(`${API}/contracts2/${contractId}/status`, { status: 'archived' }); \n      toast.success(\"Contrat archivé avec succès !\"); \n      \n      let contractObj = contracts.find(c => c.id === contractId);\n      if (!contractObj) {\n        try {\n          const res = await axios.get(`${API}/contracts2/${contractId}`);\n          contractObj = res.data;\n        } catch (e) {\n          console.error(\"Could not load contract object:\", e);\n        }\n      }\n      \n      loadContracts(); \n      loadArchivedContracts(); \n      \n      if (contractObj) {\n        const pKey = contractObj.dj_profile;\n        if (pKey) {\n          const profile = getProfileData(pKey);\n          const isFreelance = profile && (profile.statut_artiste === 'freelance' || (isArtistFreelance && isArtistFreelance(profile)));\n          if (isFreelance) {\n            setTimeout(() => {\n              openArtistNotificationDialog(contractObj, profile);\n            }, 600);\n          }\n        }\n      }\n    }\n    catch (error) { toast.error(\"Erreur lors de l'archivage du contrat\"); console.error(error); }\n  };\n\n  const moveContractToTrash = async (contractId) => {\n    try { await axios.put(`${API}/contracts2/${contractId}/status`, { status: 'deleted' }); toast.success(\"Contrat déplacé vers la corbeille\"); loadContracts(); loadDeletedContracts(); }\n    catch (error) { toast.error(\"Erreur lors de la suppression du contrat\"); console.error(error); }\n  };\n\n  const restoreContract = async (contractId) => {\n    try { \n      await axios.put(`${API}/contracts2/${contractId}/status`, { status: 'draft' }); \n      toast.success(\"Contrat restauré avec succès !\"); \n      await loadContracts(); \n      await loadDeletedContracts(); \n      setShowTrash(false); \n      setShowArchive(false); \n    }\n    catch (error) { toast.error(\"Erreur lors de la restauration du contrat\"); console.error(error); }\n  };\n\n  const permanentlyDeleteContract = async (contractId) => {\n      try { await axios.delete(`${API}/contracts2/${contractId}/permanent`); toast.success(\"Contrat supprimé définitivement\"); loadDeletedContracts(); }\n      catch (error) { toast.error(\"Erreur lors de la suppression définitive\"); console.error(error); }\n  };\n\n  const deleteArchivedContract = async (contractId) => {\n      try { await axios.put(`${API}/contracts2/${contractId}/status`, { status: 'deleted' }); toast.success(\"Contrat archivé supprimé et déplacé vers la corbeille\"); loadArchivedContracts(); loadDeletedContracts(); }\n      catch (error) { toast.error(\"Erreur lors de la suppression du contrat archivé\"); console.error(error); }\n  };\n\n  const cancelArchivedContract = async (contractId, observation) => {\n      try { await axios.put(`${API}/contracts2/${contractId}/status`, { status: 'cancelled', cancellation_observation: observation }); toast.success(\"Contrat annulé avec succès\"); loadContracts(); loadArchivedContracts(); }\n      catch (error) { toast.error(\"Erreur lors de l'annulation du contrat\"); console.error(error); }\n  };\n\n  const markArchivedAsUnsigned = async (contractId) => {\n      try { \n        const response = await axios.get(`${API}/contracts2/${contractId}`);\n        if (response.data) {\n           const updated = { ...response.data, status: 'draft', signatures: [] };\n           await axios.put(`${API}/contracts2/${contractId}`, updated);\n        } else {\n           await axios.put(`${API}/contracts2/${contractId}/status`, { status: 'draft' }); \n        }\n        toast.success(\"Contrat remis dans les contrats en attente\"); \n        await loadContracts(); \n        await loadArchivedContracts(); \n        setShowArchive(false); \n        setShowTrash(false); \n      }\n      catch (error) { toast.error(\"Erreur lors de la remise en attente du contrat\"); console.error(error); }\n  };\n\n  // ═══════════════════════════════════════════════════\n  // EVENT HANDLERS\n  // ═══════════════════════════════════════════════════\n\n  const handleClientInfoChange = (field, value) => {\n    setClientInfo(prev => {\n      const updated = { ...prev, [field]: value };\n      if (field === 'event_date' && value) { updated.setup_date = value; }\n      return updated;\n    });\n\n    if (field === 'event_type' || field === 'custom_event_type') {\n      // Si la valeur est vide pour custom_event_type, utiliser la valeur de clientInfo.event_type\n      const eventValue = field === 'custom_event_type' ? value : (field === 'event_type' && value === 'custom' ? clientInfo.custom_event_type : value);\n      const isHypnose = (eventValue || '').toLowerCase().includes('hypnose');\n      let foundKey = '';\n\n      if (isHypnose) {\n        // Recherche du modèle CGV Hypnose par nom ou clé contenant 'show hypnose' ou 'hypnose'\n        const found = Object.entries(cgvTemplates).find(([key, t]) => {\n          const name = (t.name || '').toLowerCase();\n          const k = key.toLowerCase();\n          return name.includes('show hypnose') || k.includes('show_hyp_') || k.startsWith('show_hypnose');\n        }) || Object.entries(cgvTemplates).find(([key, t]) => {\n          const name = (t.name || '').toLowerCase();\n          const k = key.toLowerCase();\n          return name.includes('hypnose') || k.includes('hypnose');\n        });\n        if (found) foundKey = found[0];\n        else foundKey = 'show_hypnose';\n      } else {\n        // Recherche du modèle standard DJ par nom ou clé contenant 'standard dj' ou 'standard'\n        const found = Object.entries(cgvTemplates).find(([key, t]) => {\n          const name = (t.name || '').toLowerCase();\n          const k = key.toLowerCase();\n          return name.includes('standard dj') || k.includes('standard_dj');\n        }) || Object.entries(cgvTemplates).find(([key, t]) => {\n          const name = (t.name || '').toLowerCase();\n          const k = key.toLowerCase();\n          return name.includes('standard') || k.includes('standard');\n        });\n        if (found) foundKey = found[0];\n        else {\n          // Sinon fallback sur le premier modèle disponible ou mariage\n          const backupKey = Object.keys(cgvTemplates).find(k => k.includes('standard') || k.includes('dj') || k.includes('mariage')) || Object.keys(cgvTemplates)[0] || '';\n          foundKey = backupKey;\n        }\n      }\n\n      setSelectedCgvTemplate(foundKey);\n      if (foundKey && cgvTemplates[foundKey]) { \n        setCgvText(cgvTemplates[foundKey].content); \n        setCgvTitle(cgvTemplates[foundKey].name || (isHypnose ? \"Show Hypnose\" : \"Conditions Générales de Vente\"));\n      } else { \n        setCgvText(''); \n      }\n\n      if (field === 'event_type') {\n        setSelectedNotes([]);\n      }\n    }\n  };\n\n  const handleOptionToggle = (optionId) => {\n    setSelectedOptions(prev => prev.map(option => option.id === optionId ? { ...option, selected: !option.selected } : option));\n  };\n\n  const handleNoteToggle = (noteKey) => {\n    setSelectedNotes(prev => prev.includes(noteKey) ? prev.filter(key => key !== noteKey) : [...prev, noteKey]);\n  };\n\n  const handleMusicStyleToggle = (style) => {\n    setSelectedMusicStyles(prev => prev.includes(style) ? prev.filter(s => s !== style) : [...prev, style]);\n  };\n\n  const handleEventClick = (eventKey, eventLabel, eventType) => {\n    setSelectedEvents(prev => {\n      const isSelected = prev.includes(eventKey);\n      if (isSelected) {\n        setEventOrder(prevOrder => prevOrder.filter(item => item.key !== eventKey));\n        return prev.filter(e => e !== eventKey);\n      } else {\n        const newOrderItem = { key: eventKey, label: eventLabel, type: eventType, icon: eventType === 'repas' ? '' : eventType === 'musique' ? '' : '' };\n        setEventOrder(prevOrder => [...prevOrder, newOrderItem]);\n        return [...prev, eventKey];\n      }\n    });\n  };\n\n  const moveEventUp = (index) => {\n    if (index > 0) { setEventOrder(prev => { const n = [...prev]; [n[index - 1], n[index]] = [n[index], n[index - 1]]; return n; }); }\n  };\n\n  const moveEventDown = (index) => {\n    setEventOrder(prev => { if (index < prev.length - 1) { const n = [...prev]; [n[index], n[index + 1]] = [n[index + 1], n[index]]; return n; } return prev; });\n  };\n\n  const removeFromOrder = (eventKey) => {\n    setEventOrder(prev => prev.filter(item => item.key !== eventKey));\n    setSelectedEvents(prev => prev.filter(e => e !== eventKey));\n  };\n\n  const handleCgvTemplateChange = (templateKey) => {\n    setSelectedCgvTemplate(templateKey);\n    if (templateKey && cgvTemplates[templateKey]) { \n      setCgvText(cgvTemplates[templateKey].content); \n      setCgvTitle(cgvTemplates[templateKey].name || \"Conditions Générales de Vente\");\n    }\n    else if (templateKey === \"custom\") { setCgvText(\"\"); }\n  };\n\n  const handleImportContract = async () => {\n    if (!importedFile) {\n      setImportError(\"Veuillez sélectionner un fichier (PDF, PNG, JPG, TXT) à importer.\");\n      return;\n    }\n    setIsImporting(true);\n    setImportError(null);\n    setImportReport(null);\n    setImportTargetContractId(\"\");\n    setImportMatchedContract(null);\n\n    const formData = new FormData();\n    formData.append('file', importedFile);\n    formData.append('category', importDocCategory);\n\n    try {\n      const token = localStorage.getItem('access_token') || localStorage.getItem('token');\n      const response = await fetch(`${API}/contracts2/import`, {\n        method: 'POST',\n        headers: {\n          'Authorization': `Bearer ${token}`\n        },\n        body: formData\n      });\n\n      let data = {};\n      const contentType = response.headers.get(\"content-type\");\n      if (contentType && contentType.includes(\"application/json\")) {\n        data = await response.json();\n      } else {\n        const textText = await response.text();\n        console.warn(\"Non-JSON response from import endpoint:\", textText);\n        throw new Error(`Erreur serveur (${response.status}) : ${textText.substring(0, 150)}...`);\n      }\n\n      if (!response.ok) {\n        throw new Error(data.detail || data.error || \"Une erreur est survenue lors de l'analyse.\");\n      }\n\n      if (data && data.matchedOptions) {\n        data.matchedOptions = data.matchedOptions.map(opt => {\n          if (opt.is_pending) {\n            return {\n              ...opt,\n              selected: false,\n              resolved_price: opt.price,\n              resolution_choice: 'decline' // Excluded by default\n            };\n          }\n          if (opt.has_price_conflict) {\n            return {\n              ...opt,\n              selected: true,\n              resolved_price: opt.price_in_document,\n              resolution_choice: 'imported'\n            };\n          } else {\n            return {\n              ...opt,\n              selected: opt.selected !== false,\n              resolved_price: opt.price,\n              resolution_choice: 'system'\n            };\n          }\n        });\n      }\n\n      setImportReport(data);\n      toast.success(\"Analyse du contrat effectuée par l'IA !\");\n\n      // Auto-detect matching existing contract by name or date similarity\n      if (data && data.extractedData && data.extractedData.client_info) {\n        const extName = (data.extractedData.client_info.name || \"\").toLowerCase().trim();\n        const extDate = (data.extractedData.client_info.event_date || \"\").trim();\n        \n        let foundMatch = null;\n        if (contracts && contracts.length > 0 && (extName || extDate)) {\n          for (const c of contracts) {\n            const cName = (c.client_info?.name || \"\").toLowerCase().trim();\n            const cDate = (c.client_info?.event_date || \"\").trim();\n            \n            // Priority 1: Exact date and similar name\n            if (extDate && cDate === extDate && extName && cName.includes(extName)) {\n              foundMatch = c;\n              break;\n            }\n            // Priority 2: Exact date match\n            if (extDate && cDate === extDate) {\n              foundMatch = c;\n              break;\n            }\n            // Priority 3: Exact name match\n            if (extName && cName === extName) {\n              foundMatch = c;\n              break;\n            }\n            // Priority 4: Partial name match\n            if (extName && cName && (cName.includes(extName) || extName.includes(cName))) {\n              foundMatch = c;\n              break;\n            }\n          }\n        }\n        \n        if (foundMatch) {\n          setImportMatchedContract(foundMatch);\n          // If the user checked \"Contrat Signé / Complémentaire\", automatically default the destination to the matched contract!\n          if (importDocCategory === \"Contrat Signé / Complémentaire\") {\n            setImportTargetContractId(foundMatch.id);\n            toast.info(`Contrat existant pour \"${foundMatch.client_info?.name}\" détecté ! Mode Complémentaire activé.`);\n          } else {\n            setImportTargetContractId(\"\");\n            toast.info(`Contrat correspondant à \"${foundMatch.client_info?.name}\" détecté comme destination d'association possible.`);\n          }\n        }\n      }\n    } catch (err) {\n      console.error(\"Import error:\", err);\n      setImportError(err.message || \"Erreur lors de la communication de l'API avec Gemini.\");\n      toast.error(err.message || \"Erreur d'importation.\");\n    } finally {\n      setIsImporting(false);\n    }\n  };\n\n  const handleResolveConflict = (optionId, decision) => {\n    setImportReport(prev => {\n      if (!prev || !prev.matchedOptions) return prev;\n      return {\n        ...prev,\n        matchedOptions: prev.matchedOptions.map(opt => {\n          if (opt.id === optionId) {\n            let selected = true;\n            let price = opt.price;\n            if (decision === 'decline' || decision === 'exclure') {\n              selected = false;\n            } else if (decision === 'imported') {\n              price = opt.price_in_document;\n            } else if (decision === 'system' || decision === 'inclure') {\n              price = opt.price;\n            }\n            return {\n              ...opt,\n              selected,\n              resolved_price: price,\n              resolution_choice: decision\n            };\n          }\n          return opt;\n        })\n      };\n    });\n  };\n\n  const applyImportedData = async () => {\n    if (!importReport || !importReport.extractedData) return;\n\n    const { extractedData, matchedOptions } = importReport;\n\n    // 1. Client info - additive and safe (never overwrite custom populated values with empty/null)\n    const mergedClientInfo = { ...clientInfo };\n    if (extractedData.client_info) {\n      Object.entries(extractedData.client_info).forEach(([key, val]) => {\n        if (val !== undefined && val !== null && val !== \"\" && val !== \"À définir\" && val !== \"a definir\") {\n          mergedClientInfo[key] = val;\n        }\n      });\n    }\n    setClientInfo(mergedClientInfo);\n\n    // 2. Base Price\n    let nextBasePrice = basePrice;\n    if (extractedData.base_price) {\n      nextBasePrice = extractedData.base_price;\n      setBasePrice(nextBasePrice);\n    }\n\n    // 3. Deposit / Acompte\n    let nextDepositAmount = customDepositAmount;\n    if (extractedData.custom_deposit_amount) {\n      nextDepositAmount = extractedData.custom_deposit_amount;\n      setCustomDepositAmount(nextDepositAmount);\n      setNoDepositRequired(false);\n    }\n\n    // 4. Blacklist / Notes - Merge and append instead of replacing/deleting!\n    let nextBlacklist = blacklist || \"\";\n    if (extractedData.blacklist && extractedData.blacklist.trim()) {\n      if (!nextBlacklist) {\n        nextBlacklist = extractedData.blacklist.trim();\n      } else if (!nextBlacklist.toLowerCase().includes(extractedData.blacklist.toLowerCase().trim())) {\n        nextBlacklist = nextBlacklist + \"\\n\" + extractedData.blacklist.trim();\n      }\n      setBlacklist(nextBlacklist);\n    }\n\n    let nextDjNotes = djNotes || \"\";\n    if (extractedData.playlist && extractedData.playlist.trim()) {\n      if (!nextDjNotes) {\n        nextDjNotes = extractedData.playlist.trim();\n      } else if (!nextDjNotes.toLowerCase().includes(extractedData.playlist.toLowerCase().trim())) {\n        nextDjNotes = nextDjNotes + \"\\n\" + extractedData.playlist.trim();\n      }\n      setDjNotes(nextDjNotes);\n    }\n\n    let nextEventNotes = eventNotes || \"\";\n    if (extractedData.event_notes && extractedData.event_notes.trim()) {\n      if (!nextEventNotes) {\n        nextEventNotes = extractedData.event_notes.trim();\n      } else if (!nextEventNotes.toLowerCase().includes(extractedData.event_notes.toLowerCase().trim())) {\n        nextEventNotes = nextEventNotes + \"\\n\" + extractedData.event_notes.trim();\n      }\n      setEventNotes(nextEventNotes);\n    }\n\n    // 5. Options (NEVER unselect already-selected options !)\n    let finalAppliedOptionsList = [];\n    setSelectedOptions(prev => {\n      const nextOpts = prev.map(opt => {\n        const isAlreadySelected = opt.selected;\n        const matched = matchedOptions ? matchedOptions.find(m => m.id === opt.id) : null;\n        const matchedSelected = matched ? (matched.selected !== false) : false;\n        \n        // Additive decision: Keep true if isAlreadySelected OR matchedSelected is true\n        const selected = isAlreadySelected || matchedSelected;\n        \n        let finalPrice = opt.price;\n        if (matched) {\n          if (isAlreadySelected) {\n            if (matchedSelected && matched.resolved_price !== undefined) {\n              finalPrice = matched.resolved_price;\n            }\n          } else if (matchedSelected) {\n            finalPrice = matched.resolved_price !== undefined ? matched.resolved_price : (matched.price || opt.price);\n          }\n        }\n        return { ...opt, selected, price: finalPrice };\n      });\n      finalAppliedOptionsList = nextOpts.filter(o => o.selected);\n      return nextOpts;\n    });\n\n    // Mirroring same logic for the immediate payload to bypass async setState delays\n    if (matchedOptions && Array.isArray(matchedOptions)) {\n      const nextOptsManual = selectedOptions.map(opt => {\n        const isAlreadySelected = opt.selected;\n        const matched = matchedOptions.find(m => m.id === opt.id);\n        const matchedSelected = matched ? (matched.selected !== false) : false;\n        const selected = isAlreadySelected || matchedSelected;\n\n        let finalPrice = opt.price;\n        if (matched) {\n          if (isAlreadySelected) {\n            if (matchedSelected && matched.resolved_price !== undefined) {\n              finalPrice = matched.resolved_price;\n            }\n          } else if (matchedSelected) {\n            finalPrice = matched.resolved_price !== undefined ? matched.resolved_price : (matched.price || opt.price);\n          }\n        }\n        return { ...opt, selected, price: finalPrice };\n      });\n      finalAppliedOptionsList = nextOptsManual.filter(o => o.selected);\n    } else {\n      finalAppliedOptionsList = selectedOptions.filter(o => o.selected);\n    }\n\n    // 6. Déroulement / Event list - merge and append new timelines without overwriting or deleting\n    let finalSelectedEventsList = [...selectedEvents];\n    let finalEventOrderList = [...eventOrder];\n    let localCustomRepas = [...customRepasEvents];\n    let localCustomMusique = [...customMusiqueEvents];\n\n    if (extractedData.deroulement && Array.isArray(extractedData.deroulement)) {\n      extractedData.deroulement.forEach((item) => {\n        const titleClean = (item.title || \"\").trim();\n        const notesClean = (item.notes || \"\").trim();\n        if (!titleClean) return;\n\n        // Check if identical or very similar step already exists in current order list\n        const alreadyExists = finalEventOrderList.some(e => \n          (e.label || \"\").toLowerCase().trim() === titleClean.toLowerCase()\n        );\n\n        if (alreadyExists) {\n          // Just update notes if existing has none and new has notes\n          finalEventOrderList = finalEventOrderList.map(e => {\n            if ((e.label || \"\").toLowerCase().trim() === titleClean.toLowerCase() && !e.note && notesClean) {\n              return { ...e, note: notesClean };\n            }\n            return e;\n          });\n          return;\n        }\n\n        // Standard timeline matching definitions\n        const standardRepas = [\"Apéritif\", \"Entrée\", \"Plat\", \"Fromage\", \"Dessert\"];\n        const standardMusique = [\"Entrée des mariés\", \"Ouverture de bal\", \"Danse de couple\", \"Musique de 80 à début 2000\", \"Musique de 80 à aujourd'hui\"];\n        const standardAnimations = [\"Blind test\", \"Chasse au trésor\", \"Quiz interactif\", \"Confessionnal\"];\n\n        const t = titleClean.toLowerCase();\n\n        const matchedRepas = standardRepas.find(e => {\n          const el = e.toLowerCase();\n          return t === el || \n                 (t.includes(\"vin\") && t.includes(\"honneur\") && el === \"apéritif\") ||\n                 (t.includes(\"plat\") && el === \"plat\");\n        });\n\n        const matchedMusique = standardMusique.find(e => {\n          const el = e.toLowerCase();\n          return t === el ||\n                 (t.includes(\"entrée\") && t.includes(\"marié\") && el === \"entrée des mariés\") ||\n                 (t.includes(\"ouverture\") && t.includes(\"bal\") && el === \"ouverture de bal\");\n        });\n\n        const matchedAnim = standardAnimations.find(e => {\n          const el = e.toLowerCase();\n          return t === el ||\n                 (t.includes(\"blind\") && t.includes(\"test\") && el === \"blind test\") ||\n                 ((t.includes(\"quiz\") || t.includes(\"quizz\")) && el === \"quiz interactif\") ||\n                 (t.includes(\"chasse\") && t.includes(\"trésor\") && el === \"chasse au trésor\");\n        });\n\n        let key = \"\";\n        let label = titleClean;\n        let type = \"repas\";\n\n        if (matchedRepas) {\n          key = `repas-${matchedRepas}`;\n          label = matchedRepas;\n          type = \"repas\";\n        } else if (matchedMusique) {\n          key = `musique-${matchedMusique}`;\n          label = matchedMusique;\n          type = \"musique\";\n        } else if (matchedAnim) {\n          key = `animation-${matchedAnim}`;\n          label = matchedAnim;\n          type = \"animation\";\n        } else {\n          // Custom event step\n          const isMusiqueWord = t.includes(\"musique\") || t.includes(\"bal\") || t.includes(\"danse\") || t.includes(\"slow\") || t.includes(\"playlist\");\n          if (isMusiqueWord) {\n            let index = localCustomMusique.indexOf(titleClean);\n            if (index === -1) {\n              localCustomMusique.push(titleClean);\n              index = localCustomMusique.length - 1;\n            }\n            key = `custom-musique-${index}`;\n            type = \"musique\";\n          } else {\n            let index = localCustomRepas.indexOf(titleClean);\n            if (index === -1) {\n              localCustomRepas.push(titleClean);\n              index = localCustomRepas.length - 1;\n            }\n            key = `custom-repas-${index}`;\n            type = \"repas\";\n          }\n        }\n\n        if (key && !finalSelectedEventsList.includes(key)) {\n          finalSelectedEventsList.push(key);\n          finalEventOrderList.push({ key, label, type, note: notesClean, icon: '' });\n        }\n      });\n\n      setCustomRepasEvents(localCustomRepas);\n      setCustomMusiqueEvents(localCustomMusique);\n      setSelectedEvents(finalSelectedEventsList);\n      setEventOrder(finalEventOrderList);\n    }\n\n    const contractDataToSave = {\n      client_info: mergedClientInfo,\n      dj_profile: selectedDjProfile,\n      dj_profile_data: getProfileData(selectedDjProfile),\n      contract_mode: contractMode || 'entreprise',\n      base_price: nextBasePrice || 0,\n      frais_mandat: fraisMandat || 0,\n      cachet_artiste: cachetArtiste || 0,\n      freelance_cachet_cap: freelanceCachetCap,\n      pack_sonorisation: packSonorisation || false,\n      pack_lumiere: packLumiere || false,\n      selected_options: finalAppliedOptionsList,\n      options_tarif_notes: optionsTarifNotes,\n      discount_amount: discountAmount || 0,\n      invoice_number: invoiceNumber || \"\",\n      artiste_invoice_number: artisteInvoiceNumber || \"\",\n      custom_deposit_amount: nextDepositAmount || 0,\n      no_deposit_required: noDepositRequired || false,\n      selected_rib: selectedRIB || \"\",\n      deposit_paid: depositPaid || false,\n      deposit_payment_method: depositPaymentMethod || \"\",\n      deposit_paid_date: depositPaidDate || \"\",\n      has_limiteur_son: hasLimiteurSon || false,\n      has_detecteur_fumee: hasDetecteurFumee || false,\n      has_no_limiteur_ni_detecteur: hasNoLimiteurNiDetecteur || false,\n      has_wifi: hasWifi || false,\n      has_4g_5g: has4g5g || false,\n      selected_notes: selectedNotes,\n      selected_pdf_notes: selectedPdfNotes,\n      predefined_notes: predefinedNotes,\n      selected_music_styles: selectedMusicStyles,\n      dj_notes: nextDjNotes,\n      blacklist: nextBlacklist,\n      catering_notes: cateringNotes,\n      catering_drinks: cateringDrinks,\n      catering_hot_meal_no_table: cateringHotMealNoTable,\n      catering_hot_meal_no_table_qty: cateringHotMealNoTableQty,\n      background_music_aperitif: backgroundMusicAperitif,\n      selected_events: finalSelectedEventsList,\n      custom_repas_events: localCustomRepas,\n      custom_musique_events: localCustomMusique,\n      event_notes: nextEventNotes,\n      event_order: finalEventOrderList,\n      hypnosis_program: hypnosisProgram,\n      technician_contact: technicianContact,\n      cgv_text: cgvText,\n      artiste_cgv_text: artisteCgvText,\n      cgv_title: cgvTitle,\n      artiste_cgv_title: artisteCgvTitle,\n      status: \"draft\",\n      draft_saved_at: new Date().toISOString()\n    };\n\n    try {\n      let savedContractResult = null;\n      \n      if (importTargetContractId) {\n        toast.info(\"Mise à jour et fusion avec le contrat existant...\");\n        \n        // Récupérer le contrat existant pour préserver les métadonnées non écrasées\n        const existingContract = contracts.find(c => c.id === importTargetContractId);\n        \n        // Fusionner avec préservation des documents existants et des signatures !\n        const blendedData = {\n          ...existingContract,\n          ...contractDataToSave,\n          client_info: {\n            ...existingContract?.client_info,\n            ...contractDataToSave.client_info\n          },\n          event_documents: existingContract?.event_documents || [],\n          signatures: existingContract?.signatures || [],\n          id: importTargetContractId,\n          updated_at: new Date().toISOString()\n        };\n        \n        const saveResponse = await axios.put(`${API}/contracts2/${importTargetContractId}`, blendedData);\n        savedContractResult = saveResponse.data;\n        setGeneratedContract(savedContractResult);\n        setContracts(prev => prev.map(c => c.id === importTargetContractId ? savedContractResult : c));\n        setEditingContract(savedContractResult);\n      } else {\n        toast.info(\"Enregistrement automatique du nouveau contrat importé...\");\n        \n        let activeInvoiceNumber = contractDataToSave.invoice_number;\n        let activeArtisteInvoiceNumber = contractDataToSave.artiste_invoice_number;\n        const needsMandat = !activeInvoiceNumber;\n        const needsArtiste = (contractMode || 'entreprise') === 'mandataire' && !activeArtisteInvoiceNumber;\n\n        if (needsMandat || needsArtiste) {\n          try {\n            let typeToIncrement = 'both';\n            if (needsMandat && !needsArtiste) {\n              typeToIncrement = 'mandat';\n            } else if (!needsMandat && needsArtiste) {\n              typeToIncrement = 'artiste';\n            }\n\n            const incResponse = await axios.post(`${API}/contracts2/counters/increment`, { type: typeToIncrement });\n            const { mandat_number, artiste_number } = incResponse.data;\n            \n            if (needsMandat) {\n              activeInvoiceNumber = mandat_number;\n              setInvoiceNumber(mandat_number);\n              contractDataToSave.invoice_number = mandat_number;\n            }\n            if (needsArtiste) {\n              activeArtisteInvoiceNumber = artiste_number;\n              setArtisteInvoiceNumber(artiste_number);\n              contractDataToSave.artiste_invoice_number = artiste_number;\n            }\n            fetchNextNumbers();\n          } catch (incError) {\n            console.error(\"Auto-numbering error on import save:\", incError);\n          }\n        }\n\n        const saveResponse = await axios.post(`${API}/contracts2`, contractDataToSave);\n        savedContractResult = saveResponse.data;\n        setGeneratedContract(savedContractResult);\n        setContracts(prev => [savedContractResult, ...prev]);\n        setEditingContract(savedContractResult);\n      }\n\n      // Now, upload the imported original contract as an attachment\n      if (importedFile && savedContractResult) {\n        toast.info(`Sauvegarde de l'original \"${importedFile.name}\" en pièce jointe...`);\n        const uploadData = new FormData();\n        uploadData.append(\"file\", importedFile);\n        uploadData.append(\"category\", importDocCategory);\n\n        const token = localStorage.getItem('access_token');\n        const headers = token ? { 'Authorization': `Bearer ${token}` } : {};\n\n        try {\n          const uploadResp = await fetch(`${BACKEND_URL}/api/contracts2/${savedContractResult.id}/documents`, {\n            method: \"POST\",\n            headers,\n            body: uploadData\n          });\n\n          if (uploadResp.ok) {\n            const uploadResult = await uploadResp.json();\n            if (uploadResult.success) {\n              toast.success(`L'original \"${importedFile.name}\" a été conservé en pièce jointe !`);\n              \n              const refreshedContract = {\n                ...savedContractResult,\n                event_documents: [...(savedContractResult.event_documents || []), uploadResult.document]\n              };\n              setGeneratedContract(refreshedContract);\n              setEditingContract(refreshedContract);\n              setContracts(prev => prev.map(c => c.id === savedContractResult.id ? refreshedContract : c));\n            }\n          } else {\n            console.error(\"Failed to automatically upload original file.\");\n            toast.warning(\"Contrat importé avec succès, mais le fichier d'origine n'a pas pu être enregistré en pièce jointe.\");\n          }\n        } catch (uploadErr) {\n          console.error(\"Error uploading imported contract:\", uploadErr);\n        }\n      } else {\n        toast.success(\"Données de l'ancien contrat injectées et enregistrées avec succès !\");\n      }\n    } catch (saveErr) {\n      console.error(\"Error auto-saving contract on import:\", saveErr);\n      toast.error(\"Erreur d'enregistrement automatique du contrat importé.\");\n    }\n\n    setIsImportModalOpen(false);\n    setImportReport(null);\n    setImportedFile(null);\n    setImportError(null);\n  };\n\n  // ═══════════════════════════════════════════════════\n  // CALCULATIONS\n  // ═══════════════════════════════════════════════════\n\n  const isDirigeant = () => {\n    const p = getProfileData(selectedDjProfile);\n    return p.nom_artistique?.toLowerCase().includes(\"r'key\") || p.nom_artistique?.toLowerCase().includes(\"rkey\") || p.titre?.includes(\"Gérant\") || p.statut_artiste === 'dirigeant';\n  };\n\n  const calculateTotal = () => {\n    const optionsTotal = selectedOptions.filter(option => option.selected).reduce((sum, option) => sum + option.price, 0);\n    if (isDirigeant()) {\n      // Mode Prestation Directe: Prix de base + Options - Remise\n      return Math.max(0, basePrice + optionsTotal - discountAmount);\n    }\n    if (contractMode === 'entreprise') {\n      // Mode Entreprise: Prix de base + Options - Remise (tout facturé par R'KEY)\n      return Math.max(0, basePrice + optionsTotal - discountAmount);\n    }\n    // Mode Mandat: Frais Mandat + Cachet Artiste + Options - Remise\n    // Support robust fallback for legacy contracts (migrated from old app) where separate mandate fees are 0 but basePrice is set\n    const mandataireRate = fraisMandat + cachetArtiste;\n    const baseRate = (mandataireRate === 0 && basePrice > 0) ? basePrice : mandataireRate;\n    return Math.max(0, baseRate + optionsTotal - discountAmount);\n  };\n\n  const calculateDepositAmount = () => {\n    const isCompany = !!(clientInfo?.company && clientInfo.company.trim().length > 0);\n    const profile = getProfileData(selectedDjProfile);\n    return calculateDepositAmountImported(\n      basePrice,\n      selectedOptions,\n      discountAmount,\n      customDepositAmount,\n      noDepositRequired,\n      isCompany,\n      contractMode,\n      profile,\n      freelanceCachetCap\n    );\n  };\n\n  const calculateRemainingBalance = () => {\n    const isCompany = !!(clientInfo?.company && clientInfo.company.trim().length > 0);\n    const profile = getProfileData(selectedDjProfile);\n    return calculateRemainingBalanceImported(\n      basePrice,\n      selectedOptions,\n      discountAmount,\n      customDepositAmount,\n      noDepositRequired,\n      isCompany,\n      contractMode,\n      profile,\n      freelanceCachetCap\n    );\n  };\n\n  const calculateSetupDate = (eventDate) => {\n    if (!eventDate) return \"\";\n    const date = new Date(eventDate);\n    date.setDate(date.getDate() - 1);\n    return date.toISOString().split('T')[0];\n  };\n\n  const selectAllMusicStyles = () => {\n    setSelectedMusicStyles([...musicStyles]);\n    toast.success(\"Tous les styles musicaux ont été sélectionnés !\");\n  };\n\n  // ═══════════════════════════════════════════════════\n  // FORM RESET\n  // ═══════════════════════════════════════════════════\n\n  const resetForm = () => {\n    setContractMode('entreprise');\n    setClientInfo({ name: \"\", company: \"\", address: \"\", ph