rev => ({ ...prev, setup_date: calculateSetupDate(prev.event_date) }));\n    }\n  }, [clientInfo.event_date]);\n\n  // ═══════════════════════════════════════════════════\n  // SAVE / LOAD CONTRACT\n  // ═══════════════════════════════════════════════════\n\n  const saveContractDraft = async (switchToPreview = true) => {\n    if (!clientInfo.name || !clientInfo.email) {\n      toast.error(\"Nom du client et email sont requis pour sauvegarder un brouillon.\");\n      return;\n    }\n\n    let activeInvoiceNumber = invoiceNumber;\n    let activeArtisteInvoiceNumber = artisteInvoiceNumber;\n\n    // Auto-generate invoice/contract numbers if they are blank\n    const needsMandat = !activeInvoiceNumber;\n    const needsArtiste = contractMode === 'mandataire' && !activeArtisteInvoiceNumber;\n\n    if (needsMandat || needsArtiste) {\n      try {\n        let typeToIncrement = 'both';\n        if (needsMandat && !needsArtiste) {\n          typeToIncrement = 'mandat';\n        } else if (!needsMandat && needsArtiste) {\n          typeToIncrement = 'artiste';\n        }\n\n        const incResponse = await axios.post(`${API}/contracts2/counters/increment`, { type: typeToIncrement });\n        const { mandat_number, artiste_number } = incResponse.data;\n        \n        if (needsMandat) {\n          activeInvoiceNumber = mandat_number;\n          setInvoiceNumber(mandat_number);\n          toast.success(`Numéro de contrat/facture automatique généré : ${mandat_number}`);\n        }\n        if (needsArtiste) {\n          activeArtisteInvoiceNumber = artiste_number;\n          setArtisteInvoiceNumber(artiste_number);\n          toast.success(`Numéro d'engagement d'artiste automatique généré : ${artiste_number}`);\n        }\n        \n        fetchNextNumbers();\n      } catch (incError) {\n        console.error(\"Auto-numbering error on save:\", incError);\n      }\n    }\n\n    const contract = {\n      client_info: {\n        name: clientInfo.name, email: clientInfo.email, phone: clientInfo.phone,\n        address: clientInfo.address, company: clientInfo.company, event_type: clientInfo.event_type,\n        event_date: clientInfo.event_date, event_location: clientInfo.event_location,\n        guest_count: clientInfo.guest_count, setup_date: clientInfo.setup_date,\n        setup_time: clientInfo.setup_time, start_time: clientInfo.start_time,\n        end_time: clientInfo.unlimited_time ? null : clientInfo.end_time,\n        unlimited_time: clientInfo.unlimited_time, phone2: clientInfo.phone2,\n        custom_event_type: clientInfo.custom_event_type, event_note: clientInfo.event_note,\n        additional_events: clientInfo.additional_events || []\n      },\n      dj_profile: selectedDjProfile,\n      dj_profile_data: getProfileData(selectedDjProfile),\n      contract_mode: contractMode,\n      base_price: basePrice || 0,\n      frais_mandat: fraisMandat || 0,\n      cachet_artiste: cachetArtiste || 0,\n      freelance_cachet_cap: freelanceCachetCap,\n      pack_sonorisation: packSonorisation || false,\n      pack_lumiere: packLumiere || false,\n      selected_options: selectedOptions.filter(opt => opt.selected),\n      options_tarif_notes: optionsTarifNotes,\n      discount_amount: discountAmount || 0,\n      invoice_number: activeInvoiceNumber || \"\",\n      artiste_invoice_number: activeArtisteInvoiceNumber || \"\",\n      custom_deposit_amount: customDepositAmount || 0,\n      no_deposit_required: noDepositRequired || false,\n      selected_rib: selectedRIB || \"\",\n      deposit_paid: depositPaid || false,\n      deposit_payment_method: depositPaymentMethod || \"\",\n      deposit_paid_date: depositPaidDate || \"\",\n      has_limiteur_son: hasLimiteurSon || false,\n      has_detecteur_fumee: hasDetecteurFumee || false,\n      has_no_limiteur_ni_detecteur: hasNoLimiteurNiDetecteur || false,\n      has_wifi: hasWifi || false,\n      has_4g_5g: has4g5g || false,\n      selected_notes: selectedNotes,\n      selected_pdf_notes: selectedPdfNotes,\n      predefined_notes: predefinedNotes,\n      selected_music_styles: selectedMusicStyles,\n      dj_notes: djNotes,\n      blacklist: blacklist,\n      catering_notes: cateringNotes,\n      catering_drinks: cateringDrinks,\n      catering_hot_meal_no_table: cateringHotMealNoTable,\n      catering_hot_meal_no_table_qty: cateringHotMealNoTableQty,\n      background_music_aperitif: backgroundMusicAperitif,\n      selected_events: selectedEvents,\n      custom_repas_events: customRepasEvents,\n      custom_musique_events: customMusiqueEvents,\n      event_notes: eventNotes,\n      event_order: eventOrder,\n      hypnosis_program: hypnosisProgram,\n      technician_contact: technicianContact,\n      cgv_text: cgvText,\n      artiste_cgv_text: artisteCgvText,\n      cgv_title: cgvTitle,\n      artiste_cgv_title: artisteCgvTitle,\n      status: \"draft\",\n      draft_saved_at: new Date().toISOString()\n    };\n\n    try {\n      if (editingContract) {\n        const response = await axios.put(`${API}/contracts2/${editingContract.id}`, contract);\n        const updatedContract = response.data;\n        setGeneratedContract(updatedContract);\n        setContracts(prev => prev.map(c => c.id === editingContract.id ? updatedContract : c));\n        toast.success(\"Brouillon de contrat mis à jour avec succès !\");\n        if (switchToPreview === true) setActiveTab(\"preview\");\n      } else {\n        const response = await axios.post(`${API}/contracts2`, contract);\n        const newContract = response.data;\n        setGeneratedContract(newContract);\n        setContracts(prev => [newContract, ...prev]);\n        setEditingContract(newContract);\n        toast.success(\"Brouillon de contrat sauvegardé avec succès !\");\n        if (switchToPreview === true) setActiveTab(\"preview\");\n      }\n    } catch (error) {\n      console.error('Error saving contract draft:', error);\n      toast.error(\"Erreur lors de la sauvegarde du brouillon\");\n    }\n  };\n\n  const loadContract = (contract) => {\n    setSelectedDjProfile(contract.dj_profile || \"\");\n    setClientInfo({\n      name: contract.client_info.name || \"\", company: contract.client_info.company || \"\",\n      address: contract.client_info.address || \"\", phone: contract.client_info.phone || \"\",\n      email: contract.client_info.email || \"\", event_date: contract.client_info.event_date || \"\",\n      event_location: contract.client_info.event_location || \"\", event_type: contract.client_info.event_type || \"\",\n      custom_event_type: contract.client_info.custom_event_type || \"\", event_note: contract.client_info.event_note || \"\",\n      setup_date: contract.client_info.setup_date || \"\", setup_time: contract.client_info.setup_time || \"À définir\",\n      start_time: contract.client_info.start_time || \"\", end_time: contract.client_info.end_time || \"\",\n      unlimited_time: contract.client_info.unlimited_time || false, phone2: contract.client_info.phone2 || \"\",\n      guest_count: contract.client_info.guest_count || \"\",\n      additional_events: contract.client_info.additional_events || []\n    });\n    \n    const contractSelectedOptions = contract.selected_options || [];\n    setSelectedOptions(availableOptions.map(option => {\n      const saved = contractSelectedOptions.find(o => o.id === option.id);\n      return {\n        ...option,\n        selected: saved ? saved.selected !== false : false,\n        price: saved && saved.price !== undefined ? saved.price : option.price\n      };\n    }));\n    \n    setDiscountAmount(contract.discount_amount || 0);\n    setInvoiceNumber(contract.invoice_number || \"\");\n    setArtisteInvoiceNumber(contract.artiste_invoice_number || \"\");\n    setCustomDepositAmount(contract.custom_deposit_amount || 0);\n    setNoDepositRequired(contract.no_deposit_required || false);\n    setSelectedRIB(contract.selected_rib || \"\");\n    setDepositPaid(contract.deposit_paid || false);\n    setDepositPaymentMethod(contract.deposit_payment_method || \"\");\n    setDepositPaidDate(contract.deposit_paid_date || \"\");\n    setBasePrice(contract.base_price || 0);\n    setContractMode(contract.contract_mode || 'entreprise');\n    setFraisMandat(contract.frais_mandat || 0);\n    setCachetArtiste(contract.cachet_artiste || 0);\n    setFreelanceCachetCap(contract.freelance_cachet_cap !== undefined ? contract.freelance_cachet_cap : 800);\n    setPackSonorisation(contract.pack_sonorisation || false);\n    setPackLumiere(contract.pack_lumiere || false);\n    setOptionsTarifNotes(contract.options_tarif_notes || \"\");\n    setHasLimiteurSon(contract.has_limiteur_son || false);\n    setHasDetecteurFumee(contract.has_detecteur_fumee || false);\n    setHasNoLimiteurNiDetecteur(contract.has_no_limiteur_ni_detecteur || false);\n    setHasWifi(contract.has_wifi || false);\n    setHas4g5g(contract.has_4g_5g || false);\n    setSelectedPdfNotes(contract.selected_pdf_notes || []);\n    setSelectedNotes(contract.selected_notes || []);\n    setSelectedMusicStyles(contract.selected_music_styles || []);\n    setDjNotes(contract.dj_notes || \"\");\n    setBlacklist(contract.blacklist || \"\");\n    setCateringNotes(contract.catering_notes || \"\");\n    setCateringDrinks(contract.catering_drinks || false);\n    setCateringHotMealNoTable(contract.catering_hot_meal_no_table || false);\n    setCateringHotMealNoTableQty(contract.catering_hot_meal_no_table_qty || 0);\n    setBackgroundMusicAperitif(contract.background_music_aperitif || \"\");\n    setSelectedEvents(contract.selected_events || []);\n    setCustomRepasEvents(contract.custom_repas_events || []);\n    setCustomMusiqueEvents(contract.custom_musique_events || []);\n    setEventNotes(contract.event_notes || \"\");\n    setEventOrder(contract.event_order || []);\n    setHypnosisProgram(contract.hypnosis_program || defaultHypnosisProgram);\n    setTechnicianContact(contract.technician_contact || { name: \"\", email: \"\", phone: \"\" });\n    setCgvText(contract.cgv_text || \"\");\n    setArtisteCgvText(contract.artiste_cgv_text || defaultArtistCgv);\n    setCgvTitle(contract.cgv_title || \"Conditions Générales de Vente\");\n    setArtisteCgvTitle(contract.artiste_cgv_title || \"Conditions Générales de l'Artiste\");\n    setEditingContract(contract);\n    setActiveTab(\"create\");\n    toast.success(\"Contrat chargé pour modification\");\n  };\n\n  const duplicateContract = (contract) => {\n    setSelectedDjProfile(contract.dj_profile || \"\");\n    setClientInfo({\n      name: contract.client_info?.name || \"\", company: contract.client_info?.company || \"\",\n      address: contract.client_info?.address || \"\", phone: contract.client_info?.phone || \"\",\n      email: contract.client_info?.email || \"\", event_date: contract.client_info?.event_date || \"\",\n      event_location: contract.client_info?.event_location || \"\", event_type: contract.client_info?.event_type || \"\",\n      custom_event_type: contract.client_info?.custom_event_type || \"\", event_note: contract.client_info?.event_note || \"\",\n      setup_date: contract.client_info?.setup_date || \"\", setup_time: contract.client_info?.setup_time || \"À définir\",\n      start_time: contract.client_info?.start_time || \"\", end_time: contract.client_info?.end_time || \"\",\n      unlimited_time: contract.client_info?.unlimited_time || false, phone2: contract.client_info?.phone2 || \"\",\n      guest_count: contract.client_info?.guest_count || \"\",\n      additional_events: contract.client_info?.additional_events || []\n    });\n    \n    const contractSelectedOptions = contract.selected_options || [];\n    setSelectedOptions(availableOptions.map(option => {\n      const saved = contractSelectedOptions.find(o => o.id === option.id);\n      return {\n        ...option,\n        selected: saved ? saved.selected !== false : false,\n        price: saved && saved.price !== undefined ? saved.price : option.price\n      };\n    }));\n    \n    setDiscountAmount(contract.discount_amount || 0);\n    setInvoiceNumber(\"\"); \n    setArtisteInvoiceNumber(\"\"); \n    setCustomDepositAmount(contract.custom_deposit_amount || 0);\n    setNoDepositRequired(contract.no_deposit_required || false);\n    setSelectedRIB(contract.selected_rib || \"\");\n    setDepositPaid(false); \n    setDepositPaymentMethod(\"\");\n    setDepositPaidDate(\"\");\n    setBasePrice(contract.base_price || 0);\n    setContractMode(contract.contract_mode || 'entreprise');\n    setFraisMandat(contract.frais_mandat || 0);\n    setCachetArtiste(contract.cachet_artiste || 0);\n    setFreelanceCachetCap(contract.freelance_cachet_cap !== undefined ? contract.freelance_cachet_cap : 800);\n    setPackSonorisation(contract.pack_sonorisation || false);\n    setPackLumiere(contract.pack_lumiere || false);\n    setOptionsTarifNotes(contract.options_tarif_notes || \"\");\n    setHasLimiteurSon(contract.has_limiteur_son || false);\n    setHasDetecteurFumee(contract.has_detecteur_fumee || false);\n    setHasNoLimiteurNiDetecteur(contract.has_no_limiteur_ni_detecteur || false);\n    setHasWifi(contract.has_wifi || false);\n    setHas4g5g(contract.has_4g_5g || false);\n    setSelectedPdfNotes(contract.selected_pdf_notes || []);\n    setSelectedNotes(contract.selected_notes || []);\n    setSelectedMusicStyles(contract.selected_music_styles || []);\n    setDjNotes(contract.dj_notes || \"\");\n    setBlacklist(contract.blacklist || \"\");\n    setCateringNotes(contract.catering_notes || \"\");\n    setCateringDrinks(contract.catering_drinks || false);\n    setCateringHotMealNoTable(contract.catering_hot_meal_no_table || false);\n    setCateringHotMealNoTableQty(contract.catering_hot_meal_no_table_qty || 0);\n    setBackgroundMusicAperitif(contract.background_music_aperitif || \"\");\n    setSelectedEvents(contract.selected_events || []);\n    setCustomRepasEvents(contract.custom_repas_events || []);\n    setCustomMusiqueEvents(contract.custom_musique_events || []);\n    setEventNotes(contract.event_notes || \"\");\n    setEventOrder(contract.event_order || []);\n    setHypnosisProgram(contract.hypnosis_program || defaultHypnosisProgram);\n    setTechnicianContact(contract.technician_contact || { name: \"\", email: \"\", phone: \"\" });\n    setCgvText(contract.cgv_text || \"\");\n    setArtisteCgvText(contract.artiste_cgv_text || defaultArtistCgv);\n    setCgvTitle(contract.cgv_title || \"Conditions Générales de Vente\");\n    setArtisteCgvTitle(contract.artiste_cgv_title || \"Conditions Générales de l'Artiste\");\n    setEditingContract(null); \n    setGeneratedContract(null); \n    setActiveTab(\"create\");\n    toast.success(\"Contrat dupliqué ! Modifiez-le puis enregistrez-le dans l'onglet de création.\");\n  };\n\n  // ═══════════════════════════════════════════════════\n  // PDF / EMAIL ACTIONS\n  // ═══════════════════════════════════════════════════\n\n  const handlePrintContract = (contract) => {\n    generateContractAndGuide(contract, generateContractHTMLLocal, loadSignatureImages, selectedPdfNotes, apiService);\n  };\n\n  const handlePreviewContract = (contract) => {\n    const isDir = isContractDirigeant(contract);\n    const isMandat = contract.contract_mode === 'mandataire' && !isDir;\n    const isEntreprise = contract.contract_mode === 'entreprise' && !isDir;\n    \n    const clientName = contract.client_info?.name || 'Client';\n    const docs = [];\n    \n    if (isMandat) {\n      docs.push({\n        label: \"Mandat d'encaissement R'Key Prod\",\n        html: generateMandatHTML(contract, companySettings)\n      });\n      docs.push({\n        label: \"Contrat d'Engagement Artiste DJ\",\n        html: generateArtisteHTML(contract, resolveProfile)\n      });\n    } else if (isEntreprise) {\n      docs.push({\n        label: \"Contrat de Prestation (Entreprise)\",\n        html: generateEntrepriseHTML(contract, companySettings, resolveProfile)\n      });\n    } else {\n      docs.push({\n        label: \"Contrat Administratif\",\n        html: generateContractHTMLLocal(contract, null, signatureImages)\n      });\n    }\n    \n    setPreviewDoc({\n      title: `Contrat de ${clientName}`,\n      contract,\n      documents: docs,\n      activeDocIndex: 0\n    });\n  };\n\n  const handleExportSpecificPDF = async (contract, docLabel) => {\n    try {\n      const isMandatDoc = docLabel.includes(\"Mandat\");\n      const isArtisteDoc = docLabel.includes(\"Artiste\") || docLabel.includes(\"Engagement\");\n      const isEntrepriseDoc = docLabel.includes(\"Entreprise\") || docLabel.includes(\"Prestation\");\n      \n      let html;\n      let filename;\n      const cName = (contract.client_info?.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_');\n      const dateStr = getFormattedEventDate(contract);\n      \n      if (isMandatDoc) {\n        html = generateMandatHTML(contract, companySettings);\n        filename = `Contrat_Mandat_RKeyProd_${cName}_${dateStr}.pdf`;\n      } else if (isArtisteDoc) {\n        html = generateArtisteHTML(contract, resolveProfile);\n        const artisteP = resolveProfile(contract);\n        const artistName = (artisteP.nom_artistique || artisteP.nom_complet || 'Artiste').replace(/[^a-zA-Z0-9]/g, '_');\n        filename = `Contrat_Artiste_${artistName}_${cName}_${dateStr}.pdf`;\n      } else if (isEntrepriseDoc) {\n        html = generateEntrepriseHTML(contract, companySettings, resolveProfile);\n        filename = `Contrat_Prestation_RKeyProd_${cName}_${dateStr}.pdf`;\n      } else {\n        html = generateContractHTMLLocal(contract, null, signatureImages);\n        filename = `Contrat_RKEYPROD_${cName}_${dateStr}.pdf`;\n      }\n      \n      await exportHTMLToPDF(html, filename);\n    } catch (error) {\n      console.error(\"Erreur d'exportation PDF:\", error);\n      toast.error(\"Erreur lors de la génération du PDF\");\n    }\n  };\n\n  // Export PDF pour Document 1 (Mandat R'KEY PROD)\n  const handleExportMandatPDF = async () => {\n    const data = buildCurrentContractData();\n    const html = generateMandatHTML(data, companySettings);\n    await exportHTMLToPDF(html, `Contrat_Mandat_RKeyProd_${(data.client_info.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}_${getFormattedEventDate(data)}.pdf`);\n  };\n\n  // Export PDF pour Document 2 (Engagement Artiste DJ)\n  const handleExportArtistePDF = async () => {\n    const data = buildCurrentContractData();\n    const html = generateArtisteHTML(data, resolveProfile);\n    const artisteP = resolveProfile(data);\n    const artistName = (artisteP.nom_artistique || artisteP.nom_complet || 'Artiste').replace(/[^a-zA-Z0-9]/g, '_');\n    await exportHTMLToPDF(html, `Contrat_Artiste_${artistName}_${(data.client_info.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}_${getFormattedEventDate(data)}.pdf`);\n  };\n\n  // Export PDF pour Mode Entreprise (1 seul contrat global)\n  const handleExportEntreprisePDF = async () => {\n    const data = buildCurrentContractData();\n    const html = generateEntrepriseHTML(data, companySettings, resolveProfile);\n    await exportHTMLToPDF(html, `Contrat_Prestation_RKeyProd_${(data.client_info.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}_${getFormattedEventDate(data)}.pdf`);\n  };\n\n\n  // Fonction générique d'export HTML → PDF\n  const exportHTMLToPDF = async (htmlContent, fileName) => {\n    try {\n      toast.info(\"Génération PDF en cours...\", { duration: 3000 });\n      if (!window.jspdf || !window.jspdf.jsPDF) { toast.error(\"jsPDF non disponible.\"); return; }\n      const pdf = new window.jspdf.jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4', compress: true });\n      const tempContainer = document.createElement('div');\n      tempContainer.style.cssText = 'position:fixed;top:-9999px;left:-9999px;width:794px;background:white;padding:20px;';\n      tempContainer.innerHTML = htmlContent;\n      document.body.appendChild(tempContainer);\n      await new Promise(r => setTimeout(r, 1500));\n      const { default: html2canvas } = await import('html2canvas');\n      const allPages = tempContainer.querySelectorAll('[id^=\"pdf-page-\"]');\n      const pageIds = Array.from(allPages).map(el => el.id).sort((a, b) => {\n        const order = id => id === 'pdf-page-1' ? 1 : id === 'pdf-page-cgv' ? 999 : 2;\n        return order(a) - order(b);\n      });\n      let added = false;\n      for (const pageId of pageIds) {\n        const el = tempContainer.querySelector(`#${pageId}`);\n        if (!el || !el.innerHTML.trim()) continue;\n        if (added) pdf.addPage();\n        const canvas = await html2canvas(el, { scale: 1.4, useCORS: true, allowTaint: true, backgroundColor: '#ffffff', width: 794, logging: false });\n        const imgW = 190, imgH = (canvas.height * imgW) / canvas.width;\n        const imgData = canvas.toDataURL('image/jpeg', 0.88);\n        pdf.addImage(imgData, 'JPEG', 10, 10, imgW, Math.min(imgH, 277), undefined, 'FAST');\n        added = true;\n      }\n      document.body.removeChild(tempContainer);\n      pdf.save(fileName);\n      toast.success(\"PDF téléchargé !\");\n    } catch (error) {\n      console.error('Erreur PDF:', error);\n      toast.error(\"Erreur : \" + error.message);\n    }\n  };\n\n  const openContractEmailModal = (contractDataOrId, selectedTab = null) => {\n    let contractData = contractDataOrId;\n    if (!contractData.client_info) {\n      contractData = { ...contractData, ...buildCurrentContractData() };\n    }\n    \n    let contractHTML = \"\";\n    let contractHTMLs = null;\n    const isDir = isContractDirigeant(contractData);\n    const isMandat = contractData.contract_mode === 'mandataire' && !isDir;\n    const isEntreprise = contractData.contract_mode === 'entreprise' && !isDir;\n\n    if (isMandat) {\n        if (selectedTab === 'mandat') {\n            contractHTML = generateMandatHTML(contractData, companySettings);\n            contractHTMLs = [\n              {\n                 html: contractHTML,\n                 filename: `Contrat_Mandat_RKeyProd_${(contractData.client_info?.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}.pdf`\n              }\n            ];\n        } else if (selectedTab === 'artiste') {\n            contractHTML = generateArtisteHTML(contractData, resolveProfile);\n            const profile = resolveProfile(contractData);\n            const artistName = (profile.nom_artistique || profile.nom_complet || 'Artiste').replace(/[^a-zA-Z0-9]/g, '_');\n            contractHTMLs = [\n              {\n                 html: contractHTML,\n                 filename: `Contrat_Artiste_${artistName}_${(contractData.client_info?.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}.pdf`\n              }\n            ];\n        } else {\n            contractHTMLs = [\n              {\n                 html: generateMandatHTML(contractData, companySettings),\n                 filename: `Contrat_Mandat_RKeyProd_${(contractData.client_info?.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}.pdf`\n              },\n              {\n                 html: generateArtisteHTML(contractData, resolveProfile),\n                 filename: `Contrat_Artiste_${(contractData.client_info?.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}.pdf`\n              }\n            ];\n            // Keep a fallback combined html just in case\n            contractHTML = contractHTMLs[0].html + \"\\n<div class='page-break' style='page-break-after: always; height: 0; min-height: 0; margin: 0; padding: 0;'></div>\\n\" + contractHTMLs[1].html;\n        }\n    } else if (isEntreprise) {\n        contractHTML = generateEntrepriseHTML(contractData, companySettings, resolveProfile);\n    } else {\n        contractHTML = generateContractHTMLLocal(contractData, null, signatureImages);\n    }\n\n    navigate('/contracts2/send-email', { state: { contractData, contractHTML, contractHTMLs } });\n  };\n\n  const handleSignatureValidated = (signatureData) => {\n    if (generatedContract) {\n      printContractWithSignature(generatedContract, generateContractHTMLLocal);\n    }\n    setShowSignaturePad(false);\n  };\n\n  // ═══════════════════════════════════════════════════\n  // BUILD CONTRACT DATA OBJECT (for preview/export)\n  // ═══════════════════════════════════════════════════\n\n  const buildCurrentContractData = () => ({\n    client_info: clientInfo,\n    dj_profile: selectedDjProfile,\n    dj_profile_data: getProfileData(selectedDjProfile),\n    selected_options: selectedOptions.filter(opt => opt.selected),\n    options_tarif_notes: optionsTarifNotes,\n    selected_notes: selectedNotes,\n    predefined_notes: predefinedNotes,\n    selected_music_styles: selectedMusicStyles,\n    dj_notes: djNotes,\n    blacklist: blacklist,\n    catering_notes: cateringNotes,\n    catering_drinks: cateringDrinks,\n    catering_hot_meal_no_table: cateringHotMealNoTable,\n    catering_hot_meal_no_table_qty: cateringHotMealNoTableQty,\n    selected_events: selectedEvents,\n    custom_repas_events: customRepasEvents,\n    custom_musique_events: customMusiqueEvents,\n    event_notes: eventNotes,\n    event_order: eventOrder,\n    background_music_aperitif: backgroundMusicAperitif,\n    hypnosis_program: hypnosisProgram,\n    technician_contact: technicianContact,\n    cgv_text: cgvText,\n    contract_mode: contractMode,\n    base_price: basePrice,\n    frais_mandat: fraisMandat,\n    cachet_artiste: cachetArtiste,\n    pack_sonorisation: packSonorisation,\n    pack_lumiere: packLumiere,\n    discount_amount: discountAmount,\n    custom_deposit_amount: customDepositAmount,\n    no_deposit_required: noDepositRequired,\n    selected_rib: selectedRIB,\n    deposit_paid: depositPaid,\n    deposit_payment_method: depositPaymentMethod,\n    deposit_paid_date: depositPaidDate,\n    has_limiteur_son: hasLimiteurSon,\n    has_detecteur_fumee: hasDetecteurFumee,\n    has_no_limiteur_ni_detecteur: hasNoLimiteurNiDetecteur,\n    has_wifi: hasWifi,\n    has_4g_5g: has4g5g,\n    selected_pdf_notes: selectedPdfNotes,\n    invoice_number: invoiceNumber,\n    artiste_invoice_number: artisteInvoiceNumber,\n    artiste_cgv_text: artisteCgvText,\n    cgv_title: cgvTitle,\n    artiste_cgv_title: artisteCgvTitle\n  });\n\n  // ═══════════════════════════════════════════════════\n  // RENDER\n  // ═══════════════════════════════════════════════════\n\n  if (showConfiguration) {\n    return (\n      <ConfigurationPage\n        selectedOptions={selectedOptions}\n        setSelectedOptions={setSelectedOptions}\n        predefinedNotes={predefinedNotes}\n        setPredefinedNotes={setPredefinedNotes}\n        pdfNotes={pdfNotes}\n        setPdfNotes={setPdfNotes}\n        cgvTemplates={cgvTemplates}\n        setCgvTemplates={setCgvTemplates}\n        apiService={apiService}\n        setShowConfiguration={setShowConfiguration}\n      />\n    );\n  }\n\n  return (\n    <div className=\"min-h-screen bg-gradient-to-br from-slate-50 to-blue-50\">\n      \n      {/* Signature Pad Modal */}\n      <SignaturePadModal\n        showSignaturePad={showSignaturePad}\n        setShowSignaturePad={setShowSignaturePad}\n        signaturePadRef={signaturePadRef}\n        setSignaturePadRef={setSignaturePadRef}\n        setClientSignature={setClientSignature}\n        onSignatureValidated={handleSignatureValidated}\n      />\n\n      {/* Header */}\n      <div className=\"bg-white border-b shadow-sm\">\n        <div className=\"max-w-7xl mx-auto px-4 py-4\">\n          <div className=\"flex items-center justify-between\">\n            <div>\n              <h1 className=\"text-2xl font-bold text-slate-800 flex items-center space-x-2\">\n                <FileSignature className=\"h-6 w-6 text-amber-600\" />\n                <span>Contrats</span>\n              </h1>\n              <p className=\"text-sm text-slate-600 mt-1\">Gestion Agence / Mandataire</p>\n            </div>\n            <div className=\"flex items-center space-x-4\">\n              <Badge variant=\"secondary\" className=\"text-sm\">\n                {contracts.length} contrat{contracts.length !== 1 ? 's' : ''}\n              </Badge>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <div className=\"max-w-7xl mx-auto px-4 py-4\">\n        <Tabs value={activeTab} onValueChange={setActiveTab} className=\"w-full\">\n          <TabsList className=\"grid w-full grid-cols-3 mb-6\">\n            <TabsTrigger value=\"create\" className=\"flex items-center space-x-2\">\n              <FileText className=\"h-4 w-4\" />\n              <span>{editingContract ? 'Modifier' : 'Créer'}</span>\n            </TabsTrigger>\n            <TabsTrigger value=\"preview\" className=\"flex items-center space-x-2\">\n              <FileText className=\"h-4 w-4\" />\n              <span>Aperçu</span>\n            </TabsTrigger>\n            <TabsTrigger value=\"history\" className=\"flex items-center space-x-2\">\n              <Building className=\"h-4 w-4\" />\n              <span>Historique</span>\n            </TabsTrigger>\n          </TabsList>\n\n          {/* ═══════════════════════════════════════════════ */}\n          {/* CREATE CONTRACT TAB                            */}\n          {/* ═══════════════════════════════════════════════ */}\n          <TabsContent value=\"create\">\n            <div className=\"mb-6 flex justify-center space-x-2\">\n              <Button onClick={() => setActiveTab(\"history\")} variant=\"outline\" className=\"px-4 py-3 text-sm flex items-center gap-1.5 border-slate-300 text-slate-700 hover:bg-slate-100\">\n                <ArrowLeft className=\"h-4 w-4\" /> Retour au Sommaire\n              </Button>\n              <Button onClick={resetForm} variant=\"outline\" className=\"px-4 py-3 text-sm\">Reset</Button>\n              <Button onClick={() => {\n                // Pré-remplir un mariage test\n                setClientInfo({\n                  name: \"Marie Dupont\", company: \"\", address: \"12 rue des Lilas, 67000 Strasbourg\",\n                  phone: \"06 12 34 56 78\", phone2: \"\", email: \"marie.dupont@test.fr\",\n                  event_date: new Date(Date.now() + 90 * 86400000).toISOString().split('T')[0],\n                  event_location: \"Château de Pourtalès, Strasbourg\",\n                  event_type: \"Mariage\", custom_event_type: \"\", event_note: \"Thème champêtre\",\n                  setup_date: new Date(Date.now() + 89 * 86400000).toISOString().split('T')[0],\n                  setup_time: \"14h00\", start_time: \"18:00\", end_time: \"04:00\",\n                  unlimited_time: false, guest_count: \"150\"\n                });\n                setBasePrice(1200);\n                setFraisMandat(500);\n                setCachetArtiste(800);\n                setDiscountAmount(0);\n                setInvoiceNumber(\"C2-\" + new Date().getFullYear() + \"-001\");\n                toast.success(\"Données de test Mariage chargées !\");\n              }} variant=\"outline\" className=\"px-4 py-3 text-sm border-amber-400 text-amber-700 hover:bg-amber-50\" data-testid=\"test-fill-btn\">Test Mariage</Button>\n              <Button \n                onClick={() => setIsImportModalOpen(true)} \n                variant=\"outline\" \n                className=\"px-4 py-3 text-sm border-indigo-400 text-indigo-700 hover:bg-indigo-50 flex items-center gap-1.5\"\n                data-testid=\"import-contract-btn\"\n              >\n                <Upload className=\"h-4 w-4\" />\n                Importer ancien contrat\n              </Button>\n            </div>\n\n            <div className=\"grid grid-cols-1 lg:grid-cols-2 gap-6\">\n              \n              {/* DJ Selection */}\n              <div className=\"lg:col-span-2 mb-4\">\n                <div className=\"flex items-center gap-4\">\n                  <Label className=\"text-slate-700 font-semibold whitespace-nowrap\">Artiste :</Label>\n                  <select\n                    value={selectedDjProfile}\n                    onChange={(e) => {\n                      const val = e.target.value;\n                      setSelectedDjProfile(val);\n                      if (val) {\n                        const profile = getProfileData(val);\n                        if (profile.statut_artiste === 'freelance') {\n                          setContractMode('entreprise');\n                        }\n                      }\n                    }}\n                    className=\"flex-1 border border-slate-300 rounded-lg px-4 py-2.5 text-sm bg-white focus:ring-2 focus:ring-purple-300 focus:border-purple-400 outline-none\"\n                    data-testid=\"dj-profile-select\"\n                  >\n                    <option value=\"\">-- Sélectionner un artiste --</option>\n                    {Object.entries(djProfiles)\n                      .sort(([,a], [,b]) => {\n                        const aDir = (a.statut_artiste === 'dirigeant' || a.titre?.includes('Gérant')) ? 0 : 1;\n                        const bDir = (b.statut_artiste === 'dirigeant' || b.titre?.includes('Gérant')) ? 0 : 1;\n                        if (aDir !== bDir) return aDir - bDir;\n                        const nameA = a.nom_artistique || a.name || \"\";\n                        const nameB = b.nom_artistique || b.name || \"\";\n                        return nameA.localeCompare(nameB);\n                      })\n                      .map(([key, profile]) => (\n                      <option key={key} value={key}>\n                        {profile.nom_artistique || profile.name} {profile.statut_artiste === 'dirigeant' ? '(Dirigeant)' : '(Freelance)'}\n                      </option>\n                    ))}\n                  </select>\n                </div>\n                {selectedDjProfile && djProfiles[selectedDjProfile] && (() => {\n                  const p = djProfiles[selectedDjProfile];\n                  const hasData = p.nom_complet || p.email || p.phone || p.siret || p.address;\n                  return hasData ? (\n                    <div className=\"mt-3 ml-[70px] bg-slate-50 border border-slate-200 rounded-lg p-3 grid grid-cols-2 md:grid-cols-3 gap-x-6 gap-y-2 text-xs\" data-testid=\"profile-preview-card\">\n                      {p.nom_complet && <div><span className=\"text-slate-400 block\">Nom complet</span><span className=\"text-slate-700 font-medium\">{p.nom_complet}</span></div>}\n                      {p.email && <div><span className=\"text-slate-400 block\">Email</span><span className=\"text-slate-700 font-medium\">{p.email}</span></div>}\n                      {p.phone && <div><span className=\"text-slate-400 block\">Téléphone</span><span className=\"text-slate-700 font-medium\">{p.phone}</span></div>}\n                      {p.siret && <div><span className=\"text-slate-400 block\">SIRET</span><span className=\"text-slate-700 font-medium\">{p.siret}</span></div>}\n                      {p.address && <div className=\"col-span-2\"><span className=\"text-slate-400 block\">Adresse</span><span className=\"text-slate-700 font-medium\">{p.address}</span></div>}\n                    </div>\n                  ) : (\n                    <p className=\"mt-2 ml-[70px] text-xs text-amber-600\">Aucune information privée renseignée pour cet artiste. Complétez le profil dans \"Profils Artistes\".</p>\n                  );\n                })()}\n              </div>\n\n              {/* Boutons d'action rapides en haut */}\n              <div className=\"lg:col-span-2 flex justify-center gap-4 p-4 bg-slate-50/50 border border-slate-150 rounded-xl mb-2\">\n                <Button onClick={() => saveContractDraft(true)} className=\"bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 text-base font-semibold shadow-sm\" disabled={!clientInfo.name || !clientInfo.email}>\n                  <FileText className=\"h-5 w-5 mr-2\" />Aperçu du contrat\n                </Button>\n                {editingContract && (\n                  <Button onClick={() => saveContractDraft(false)} className=\"bg-green-600 hover:bg-green-700 text-white px-6 py-2.5 text-base font-semibold shadow-sm\" disabled={!clientInfo.name || !clientInfo.email}>\n                    <Save className=\"h-5 w-5 mr-2\" />Mettre à jour\n                  </Button>\n                )}\n              </div>\n\n              {/* Client Information */}\n              <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                <CardHeader className=\"pb-4\">\n                  <CardTitle className=\"flex items-center justify-between text-slate-800\">\n                    <div className=\"flex items-center space-x-2\">\n                      <User className=\"h-5 w-5 text-blue-600\" />\n                      <span>Informations Client</span>\n                    </div>\n                    <FormSubmissionsSelector onSelect={handleSubmissionSelect} buttonLabel=\"Soumissions\" />\n                  </CardTitle>\n                </CardHeader>\n                <CardContent className=\"space-y-4\">\n                  {selectedSubmission && (\n                    <div className=\"bg-blue-50 border border-blue-200 rounded-lg p-3 text-sm space-y-1 relative\" data-testid=\"contract-selected-submission\">\n                      <button\n                        onClick={handleClearSubmission}\n                        className=\"absolute top-2 right-2 text-red-400 hover:text-red-600 transition-colors\"\n                        title=\"Annuler l'import\"\n                        data-testid=\"contract-clear-submission-btn\"\n                      >\n                        <XCircle className=\"w-4 h-4\" />\n                      </button>\n                      <p className=\"font-semibold text-blue-700 pr-6\">Contact importé : {selectedSubmission.nom || 'Anonyme'}</p>\n                      <div className=\"flex flex-wrap gap-x-4 gap-y-0.5 text-xs text-blue-600\">\n                        {selectedSubmission.email && <span>{selectedSubmission.email}</span>}\n                        {selectedSubmission.telephone && <span>{selectedSubmission.telephone}</span>}\n                        {selectedSubmission.date_evenement && <span>{formatDateDisplay(selectedSubmission.date_evenement)}</span>}\n                      </div>\n                    </div>\n                  )}\n\n                  {/* Rechercher/Importer un Client existant du CRM */}\n                  <div id=\"crm-search-container\" className=\"bg-slate-50 border border-slate-200 rounded-lg p-3 space-y-2 relative\">\n                    <div className=\"flex items-center justify-between\">\n                      <Label htmlFor=\"crm-search\" className=\"text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-1.5\">\n                        <Users className=\"h-3.5 w-3.5 text-blue-550\" /> Rechercher un client du CRM (Pré-remplissage automatique)\n                      </Label>\n                      {searchCrmQuery && (\n                        <button \n                          type=\"button\"\n                          onClick={() => { setSearchCrmQuery(\"\"); setShowCrmDropdown(false); }}\n                          className=\"text-xs text-slate-400 hover:text-slate-600 font-medium\"\n                        >\n                          Effacer\n                        </button>\n                      )}\n                    </div>\n                    <div className=\"relative\">\n                      <Input\n                        id=\"crm-search\"\n                        value={searchCrmQuery}\n                        onChange={(e) => {\n                          setSearchCrmQuery(e.target.value);\n                          setShowCrmDropdown(true);\n                        }}\n                        onFocus={() => setShowCrmDropdown(true)}\n                        placeholder=\"Rechercher par nom, email, entreprise, téléphone...\"\n                        className=\"bg-white border-slate-300 focus:border-blue-500 pl-9\"\n                      />\n                      <Search className=\"absolute left-3 top-2.5 h-4 w-4 text-slate-400 pointer-events-none\" />\n                      \n                      {showCrmDropdown && searchCrmQuery.trim() !== \"\" && (\n                        <div className=\"absolute z-50 left-0 right-0 mt-1 max-h-60 overflow-y-auto bg-white border border-slate-200 rounded-lg shadow-lg divide-y divide-slate-100\">\n                          {filteredCrmCompanies.length === 0 ? (\n                            <div className=\"p-3 text-sm text-slate-400 text-center\">\n                              Aucun client trouvé dans le CRM pour \"{searchCrmQuery}\"\n                            </div>\n                          ) : (\n                            filteredCrmCompanies.map(c => {\n                              const isParticulier = c.type_client === \"Particulier\";\n                              const provenance = getCompanyProvenance(c);\n                              return (\n                                <button\n                                  key={c.id}\n                                  type=\"button\"\n                                  onClick={() => handleSelectCrmCompany(c)}\n                                  className=\"w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center justify-between gap-4 transition-colors\"\n                                >\n                                  <div className=\"min-w-0 flex-1\">\n                                    <div className=\"flex items-center gap-2\">\n                                      <span className=\"text-sm select-none shrink-0\">\n                                        {isParticulier ? \"👤\" : c.type_client === \"Association\" ? \"🤝\" : \"🏢\"}\n                                      </span>\n                                      <span className=\"font-semibold text-slate-800 text-sm truncate\">{c.nom}</span>\n                                      <Badge variant=\"outline\" className=\"text-[10px] py-0 px-1.5 font-normal select-none bg-slate-100 border-slate-200\">\n                                        {c.type_client}\n                                      </Badge>\n                                    </div>\n                                    <div className=\"flex flex-wrap gap-x-2 gap-y-0.5 text-xs text-slate-500 mt-1\">\n                                      {c.email && <span className=\"truncate\">{c.email}</span>}\n                                      {c.telephone && <span>• {c.telephone}</span>}\n                                      {c.adresse && <span className=\"truncate\">• {c.adresse}</span>}\n                                    </div>\n                                  </div>\n                                  {provenance && (\n                                    <Badge className={`text-[10px] uppercase font-semibold select-none shrink-0 ${\n                                      provenance === \"location\" ? \"bg-blue-100 text-blue-800 hover:bg-blue-100 border-blue-200\" : \"bg-purple-100 text-purple-800 hover:bg-purple-100 border-purple-200\"\n                                    }`}>\n                                      {provenance === \"location\" ? \"📦 Loc\" : \"🎵 Prest\"}\n                                    </Badge>\n                                  )}\n                                </button>\n                              );\n                            })\n                          )}\n                        </div>\n                      )}\n                    </div>\n                  </div>\n                  <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"name\" className=\"text-slate-700\">Nom complet *</Label>\n                      <Input id=\"name\" value={clientInfo.name} onChange={(e) => handleClientInfoChange(\"name\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                    </div>\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"company\" className=\"text-slate-700 flex items-center space-x-1\"><Building className=\"h-4 w-4\" /><span>Entreprise (optionnel)</span></Label>\n                      <Input id=\"company\" value={clientInfo.company} onChange={(e) => handleClientInfoChange(\"company\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                    </div>\n                  </div>\n\n                  <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"email\" className=\"text-slate-700 flex items-center space-x-1\"><Mail className=\"h-4 w-4\" /><span>Email *</span></Label>\n                      <Input id=\"email\" type=\"email\" value={clientInfo.email} onChange={(e) => handleClientInfoChange(\"email\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                    </div>\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"phone\" className=\"text-slate-700 flex items-center space-x-1\"><Phone className=\"h-4 w-4\" /><span>Téléphone</span></Label>\n                      <Input id=\"phone\" value={clientInfo.phone} onChange={(e) => handleClientInfoChange(\"phone\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                    </div>\n                  </div>\n\n                  <div className=\"space-y-2\">\n                    <Label htmlFor=\"address\" className=\"text-slate-700\">Adresse complète</Label>\n                    <Textarea id=\"address\" value={clientInfo.address} onChange={(e) => handleClientInfoChange(\"address\", e.target.value)} rows={2} className=\"border-slate-300 focus:border-blue-500\" />\n                  </div>\n\n                  <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"event_type\" className=\"text-slate-700\">Type d'événement</Label>\n                      <Select value={clientInfo.event_type} onValueChange={(value) => { handleClientInfoChange(\"event_type\", value); if (value !== \"custom\") { handleClientInfoChange(\"custom_event_type\", \"\"); } }}>\n                        <SelectTrigger className=\"border-slate-300 focus:border-blue-500\"><SelectValue placeholder=\"Sélectionner un type\" /></SelectTrigger>\n                        <SelectContent>\n                          {eventTypesList.map((type, index) => (<SelectItem key={`event-${index}-${type}`} value={type}>{type}</SelectItem>))}\n                          <SelectItem key=\"custom\" value=\"custom\">Type personnalisé</SelectItem>\n                        </SelectContent>\n                      </Select>\n                    </div>\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"event_note\" className=\"text-slate-700\">Note événement <span className=\"text-slate-400 text-xs\">(optionnel, 100 car. max)</span></Label>\n                      <Input id=\"event_note\" value={clientInfo.event_note} onChange={(e) => handleClientInfoChange(\"event_note\", e.target.value.slice(0, 100))} className=\"border-slate-300 focus:border-blue-500\" maxLength={100} />\n                    </div>\n                  </div>\n                  \n                  {clientInfo.event_type === \"custom\" && (\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"custom_event_type\" className=\"text-slate-700\">Type d'événement personnalisé</Label>\n                      <Input id=\"custom_event_type\" value={clientInfo.custom_event_type} onChange={(e) => handleClientInfoChange(\"custom_event_type\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                    </div>\n                  )}\n\n                  <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"event_date\" className=\"text-slate-700 flex items-center space-x-1\"><Calendar className=\"h-4 w-4\" /><span>Date de l'événement *</span></Label>\n                      <Input id=\"event_date\" type=\"date\" value={clientInfo.event_date} onChange={(e) => handleClientInfoChange(\"event_date\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                    </div>\n                    <div className=\"space-y-2 relative\" id=\"venue-select-container\">\n                      <Label htmlFor=\"event_location\" className=\"text-slate-700 flex items-center space-x-1\"><MapPin className=\"h-4 w-4\" /><span>Lieu de l'événement *</span></Label>\n                      <div className=\"relative\">\n                        <button\n                          type=\"button\"\n                          onClick={() => setIsVenueDropdownOpen(!isVenueDropdownOpen)}\n                          className=\"w-full text-left bg-white border border-slate-300 hover:border-slate-400 rounded-md px-3 py-2 text-sm text-slate-800 flex justify-between items-center focus:outline-none focus:ring-2 focus:ring-blue-500\"\n                        >\n                          <span className=\"truncate\">{clientInfo.event_location || \"Sélectionnez un lieu de réception...\"}</span>\n                          <span className=\"text-slate-400 text-xs\">▼</span>\n                        </button>\n\n                        {isVenueDropdownOpen && (\n                          <div className=\"absolute left-0 right-0 mt-1 bg-white border border-slate-300 rounded-md shadow-lg z-50 flex flex-col max-h-[300px] overflow-hidden\">\n                            <div className=\"p-2 border-b bg-slate-50 flex gap-2 items-center\">\n                              <Input\n                                placeholder=\"Rechercher une salle, ville...\"\n                                value={venueSearch}\n                                onChange={(e) => setVenueSearch(e.target.value)}\n                                className=\"h-8 text-xs flex-1\"\n                              />\n                              <Button\n                                type=\"button\"\n                                variant=\"ghost\"\n                                size=\"sm\"\n                                onClick={() => setIsVenueDropdownOpen(false)}\n                                className=\"h-8 px-2 text-xs\"\n                              >\n                                Fermer\n                              </Button>\n                            </div>\n\n                            <div className=\"flex-1 overflow-y-auto max-h-[200px]\">\n                              {venues.length === 0 ? (\n                                <div className=\"p-4 text-center text-xs text-slate-500\">Aucune salle disponible</div>\n                              ) : (\n                                Object.entries(\n                                  venues\n                                    .filter(v => {\n                                      const q = venueSearch.toLowerCase();\n                                      return (\n                                        (v.name || \"\").toLowerCase().includes(q) ||\n                                        (v.city || \"\").toLowerCase().includes(q) ||\n                                        (v.department || \"\").toLowerCase().includes(q)\n                                      );\n                                    })\n                                    .reduce((acc, v) => {\n                                      const dept = v.department || \"Autre\";\n                                      const city = v.city || \"Autre\";\n                                      if (!acc[dept]) acc[dept] = {};\n                                      if (!acc[dept][city]) acc[dept][city] = [];\n                                      acc[dept][city].push(v);\n                                      return acc;\n                                    }, {})\n                                ).map(([dept, cities]) => (\n                                  <div key={dept} className=\"text-xs\">\n                                    <div className=\"bg-indigo-50 text-indigo-900 font-bold px-3 py-1 uppercase tracking-wider\">{dept}</div>\n                                    {Object.entries(cities).map(([city, hallList]) => (\n                                      <div key={city} className=\"pl-2\">\n                                        <div className=\"text-slate-500 font-semibold py-0.5 uppercase text-[10px]\">{city}</div>\n                                        {hallList.map(h => (\n                                          <div\n                                            key={h.id}\n                                            onClick={() => {\n                                              handleClientInfoChange(\"event_location\", `${h.department} / ${h.city} / ${h.name}`);\n                                              setClientInfo(prev => ({ ...prev, venue_id: h.id }));\n                                              setIsVenueDropdownOpen(false);\n                                            }}\n                                            className=\"hover:bg-slate-100 pl-4 pr-3 py-1.5 cursor-pointer flex justify-between items-center text-slate-700 text-xs\"\n                                          >\n                                            <span className=\"font-medium\">{h.name}</span>\n                                            {clientInfo.venue_id === h.id && <span className=\"text-indigo-600 text-xs\">✓</span>}\n                                          </div>\n                                        ))}\n                                      </div>\n                                    ))}\n                                  </div>\n                                ))\n                              )}\n                            </div>\n\n                            <div \n                              onClick={() => {\n                                setIsNewVenueDialogOpen(true);\n                                setIsVenueDropdownOpen(false);\n                              }}\n                              className=\"bg-slate-50 border-t p-2.5 text-center text-xs text-indigo-600 hover:bg-indigo-50 font-bold cursor-pointer transition-colors\"\n                            >\n                              ➕ Ajouter un nouveau lieu de réception...\n                            </div>\n                          </div>\n                        )}\n                      </div>\n                    </div>\n                  </div>\n\n                  {/* Informations supplémentaires */}\n                  <div className=\"space-y-4 pt-4 border-t\">\n                    <h3 className=\"text-lg font-semibold text-slate-800\">Informations Supplémentaires</h3>\n                    <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"guest_count\" className=\"text-slate-700\">Nombre d'invités attendu</Label>\n                        <Input id=\"guest_count\" type=\"text\" value={clientInfo.guest_count} onChange={(e) => handleClientInfoChange(\"guest_count\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                      </div>\n                    </div>\n\n                    <div className=\"space-y-2\">\n                      <Label htmlFor=\"phone2\" className=\"text-slate-700\">Téléphone 2 (facultatif)</Label>\n                      <Input id=\"phone2\" value={clientInfo.phone2} onChange={(e) => handleClientInfoChange(\"phone2\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                    </div>\n\n                    {/* Planning de la prestation */}\n                    <div className=\"space-y-4 p-4 bg-blue-50 rounded-lg\">\n                      <h4 className=\"font-semibold text-blue-800\">Planning de la prestation</h4>\n                      <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"setup_date\" className=\"text-slate-700\">Date d'installation</Label>\n                          <Input id=\"setup_date\" type=\"date\" value={clientInfo.setup_date} onChange={(e) => handleClientInfoChange(\"setup_date\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                        </div>\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"setup_time\" className=\"text-slate-700\">Heure d'installation</Label>\n                          <Input id=\"setup_time\" type=\"text\" value={clientInfo.setup_time} onChange={(e) => handleClientInfoChange(\"setup_time\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                          <small className=\"text-slate-500 text-xs\">Par exemple: 14h00, À définir, etc.</small>\n                        </div>\n                      </div>\n                      \n                      <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"start_time\" className=\"text-slate-700\">Début de prestation</Label>\n                          <Input id=\"start_time\" type=\"time\" value={clientInfo.start_time} onChange={(e) => handleClientInfoChange(\"start_time\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                        </div>\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"end_time\" className=\"text-slate-700\">Fin de prestation</Label>\n                          <div className=\"flex items-center space-x-2\">\n                            <Input id=\"end_time\" type=\"time\" value={clientInfo.end_time} onChange={(e) => handleClientInfoChange(\"end_time\", e.target.value)} className=\"border-slate-300 focus:border-blue-500\" disabled={clientInfo.unlimited_time} />\n                            <div className=\"flex items-center space-x-1\">\n                              <Checkbox id=\"unlimited_time\" checked={clientInfo.unlimited_time} onCheckedChange={(checked) => handleClientInfoChange(\"unlimited_time\", checked)} />\n                              <Label htmlFor=\"unlimited_time\" className=\"text-sm\">Illimité</Label>\n                            </div>\n                          </div>\n                        </div>\n                      </div>\n                    </div>\n\n                    {/* Dates d'événements supplémentaires */}\n                    <div className=\"space-y-4 p-4 bg-slate-50 border border-slate-200 rounded-lg\">\n                      <div className=\"flex items-center justify-between\">\n                        <h4 className=\"font-semibold text-slate-800 flex items-center gap-2\">\n                          <Calendar className=\"h-5 w-5 text-indigo-600\" />\n                          <span>Dates d'événements supplémentaires ({clientInfo.additional_events?.length || 0})</span>\n                        </h4>\n                        <Button \n                          type=\"button\" \n                          variant=\"outline\" \n                          size=\"sm\" \n                          onClick={() => {\n                            const newEvent = {\n                              event_date: \"\",\n                              setup_date: \"\",\n                              setup_time: \"À définir\",\n                              start_time: \"\",\n                              end_time: \"\",\n                              unlimited_time: false\n                            };\n                            setClientInfo(prev => ({\n                              ...prev,\n                              additional_events: [...(prev.additional_events || []), newEvent]\n                            }));\n                          }}\n                          className=\"text-indigo-600 border-indigo-200 hover:bg-indigo-50 flex items-center gap-1.5\"\n                        >\n                          <Plus className=\"h-4 w-4\" />\n                          <span>Ajouter une date</span>\n                        </Button>\n                      </div>\n\n                      {(!clientInfo.additional_events || clientInfo.additional_events.length === 0) ? (\n                        <p className=\"text-xs text-slate-500 italic\">Aucune autre date cochée pour ce contrat.</p>\n                      ) : (\n                        <div className=\"space-y-4 mt-2\">\n                          {clientInfo.additional_events.map((evt, idx) => (\n                            <div key={`add-evt-${idx}`} className=\"p-3 bg-white border border-slate-200 rounded-md relative space-y-3\">\n                              <Button\n                                type=\"button\"\n                                variant=\"ghost\"\n                                size=\"sm\"\n                                onClick={() => {\n                                  setClientInfo(prev => ({\n                                    ...prev,\n                                    additional_events: prev.additional_events.filter((_, i) => i !== idx)\n                                  }));\n                                }}\n                                className=\"absolute right-2 top-2 h-7 w-7 p-0 text-red-500 hover:bg-red-50 hover:text-red-700\"\n                              >\n                                <Trash2 className=\"h-4 w-4\" />\n                              </Button>\n\n                              <p className=\"text-sm font-semibold text-indigo-700 pr-8\">Date supplémentaire #{idx + 2}</p>\n\n                              <div className=\"grid grid-cols-1 md:grid-cols-2 gap-3\">\n                                <div className=\"space-y-1\">\n                                  <Label className=\"text-xs text-slate-600\">Date de l'événement</Label>\n                                  <Input \n                                    type=\"date\"\n                                    value={evt.event_date || \"\"}\n                                    onChange={(e) => {\n                                      const val = e.target.value;\n                                      setClientInfo(prev => {\n                                        const copy = [...(prev.additional_events || [])];\n                                        copy[idx] = { ...copy[idx], event_date: val, setup_date: val };\n                                        return { ...prev, additional_events: copy };\n                                      });\n                                    }}\n                                    className=\"h-8 text-xs border-slate-300 focus:border-indigo-500\"\n                                  />\n                                </div>\n                                <div className=\"space-y-1\">\n                                  <Label className=\"text-xs text-slate-600\">Date d'installation</Label>\n                                  <Input \n                                    type=\"date\"\n                                    value={evt.setup_date || \"\"}\n                                    onChange={(e) => {\n                                      const val = e.target.value;\n                                      setClientInfo(prev => {\n                                        const copy = [...(prev.additional_events || [])];\n                                        copy[idx] = { ...copy[idx], setup_date: val };\n                                        return { ...prev, additional_events: copy };\n                                      });\n                                    }}\n                                    className=\"h-8 text-xs border-slate-300 focus:border-indigo-500\"\n                                  />\n                                </div>\n                              </div>\n\n                              <div className=\"grid grid-cols-1 md:grid-cols-3 gap-3\">\n                                <div className=\"space-y-1\">\n                                  <Label className=\"text-xs text-slate-600\">Heure d'installation</Label>\n                                  <Input \n                                    type=\"text\"\n                                    placeholder=\"Ex: 14h00, À définir\"\n                                    value={evt.setup_time || \"À définir\"}\n                                    onChange={(e) => {\n                                      const val = e.target.value;\n                                      setClientInfo(prev => {\n                                        const copy = [...(prev.additional_events || [])];\n                                        copy[idx] = { ...copy[idx], setup_time: val };\n                                        return { ...prev, additional_events: copy };\n                                      });\n                                    }}\n                                    className=\"h-8 text-xs border-slate-300 focus:border-indigo-500\"\n                                  />\n                                </div>\n                                <div className=\"space-y-1\">\n                                  <Label className=\"text-xs text-slate-600\">Début de prestation</Label>\n                                  <Input \n                                    type=\"time\"\n                                    value={evt.start_time || \"\"}\n                                    onChange={(e) => {\n                                      const val = e.target.value;\n                                      setClientInfo(prev => {\n                                        const copy = [...(prev.additional_events || [])];\n                                        copy[idx] = { ...copy[idx], start_time: val };\n                                        return { ...prev, additional_events: copy };\n                                      });\n                                    }}\n                                    className=\"h-8 text-xs border-slate-300 focus:border-indigo-500\"\n                                  />\n                                </div>\n                                <div className=\"space-y-1\">\n                                  <Label className=\"text-xs text-slate-600\">Fin de prestation</Label>\n                                  <div className=\"flex items-center space-x-2\">\n                                    <Input \n                                      type=\"time\"\n                                      value={evt.end_time || \"\"}\n                                      onChange={(e) => {\n                                        const val = e.target.value;\n                                        setClientInfo(prev => {\n                                          const copy = [...(prev.additional_events || [])];\n                                          copy[idx] = { ...copy[idx], end_time: val };\n                                          return { ...prev, additional_events: copy };\n                                        });\n                                      }}\n                                      disabled={evt.unlimited_time}\n                                      className=\"h-8 text-xs border-slate-300 focus:border-indigo-500 flex-1\"\n                                    />\n                                    <div className=\"flex items-center space-x-1\">\n                                      <Checkbox \n                                        id={`unlimited-${idx}`}\n                                        checked={evt.unlimited_time || false}\n                                        onCheckedChange={(checked) => {\n                                          setClientInfo(prev => {\n                                            const copy = [...(prev.additional_events || [])];\n                                            copy[idx] = { ...copy[idx], unlimited_time: checked };\n                                            return { ...prev, additional_events: copy };\n                                          });\n                                        }}\n                                      />\n                                      <Label htmlFor={`unlimited-${idx}`} className=\"text-xs\">Illimité</Label>\n                                    </div>\n                                  </div>\n                                </div>\n                              </div>\n                            </div>\n                          ))}\n                        </div>\n                      )}\n                    </div>\n\n                    {/* Catering - Stacked Minimalist Design */}\n                    <div className=\"pt-5 border-t border-slate-200/80 space-y-4\">\n                      <Label className=\"text-slate-700 font-semibold block text-base\">Catering (Restauration Artiste)</Label>\n\n                      <div className=\"space-y-4\">\n                        {/* Line 1: Plat chaud hors table with Stepper */}\n                        <div className=\"flex flex-col sm:flex-row sm:items-center justify-between py-2 border-b border-slate-100 gap-3\">\n                          <label htmlFor=\"cateringHotMealNoTableInput\" className=\"text-sm font-medium text-slate-700 cursor-pointer select-none flex items-center gap-3\">\n                            <Checkbox \n                              id=\"cateringHotMealNoTableInput\" \n                              checked={cateringHotMealNoTable} \n                              onCheckedChange={(checked) => {\n                                setCateringHotMealNoTable(checked);\n                                if (checked && (!cateringHotMealNoTableQty || Number(cateringHotMealNoTableQty) === 0)) {\n                                  setCateringHotMealNoTableQty(1);\n                                } else if (!checked) {\n                                  setCateringHotMealNoTableQty(0);\n                                }\n                              }} \n                            />\n                            <span className=\"text-slate-800\">Plat chaud (pas de place à table)</span>\n                          </label>\n\n                          {cateringHotMealNoTable && (\n                            <div className=\"flex items-center space-x-2\">\n                              <span className=\"text-xs text-slate-500 font-medium\">Quantité :</span>\n                              <div className=\"flex items-center border border-slate-300 rounded-lg bg-white overflow-hidden shadow-sm\">\n                                <button\n                                  type=\"button\"\n                                  onClick={() => {\n                                    const nextQty = Math.max(0, Number(cateringHotMealNoTableQty) - 1);\n                                    setCateringHotMealNoTableQty(nextQty);\n                                    if (nextQty === 0) {\n                                      setCateringHotMealNoTable(false);\n                                    }\n                                  }}\n                                  className=\"h-8 w-8 flex items-center justify-center text-slate-600 hover:bg-slate-50 active:scale-95 transition-all text-lg font-semibold border-r border-slate-200\"\n                                >\n                                  <Minus className=\"h-3 w-3\" />\n                                </button>\n                                <input \n                                  type=\"number\"\n                                  min=\"0\"\n                                  value={cateringHotMealNoTableQty}\n                                  onChange={e => {\n                                    const valStr = e.target.value;\n                                    const valNum = valStr === '' ? 0 : (parseInt(valStr, 10) || 0);\n                                    setCateringHotMealNoTableQty(valNum);\n                                    if (valNum > 0) {\n                                      setCateringHotMealNoTable(true);\n                                    } else {\n                                      setCateringHotMealNoTable(false);\n                                    }\n                                  }}\n                                  className=\"w-10 h-8 text-center text-sm font-bold border-0 focus:outline-none focus:ring-0 text-slate-800 bg-transparent [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none\"\n                                />\n                                <button\n                                  type=\"button\"\n                                  onClick={() => {\n                                    setCateringHotMealNoTableQty(Number(cateringHotMealNoTableQty) + 1);\n                                  }}\n                                  className=\"h-8 w-8 flex items-center justify-center text-slate-600 hover:bg-slate-50 active:scale-95 transition-all text-lg font-semibold border-l border-slate-200\"\n                                >\n                                  <Plus className=\"h-3 w-3\" />\n                                </button>\n                              </div>\n                            </div>\n                          )}\n                        </div>\n\n                        {/* Line 2: Boissons comprises */}\n                        <div className=\"flex items-center py-2 border-b border-slate-100\">\n                          <label htmlFor=\"cateringDrinksInput\" className=\"text-sm font-medium text-slate-700 cursor-pointer select-none flex items-center gap-3\">\n                            <Checkbox \n                              id=\"cateringDrinksInput\" \n                              checked={cateringDrinks} \n                              onCheckedChange={setCateringDrinks} \n                            />\n                            <span className=\"text-slate-800\">Boissons comprises (softs et boissons chaudes)</span>\n                          </label>\n                        </div>\n\n                        {/* Line 3: Conditions de repas / Notes - Champ libre */}\n                        <div className=\"space-y-1.5 pt-1\">\n                          <Label htmlFor=\"cateringNotesInput\" className=\"text-xs font-semibold text-slate-500 uppercase tracking-wider\">Conditions de repas / Remarques</Label>\n                          <Input \n                            id=\"cateringNotesInput\"\n                            value={cateringNotes} \n                            onChange={(e) => setCateringNotes(e.target.value)} \n                            placeholder=\"Ex: Plat chaud, dessert, sans porc, etc.\" \n                            className=\"border-slate-300 hover:border-slate-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 rounded-lg w-full text-slate-800 h-10 font-normal text-sm\" \n                          />\n                        </div>\n                      </div>\n                    </div>\n                  </div>\n                </CardContent>\n              </Card>\n\n              {/* Section Programme Show Hypnose */}\n              {clientInfo.event_type === \"Show Hypnose\" && (\n                <div className=\"lg:col-span-2\">\n                  <Card className=\"shadow-lg border-0 bg-gradient-to-r from-purple-600 to-pink-600 text-white\">\n                    <CardHeader className=\"pb-4\">\n                      <CardTitle className=\"text-center text-xl font-bold flex items-center justify-center\">Programme Show Hypnose - Déroulement du Jour J</CardTitle>\n                      <CardDescription className=\"text-center text-purple-100\">Planning détaillé modifiable selon vos besoins</CardDescription>\n                    </CardHeader>\n                    <CardContent className=\"space-y-6\">\n                      {/* Planning de la journée */}\n                      <div className=\"bg-white/10 rounded-lg p-4 space-y-4\">\n                        <h3 className=\"font-semibold text-lg mb-4\">Planning de la journée</h3>\n                        <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Arrivée des techniciens</Label><Input type=\"time\" value={hypnosisProgram.techniciansArrival} onChange={(e) => setHypnosisProgram(prev => ({...prev, techniciansArrival: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Repas des techniciens</Label><Input type=\"time\" value={hypnosisProgram.techniciansLunch} onChange={(e) => setHypnosisProgram(prev => ({...prev, techniciansLunch: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Réglages son et lumières</Label><Input value={hypnosisProgram.soundLightAdjustments} onChange={(e) => setHypnosisProgram(prev => ({...prev, soundLightAdjustments: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Arrivée de l'artiste</Label><Input type=\"time\" value={hypnosisProgram.artistArrival} onChange={(e) => setHypnosisProgram(prev => ({...prev, artistArrival: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                        </div>\n                      </div>\n\n                      {/* Catering */}\n                      <div className=\"bg-white/10 rounded-lg p-4 space-y-4\">\n                        <h3 className=\"font-semibold text-lg mb-4\">Catering pour les techniciens</h3>\n                        <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Nombre de repas midi</Label><Input type=\"number\" min=\"0\" value={hypnosisProgram.cateringLunchCount} onChange={(e) => setHypnosisProgram(prev => ({...prev, cateringLunchCount: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Nombre de repas soir</Label><Input type=\"number\" min=\"0\" value={hypnosisProgram.cateringDinnerCount} onChange={(e) => setHypnosisProgram(prev => ({...prev, cateringDinnerCount: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                        </div>\n                      </div>\n\n                      {/* Planning du spectacle */}\n                      <div className=\"bg-white/10 rounded-lg p-4 space-y-4\">\n                        <h3 className=\"font-semibold text-lg mb-4\">Planning du spectacle</h3>\n                        <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Ouverture des portes</Label><Input type=\"time\" value={hypnosisProgram.doorsOpen} onChange={(e) => setHypnosisProgram(prev => ({...prev, doorsOpen: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Début du spectacle</Label><Input type=\"time\" value={hypnosisProgram.showStartTime} onChange={(e) => setHypnosisProgram(prev => ({...prev, showStartTime: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Entracte</Label><Input type=\"time\" value={hypnosisProgram.intermissionTime} onChange={(e) => setHypnosisProgram(prev => ({...prev, intermissionTime: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Durée entracte (minutes)</Label><Input type=\"number\" value={hypnosisProgram.intermissionDuration} onChange={(e) => setHypnosisProgram(prev => ({...prev, intermissionDuration: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Reprise du spectacle</Label><Input type=\"time\" value={hypnosisProgram.secondPartTime} onChange={(e) => setHypnosisProgram(prev => ({...prev, secondPartTime: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Fin du spectacle</Label><Input type=\"time\" value={hypnosisProgram.showEndTime} onChange={(e) => setHypnosisProgram(prev => ({...prev, showEndTime: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                        </div>\n                      </div>\n\n                      {/* Après-spectacle */}\n                      <div className=\"bg-white/10 rounded-lg p-4 space-y-4\">\n                        <h3 className=\"font-semibold text-lg mb-4\">Après-spectacle</h3>\n                        <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                          <div className=\"space-y-2\"><Label className=\"text-white/90\">Fin du démontage</Label><Input type=\"time\" value={hypnosisProgram.dismantlingEnd} onChange={(e) => setHypnosisProgram(prev => ({...prev, dismantlingEnd: e.target.value}))} className=\"bg-white/20 border-white/30 text-white placeholder-white/70\" /></div>\n                        </div>\n                      </div>\n\n                      <div className=\"flex justify-center pt-4\">\n                        <Button type=\"button\" onClick={() => setHypnosisProgram(defaultHypnosisProgram)} className=\"bg-white/20 hover:bg-white/30 text-white border-white/30\">Réinitialiser aux horaires par défaut</Button>\n                      </div>\n                    </CardContent>\n                  </Card>\n                  \n                  {/* Contact Technicien de Salle */}\n                  <Card className=\"shadow-lg border-0 bg-gradient-to-r from-blue-500 to-teal-600 text-white mt-6\">\n                    <CardHeader className=\"pb-4\">\n                      <CardTitle className=\"text-center text-xl font-bold\">Contact Technicien de Salle</CardTitle>\n                      <CardDescription className=\"text-center text-blue-100\">Coordonnées du technicien pour la coordination technique</CardDescription>\n                    </CardHeader>\n                    <CardContent className=\"space-y-4\">\n                      <div className=\"space-y-2\"><Label className=\"text-white font-medium\">Nom & Prénom</Label><Input value={technicianContact.name} onChange={(e) => setTechnicianContact(prev => ({ ...prev, name: e.target.value }))} className=\"bg-white/10 border-white/20 text-white placeholder-white/60 focus:bg-white/20\" /></div>\n                      <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                        <div className=\"space-y-2\"><Label className=\"text-white font-medium\">Adresse email</Label><Input type=\"email\" value={technicianContact.email} onChange={(e) => setTechnicianContact(prev => ({ ...prev, email: e.target.value }))} className=\"bg-white/10 border-white/20 text-white placeholder-white/60 focus:bg-white/20\" /></div>\n                        <div className=\"space-y-2\"><Label className=\"text-white font-medium\">Numéro de téléphone</Label><Input type=\"tel\" value={technicianContact.phone} onChange={(e) => setTechnicianContact(prev => ({ ...prev, phone: e.target.value }))} className=\"bg-white/10 border-white/20 text-white placeholder-white/60 focus:bg-white/20\" /></div>\n                      </div>\n                    </CardContent>\n                  </Card>\n                </div>\n              )}\n\n              {/* Options et Tarifs pour Show Hypnose et Intervention hypnose */}\n              {['Show Hypnose', 'Intervention hypnose'].includes(clientInfo.event_type) && (\n                <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                  <CardHeader className=\"pb-4\">\n                    <CardTitle className=\"text-slate-800\">Tarifs et Paiement</CardTitle>\n                    <CardDescription>Configurez le tarif et les conditions de paiement</CardDescription>\n                  </CardHeader>\n                  <CardContent className=\"space-y-4\">\n                    <div className=\"space-y-2\"><Label className=\"text-slate-700\">Prix de base</Label><div className=\"flex items-center space-x-2\"><Euro className=\"h-4 w-4 text-slate-500\" /><Input type=\"number\" value={basePrice} onChange={(e) => setBasePrice(Number(e.target.value))} className=\"border-slate-300 focus:border-blue-500 w-32\" min=\"0\" step=\"10\" /></div></div>\n                    <div className=\"space-y-2\"><Label className=\"text-slate-700\">Remise (optionnel)</Label><div className=\"flex items-center space-x-2\"><Euro className=\"h-4 w-4 text-slate-500\" /><Input type=\"number\" value={discountAmount} onChange={(e) => setDiscountAmount(Number(e.target.value))} className=\"border-slate-300 focus:border-blue-500 w-32\" min=\"0\" step=\"5\" /></div></div>\n                    <Separator />\n                    <div className=\"space-y-2\"><Label className=\"text-slate-700\">Acompte personnalisé (optionnel)</Label><div className=\"flex items-center space-x-2\"><Euro className=\"h-4 w-4 text-slate-500\" /><Input type=\"number\" value={customDepositAmount} onChange={(e) => setCustomDepositAmount(Number(e.target.value))} className=\"border-slate-300 focus:border-blue-500 w-32\" min=\"0\" step=\"10\" /></div><p className=\"text-xs text-slate-500\">Par défaut: {clientInfo?.company?.trim() ? \"30%\" : \"50%\"} du tarif de base</p></div>\n                    <div className=\"flex items-center space-x-2\"><Checkbox id=\"no_deposit_hypnosis\" checked={noDepositRequired} onCheckedChange={(checked) => setNoDepositRequired(checked)} /><Label htmlFor=\"no_deposit_hypnosis\" className=\"text-sm font-normal cursor-pointer\">Client de confiance - Aucun acompte requis</Label></div>\n                    <Separator />\n                    <div className=\"bg-blue-50 border border-blue-200 rounded-lg p-4 space-y-2\">\n                      <h3 className=\"font-semibold text-slate-800 text-sm\">Récapitulatif financier</h3>\n                      <div className=\"space-y-1 text-sm\">\n                        <div className=\"flex justify-between\"><span>Tarif de base :</span><span className=\"font-medium\">{basePrice.toFixed(2)} €</span></div>\n                        {discountAmount > 0 && <div className=\"flex justify-between text-red-600\"><span>Remise :</span><span className=\"font-medium\">-{discountAmount.toFixed(2)} €</span></div>}\n                        <Separator />\n                        <div className=\"flex justify-between font-bold\"><span>Total TTC :</span><span>{calculateTotal().toFixed(2)} €</span></div>\n                        <div className=\"flex justify-between text-blue-600\"><span>Acompte :</span><span className=\"font-medium\">{calculateDepositAmount().toFixed(2)} €</span></div>\n                        <div className=\"flex justify-between text-green-600\"><span>Solde à régler :</span><span className=\"font-medium\">{calculateRemainingBalance().toFixed(2)} €</span></div>\n                        {(() => {\n                          const hasFreelance = contractMode === 'entreprise' && (selectedDjProfile === \"\" || isArtistFreelance(getProfileData(selectedDjProfile)));\n                          if (!hasFreelance) return null;\n\n                          const optionsTotalForMargin = (selectedOptions || [])\n                            .filter(option => option.selected && !option.is_addition_post_signature && !option.added_post_signature)\n                            .reduce((sum, option) => sum + option.price, 0);\n\n                          const baseTTC = Math.max(0, basePrice - discountAmount);\n                          const baseHT = baseTTC / 1.2;\n\n                          const optionsTTC = optionsTotalForMargin;\n                          const optionsHT = optionsTTC / 1.2;\n\n                          const totalTTC = baseTTC + optionsTTC;\n                          const totalHT = totalTTC / 1.2;\n\n                          let baseCachetDJ = 0;\n                          if (totalTTC > 1500) {\n                            baseCachetDJ = 900;\n                          } else {\n                            baseCachetDJ = baseHT * 0.6428;\n                          }\n\n                          const optionsCachetDJ = optionsHT * 0.20;\n                          const cachetDJRaw = baseCachetDJ + optionsCachetDJ;\n                          let cachetDJ = Math.floor(cachetDJRaw / 10) * 10;\n                          if (cachetDJ > freelanceCachetCap) {\n                            cachetDJ = freelanceCachetCap;\n                          }\n\n                          const marginHT = totalHT - cachetDJ;\n                          const acompteTTC = Math.ceil((marginHT * 1.2) / 5) * 5;\n                          const soldeTTC = totalTTC - acompteTTC;\n\n                          return (\n                            <div className=\"mt-3 pt-3 border-t border-blue-200 text-xs space-y-2\">\n                              <div className=\"flex items-center justify-between text-blue-700 font-bold mb-1\">\n                                <span>⚙️ MARGE INTERNE {selectedDjProfile === \"\" ? \"(SIMULÉE)\" : \"\"} :</span>\n                                <span className=\"text-[10px] bg-blue-100 px-1.5 py-0.5 rounded text-blue-800\">\n                                  {selectedDjProfile === \"\" ? \"Sans artiste\" : \"Freelance\"}\n                                </span>\n                              </div>\n                              <div className=\"grid grid-cols-2 gap-y-1 bg-white/80 p-2.5 rounded border border-blue-100 font-mono text-[11px] text-slate-700\">\n                                <div className=\"text-slate-500\">Total HT :</div>\n                               <div className=\"text-right font-semibold\">{totalHT.toFixed(2)} €</div>\n                                \n                               <div className=\"text-slate-500\">Cachet du DJ hors-taxe (Plafond {freelanceCachetCap} €) :</div>\n                               <div className=\"text-right font-semibold text-purple-600\">{cachetDJ.toFixed(2)} €</div>\n                                \n                               <div className=\"text-slate-500\">Marge Brute HT :</div>\n                               <div className=\"text-right font-bold text-emerald-600\">{marginHT.toFixed(2)} €</div>\n                                \n                               <div className=\"col-span-2 border-t border-dashed border-slate-200 my-1\"></div>\n                                \n                               <div className=\"text-blue-700 font-semibold\">Acompte (Marge TTC) :</div>\n                               <div className=\"text-right font-bold text-blue-700\">{acompteTTC.toFixed(2)} €</div>\n                                \n                               <div className=\"text-green-700 font-semibold\">Solde (Cachet DJ TTC) :</div>\n                               <div className=\"text-right font-bold text-green-700\">{soldeTTC.toFixed(2)} €</div>\n                              </div>\n                            </div>\n                          );\n                        })()}\n                      </div>\n                    </div>\n                    <Textarea value={optionsTarifNotes} onChange={(e) => setOptionsTarifNotes(e.target.value)} className=\"border-slate-300 focus:border-blue-500\" rows={3} />\n                  </CardContent>\n                </Card>\n              )}\n\n              {/* Tarifs - Contrats 2 (adaptatif Dirigeant / Mandat) */}\n              {!['Show Hypnose', 'Intervention hypnose'].includes(clientInfo.event_type) && (\n              <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                <CardHeader className=\"pb-4\">\n                  <CardTitle className=\"text-slate-800 flex items-center gap-2\">\n                    {isDirigeant() ? 'Options et Tarifs' : 'Tarifs & Répartition'}\n                    {selectedDjProfile && !isDirigeant() && (\n                      contractMode === 'entreprise' ? (\n                        <Badge className=\"bg-blue-600 text-white text-xs\">Mode Entreprise</Badge>\n                      ) : (\n                        <Badge className=\"bg-amber-500 text-white text-xs\">Mode Mandat</Badge>\n                      )\n                    )}\n                  </CardTitle>\n                  <CardDescription>{isDirigeant() ? 'Configurez les options et le tarif du contrat' : 'Répartition des montants entre l\\'agence et l\\'artiste'}</CardDescription>\n                </CardHeader>\n                <CardContent className=\"space-y-4\">\n                  {/* Prix de base & Plafond DJ Freelance */}\n                  <div className=\"flex flex-wrap gap-4 items-end bg-slate-50/50 p-4 rounded-lg border border-slate-100\">\n                    {/* Prix de base simple - Non modifiable en mode mandat */}\n                    <div className=\"space-y-2\">\n                      <Label className=\"text-slate-700\">Prix de base (TTC)</Label>\n                      <div className=\"flex items-center space-x-2\">\n                        <Euro className=\"h-4 w-4 text-slate-500\" />\n                        <Input \n                          type=\"number\" \n                          value={basePrice} \n                          onChange={(e) => setBasePrice(Number(e.target.value))} \n                          disabled={!(isDirigeant() || contractMode === 'entreprise')}\n                          className={`w-32 font-bold ${!(isDirigeant() || contractMode === 'entreprise') ? \"border-slate-200 bg-slate-50 text-slate-400 cursor-not-allowed\" : \"border-slate-300 focus:border-blue-500\"}`} \n                          min=\"0\" \n                          step=\"10\" \n                        />\n                      </div>\n                    </div>\n\n                    {/* Plafond Cachet DJ Freelance */}\n                    {contractMode === 'entreprise' && (selectedDjProfile === \"\" || isArtistFreelance(getProfileData(selectedDjProfile))) && (\n                      <div className=\"space-y-2\">\n                        <Label className=\"text-slate-700 font-semibold flex items-center gap-1.5\">\n                          Plafond DJ freelance HT\n                        </Label>\n                        <div className=\"flex items-center space-x-2\">\n                          <Euro className=\"h-4 w-4 text-purple-500\" />\n                          <Input \n                            type=\"number\" \n                            value={freelanceCachetCap} \n                            onChange={(e) => setFreelanceCachetCap(Number(e.target.value) || 0)} \n                            className=\"border-slate-300 focus:border-purple-500 w-32 font-bold\" \n                            min=\"0\" \n                            step=\"50\" \n                          />\n                        </div>\n                      </div>\n                    )}\n                  </div>\n\n                  {/* Mode Mandat: Frais + Cachet */}\n                  {!isDirigeant() && contractMode === 'mandataire' && (\n                    <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                      <div className=\"space-y-2 p-4 bg-orange-50 rounded-lg border border-orange-200\">\n                        <Label className=\"text-orange-800 font-semibold\">Frais de Mandat & Gestion</Label>\n                        <p className=\"text-xs text-orange-600\">Part R'KEY PROD</p>\n                        <div className=\"flex items-center space-x-2\">\n                          <Euro className=\"h-4 w-4 text-orange-500\" />\n                          <Input \n                            type=\"number\" \n                            value={fraisMandat} \n                            onChange={(e) => {\n                              const newFrais = Number(e.target.value) || 0;\n                              setFraisMandat(newFrais);\n                              setBasePrice(newFrais + cachetArtiste);\n                            }} \n                            className=\"border-orange-300 focus:border-orange-500 w-full font-bold [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none\" \n                            min=\"0\" \n                            step=\"10\" \n                            data-testid=\"frais-mandat-input\" \n                          />\n                        </div>\n                      </div>\n                      <div className=\"space-y-2 p-4 bg-purple-50 rounded-lg border border-purple-200\">\n                        <Label className=\"text-purple-800 font-semibold\">Cachet Artiste</Label>\n                        <p className=\"text-xs text-purple-600\">Part du DJ partenaire</p>\n                        <div className=\"flex items-center space-x-2\">\n                          <Euro className=\"h-4 w-4 text-purple-500\" />\n                          <Input \n                            type=\"number\" \n                            value={cachetArtiste} \n                            onChange={(e) => {\n                              const newCachet = Number(e.target.value) || 0;\n                              setCachetArtiste(newCachet);\n                              setBasePrice(fraisMandat + newCachet);\n                            }} \n                            className=\"border-purple-300 focus:border-purple-500 w-full font-bold [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none\" \n                            min=\"0\" \n                            step=\"10\" \n                            data-testid=\"cachet-artiste-input\" \n                          />\n                        </div>\n                      </div>\n                    </div>\n                  )}\n\n                  <div className=\"space-y-2\"><Label className=\"text-slate-700\">Remise (optionnel)</Label><div className=\"flex items-center space-x-2\"><Euro className=\"h-4 w-4 text-slate-500\" /><Input type=\"number\" value={discountAmount} onChange={(e) => setDiscountAmount(Number(e.target.value))} className=\"border-slate-300 focus:border-blue-500 w-32\" min=\"0\" step=\"5\" /></div></div>\n\n                  <Separator />\n\n                  {/* Options Matériel (communes aux deux modes) */}\n                  <div className=\"grid grid-cols-1 gap-3\">\n                    {selectedOptions.filter(opt => !opt.event_categories || opt.event_categories.length === 0 || opt.event_categories.includes(clientInfo.event_type)).map((option) => (\n                      <div key={option.id} className={`p-3 rounded-lg border-2 transition-all cursor-pointer ${option.selected ? \"border-blue-500 bg-blue-50\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleOptionToggle(option.id)}>\n                        <div className=\"flex items-center justify-between\">\n                          <div className=\"flex items-center space-x-3\">\n                            <Checkbox checked={option.selected} readOnly />\n                            <div><p className=\"font-medium text-slate-800\">{option.name}</p><Badge variant=\"secondary\" className=\"mt-1\">{option.price}€</Badge></div>\n                          </div>\n                        </div>\n                      </div>\n                    ))}\n                  </div>\n\n\n                  <Separator />\n\n                  {/* Récapitulatif */}\n                  <div className={`p-4 rounded-lg border ${(isDirigeant() || contractMode === 'entreprise') ? 'bg-blue-50 border-blue-200' : 'bg-gradient-to-r from-blue-50 to-purple-50 border-blue-200'}`}>\n                    <div className=\"space-y-2 text-sm\">\n                      {(isDirigeant() || contractMode === 'entreprise') ? (\n                        <>\n                          <div className=\"flex justify-between\"><span>Tarif de base :</span><span className=\"font-medium\">{basePrice.toFixed(2)} €</span></div>\n                          {selectedOptions.filter(o => o.selected).map(o => (\n                            <div key={o.id} className=\"flex justify-between text-slate-600\"><span>{o.name} :</span><span className=\"font-medium\">{o.price.toFixed(2)} €</span></div>\n                          ))}\n                        </>\n                      ) : (\n                        <>\n                          <div className=\"flex justify-between\"><span className=\"text-orange-700\">Frais de Mandat & Gestion :</span><span className=\"font-medium\">{fraisMandat.toFixed(2)} €</span></div>\n                          <div className=\"flex justify-between\"><span className=\"text-purple-700\">Cachet Artiste :</span><span className=\"font-medium\">{cachetArtiste.toFixed(2)} €</span></div>\n                          {selectedOptions.filter(o => o.selected).map(o => (\n                            <div key={o.id} className=\"flex justify-between text-slate-600\"><span>{o.name} :</span><span className=\"font-medium\">{o.price.toFixed(2)} €</span></div>\n                          ))}\n                        </>\n                      )}\n                      {discountAmount > 0 && <div className=\"flex justify-between text-red-600\"><span>Remise :</span><span className=\"font-medium\">-{discountAmount.toFixed(2)} €</span></div>}\n                      <Separator />\n                      <div className=\"flex justify-between items-center pt-1\">\n                        <span className=\"text-lg font-bold text-slate-800\">Total {isDirigeant() ? '' : 'Client'} :</span>\n                        <span className=\"text-2xl font-bold text-blue-600\">{calculateTotal().toFixed(2)} €</span>\n                      </div>\n                      {(() => {\n                        const hasFreelance = contractMode === 'entreprise' && (selectedDjProfile === \"\" || isArtistFreelance(getProfileData(selectedDjProfile)));\n                        if (!hasFreelance) return null;\n\n                        const optionsTotalForMargin = (selectedOptions || [])\n                          .filter(option => option.selected && !option.is_addition_post_signature && !option.added_post_signature)\n                          .reduce((sum, option) => sum + option.price, 0);\n\n                        const baseTTC = Math.max(0, basePrice - discountAmount);\n                        const baseHT = baseTTC / 1.2;\n\n                        const optionsTTC = optionsTotalForMargin;\n                        const optionsHT = optionsTTC / 1.2;\n\n                        const totalTTC = baseTTC + optionsTTC;\n                        const totalHT = totalTTC / 1.2;\n\n                        let baseCachetDJ = 0;\n                        if (totalTTC > 1500) {\n                          baseCachetDJ = 900;\n                        } else {\n                          baseCachetDJ = baseHT * 0.6428;\n                        }\n\n                        const optionsCachetDJ = optionsHT * 0.20;\n                        const cachetDJRaw = baseCachetDJ + optionsCachetDJ;\n                        let cachetDJ = Math.floor(cachetDJRaw / 10) * 10;\n                        if (cachetDJ > freelanceCachetCap) {\n                          cachetDJ = freelanceCachetCap;\n                        }\n\n                        const marginHT = totalHT - cachetDJ;\n                        const acompteTTC = Math.ceil((marginHT * 1.2) / 5) * 5;\n                        const soldeTTC = totalTTC - acompteTTC;\n\n                        return (\n                          <div className=\"mt-3 pt-3 border-t border-blue-200 text-xs space-y-2\">\n                            <div className=\"flex items-center justify-between text-blue-700 font-bold mb-1\">\n                              <span>⚙️ MARGE INTERNE {selectedDjProfile === \"\" ? \"(SIMULÉE)\" : \"\"} :</span>\n                              <span className=\"text-[10px] bg-blue-100 px-1.5 py-0.5 rounded text-blue-800\">\n                                {selectedDjProfile === \"\" ? \"Sans artiste\" : \"Freelance\"}\n                              </span>\n                            </div>\n                            <div className=\"grid grid-cols-2 gap-y-1 bg-white/80 p-2.5 rounded border border-blue-100 font-mono text-[11px] text-slate-700\">\n                              <div className=\"text-slate-500\">Total HT :</div>\n                              <div className=\"text-right font-semibold\">{totalHT.toFixed(2)} €</div>\n                              \n                              <div className=\"text-slate-500\">Cachet du DJ hors-taxe (Plafond {freelanceCachetCap} €) :</div>\n                              <div className=\"text-right font-semibold text-purple-600\">{cachetDJ.toFixed(2)} €</div>\n                              \n                              <div className=\"text-slate-500\">Marge Brute HT :</div>\n                              <div className=\"text-right font-bold text-emerald-600\">{marginHT.toFixed(2)} €</div>\n                              \n                              <div className=\"col-span-2 border-t border-dashed border-slate-200 my-1\"></div>\n                              \n                              <div className=\"text-blue-700 font-semibold\">Acompte (Marge TTC) :</div>\n                              <div className=\"text-right font-bold text-blue-700\">{acompteTTC.toFixed(2)} €</div>\n                              \n                              <div className=\"text-green-700 font-semibold\">Solde (Cachet DJ TTC) :</div>\n                              <div className=\"text-right font-bold text-green-700\">{soldeTTC.toFixed(2)} €</div>\n                            </div>\n                          </div>\n                        );\n                      })()}\n                    </div>\n                  </div>\n\n                  <div className=\"space-y-2\">\n                    <Label className=\"text-slate-700\">Notes sur les tarifs (optionnel)</Label>\n                    <textarea value={optionsTarifNotes} onChange={(e) => setOptionsTarifNotes(e.target.value)} className=\"flex min-h-[80px] w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50\" rows={3} />\n                  </div>\n                </CardContent>\n              </Card>\n              )}\n\n              {/* Section Organisation et notes DJ (Nouveau) */}\n              {!['Show Hypnose', 'Intervention hypnose'].includes(clientInfo.event_type) && (\n              <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                <CardHeader className=\"pb-4\">\n                  <CardTitle className=\"text-slate-800\">Organisation et notes DJ</CardTitle>\n                  <CardDescription>Sélectionnez les documents à inclure dans le Guide Organisation</CardDescription>\n                </CardHeader>\n                <CardContent className=\"space-y-4\">\n                  <div className=\"space-y-2 pb-4 border-b\">\n                     <Label className=\"text-slate-700\">Notes DJ complémentaires (visible uniquement par le DJ)</Label>\n                     <Textarea value={djNotes} onChange={(e) => setDjNotes(e.target.value)} rows={3} className=\"border-slate-300 focus:border-blue-500\" placeholder=\"Informations complémentaires, remarques particulières...\" />\n                  </div>\n                  <div className=\"grid grid-cols-1 gap-3\">\n                    {/* PDF uploadés */}\n                    {pdfNotes.map((note) => (\n                      <div \n                        key={note.id} \n                        className={`p-3 rounded-lg border-2 transition-all cursor-pointer ${selectedPdfNotes.includes(note.id) ? \"border-blue-500 bg-blue-50\" : \"border-slate-200 bg-white hover:border-slate-300\"}`}\n                        onClick={() => {\n                          setSelectedPdfNotes(prev => prev.includes(note.id) ? prev.filter(i => i !== note.id) : [...prev, note.id]);\n                        }}\n                      >\n                        <div className=\"flex items-center justify-between\">\n                          <div className=\"flex items-center space-x-3 flex-1\">\n                            <Checkbox checked={selectedPdfNotes.includes(note.id)} readOnly />\n                            <div className=\"flex-1\">\n                              <p className=\"font-medium text-slate-800\">{note.title}</p>\n                              <p className=\"text-xs text-slate-500\">Document PDF</p>\n                            </div>\n                          </div>\n                        </div>\n                      </div>\n                    ))}\n                  </div>\n\n                  {/* Informations techniques de la salle */}\n                  <div className=\"space-y-2 pt-4 border-t mt-4\">\n                    <Label className=\"text-slate-700 font-semibold\">Informations techniques de la salle</Label>\n                    <p className=\"text-xs text-slate-500 mb-2\">Ces informations apparaîtront dans le PDF du contrat</p>\n                    <div className=\"grid grid-cols-1 md:grid-cols-3 gap-3\">\n                      <div className={`p-3 rounded-lg border-2 transition-all cursor-pointer ${hasLimiteurSon ? \"border-orange-500 bg-orange-50\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => { setHasLimiteurSon(!hasLimiteurSon); if (!hasLimiteurSon) setHasNoLimiteurNiDetecteur(false); }}>\n                        <div className=\"flex items-center space-x-3\"><Checkbox checked={hasLimiteurSon} onCheckedChange={(checked) => { setHasLimiteurSon(checked); if (checked) setHasNoLimiteurNiDetecteur(false); }} /><p className=\"font-medium text-slate-800 text-sm\">Limiteur de son</p></div>\n                      </div>\n                      <div className={`p-3 rounded-lg border-2 transition-all cursor-pointer ${hasDetecteurFumee ? \"border-red-500 bg-red-50\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => { setHasDetecteurFumee(!hasDetecteurFumee); if (!hasDetecteurFumee) setHasNoLimiteurNiDetecteur(false); }}>\n                        <div className=\"flex items-center space-x-3\"><Checkbox checked={hasDetecteurFumee} onCheckedChange={(checked) => { setHasDetecteurFumee(checked); if (checked) setHasNoLimiteurNiDetecteur(false); }} /><p className=\"font-medium text-slate-800 text-sm\">Détecteur de fumée</p></div>\n                      </div>\n                      <div className={`p-3 rounded-lg border-2 transition-all cursor-pointer ${hasNoLimiteurNiDetecteur ? \"border-green-500 bg-green-50\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => { const nv = !hasNoLimiteurNiDetecteur; setHasNoLimiteurNiDetecteur(nv); if (nv) { setHasLimiteurSon(false); setHasDetecteurFumee(false); } }}>\n                        <div className=\"flex items-center space-x-3\"><Checkbox checked={hasNoLimiteurNiDetecteur} onCheckedChange={(checked) => { setHasNoLimiteurNiDetecteur(checked); if (checked) { setHasLimiteurSon(false); setHasDetecteurFumee(false); } }} /><p className=\"font-medium text-slate-800 text-sm\">Aucun</p></div>\n                      </div>\n                    </div>\n                    \n                    <div className=\"grid grid-cols-1 md:grid-cols-2 gap-3 mt-3\">\n                      <div className={`p-3 rounded-lg border-2 transition-all cursor-pointer ${hasWifi ? \"border-blue-500 bg-blue-50\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => { setHasWifi(!hasWifi); }}>\n                        <div className=\"flex items-center space-x-3\"><Checkbox checked={hasWifi} onCheckedChange={(checked) => { setHasWifi(checked); }} /><p className=\"font-medium text-slate-800 text-sm\">Wi-Fi disponible dans la salle</p></div>\n                      </div>\n                      <div className={`p-3 rounded-lg border-2 transition-all cursor-pointer ${has4g5g ? \"border-sky-500 bg-sky-50\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => { setHas4g5g(!has4g5g); }}>\n                        <div className=\"flex items-center space-x-3\"><Checkbox checked={has4g5g} onCheckedChange={(checked) => { setHas4g5g(checked); }} /><p className=\"font-medium text-slate-800 text-sm\">Réseau 4G/5G disponible</p></div>\n                      </div>\n                    </div>\n                  </div>\n                </CardContent>\n              </Card>\n              )}\n\n              {/* Styles Musicaux (Uniquement pour R'Key) */}\n              {!['Show Hypnose', 'Intervention hypnose'].includes(clientInfo.event_type) && (getProfileData(selectedDjProfile).nom_artistique?.toLowerCase().includes(\"r'key\") || getProfileData(selectedDjProfile).titre?.includes(\"Gérant\")) && (\n              <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                <CardHeader className=\"pb-4\">\n                  <CardTitle className=\"text-slate-800\">Styles Musicaux</CardTitle>\n                  <CardDescription>Sélectionnez les styles musicaux prévus pour la soirée</CardDescription>\n                </CardHeader>\n                <CardContent className=\"space-y-4\">\n                  <div className=\"flex justify-end mb-3\">\n                    <Button type=\"button\" onClick={selectAllMusicStyles} variant=\"outline\" size=\"sm\" className=\"text-purple-600 border-purple-300 hover:bg-purple-50\">Tout sélectionner</Button>\n                  </div>\n                  <div className=\"grid grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-2\">\n                    {musicStyles.map((style) => (\n                      <div key={style} className={`p-2 rounded-lg border-2 transition-all cursor-pointer text-center text-sm ${selectedMusicStyles.includes(style) ? \"border-purple-500 bg-purple-50 text-purple-700\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleMusicStyleToggle(style)}>\n                        {style}\n                      </div>\n                    ))}\n                  </div>\n                  <div className=\"space-y-2 pt-4 border-t\"><Label className=\"text-slate-700\">Fond sonore apéritif</Label><Input value={backgroundMusicAperitif} onChange={(e) => setBackgroundMusicAperitif(e.target.value)} className=\"border-slate-300 focus:border-blue-500\" /></div>\n                  <div className=\"grid grid-cols-1 md:grid-cols-1 gap-4 pt-2\">\n                    <div className=\"space-y-2\"><Label className=\"text-slate-700\">Musiques à éviter</Label><Textarea value={blacklist} onChange={(e) => setBlacklist(e.target.value)} rows={2} className=\"border-slate-300 focus:border-blue-500\" /></div>\n                  </div>\n                </CardContent>\n              </Card>\n              )}\n\n              {/* Déroulement de Soirée (Uniquement pour R'Key) */}\n              {!['Show Hypnose', 'Intervention hypnose'].includes(clientInfo.event_type) && (getProfileData(selectedDjProfile).nom_artistique?.toLowerCase().includes(\"r'key\") || getProfileData(selectedDjProfile).titre?.includes(\"Gérant\")) && (\n              <div className=\"lg:col-span-2\">\n                <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                  <CardHeader className=\"pb-4\">\n                    <CardTitle className=\"text-slate-800\">Déroulement de Soirée</CardTitle>\n                    <CardDescription>Organisez les événements et animations de votre soirée</CardDescription>\n                  </CardHeader>\n                  <CardContent className=\"space-y-6\">\n                    {/* Événements Repas */}\n                    <div className=\"space-y-4\">\n                      <h3 className=\"text-lg font-semibold text-slate-800\">Événements du Repas</h3>\n                      <div className=\"grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-2\">\n                        {eventCategories.repas.map((event) => (\n                          <div key={`repas-${event}`} className={`p-3 rounded-lg border-2 transition-all cursor-pointer text-center ${selectedEvents.includes(`repas-${event}`) ? \"border-orange-500 bg-orange-50 text-orange-700\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleEventClick(`repas-${event}`, event, 'repas')}>{event}</div>\n                        ))}\n                      </div>\n                      <div className=\"flex space-x-2\">\n                        <Input value={newRepasEvent} onChange={(e) => setNewRepasEvent(e.target.value)} className=\"border-slate-300 focus:border-blue-500\" onKeyPress={(e) => { if (e.key === 'Enter' && newRepasEvent.trim()) { setCustomRepasEvents(prev => [...prev, newRepasEvent.trim()]); setNewRepasEvent(\"\"); } }} />\n                        <Button type=\"button\" onClick={() => { if (newRepasEvent.trim()) { setCustomRepasEvents(prev => [...prev, newRepasEvent.trim()]); setNewRepasEvent(\"\"); } }} className=\"bg-orange-600 hover:bg-orange-700\">+</Button>\n                      </div>\n                      {customRepasEvents.length > 0 && (\n                        <div className=\"grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-2\">\n                          {customRepasEvents.map((event, index) => (\n                            <div key={`custom-repas-${index}`} className={`p-3 rounded-lg border-2 transition-all cursor-pointer text-center ${selectedEvents.includes(`custom-repas-${index}`) ? \"border-orange-500 bg-orange-50 text-orange-700\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleEventClick(`custom-repas-${index}`, event, 'repas')}>\n                              {event}<button className=\"ml-2 text-red-500 hover:text-red-700\" onClick={(e) => { e.stopPropagation(); setCustomRepasEvents(prev => prev.filter((_, i) => i !== index)); setSelectedEvents(prev => prev.filter(ev => ev !== `custom-repas-${index}`)); }}>×</button>\n                            </div>\n                          ))}\n                        </div>\n                      )}\n                    </div>\n\n                    {/* Événements Musique */}\n                    <div className=\"space-y-4\">\n                      <h3 className=\"text-lg font-semibold text-slate-800\">Musique</h3>\n                      <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2\">\n                        {eventCategories.musique.map((event) => (\n                          <div key={`musique-${event}`} className={`p-3 rounded-lg border-2 transition-all cursor-pointer text-center ${selectedEvents.includes(`musique-${event}`) ? \"border-green-500 bg-green-50 text-green-700\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleEventClick(`musique-${event}`, event, 'musique')}>{event}</div>\n                        ))}\n                      </div>\n                      <div className=\"flex space-x-2\">\n                        <Input value={newMusiqueEvent} onChange={(e) => setNewMusiqueEvent(e.target.value)} className=\"border-slate-300 focus:border-blue-500\" onKeyPress={(e) => { if (e.key === 'Enter' && newMusiqueEvent.trim()) { setCustomMusiqueEvents(prev => [...prev, newMusiqueEvent.trim()]); setNewMusiqueEvent(\"\"); } }} />\n                        <Button type=\"button\" onClick={() => { if (newMusiqueEvent.trim()) { setCustomMusiqueEvents(prev => [...prev, newMusiqueEvent.trim()]); setNewMusiqueEvent(\"\"); } }} className=\"bg-green-600 hover:bg-green-700\">+</Button>\n                      </div>\n                      {customMusiqueEvents.length > 0 && (\n                        <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2\">\n                          {customMusiqueEvents.map((event, index) => (\n                            <div key={`custom-musique-${index}`} className={`p-3 rounded-lg border-2 transition-all cursor-pointer text-center ${selectedEvents.includes(`custom-musique-${index}`) ? \"border-green-500 bg-green-50 text-green-700\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleEventClick(`custom-musique-${index}`, event, 'musique')}>\n                              {event}<button className=\"ml-2 text-red-500 hover:text-red-700\" onClick={(e) => { e.stopPropagation(); setCustomMusiqueEvents(prev => prev.filter((_, i) => i !== index)); setSelectedEvents(prev => prev.filter(ev => ev !== `custom-musique-${index}`)); }}>×</button>\n                            </div>\n                          ))}\n                        </div>\n                      )}\n                    </div>\n\n                    {/* Événements Animations */}\n                    <div className=\"space-y-4\">\n                      <h3 className=\"text-lg font-semibold text-slate-800\">Animations</h3>\n                      <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-2\">\n                        {animationEvents.map((event) => (\n                          <div key={`animation-${event}`} className={`p-3 rounded-lg border-2 transition-all cursor-pointer text-center ${selectedEvents.includes(`animation-${event}`) ? \"border-purple-500 bg-purple-50 text-purple-700\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleEventClick(`animation-${event}`, event, 'animation')}>{event}</div>\n                        ))}\n                      </div>\n                      <div className=\"flex space-x-2\">\n                        <Input value={newAnimationEvent} onChange={(e) => setNewAnimationEvent(e.target.value)} className=\"border-slate-300 focus:border-blue-500\" onKeyPress={(e) => { if (e.key === 'Enter' && newAnimationEvent.trim()) { setCustomAnimationEvents(prev => [...prev, newAnimationEvent.trim()]); setNewAnimationEvent(\"\"); } }} />\n                        <Button type=\"button\" onClick={() => { if (newAnimationEvent.trim()) { setCustomAnimationEvents(prev => [...prev, newAnimationEvent.trim()]); setNewAnimationEvent(\"\"); } }} className=\"bg-purple-600 hover:bg-purple-700\">+</Button>\n                      </div>\n                      {customAnimationEvents.length > 0 && (\n                        <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-2\">\n                          {customAnimationEvents.map((event, index) => (\n                            <div key={`custom-animation-${index}`} className={`p-3 rounded-lg border-2 transition-all cursor-pointer text-center ${selectedEvents.includes(`custom-animation-${index}`) ? \"border-purple-500 bg-purple-50 text-purple-700\" : \"border-slate-200 bg-white hover:border-slate-300\"}`} onClick={() => handleEventClick(`custom-animation-${index}`, event, 'animation')}>\n                              {event}<button className=\"ml-2 text-red-500 hover:text-red-700\" onClick={(e) => { e.stopPropagation(); setCustomAnimationEvents(prev => prev.filter((_, i) => i !== index)); setSelectedEvents(prev => prev.filter(ev => ev !== `custom-animation-${index}`)); }}>×</button>\n                            </div>\n                          ))}\n                        </div>\n                      )}\n                    </div>\n\n                    {/* Ordre chronologique */}\n                    {eventOrder.length > 0 && (\n                      <div className=\"space-y-4 p-4 bg-gradient-to-r from-blue-50 to-purple-50 rounded-lg border-2 border-blue-200\">\n                        <h4 className=\"text-lg font-semibold text-slate-800\">Ordre chronologique de la soirée</h4>\n                        <div className=\"space-y-2\">\n                          {eventOrder.map((event, index) => (\n                            <div key={event.key} className=\"flex items-center justify-between p-3 bg-white rounded-lg border shadow-sm\">\n                              <div className=\"flex items-center space-x-3\">\n                                <span className=\"bg-blue-100 text-blue-800 px-2 py-1 rounded-full text-sm font-medium\">{index + 1}</span>\n                                <span className=\"text-lg\">{event.icon}</span>\n                                <span className=\"font-medium text-slate-700\">{event.label}</span>\n                              </div>\n                              <div className=\"flex items-center space-x-1\">\n                                <button type=\"button\" onClick={() => moveEventUp(index)} disabled={index === 0} className=\"p-1 rounded text-slate-600 hover:bg-slate-100 disabled:opacity-50 disabled:cursor-not-allowed\" title=\"Monter\">↑</button>\n                                <button type=\"button\" onClick={() => moveEventDown(index)} disabled={index === eventOrder.length - 1} className=\"p-1 rounded text-slate-600 hover:bg-slate-100 disabled:opacity-50 disabled:cursor-not-allowed\" title=\"Descendre\">↓</button>\n                                <button type=\"button\" onClick={() => removeFromOrder(event.key)} className=\"p-1 rounded text-red-600 hover:bg-red-100\" title=\"Supprimer\">×</button>\n                              </div>\n                            </div>\n                          ))}\n                        </div>\n                      </div>\n                    )}\n\n                    <div className=\"space-y-2\"><Label className=\"text-slate-700\">Notes et observations pour le déroulement</Label><Textarea value={eventNotes} onChange={(e) => setEventNotes(e.target.value)} rows={3} className=\"border-slate-300 focus:border-blue-500\" /></div>\n                  </CardContent>\n                </Card>\n              </div>\n              )}\n\n              {/* Conditions de Paiement Détaillées (Mode Dirigeant uniquement) */}\n              {isDirigeant() && (\n              <div className=\"lg:col-span-2\">\n                <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                  <CardHeader className=\"pb-4\">\n                    <CardTitle className=\"text-slate-800\">Conditions de Paiement</CardTitle>\n                    <CardDescription>Configuration des modalités de paiement et acompte</CardDescription>\n                  </CardHeader>\n                  <CardContent className=\"space-y-6\">\n                    <div className=\"bg-blue-50 p-4 rounded-lg space-y-2\">\n                      <div className=\"flex justify-between\"><span className=\"font-medium\">Montant total:</span><span className=\"font-bold text-blue-600\">{calculateTotal()}€</span></div>\n                      {(() => {\n                        const isFreelance = contractMode === 'entreprise' && (selectedDjProfile === \"\" || isArtistFreelance(getProfileData(selectedDjProfile)));\n                        if (isFreelance) {\n                          const total = calculateTotal();\n                          const deposit = calculateDepositAmount();\n                          const rawPct = total > 0 ? (deposit / total) * 100 : 0;\n                          let percentage = Math.round(rawPct / 5) * 5;\n                          if (percentage < 0) percentage = 0;\n                          if (percentage > 100) percentage = 100;\n                          const soldePct = 100 - percentage;\n                          return (\n                            <>\n                              <div className=\"flex justify-between\">\n                                <span>Acompte (Marge TTC{percentage > 0 ? ` ${percentage}%` : ''}):</span>\n                                <span className=\"font-semibold text-green-600\">{calculateDepositAmount()}€</span>\n                              </div>\n                              <div className=\"flex justify-between\">\n                                <span>Solde restant (Cachet DJ TTC{percentage > 0 ? ` ${soldePct}%` : ''}):</span>\n                                <span className=\"font-semibold\">{calculateRemainingBalance()}€</span>\n                              </div>\n                            </>\n                          );\n                        }\n                        const isCompany = !!(clientInfo?.company && clientInfo.company.trim().length > 0);\n                        const ratioStr = isCompany ? \"30%\" : \"50%\";\n                        return (\n                          <>\n                            <div className=\"flex justify-between\">\n                              <span>Acompte ({ratioStr} tarif + options complètes):</span>\n                              <span className=\"font-semibold text-green-600\">{calculateDepositAmount()}€</span>\n                            </div>\n                            <div className=\"flex justify-between\">\n                              <span>Solde restant:</span>\n                              <span className=\"font-semibold\">{calculateRemainingBalance()}€</span>\n                            </div>\n                          </>\n                        );\n                      })()}\n                    </div>\n\n                    <div className=\"flex items-center space-x-2 p-3 bg-blue-50 rounded-lg border border-blue-200\">\n                      <Checkbox id=\"no_deposit_required\" checked={noDepositRequired} onCheckedChange={(checked) => { setNoDepositRequired(checked); if (checked) { setCustomDepositAmount(0); } }} />\n                      <Label htmlFor=\"no_deposit_required\" className=\"text-blue-700 font-medium cursor-pointer\">Client de confiance - Pas d'acompte requis</Label>\n                    </div>\n\n                    <div className=\"space-y-2\">\n                      <Label className=\"text-slate-700\">Acompte personnalisé (optionnel)</Label>\n                      <div className=\"flex items-center space-x-2\">\n                        <Euro className=\"h-4 w-4 text-slate-500\" />\n                        <Input type=\"number\" value={customDepositAmount} onChange={(e) => setCustomDepositAmount(Number(e.target.value))} className=\"border-slate-300 focus:border-blue-500 w-32\" min=\"0\" step=\"10\" disabled={noDepositRequired} />\n                      </div>\n                    </div>\n\n                    <div className=\"space-y-2\">\n                      <Label className=\"text-slate-700\">Coordonnées bancaires pour le paiement</Label>\n                      <div className=\"bg-gray-50 p-3 rounded-lg text-sm border border-slate-200\" data-testid=\"company-rib-display\">\n                        <p><strong>Banque :</strong> {companySettings.bank_name}</p>\n                        <p><strong>IBAN :</strong> {companySettings.bank_iban}</p>\n                        <p><strong>BIC :</strong> {companySettings.bank_bic}</p>\n                        <p><strong>Titulaire :</strong> {companySettings.bank_titulaire}</p>\n                      </div>\n                    </div>\n\n                    <div className=\"space-y-4\">\n                      <div className=\"flex items-center space-x-2\">\n                        <Checkbox id=\"deposit_paid\" checked={depositPaid} onCheckedChange={setDepositPaid} />\n                        <Label htmlFor=\"deposit_paid\" className=\"text-slate-700\">Acompte déjà payé</Label>\n                      </div>\n                      {depositPaid && (\n                        <>\n                          <div className=\"space-y-2\">\n                            <Label className=\"text-slate-700\">Mode de paiement de l'acompte</Label>\n                            <Select value={depositPaymentMethod} onValueChange={setDepositPaymentMethod}>\n                              <SelectTrigger className=\"border-slate-300 focus:border-blue-500\"><SelectValue placeholder=\"Comment l'acompte a été payé ?\" /></SelectTrigger>\n                              <SelectContent>\n                                <SelectItem value=\"virement\">Virement bancaire</SelectItem>\n                                <SelectItem value=\"especes\">Espèces</SelectItem>\n                                <SelectItem value=\"cheque\">Chèque</SelectItem>\n                                <SelectItem value=\"carte\">Carte bancaire</SelectItem>\n                              </SelectContent>\n                            </Select>\n                          </div>\n                          <div className=\"space-y-2\">\n                            <Label className=\"text-slate-700\">Date de versement de l'acompte</Label>\n                            <Input type=\"date\" value={depositPaidDate} onChange={(e) => setDepositPaidDate(e.target.value)} className=\"border-slate-300 focus:border-blue-500\" />\n                          </div>\n                        </>\n                      )}\n                    </div>\n                  </CardContent>\n                </Card>\n              </div>\n              )}\n\n\n\n              {/* Card Pièces Jointes & Documents */}\n              <div className=\"lg:col-span-2\">\n                <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                  <CardHeader className=\"pb-4\">\n                    <CardTitle className=\"text-emerald-800 flex items-center gap-2\">\n                      <Paperclip className=\"w-5 h-5 text-emerald-700\" />\n                      <span>Pièces Jointes & Documents (Ancien contrat, contrat signé, etc.)</span>\n                    </CardTitle>\n                    <CardDescription>\n                      Associez des documents administratifs (fichiers PDF, images converties automatiquement) à ce contrat.\n                    </CardDescription>\n                  </CardHeader>\n                  <CardContent className=\"space-y-4\">\n                    {editingContract ? (\n                      <div className=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n                        {/* Zone d'importation de fichiers */}\n                        <div className=\"border-2 border-dashed border-emerald-200 hover:border-emerald-450 bg-emerald-50/5 rounded-xl p-6 transition-all\">\n                          <div className=\"flex flex-col items-center text-center\">\n                            <div className=\"p-3 bg-white rounded-full shadow-sm text-emerald-700 mb-3\">\n                              <Upload className=\"w-6 h-6 animate-pulse\" />\n                            </div>\n                            <h3 className=\"font-semibold text-gray-700 mb-1 text-sm\">Ajouter un document</h3>\n                            <p className=\"text-xs text-gray-500 mb-4 max-w-xs\">PDF, PNG, JPG, JPEG ou HEIC (les images seront automatiquement converties en PDF)</p>\n                            \n                            <div className=\"w-full max-w-xs mb-4\">\n                              <label className=\"block text-left text-xs font-bold text-gray-600 mb-1.5 uppercase tracking-wider\">\n                                Nature du document à ajouter :\n                              </label>\n                              <select\n                                value={inlineUploadCategory}\n                                onChange={(e) => setInlineUploadCategory(e.target.value)}\n                                className=\"w-full px-3 py-2 bg-white border border-gray-200 rounded-lg text-sm text-gray-700 focus:ring-2 focus:ring-emerald-500 outline-none\"\n                              >\n                                <option value=\"Contrat Initial\">Contrat Initial (Envoyé)</option>\n                                <option value=\"Contrat Signé / Complémentaire\">Contrat Signé / Complémentaire (Retourné)</option>\n                                <option value=\"Administrative\">Autre Document Administratif</option>\n                              </select>\n                            </div>\n                            \n                            <label className=\"cursor-pointer\">\n                              <div className=\"bg-emerald-700 hover:bg-emerald-800 text-white font-medium text-sm px-4 py-2 rounded-lg shadow-sm transition-all flex items-center gap-1.5 justify-center\">\n                                {uploadingAttachment ? (\n                                  <>\n                                    <Loader2 className=\"w-4 h-4 animate-spin\" />\n                                    Traitement...\n                                  </>\n                                ) : (\n                                  <>\n                                    <Plus className=\"w-4 h-4\" />\n                                    Téléverser un document\n                                  </>\n                                )}\n                              </div>\n                              <input\n                                type=\"file\"\n                                accept=\"application/pdf, image/png, image/jpeg, image/jpg, .heic, .heif\"\n                                className=\"hidden\"\n                                onChange={handleInlineAttachmentUpload}\n                                disabled={uploadingAttachment}\n                                multiple\n                              />\n                            </label>\n                          </div>\n                        </div>\n\n                        {/* Liste des documents associés */}\n                        <div className=\"space-y-3\">\n                          <h4 className=\"font-semibold text-gray-800 text-sm flex items-center gap-2 border-b pb-2\">\n                            <FileText className=\"w-4 h-4 text-emerald-700\" />\n                            Documents associés ({editingContract.event_documents?.length || 0})\n                          </h4>\n                          \n                          {editingContract.event_documents && editingContract.event_documents.length > 0 ? (\n                            <div className=\"divide-y max-h-60 overflow-y-auto\">\n                              {editingContract.event_documents.map((doc) => (\n                                <div key={doc.id} className=\"flex items-center justify-between py-3 text-sm border-b border-gray-150 last:border-none\">\n                                  <div className=\"flex flex-col gap-1 min-w-0 flex-1 pr-4\">\n                                    <div className=\"flex items-center gap-2 truncate\">\n                                      <FileText className=\"w-4 h-4 text-emerald-600 flex-shrink-0\" />\n                                      <span className=\"truncate font-medium text-gray-750\" title={doc.filename}>{doc.filename}</span>\n                                      <span className=\"text-[10px] text-gray-400 flex-shrink-0\">\n                                        ({new Date(doc.uploaded_at).toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' })})\n                                      </span>\n                                    </div>\n                                    <div className=\"flex items-center gap-1.5 mt-0.5\">\n                                      {doc.category === \"Contrat Initial\" ? (\n                                        <span className=\"inline-flex items-center text-[10px] uppercase tracking-wider font-bold py-0.5 px-2 bg-blue-50 text-blue-700 border border-blue-200 rounded\">\n                                          Contrat Initial (Envoyé)\n                                        </span>\n                                      ) : (doc.category === \"Contrat Signé / Complémentaire\" || doc.category === \"Contrat Signé / Complémentaire (Retourné)\") ? (\n                                        <span className=\"inline-flex items-center text-[10px] uppercase tracking-wider font-bold py-0.5 px-2 bg-emerald-50 text-emerald-800 border border-emerald-250 rounded\">\n                                          Contrat Signé (Retourné)\n                                        </span>\n                                      ) : (\n                                        <span className=\"inline-flex items-center text-[10px] uppercase tracking-wider font-bold py-0.5 px-2 bg-slate-50 text-slate-650 border border-slate-200 rounded\">\n                                          {doc.category || \"Autre Document\"}\n                                        </span>\n                                      )}\n                                    </div>\n                                  </div>\n                                  <div className=\"flex items-center gap-2 flex-shrink-0\">\n                                    <Button \n                                      variant=\"outline\" \n                                      size=\"sm\" \n                                      onClick={() => handleInlinePreviewAttachment(doc)} \n                                      title=\"Visualiser\"\n                                    >\n                                      <Eye className=\"w-4 h-4\" />\n                                    </Button>\n                                    <Button \n                                      variant=\"ghost\" \n                                      size=\"sm\" \n                                      onClick={() => handleInlineDeleteAttachment(doc.id)} \n                                      className=\"text-red-500 hover:text-red-700 hover:bg-red-50\"\n                                      title=\"Supprimer\"\n                                    >\n                                      <Trash2 className=\"w-4 h-4\" />\n                                    </Button>\n                                  </div>\n                                </div>\n                              ))}\n                            </div>\n                          ) : (\n                            <div className=\"text-center py-8 text-gray-400 text-sm italic bg-gray-50/50 rounded-lg\">\n                              Aucune pièce jointe associée pour le moment.\n                            </div>\n                          )}\n                        </div>\n                      </div>\n                    ) : (\n                      <div className=\"bg-amber-50 border border-amber-200 text-amber-800 rounded-xl p-4 text-sm flex items-start gap-2.5\">\n                        <AlertCircle className=\"w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5\" />\n                        <div>\n                          <p className=\"font-semibold\">Contrat non sauvegardé</p>\n                          <p className=\"text-xs text-amber-700 mt-1\">\n                            Veuillez enregistrer votre brouillon ou cliquer sur \"Aperçu du contrat\" pour générer et enregistrer ce contrat dans la base de données. Vous pourrez ensuite y associer des fichiers en pièces jointes.\n                          </p>\n                        </div>\n                      </div>\n                    )}\n                  </CardContent>\n                </Card>\n              </div>\n\n\n\n              {/* Bouton d'action */}\n              <div className=\"lg:col-span-2 flex justify-center gap-4 mb-6\">\n                <Button onClick={() => saveContractDraft(true)} className=\"bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 text-lg\" disabled={!clientInfo.name || !clientInfo.email}>\n                  <FileText className=\"h-5 w-5 mr-2\" />Aperçu du contrat\n                </Button>\n                {editingContract && (\n                  <Button onClick={() => saveContractDraft(false)} className=\"bg-green-600 hover:bg-green-700 text-white px-8 py-3 text-lg\" disabled={!clientInfo.name || !clientInfo.email}>\n                    <Save className=\"h-5 w-5 mr-2\" />Mettre à jour\n                  </Button>\n                )}\n              </div>\n\n              {/* CGV Section */}\n              <div className=\"lg:col-span-2\">\n                <Card className=\"shadow-lg border-0 bg-white/70 backdrop-blur-sm\">\n                  <CardHeader className=\"pb-4\">\n                    <CardTitle className=\"text-slate-800\">Conditions Générales de Vente</CardTitle>\n                    <CardDescription>Choisissez un modèle prédéfini ou personnalisez vos CGV *</CardDescription>\n                  </CardHeader>\n                  <CardContent className=\"space-y-4\">\n                    <div className=\"space-y-2\">\n                      <Label className=\"text-slate-700\">Modèle de CGV *</Label>\n                      <Select value={selectedCgvTemplate} onValueChange={handleCgvTemplateChange} required>\n                        <SelectTrigger className={`bg-white border-slate-300 focus:border-blue-500 ${!selectedCgvTemplate ? 'border-red-300' : ''}`}><SelectValue placeholder=\"Sélectionner un modèle *\" /></SelectTrigger>\n                        <SelectContent className=\"bg-white\">\n                          <SelectItem key=\"custom\" value=\"custom\">Personnalisé</SelectItem>\n                          {Object.entries(cgvTemplates).map(([key, template]) => (\n                            <SelectItem key={key} value={key}>\n                              {template.name || key.replace(/_[0-9]+$/, '').replace(/_/g, ' ').trim().replace(/\\b\\w/g, c => c.toUpperCase())}\n                            </SelectItem>\n                          ))}\n                        </SelectContent>\n                      </Select>\n                    </div>\n                    <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n                      <div className=\"space-y-2\">\n                        <Label className=\"text-slate-700\">Titre des CGV sur le PDF / Contrat</Label>\n                        <Input \n                          value={cgvTitle} \n                          onChange={(e) => setCgvTitle(e.target.value)} \n                          className=\"bg-white border-slate-300 focus:border-blue-500 font-medium\" \n                          placeholder=\"Conditions Générales de Vente\"\n                        />\n                      </div>\n                    </div>\n                    <div className=\"space-y-2\"><Label className=\"text-slate-700\">Texte des CGV</Label><Textarea value={cgvText} onChange={(e) => setCgvText(e.target.value)} rows={6} className=\"border-slate-300 focus:border-blue-500\" /></div>\n                    {selectedCgvTemplate && selectedCgvTemplate !== 'custom' && (\n                      <Button variant=\"outline\" size=\"sm\" className=\"text-blue-600 border-blue-300 hover:bg-blue-50\" onClick={async () => {\n                        try {\n                          const updated = { ...cgvTemplates };\n                          updated[selectedCgvTemplate] = { ...updated[selectedCgvTemplate], content: cgvText };\n                          await axios.put(`${API}/cgv-templates`, { templates: updated });\n                          setCgvTemplates(updated);\n                          toast.success('Modèle CGV sauvegardé');\n                        } catch { toast.error('Erreur sauvegarde CGV'); }\n                      }} data-testid=\"save-cgv-template-btn\">\n                        <Save className=\"w-4 h-4 mr-1\" />Sauvegarder ce modèle\n                      </Button>\n                    )}\n                    \n                    {/* CGV Artiste pour le Mode Mandat */}\n                    {contractMode === 'mandataire' && (\n                      <>\n                        <Separator className=\"my-6\" />\n                        <div className=\"space-y-3\">\n                          <Label className=\"text-slate-800 font-semibold text-sm flex items-center gap-1.5 md:text-base\">\n                            Conditions Générales de l'Artiste (Document 2 - Contrat DJ)\n                          </Label>\n                          <CardDescription className=\"text-xs text-slate-500\">\n                            Ces conditions s'appliquent séparément sur le Document 2 du mode mandat. Éditez ce texte pour ce contrat ou cliquez sur \"Sauvegarder par défaut\" pour l'enregistrer globalement.\n                          </CardDescription>\n                          <div className=\"space-y-2 max-w-sm\">\n                            <Label className=\"text-slate-700 text-xs\">Titre des CGV de l'Artiste sur le PDF</Label>\n                            <Input \n                              value={artisteCgvTitle} \n                              onChange={(e) => setArtisteCgvTitle(e.target.value)} \n                              className=\"bg-white border-slate-300 focus:border-blue-500 text-xs\" \n                              placeholder=\"Conditions Générales\"\n                            />\n                          </div>\n                          <Textarea \n                            value={artisteCgvText} \n                            onChange={(e) => setArtisteCgvText(e.target.value)} \n                            rows={8} \n                            className=\"border-slate-300 focus:border-blue-500 font-mono text-[11px] leading-relaxed bg-slate-50/50\" \n                            placeholder=\"Saisissez les CGV de l'artiste...\"\n                          />\n                          <div className=\"flex flex-wrap gap-2 pt-1\">\n                            <Button \n                              variant=\"outline\" \n                              size=\"sm\" \n                              className=\"text-blue-600 border-blue-300 hover:bg-blue-50 transition\" \n                              onClick={async () => {\n                                try {\n                                  const token = localStorage.getItem('access_token');\n                                  const response = await fetch(`${API}/global-settings`, {\n                                    headers: { Authorization: `Bearer ${token}` }\n                                  });\n                                  let existingData = {};\n                                  if (response.ok) {\n                                    existingData = await response.json();\n                                  }\n                                  const updated = { \n                                    ...existingData, \n                                    artiste_cgv_text: artisteCgvText,\n                                    type: 'company',\n                                    updated_at: new Date().toISOString()\n                                  };\n                                  await axios.put(`${API}/global-settings`, updated);\n                                  toast.success('Sauvegardé avec succès dans la configuration globale !');\n                                } catch (err) {\n                                  console.error(\"Save failure:\", err);\n                                  toast.error('Erreur de sauvegarde globale');\n                                }\n                              }}\n                            >\n                              <Save className=\"w-4 h-4 mr-1\" />Sauvegarder par défaut\n                            </Button>\n                            <Button \n                              variant=\"outline\" \n                              size=\"sm\" \n                              className=\"text-slate-600 border-slate-250 hover:bg-slate-50 transition\" \n                              onClick={() => {\n                                if (window.confirm(\"Voulez-vous réinitialiser le texte par défaut de l'Artiste ?\")) {\n                                  setArtisteCgvText(defaultArtistCgv);\n                                  toast.success('Texte réinitialisé !');\n                                }\n                              }}\n                            >\n                              <RotateCcw className=\"w-4 h-4 mr-1\" />Réinitialiser d'origine\n                            </Button>\n                          </div>\n                        </div>\n                      </>\n                    )}\n                  </CardContent>\n                </Card>\n              </div>\n            </div>\n          </TabsContent>\n\n          {/* ═══════════════════════════════════════════════ */}\n          {/* PREVIEW TAB (composant extrait)                */}\n          {/* ═══════════════════════════════════════════════ */}\n          <TabsContent value=\"preview\">\n            <ErrorBoundary>\n              <div className=\"bg-white rounded-xl shadow-md border border-slate-200 overflow-hidden min-h-[600px]\">\n                <ContractPreview\n                  generatedContract={generatedContract}\n                  generateContractHTMLForPreview={(mode) => generateContractHTMLLocal(buildCurrentContractData(), null, signatureImages, { mode })}\n                  onExportPDF={() => generateContractAndGuide(buildCurrentContractData(), generateContractHTMLLocal, loadSignatureImages, selectedPdfNotes, apiService)}\n                  onSendEmail={(selectedTab) => openContractEmailModal({\n                    id: generatedContract?.id || editingContract?.id,\n                    ...buildCurrentContractData()\n                  }, selectedTab)}\n                  selectedPdfNotes={selectedPdfNotes}\n                  onGetCompiledGuideBlob={() => getCompiledGuideBlob(buildCurrentContractData(), generateContractHTMLLocal, loadSignatureImages, selectedPdfNotes, apiService)}\n                  isMandatMode={!isDirigeant() && contractMode === 'mandataire'}\n                  isEntrepriseMode={!isDirigeant() && contractMode === 'entreprise'}\n                  generateMandatHTMLForPreview={() => generateMandatHTML(buildCurrentContractData(), companySettings)}\n                  generateArtisteHTMLForPreview={() => generateArtisteHTML(buildCurrentContractData(), resolveProfile)}\n                  generateEntrepriseHTMLForPreview={() => generateEntrepriseHTML(buildCurrentContractData(), companySettings, resolveProfile)}\n                  onExportMandatPDF={handleExportMandatPDF}\n                  onExportArtistePDF={handleExportArtistePDF}\n                  onExportEntreprisePDF={handleExportEntreprisePDF}\n                  artisteName={(() => { const p = getProfileData(selectedDjProfile); return p.nom_artistique || p.nom_complet || ''; })()}\n                  totalMandat={(() => { const opts = selectedOptions.filter(o => o.selected).reduce((s, o) => s + o.price, 0); return Math.max(0, fraisMandat + opts - discountAmount); })()}\n                  totalArtiste={cachetArtiste}\n                  totalEntreprise={(() => { const opts = selectedOptions.filter(o => o.selected).reduce((s, o) => s + o.price, 0); return Math.max(0, basePrice + opts - discountAmount); })()}\n                  cachetInterne={cachetArtiste}\n                />\n              </div>\n            </ErrorBoundary>\n          </TabsContent>\n\n          {/* ═══════════════════════════════════════════════ */}\n          {/* HISTORY TAB (composant extrait)                */}\n          {/* ═══════════════════════════════════════════════ */}\n          <TabsContent value=\"history\">\n            <ContractHistory\n              contracts={contracts}\n              deletedContracts={deletedContracts}\n              archivedContracts={archivedContracts}\n              showTrash={showTrash}\n              setShowTrash={setShowTrash}\n              showArchive={showArchive}\n              setShowArchive={setShowArchive}\n              setShowConfiguration={setShowConfiguration}\n              setActiveTab={setActiveTab}\n              onPrintContract={handlePrintContract}\n              onPreviewContract={handlePreviewContract}\n              onLoadContract={loadContract}\n              onDuplicateContract={duplicateContract}\n              onMarkAsSent={markContractAsSent}\n              onMarkAsSigned={markContractAsSigned}\n              onMoveToTrash={moveContractToTrash}\n              onRestore={restoreContract}\n              onPermanentDelete={permanentlyDeleteContract}\n              onMarkArchivedAsUnsigned={markArchivedAsUnsigned}\n              onDeleteArchived={deleteArchivedContract}\n              onCancelArchived={cancelArchivedContract}\n              onManageAttachments={handleManageAttachments}\n            />\n          </TabsContent>\n        </Tabs>\n      </div>\n\n      {/* Real Document Preview Modal (In-App) */}\n      {previewDoc && (\n        <div \n          className=\"fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/65 backdrop-blur-xs p-4 sm:p-6 text-slate-800\"\n          onClick={() => setPreviewDoc(null)}\n        >\n          <div \n            className=\"bg-white rounded-2xl w-full max-w-5xl h-[85vh] flex flex-col shadow-2xl border border-slate-100 overflow-hidden relative animate-in fade-in zoom-in-95 duration-200\"\n            onClick={(e) => e.stopPropagation()}\n          >\n            {/* Header */}\n            <div className=\"flex flex-col sm:flex-row sm:items-center justify-between px-6 py-4 border-b bg-slate-50 flex-shrink-0 gap-4\">\n              <div className=\"min-w-0\">\n                <h3 className=\"text-base font-bold text-slate-800 truncate\" title={previewDoc.title}>\n                  Aperçu : {previewDoc.title}\n                </h3>\n              </div>\n              \n              {/* Document switcher if multiple exist */}\n              {previewDoc.documents.length > 1 && (\n                <div className=\"flex items-center gap-1 bg-slate-200/60 p-1 rounded-xl border border-slate-300/50 self-start\">\n                  {previewDoc.documents.map((doc, idx) => (\n                    <button\n                      key={idx}\n                      onClick={() => setPreviewDoc(prev => ({ ...prev, activeDocIndex: idx }))}\n                      className={`px-3 py-1 text-xs font-semibold rounded-lg transition-all ${\n                        previewDoc.activeDocIndex === idx\n                          ? \"bg-white text-indigo-700 shadow-xs\"\n                          : \"text-slate-600 hover:text-slate-800\"\n                      }`}\n                    >\n                      {doc.label}\n                    </button>\n                  ))}\n                </div>\n              )}\n\n              <div className=\"flex items-center gap-2 flex-shrink-0\">\n                <Button \n                  onClick={() => handleExportSpecificPDF(previewDoc.contract, previewDoc.documents[previewDoc.activeDocIndex].label)}\n                  className=\"bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-1.5 rounded-lg text-xs font-semibold shadow-xs transition-colors flex items-center gap-1.5 h-auto\"\n                >\n                  <Download className=\"w-3.5 h-3.5\" /> Télécharger PDF\n                </Button>\n                <button \n                  onClick={() => setPreviewDoc(null)}\n                  className=\"p-1.5 rounded-lg text-slate-400 hover:text-slate-600 hover:bg-slate-200 transition-colors\"\n                  title=\"Fermer\"\n                >\n                  <X className=\"w-5 h-5\" />\n                </button>\n              </div>\n            </div>\n\n            {/* Content of preview */}\n            <div className=\"flex-1 bg-slate-150 overflow-y-auto relative min-h-0 p-4\">\n              <div className=\"max-w-4xl mx-auto my-4 bg-white p-6 sm:p-10 shadow-md border rounded-xl overflow-x-auto select-text font-serif text-slate-900 leading-relaxed\">\n                <div dangerouslySetInnerHTML={{ __html: previewDoc.documents[previewDoc.activeDocIndex].html }} />\n              </div>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Dialogue Pièces Jointes */}\n      <Dialog open={showAttachmentsDialog} onOpenChange={setShowAttachmentsDialog}>\n        <DialogContent className=\"max-w-2xl max-h-[85vh] overflow-y-auto text-slate-800\">\n          <DialogHeader>\n            <DialogTitle className=\"flex items-center gap-2 text-emerald-800\">\n              <Paperclip className=\"w-5 h-5 text-emerald-700\" />\n              Pièces Jointes & Documents Administratifs - {selectedContractForAttachments?.client_name || selectedContractForAttachments?.client_info?.name || \"Client\"}\n            </DialogTitle>\n            <DialogDescription>\n              Gérez les pièces jointes et les documents du contrat et du DJ-client (images JPG/PNG/HEIC converties automatiquement en PDF, ou directement des fichiers PDF).\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"space-y-6 py-4\">\n            {/* Zone d'importation de fichiers */}\n            <div className=\"border-2 border-dashed border-emerald-200 hover:border-emerald-400 bg-emerald-50/5 rounded-xl p-6 transition-all\">\n              <div className=\"flex flex-col items-center text-center\">\n                <div className=\"p-3 bg-white rounded-full shadow-sm text-emerald-700 mb-3\">\n                  <Upload className=\"w-6 h-6 animate-pulse\" />\n                </div>\n                <h3 className=\"font-semibold text-gray-700 mb-1 text-sm\">Téléverser de nouveaux documents</h3>\n                <p className=\"text-xs text-gray-500 mb-4 max-w-xs\">PDF, PNG, JPG, JPEG, HEIC (les images seront automatiquement converties en documents PDF)</p>\n                \n                <div className=\"w-full max-w-xs mb-4\">\n                  <label className=\"block text-left text-xs font-bold text-gray-650 mb-1.5 uppercase tracking-wider\">\n                    Nature du document à ajouter :\n                  </label>\n                  <select\n                    value={historyUploadCategory}\n                    onChange={(e) => setHistoryUploadCategory(e.target.value)}\n                    className=\"w-full px-3 py-2 bg-white border border-emerald-200 rounded-lg text-sm text-gray-700 focus:ring-2 focus:ring-emerald-500 outline-none shadow-xs\"\n                  >\n                    <option value=\"Contrat Initial\">Contrat Initial (Envoyé)</option>\n                    <option value=\"Contrat Signé / Complémentaire\">Contrat Signé / Complémentaire (Retourné)</option>\n                    <option value=\"Administrative\">Autre Document Administratif</option>\n                  </select>\n                </div>\n                \n                <label className=\"cursor-pointer\">\n                  <div className=\"bg-emerald-700 hover:bg-emerald-800 text-white font-medium text-sm px-4 py-2 rounded-lg shadow-sm transition-all flex items-center gap-1.5\">\n                    {uploadingAttachment ? (\n                      <>\n                        <Loader2 className=\"w-4 h-4 animate-spin\" />\n                        Traitement en cours...\n                      </>\n                    ) : (\n                      <>\n                        <Plus className=\"w-4 h-4\" />\n                        Sélectionner des fichiers\n                      </>\n                    )}\n                  </div>\n                  <input\n                    type=\"file\"\n                    accept=\"application/pdf, image/png, image/jpeg, image/jpg, .heic, .heif\"\n                    className=\"hidden\"\n                    onChange={handleAttachmentUpload}\n                    disabled={uploadingAttachment}\n                    multiple\n                  />\n                </label>\n              </div>\n            </div>\n\n            {/* Liste des documents */}\n            <div className=\"space-y-3\">\n              <h4 className=\"font-semibold text-gray-800 text-sm flex items-center gap-2\">\n                <FileText className=\"w-4 h-4 text-emerald-700\" />\n                Documents associés ({selectedContractForAttachments?.event_documents?.length || 0})\n              </h4>\n              \n              {(!selectedContractForAttachments?.event_documents || selectedContractForAttachments.event_documents.length === 0) ? (\n                <div className=\"text-center py-8 bg-gray-50 rounded-lg border border-dashed border-gray-200\">\n                  <FileText className=\"w-10 h-10 text-gray-300 mx-auto mb-2\" />\n                  <p className=\"text-sm text-gray-500\">Aucun document n'a encore été associé à ce contrat.</p>\n                </div>\n              ) : (\n                <div className=\"grid grid-cols-1 gap-2.5 max-h-[40vh] overflow-y-auto pr-1\">\n                  {selectedContractForAttachments.event_documents.map((doc) => (\n                    <div key={doc.id} className=\"flex items-center justify-between p-3.5 bg-white border border-gray-100 rounded-lg shadow-sm hover:border-emerald-200 hover:shadow-md transition-all\">\n                      <div className=\"flex items-center gap-3 min-w-0 flex-1\">\n                        <div className=\"p-2 bg-emerald-50 text-emerald-700 rounded\">\n                          <FileText className=\"w-5 h-5\" />\n                        </div>\n                        <div className=\"min-w-0 flex-1\">\n                          <p className=\"text-sm font-medium text-gray-700 truncate\" title={doc.filename}>{doc.filename}</p>\n                          <p className=\"text-xs text-gray-400 mt-1.5 flex flex-wrap items-center gap-1.5\">\n                            <span className=\"text-gray-500\">Nature:</span>\n                            {doc.category === \"Contrat Initial\" ? (\n                              <span className=\"font-bold text-[10px] uppercase tracking-wider py-0.5 px-2 bg-blue-50 text-blue-700 border border-blue-200 rounded\">\n                                Contrat Initial (Envoyé)\n                              </span>\n                            ) : doc.category === \"Contrat Signé / Complémentaire\" || doc.category === \"Contrat Signé / Complémentaire (Retourné)\" ? (\n                              <span className=\"font-bold text-[10px] uppercase tracking-wider py-0.5 px-2 bg-emerald-50 text-emerald-800 border border-emerald-250 rounded\">\n                                Contrat Signé (Retourné)\n                              </span>\n                            ) : (\n                              <span className=\"font-bold text-[10px] uppercase tracking-wider py-0.5 px-2 bg-slate-50 text-slate-650 border border-slate-200 rounded\">\n                                {doc.category || \"Autre Document\"}\n                              </span>\n                            )}\n                            {doc.uploaded_at && <span className=\"text-[10px] text-gray-400 ml-1\">envoi : {new Date(doc.uploaded_at).toLocaleDateString(\"fr-FR\", { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' })}</span>}\n                          </p>\n                        </div>\n                      </div>\n                      <div className=\"flex items-center gap-2 shrink-0 ml-2\">\n                        <Button\n                          variant=\"ghost\"\n                          size=\"sm\"\n                          onClick={() => handlePreviewAttachment(doc)}\n                          className=\"h-8 px-2 text-emerald-700 hover:text-emerald-800 hover:bg-emerald-50\"\n                          title=\"Visionner en direct\"\n                        >\n                          <Eye className=\"w-4 h-4\" />\n                        </Button>\n                        <Button\n                          variant=\"ghost\"\n                          size=\"sm\"\n                          onClick={() => handleDeleteAttachment(doc.id)}\n                          className=\"h-8 px-2 text-red-600 hover:text-red-700 hover:bg-red-50\"\n                          title=\"Supprimer\"\n                        >\n                          <Trash2 className=\"w-4 h-4 text-red-600\" />\n                        </Button>\n                      </div>\n                    </div>\n                  ))}\n                </div>\n              )}\n            </div>\n          </div>\n\n          <DialogFooter>\n            <Button variant=\"outline\" onClick={() => setShowAttachmentsDialog(false)}>\n              Fermer\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n\n      {/* Visionnage Direct du PDF */}\n      <Dialog open={!!previewPdfUrl} onOpenChange={(open) => { if (!open) setPreviewPdfUrl(null); }}>\n        <DialogContent className=\"max-w-4xl h-[90vh] flex flex-col p-4 text-slate-800\">\n          <DialogHeader className=\"pb-2\">\n            <DialogTitle className=\"flex items-center gap-2 text-emerald-800\">\n              <Eye className=\"w-5 h-5 text-emerald-700\" />\n              Aperçu en Direct - {previewPdfFilename}\n            </DialogTitle>\n            <DialogDescription>\n              Prévisualisation en direct de la pièce jointe\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"flex-1 w-full overflow-hidden rounded-lg border bg-gray-100\">\n            {previewPdfUrl ? (\n              <iframe\n                src={previewPdfUrl}\n                className=\"w-full h-full rounded\"\n                title=\"Aperçu Document PDF\"\n              />\n            ) : (\n              <div className=\"flex items-center justify-center h-full text-slate-400\">\n                <Loader2 className=\"w-8 h-8 animate-spin mr-2\" />\n                Chargement en cours...\n              </div>\n            )}\n          </div>\n\n          <DialogFooter className=\"pt-2\">\n            <Button variant=\"outline\" className=\"border-emerald-200 text-emerald-700 hover:bg-emerald-50\" onClick={() => setPreviewPdfUrl(null)}>\n              Fermer\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n\n      {/* Modal d'ajout rapide de lieu de réception */}\n      {isNewVenueDialogOpen && (\n        <div className=\"fixed inset-0 z-[70] flex items-center justify-center bg-slate-900/65 backdrop-blur-xs p-4 text-slate-800\">\n          <div className=\"bg-white rounded-2xl w-full max-w-md shadow-2xl border p-6 flex flex-col gap-4 animate-in fade-in zoom-in-95 duration-150\">\n            <div className=\"flex items-center justify-between border-b pb-3\">\n              <h3 className=\"text-base font-bold text-slate-900 flex items-center gap-2\">\n                <MapPin className=\"h-5 w-5 text-indigo-600\" />\n                Ajouter un nouveau lieu\n              </h3>\n              <button \n                type=\"button\" \n                onClick={() => setIsNewVenueDialogOpen(false)} \n                className=\"text-slate-400 hover:text-slate-600 font-bold\"\n              >\n                ✕\n              </button>\n            </div>\n\n            <div className=\"space-y-4\">\n              <div className=\"space-y-1\">\n                <Label htmlFor=\"quick-venue-name\" className=\"text-xs font-bold text-slate-700\">Nom de la salle *</Label>\n                <Input\n                  id=\"quick-venue-name\"\n                  placeholder=\"Ex: Salle des fêtes, Château...\"\n                  value={newVenueForm.name}\n                  onChange={(e) => setNewVenueForm(prev => ({ ...prev, name: e.target.value }))}\n                />\n              </div>\n              <div className=\"grid grid-cols-2 gap-3\">\n                <div className=\"space-y-1\">\n                  <Label htmlFor=\"quick-venue-dept\" className=\"text-xs font-bold text-slate-700\">Département *</Label>\n                  <Input\n                    id=\"quick-venue-dept\"\n                    placeholder=\"Ex: Bas-Rhin, 67\"\n                    value={newVenueForm.department}\n                    onChange={(e) => setNewVenueForm(prev => ({ ...prev, department: e.target.value }))}\n                  />\n                </div>\n                <div className=\"space-y-1\">\n                  <Label htmlFor=\"quick-venue-city\" className=\"text-xs font-bold text-slate-700\">Ville *</Label>\n                  <Input\n                    id=\"quick-venue-city\"\n                    placeholder=\"Ex: Mussig\"\n                    value={newVenueForm.city}\n                    onChange={(e) => setNewVenueForm(prev => ({ ...prev, city: e.target.value }))}\n                  />\n                </div>\n              </div>\n            </div>\n\n            <div className=\"flex justify-end gap-2 pt-3 border-t\">\n              <Button \n                type=\"button\" \n                variant=\"outline\" \n                size=\"sm\" \n                onClick={() => setIsNewVenueDialogOpen(false)}\n              >\n                Annuler\n              </Button>\n              <Button \n                type=\"button\" \n                size=\"sm\" \n                onClick={handleQuickCreateVenue}\n                className=\"bg-indigo-600 hover:bg-indigo-700 text-white font-bold\"\n              >\n                Créer la salle\n              </Button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Modal d'importation de vieux contrats */}\n      {isImportModalOpen && (\n        <div className=\"fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-xs p-4 sm:p-6 text-slate-800\">\n          <div className=\"bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] flex flex-col shadow-2xl border border-slate-100 overflow-hidden relative animate-in fade-in zoom-in-95 duration-200\">\n            {/* Header */}\n            <div className=\"flex items-center justify-between px-6 py-4 border-b bg-slate-50 shrink-0\">\n              <div className=\"flex items-center space-x-2\">\n                <Upload className=\"h-5 w-5 text-indigo-600\" />\n                <h3 className=\"text-lg font-bold text-slate-800\">\n                  Importer un vieux contrat (Word, PDF, Image...)\n                </h3>\n              </div>\n              <button \n                type=\"button\"\n                onClick={() => {\n                  setIsImportModalOpen(false);\n                  setImportReport(null);\n                  setImportedFile(null);\n                  setImportError(null);\n                }}\n                className=\"text-slate-400 hover:text-slate-600 p-1.5 hover:bg-slate-100 rounded-lg transition-colors\"\n                title=\"Quitter\"\n              >\n                <X className=\"h-5 w-5\" />\n              </button>\n            </div>\n\n            {/* Content Area */}\n            <div className=\"flex-1 overflow-y-auto p-6 space-y-6\">\n              {!importReport ? (\n                // Step 1: Upload and analyze\n                <div className=\"space-y-4\">\n                  <p className=\"text-sm text-slate-600 leading-relaxed\">\n                    Déposez votre ancien contrat (Word converti en PDF, fichier PDF exporté de Google Docs, photo/scan d'un contrat papier, ou fichier texte standard). L'intelligence artificielle Gemini lira le document, en extraira toutes les options techniques et les données client, et les comparera à vos tarifs actuels.\n                  </p>\n\n                  {/* Drag and Drop Zone */}\n                  <div \n                    onClick={() => document.getElementById('contract-file-upload').click()}\n                    className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all ${\n                      importedFile \n                        ? 'border-indigo-500 bg-indigo-50/30' \n                        : 'border-slate-300 hover:border-slate-400 bg-slate-50/50'\n                    }`}\n                  >\n                    <input \n                      id=\"contract-file-upload\" \n                      type=\"file\" \n                      accept=\".pdf,.png,.jpg,.jpeg,.webp,.txt\"\n                      className=\"hidden\" \n                      onChange={(e) => {\n                        if (e.target.files && e.target.files[0]) {\n                          setImportedFile(e.target.files[0]);\n                          setImportError(null);\n                        }\n                      }}\n                    />\n                    <Upload className=\"h-10 w-10 text-slate-400 mx-auto mb-3\" />\n                    {importedFile ? (\n                      <div className=\"space-y-1\">\n                        <p className=\"text-sm font-semibold text-slate-800\">{importedFile.name}</p>\n                        <p className=\"text-xs text-slate-500\">{(importedFile.size / 1024 / 1024).toFixed(2)} MB</p>\n                      </div>\n                    ) : (\n                      <div className=\"space-y-1\">\n                        <p className=\"text-sm font-semibold text-slate-700\">Sélectionnez ou glissez un fichier ici</p>\n                        <p className=\"text-xs text-slate-500\">Formats acceptés : PDF, PNG, JPG, JPEG, WEBP, TXT</p>\n                      </div>\n                    )}\n                  </div>\n\n                  {importError && (\n                    <div className=\"p-3 bg-red-50 border border-red-100 rounded-lg text-xs text-red-600 flex items-center space-x-2\">\n                      <span className=\"font-bold\">Erreur:</span>\n                      <span>{importError}</span>\n                    </div>\n                  )}\n\n                  {isImporting && (\n                    <div className=\"p-6 bg-slate-50 rounded-xl space-y-4 text-center border\">\n                      <Loader2 className=\"h-8 w-8 text-indigo-600 animate-spin mx-auto animate-duration-1000\" />\n                      <div className=\"space-y-1\">\n                        <p className=\"text-sm font-semibold text-slate-700\">Analyse intelligente en cours, veuillez patienter...</p>\n                        <p className=\"text-xs text-slate-500\">\n                          Gemini lit les clauses, décode les options et valide les tarifs d'options...\n                        </p>\n                      </div>\n                    </div>\n                  )}\n                </div>\n              ) : (\n                // Step 2: Show Report, parsed conflicts and validate\n                <div className=\"space-y-6\">\n                  {/* Journal de Validation / Conflits */}\n                  <div className=\"space-y-3\">\n                    <h4 className=\"text-sm font-semibold text-slate-800 flex items-center space-x-2\">\n                      <span className=\"bg-amber-100 text-amber-700 h-6 w-6 rounded-full flex items-center justify-center text-xs\">📝</span>\n                      <span>Journal de Validation & Conflits de Tarifs</span>\n                    </h4>\n                    {importReport.conflicts && importReport.conflicts.length > 0 ? (\n                      <div className=\"bg-amber-50 border border-amber-200 rounded-xl p-4 space-y-2\">\n                        {importReport.conflicts.map((conflict, cIdx) => (\n                          <div key={cIdx} className=\"text-xs text-amber-900 leading-relaxed flex items-start space-x-1.5\">\n                            <span className=\"shrink-0\">•</span>\n                            <span>{conflict}</span>\n                          </div>\n                        ))}\n                      </div>\n                    ) : (\n                      <div className=\"bg-emerald-50 border border-emerald-100 rounded-xl p-4 text-xs text-emerald-800 flex items-center space-x-1.5\">\n                        <span>✨</span>\n                        <span>Aucun conflit de tarifs ni anomalie détectés ! Toutes les options correspondent parfaitement aux prix système.</span>\n                      </div>\n                    )}\n                  </div>\n\n                  {/* Résolution Interactive des Conflits de Tarifs et Choix d'Options */}\n                  {importReport.matchedOptions && importReport.matchedOptions.some(opt => opt.has_price_conflict || opt.is_pending) && (\n                    <div className=\"space-y-3 bg-blue-50/50 border border-blue-100 rounded-xl p-4\">\n                      <h4 className=\"text-sm font-semibold text-blue-800 flex items-center space-x-1.5\">\n                        <span className=\"text-base\">🎯</span>\n                        <span>Décisions sur les options (Recommandé)</span>\n                      </h4>\n                      <p className=\"text-xs text-slate-600 leading-relaxed\">\n                        L'IA a détecté des options avec un tarif différent ou marquées comme \"à définir\". Sélectionnez votre action privilégiée :\n                      </p>\n                      \n                      <div className=\"space-y-3 mt-2\">\n                        {importReport.matchedOptions.filter(opt => opt.has_price_conflict || opt.is_pending).map((opt) => (\n                          <div key={opt.id} className=\"bg-white border border-slate-200 rounded-xl p-3 shadow-xs space-y-3\">\n                            <div className=\"flex items-center justify-between border-b pb-2\">\n                              <span className=\"font-semibold text-slate-700 text-xs\">{opt.name}</span>\n                              {opt.is_pending ? (\n                                <span className=\"bg-amber-100 text-amber-800 border border-amber-200 text-[10px] font-extrabold px-2 py-0.5 rounded-full\">\n                                  Option \"À définir\"\n                                </span>\n                              ) : (\n                                <span className=\"bg-blue-100 text-blue-800 text-[10px] font-bold px-2 py-0.5 rounded-full border border-blue-200\">\n                                  Prix différent détecté\n                                </span>\n                              )}\n                            </div>\n                            \n                            {opt.is_pending ? (\n                              <div className=\"grid grid-cols-2 gap-2\">\n                                {/* Option pour un choix à définir : Inclure (Tarif standard) */}\n                                <button\n                                  type=\"button\"\n                                  onClick={() => handleResolveConflict(opt.id, 'inclure')}\n                                  className={`flex flex-col items-center justify-center p-2 rounded-lg border text-center transition-all ${\n                                    opt.selected === true\n                                      ? 'border-emerald-600 bg-emerald-50 text-emerald-900 ring-2 ring-emerald-200 ring-opacity-50'\n                                      : 'border-slate-150 bg-slate-50 text-slate-600 hover:bg-slate-100'\n                                  }`}\n                                >\n                                  <span className=\"text-[9px] text-slate-400 font-bold uppercase tracking-wider\">Activer</span>\n                                  <span className=\"text-sm font-bold text-slate-800 mt-1\">Inclure ({opt.price} €)</span>\n                                  <span className=\"text-[8px] text-emerald-600 font-extrabold mt-1\">\n                                    RAJOUTER\n                                  </span>\n                                </button>\n\n                                {/* Option pour un choix à définir : Exclure */}\n                                <button\n                                  type=\"button\"\n                                  onClick={() => handleResolveConflict(opt.id, 'exclure')}\n                                  className={`flex flex-col items-center justify-center p-2 rounded-lg border text-center transition-all ${\n                                    opt.selected === false\n                                      ? 'border-slate-450 bg-slate-100 text-slate-900 ring-2 ring-slate-200 ring-opacity-50'\n                                      : 'border-slate-150 bg-slate-50 text-slate-600 hover:bg-slate-100'\n                                  }`}\n                                >\n                                  <span className=\"text-[9px] text-slate-400 font-bold uppercase tracking-wider\">Laisser de côté</span>\n                                  <span className=\"text-sm font-bold text-slate-500 mt-1\">Exclure</span>\n                                  <span className=\"text-[8px] text-slate-500 font-bold mt-1\">\n                                    SANS OPTION\n                                  </span>\n                                </button>\n                              </div>\n                            ) : (\n                              <div className=\"grid grid-cols-3 gap-2\">\n                                {/* Option 1: Keep Imported Price */}\n                                <button\n                                  type=\"button\"\n                                  onClick={() => handleResolveConflict(opt.id, 'imported')}\n                                  className={`flex flex-col items-center justify-center p-2 rounded-lg border text-center transition-all ${\n                                    opt.resolution_choice === 'imported' && opt.selected !== false\n                                      ? 'border-indigo-600 bg-indigo-50 text-indigo-900 ring-2 ring-indigo-200 ring-opacity-50'\n                                      : 'border-slate-150 bg-slate-50 text-slate-600 hover:bg-slate-100'\n                                  }`}\n                                >\n                                  <span className=\"text-[9px] text-slate-400 font-bold uppercase tracking-wider\">Tarif Importé</span>\n                                  <span className=\"text-sm font-bold text-slate-800 mt-1\">{opt.price_in_document} €</span>\n                                  <span className=\"text-[8px] bg-emerald-100 text-emerald-800 font-extrabold px-1 py-0.5 rounded mt-1 shadow-2xs\">\n                                    CONSERVÉ\n                                  </span>\n                                </button>\n\n                                {/* Option 2: Apply Current Catalog Price */}\n                                <button\n                                  type=\"button\"\n                                  onClick={() => handleResolveConflict(opt.id, 'system')}\n                                  className={`flex flex-col items-center justify-center p-2 rounded-lg border text-center transition-all ${\n                                    opt.resolution_choice === 'system' && opt.selected !== false\n                                      ? 'border-indigo-600 bg-indigo-50 text-indigo-900 ring-2 ring-indigo-200 ring-opacity-50'\n                                      : 'border-slate-150 bg-slate-50 text-slate-600 hover:bg-slate-100'\n                                  }`}\n                                >\n                                  <span className=\"text-[9px] text-slate-400 font-bold uppercase tracking-wider\">Tarif Système</span>\n                                  <span className=\"text-sm font-bold text-slate-800 mt-1\">{opt.price} €</span>\n                                  <span className=\"text-[8px] text-slate-500 font-bold mt-1.5\">\n                                    Catalogue\n                                  </span>\n                                </button>\n\n                                {/* Option 3: Exclude Option */}\n                                <button\n                                  type=\"button\"\n                                  onClick={() => handleResolveConflict(opt.id, 'decline')}\n                                  className={`flex flex-col items-center justify-center p-2 rounded-lg border text-center transition-all ${\n                                    opt.selected === false\n                                      ? 'border-red-500 bg-red-50 text-red-900 ring-2 ring-red-200 ring-opacity-50'\n                                      : 'border-slate-150 bg-slate-50 text-slate-600 hover:bg-slate-100'\n                                  }`}\n                                >\n                                  <span className=\"text-[9px] text-slate-400 font-bold uppercase tracking-wider\">Désactiver</span>\n                                  <span className=\"text-xs font-semibold text-red-600 mt-1\">EXCLURE</span>\n                                  <span className=\"text-[8px] text-slate-500 font-bold mt-1.5\">\n                                    Pas d'option\n                                  </span>\n                                </button>\n                              </div>\n                            )}\n                          </div>\n                        ))}\n                      </div>\n                    </div>\n                  )}\n\n                  {/* Target Contract Association Box */}\n                  <div className=\"bg-indigo-50/40 border border-indigo-100 rounded-xl p-4.5 space-y-3.5 shadow-xs\">\n                    <div className=\"flex items-center gap-2\">\n                      <Paperclip className=\"h-4 w-4 text-indigo-600\" />\n                      <label className=\"text-xs font-bold text-slate-700 uppercase tracking-wider\">\n                        Destination ou association de l'import :\n                      </label>\n                    </div>\n                    \n                    <div className=\"space-y-2.5\">\n                      <div className=\"flex flex-col sm:flex-row gap-3\">\n                        <button\n                          type=\"button\"\n                          onClick={() => {\n                            setImportTargetContractId(\"\");\n                          }}\n                          className={`flex-1 px-4 py-3 text-xs font-bold border rounded-lg transition-all text-center cursor-pointer ${\n                            !importTargetContractId\n                              ? \"bg-indigo-600 text-white border-indigo-700 shadow-sm\"\n                              : \"bg-white border-slate-200 text-slate-600 hover:bg-slate-50\"\n                          }`}\n                        >\n                          Créer un nouveau contrat indépendant\n                        </button>\n                        \n                        {contracts && contracts.length > 0 && (\n                          <select\n                            value={importTargetContractId}\n                            onChange={(e) => setImportTargetContractId(e.target.value)}\n                            className={`flex-1 px-3 py-2.5 bg-white border rounded-lg text-xs font-semibold outline-none transition-all cursor-pointer ${\n                              importTargetContractId\n                                ? \"border-emerald-500 ring-2 ring-emerald-50 text-emerald-900 font-bold\"\n                                : \"border-slate-200 text-slate-600 hover:border-slate-300\"\n                            }`}\n                          >\n                            <option value=\"\">-- Mettre à jour un contrat existant --</option>\n                            {contracts\n                              .filter(c => c.status === 'draft' || c.status === 'validated')\n                              .map(c => (\n                                <option key={c.id} value={c.id}>\n                                  {c.client_info?.name || \"Client Sans Nom\"} ({c.client_info?.event_date || \"Pas de Date\"}) - {c.invoice_number || \"Brouillon / Sans Numéro\"}\n                                </option>\n                              ))}\n                          </select>\n                        )}\n                      </div>\n\n                      {importTargetContractId && (\n                        <div className=\"p-3 bg-emerald-50/80 border border-emerald-100 rounded-lg text-xs text-emerald-800 flex items-start gap-2.5 animate-fadeIn\">\n                          <FileCheck className=\"w-4.5 h-4.5 text-emerald-600 mt-0.5 flex-shrink-0\" />\n                          <div>\n                            <p className=\"font-bold\">Mode Complémentaire Activé !</p>\n                            <p className=\"mt-0.5 text-emerald-700 leading-relaxed\">\n                              Le fichier d'origine sera rattaché au contrat existant pour <strong className=\"font-bold text-emerald-900\">{contracts.find(c => c.id === importTargetContractId)?.client_info?.name}</strong>. Les nouvelles options s'ajouteront ou fusionneront sans perte d'historique.\n                            </p>\n                          </div>\n                        </div>\n                      )}\n                      \n                      {!importTargetContractId && importMatchedContract && (\n                        <div className=\"p-3 bg-amber-50/80 border border-amber-100 rounded-lg text-xs text-amber-800 flex items-start gap-2.5\">\n                          <AlertCircle className=\"w-4.5 h-4.5 text-amber-600 mt-0.5 flex-shrink-0\" />\n                          <div>\n                            <p className=\"font-bold\">Contrat existant similaire détecté !</p>\n                            <p className=\"mt-0.5 text-amber-700 leading-relaxed\">\n                              Un contrat existant a été trouvé pour <strong className=\"font-bold text-amber-900\">{importMatchedContract.client_info?.name}</strong> ({importMatchedContract.client_info?.event_date}). \n                              <button\n                                type=\"button\"\n                                onClick={() => setImportTargetContractId(importMatchedContract.id)}\n                                className=\"ml-1.5 underline hover:text-amber-950 font-bold cursor-pointer\"\n                              >\n                                Cliquez ici pour l'associer comme complémentaire\n                              </button>\n                            </p>\n                          </div>\n                        </div>\n                      )}\n                    </div>\n                  </div>\n\n                  {/* Summary of parsed values */}\n                  <div className=\"border border-slate-150 rounded-xl overflow-hidden bg-slate-55/50\">\n                    <div className=\"px-4 py-2 bg-slate-100 border-b\">\n                      <p className=\"text-xs font-semibold text-slate-700\">Résumé des données extraites</p>\n                    </div>\n                    <div className=\"p-4 grid grid-cols-1 md:grid-cols-2 gap-4 text-sm\">\n                      <div className=\"space-y-2\">\n                        <p className=\"text-xs uppercase tracking-wider text-slate-400 font-bold\">Client</p>\n                        <p><strong className=\"text-slate-600\">Nom :</strong> {importReport.extractedData.client_info.name || \"—\"}</p>\n                        <p><strong className=\"text-slate-600\">Email :</strong> {importReport.extractedData.client_info.email || \"—\"}</p>\n                        <p><strong className=\"text-slate-600\">Tel :</strong> {importReport.extractedData.client_info.phone || \"—\"}</p>\n                        <p><strong className=\"text-slate-600\">Adresse :</strong> {importReport.extractedData.client_info.address || \"—\"}</p>\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <p className=\"text-xs uppercase tracking-wider text-slate-400 font-bold\">Prestation</p>\n                        <p><strong className=\"text-slate-600\">Événement :</strong> {importReport.extractedData.client_info.event_type} à {importReport.extractedData.client_info.event_location || \"—\"}</p>\n                        <p><strong className=\"text-slate-600\">Date :</strong> {importReport.extractedData.client_info.event_date || \"—\"}</p>\n                        <p><strong className=\"text-slate-600\">Tarif de base :</strong> {importReport.extractedData.base_price} €</p>\n                        <p><strong className=\"text-slate-600\">Acompte :</strong> {importReport.extractedData.custom_deposit_amount} €</p>\n                      </div>\n\n                      {importReport.matchedOptions && importReport.matchedOptions.length > 0 && (\n                        <div className=\"md:col-span-2 space-y-2 pt-2 border-t text-slate-800\">\n                          <p className=\"text-xs uppercase tracking-wider text-slate-400 font-bold\">Options Associées ({importReport.matchedOptions.length})</p>\n                          <div className=\"flex flex-wrap gap-1.5\">\n                            {importReport.matchedOptions.map((opt, oIdx) => {\n                              if (opt.selected === false) {\n                                return (\n                                  <span key={oIdx} className=\"bg-slate-100 border border-slate-200 text-slate-400 line-through text-xs font-semibold px-2.5 py-1 rounded-lg italic\">\n                                    {opt.name} (Exclu)\n                                  </span>\n                                );\n                              }\n                              const displayPrice = opt.resolved_price !== undefined ? opt.resolved_price : opt.price;\n                              const isConflictResolved = opt.has_price_conflict;\n                              return (\n                                <span key={oIdx} className={`text-xs font-semibold px-2.5 py-1 rounded-lg border ${\n                                  isConflictResolved \n                                    ? \"bg-indigo-50 border-indigo-200 text-indigo-800 shadow-3xs\" \n                                    : \"bg-emerald-50 border-emerald-150 text-emerald-800\"\n                                }`}>\n                                  {opt.name} ({displayPrice} €)\n                                  {isConflictResolved && (\n                                    <span className=\"ml-1 text-[9px] text-indigo-500 font-extrabold tracking-wide uppercase\">\n                                      [{opt.resolution_choice === 'imported' ? 'Tarif Importé' : 'Tarif Catalogue'}]\n                                    </span>\n                                  )}\n                                </span>\n                              );\n                            })}\n                          </div>\n                        </div>\n                      )}\n\n                      {importReport.extractedData.deroulement && importReport.extractedData.deroulement.length > 0 && (\n                        <div className=\"md:col-span-2 space-y-2 pt-2 border-t text-slate-800\">\n                          <p className=\"text-xs uppercase tracking-wider text-slate-400 font-bold\">Déroulement et Chronologie ({importReport.extractedData.deroulement.length} étapes)</p>\n                          <div className=\"space-y-1.5\">\n                            {importReport.extractedData.deroulement.map((item, dIdx) => (\n                              <div key={dIdx} className=\"text-xs flex flex-col md:flex-row md:items-center bg-white p-2 rounded-lg border\">\n                                <span className=\"font-bold text-slate-700 min-w-[140px] truncate\">{item.title}</span>\n                                <span className=\"text-slate-500 italic md:ml-4\">{item.notes || \"Sans note\"}</span>\n                              </div>\n                            ))}\n                          </div>\n                        </div>\n                      )}\n                    </div>\n                  </div>\n                </div>\n              )}\n            </div>\n\n            {/* Footer */}\n            <div className=\"px-6 py-4 border-t bg-slate-50 flex items-center justify-between shrink-0\">\n              <Button \n                onClick={() => {\n                  setImportReport(null);\n                  setImportedFile(null);\n                  setImportError(null);\n                  setImportTargetContractId(\"\");\n                  setImportMatchedContract(null);\n                }}\n                variant=\"outline\"\n                className=\"px-4 py-2 text-sm text-slate-600\"\n                disabled={isImporting}\n              >\n                {importReport ? \"Recommencer\" : \"Réinitialiser\"}\n              </Button>\n\n              <div className=\"flex items-center space-x-2\">\n                <Button \n                  onClick={() => {\n                    setIsImportModalOpen(false);\n                    setImportReport(null);\n                    setImportedFile(null);\n                    setImportError(null);\n                    setImportTargetContractId(\"\");\n                    setImportMatchedContract(null);\n                  }}\n                  variant=\"ghost\"\n                  className=\"px-4 py-2 text-sm text-slate-500\"\n                  disabled={isImporting}\n                >\n                  Annuler\n                </Button>\n\n                {!importReport ? (\n                  <Button \n                    onClick={handleImportContract}\n                    disabled={isImporting || !importedFile}\n                    className=\"px-5 py-2 text-sm bg-indigo-600 hover:bg-indigo-700 text-white flex items-center gap-1.5 shadow-sm rounded-xl\"\n                  >\n                    {isImporting ? (\n                      <>\n                        <Loader2 className=\"h-4 w-4 animate-spin\" />\n                        Analyse...\n                      </>\n                    ) : (\n                      <>\n                        <Upload className=\"h-4 w-4\" />\n                        Analyser le contrat\n                      </>\n                    )}\n                  </Button>\n                ) : (\n                  <Button \n                    onClick={applyImportedData}\n                    className=\"px-5 py-2 text-sm bg-indigo-600 hover:bg-indigo-700 text-white flex items-center gap-1.5 shadow-sm rounded-xl\"\n                  >\n                    <span>Injecter dans le formulaire</span>\n                    <span>→</span>\n                  </Button>\n                )}\n              </div>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Dialogue d'envoi de notification email à l'artiste/freelance */}\n      <Dialog open={isArtistNotifOpen} onOpenChange={setIsArtistNotifOpen}>\n        <DialogContent className=\"max-w-2xl bg-white rounded-xl shadow-2xl border border-indigo-105\">\n          <DialogHeader className=\"border-b pb-4\">\n            <DialogTitle className=\"flex items-center gap-2 text-indigo-900 font-bold text-xl\">\n              <Mail className=\"h-6 w-6 text-indigo-600\" />\n              <span>Informer l'artiste freelance du contrat signé</span>\n            </DialogTitle>\n            <DialogDescription className=\"text-slate-500 text-sm mt-1\">\n              Félicitations pour la signature ! Voulez-vous envoyer une notification par email à <strong>{notifArtistProfile?.nom_artistique || notifArtistProfile?.nom_complet}</strong> pour confirmer sa prestation ?\n            </DialogDescription>\n          </DialogHeader>\n\n          <div className=\"space-y-4 py-4\">\n            <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4\">\n              <div className=\"space-y-1 col-span-1\">\n                <Label className=\"text-xs font-bold text-slate-700\">Adresse e-mail destinataire</Label>\n                <Input \n                  type=\"email\" \n                  value={notifRecipientEmail} \n                  onChange={(e) => setNotifRecipientEmail(e.target.value)}\n                  className=\"border-slate-300 shadow-sm\"\n                  placeholder=\"email@artiste.com\"\n                />\n              </div>\n\n              <div className=\"space-y-1 col-span-1\">\n                <Label className=\"text-xs font-bold text-slate-700\">Choisir un modèle d'email</Label>\n                <select\n                  className=\"w-full h-10 px-3 py-2 text-sm bg-white border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-505 cursor-pointer\"\n                  value={notifSelectedTemplateId}\n                  onChange={(e) => handleNotifTemplateChange(e.target.value)}\n                >\n                  {notifTemplates.map(t => (\n                    <option key={t.id} value={t.id}>{t.name} {t.is_default ? \"(Par défaut)\" : \"\"}</option>\n                  ))}\n                  {notifTemplates.length === 0 && <option value=\"\">Aucun modèle (Saisie manuelle)</option>}\n                </select>\n              </div>\n            </div>\n\n            <div className=\"space-y-1\">\n              <Label className=\"text-xs font-bold text-slate-700\">Objet du message</Label>\n              <Input \n                value={notifEmailSubject} \n                onChange={(e) => setNotifEmailSubject(e.target.value)}\n                className=\"border-slate-300 shadow-sm font-medium\"\n              />\n            </div>\n\n            <div className=\"space-y-1\">\n              <Label className=\"text-xs font-bold text-slate-700\">Message (Formatage simple ou HTML)</Label>\n              <Textarea \n                value={notifEmailBody} \n                onChange={(e) => setNotifEmailBody(e.target.value)}\n                rows={8}\n                className=\"border-slate-300 shadow-sm font-sans text-sm focus:ring-indigo-500 focus:border-indigo-500\"\n              />\n            </div>\n          </div>\n\n          <DialogFooter className=\"border-t pt-4 flex gap-2 justify-end\">\n            <Button \n              variant=\"outline\" \n              onClick={() => {\n                setIsArtistNotifOpen(false);\n                setNotifContract(null);\n                setNotifArtistProfile(null);\n                toast.info(\"Notification sautée, contrat signé avec succès.\");\n              }} \n              disabled={notifIsSending}\n              className=\"text-slate-600 border-slate-300 hover:bg-slate-50 transition-colors\"\n            >\n              Passer sans envoyer\n            </Button>\n            <Button \n              onClick={sendArtistNotification} \n              disabled={notifIsSending || !notifRecipientEmail.trim()}\n              className=\"bg-indigo-600 hover:bg-indigo-700 text-white min-w-[120px] transition-colors\"\n            >\n              {notifIsSending ? \"Envoi...\" : <><Mail className=\"h-4 w-4 mr-2\" />Envoyer le mail</>}\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n    </div>\n  );\n}\n\nexport default Contracts2App;\n","import React, { useState, useEffect, useRef, useMemo } from 'react';\nimport { useSearchParams } from 'react-router-dom';\nimport { Button } from './ui/button';\nimport { Input } from './ui/input';\nimport { Label } from './ui/label';\nimport { Card, CardContent, CardHeader, CardTitle } from './ui/card';\nimport { Checkbox } from './ui/checkbox';\nimport { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from './ui/select';\nimport { toast } from 'sonner';\nimport { \n  FileText, Send, Eye, Euro, Mail, Plus, Trash2, Edit2, Save, Star, Loader2,\n  CheckCircle, Image as ImageIcon, Settings2, ChevronUp, ChevronDown, XCircle, History\n} from 'lucide-react';\nimport ReactQuill from 'react-quill';\nimport 'react-quill/dist/quill.snow.css';\nimport { Document, Page, pdfjs } from 'react-pdf';\nimport 'react-pdf/dist/esm/Page/AnnotationLayer.css';\nimport 'react-pdf/dist/esm/Page/TextLayer.css';\nimport api from '../services/api';\nimport FormSubmissionsSelector from './FormSubmissionsSelector';\nimport VariableInsertMenu, { VARIABLES } from './VariableInsertMenu';\nimport { useEmailSignature } from '../hooks/useEmailSignature';\n\n// Modules extraits\nimport { quillModules, quillFormats, categoryLabels, initialManualQuoteForm } from './devis/constants';\nimport { SuiviTab } from './devis/SuiviTab';\nimport {\n  PdfPreviewDialog, TemplateDialog, EditPageDialog, AddPageDialog,\n  PagePreviewDialog, RelanceDialog, NotesDialog, ManualQuoteDialog\n} from './devis/DevisDialogs';\n\n// Configure PDF.js worker\npdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;\n\nconst DevisEnvoiApp = () => {\n  const { signatureHtml } = useEmailSignature();\n  // ═══════════════════════════════════════════\n  // STATE\n  // ═══════════════════════════════════════════\n  const [availablePages, setAvailablePages] = useState([]);\n  const [selectedPages, setSelectedPages] = useState([]);\n  const [priceAmount, setPriceAmount] = useState('');\n  const [priceType, setPriceType] = useState('TTC');\n  const [eventDate, setEventDate] = useState('');\n  const [eventDateType, setEventDateType] = useState('full');\n  const [recipientEmail, setRecipientEmail] = useState('');\n  const [emailSubject, setEmailSubject] = useState('');\n  const [emailBody, setEmailBody] = useState('');\n  const [templates, setTemplates] = useState([]);\n  const [showTemplateDialog, setShowTemplateDialog] = useState(false);\n  const [editingTemplate, setEditingTemplate] = useState(null);\n  const [templateForm, setTemplateForm] = useState({ name: '', subject: '', body: '', is_default: false });\n  const [pdfPreview, setPdfPreview] = useState(null);\n  const [pdfBlobUrl, setPdfBlobUrl] = useState(null);\n  const [showPreview, setShowPreview] = useState(false);\n  const [numPages, setNumPages] = useState(null);\n  const [currentPage, setCurrentPage] = useState(1);\n  const [endTime, setEndTime] = useState('');\n  const [unlimitedTime, setUnlimitedTime] = useState(false);\n  const [showPageManagement, setShowPageManagement] = useState(false);\n  const [editingPage, setEditingPage] = useState(null);\n  const [pageForm, setPageForm] = useState({ label: '', category: 'artiste', is_tarif: false });\n  const [showAddPageDialog, setShowAddPageDialog] = useState(false);\n  const [newPageFile, setNewPageFile] = useState(null);\n  const [uploadingPage, setUploadingPage] = useState(false);\n  const [pagePreviewData, setPagePreviewData] = useState(null);\n  const [showPagePreview, setShowPagePreview] = useState(false);\n  const fileInputRef = useRef(null);\n  const [loadingPages, setLoadingPages] = useState(true);\n  const [generatingPdf, setGeneratingPdf] = useState(false);\n  const [sendingEmail, setSendingEmail] = useState(false);\n  const [savingTemplate, setSavingTemplate] = useState(false);\n  const [searchParams] = useSearchParams();\n  const [activeTab, setActiveTab] = useState(() => {\n    const tabParam = searchParams.get('tab');\n    return tabParam === 'suivi' ? 'suivi' : 'envoi';\n  });\n  const [sentQuotes, setSentQuotes] = useState([]);\n  const [loadingSentQuotes, setLoadingSentQuotes] = useState(false);\n  const [statusFilter, setStatusFilter] = useState('all');\n  const [searchFilter, setSearchFilter] = useState('');\n  const [showRelanceDialog, setShowRelanceDialog] = useState(false);\n  const [selectedQuoteForRelance, setSelectedQuoteForRelance] = useState(null);\n  const [relanceNote, setRelanceNote] = useState('');\n  const [showNotesDialog, setShowNotesDialog] = useState(false);\n  const [selectedQuoteForNotes, setSelectedQuoteForNotes] = useState(null);\n  const [notesText, setNotesText] = useState('');\n  const [showAddManualDialog, setShowAddManualDialog] = useState(false);\n  const [manualQuoteForm, setManualQuoteForm] = useState(initialManualQuoteForm);\n  const [manualQuoteFile, setManualQuoteFile] = useState(null);\n  const [savingManualQuote, setSavingManualQuote] = useState(false);\n  const manualFileInputRef = useRef(null);\n  const [selectedSubmission, setSelectedSubmission] = useState(null);\n  const quillRef = useRef(null);\n  const subjectInputRef = useRef(null);\n\n  // Handle submission selection - pre-fill fields\n  const handleSubmissionSelect = (fields) => {\n    if (fields.email) setRecipientEmail(fields.email);\n    if (fields.date_evenement) {\n      const raw = fields.date_evenement;\n      const parsed = parseDateToISO(raw);\n      if (parsed) {\n        setEventDate(parsed);\n        setEventDateType('full');\n      } else {\n        setEventDate(raw);\n        setEventDateType('text');\n      }\n    }\n    setSelectedSubmission(fields);\n  };\n\n  // Clear imported submission\n  const handleClearSubmission = () => {\n    setSelectedSubmission(null);\n  };\n\n  // Parse date to yyyy-mm-dd (for the HTML date input)\n  const parseDateToISO = (dateStr) => {\n    if (!dateStr) return null;\n    if (/^\\d{4}-\\d{2}-\\d{2}$/.test(dateStr)) return dateStr;\n    const match = dateStr.match(/^(\\d{1,2})[/\\-.](\\d{1,2})[/\\-.](\\d{4})$/);\n    if (match) return `${match[3]}-${match[2].padStart(2,'0')}-${match[1].padStart(2,'0')}`;\n    const d = new Date(dateStr);\n    if (!isNaN(d.getTime())) return d.toISOString().split('T')[0];\n    return null;\n  };\n\n  // Format date as JJ-MM-AAAA for display\n  const formatDateDisplay = (dateStr) => {\n    if (!dateStr) return '';\n    const parsed = parseDateToISO(dateStr);\n    if (parsed) {\n      const [y, m, d] = parsed.split('-');\n      return `${d}-${m}-${y}`;\n    }\n    return dateStr;\n  };\n\n  // Insert variable at cursor in email body (ReactQuill)\n  const handleInsertVariable = (variable) => {\n    const quill = document.querySelector('.ql-editor');\n    if (quill) {\n      const sel = window.getSelection();\n      if (sel.rangeCount > 0 && quill.contains(sel.anchorNode)) {\n        const range = sel.getRangeAt(0);\n        const textNode = document.createTextNode(variable);\n        range.deleteContents();\n        range.insertNode(textNode);\n        range.setStartAfter(textNode);\n        range.collapse(true);\n        sel.removeAllRanges();\n        sel.addRange(range);\n        setEmailBody(quill.innerHTML);\n      } else {\n        setEmailBody(prev => prev ? prev.replace(/<\\/p>(?![\\s\\S]*<\\/p>)/, `${variable}</p>`) : `<p>${variable}</p>`);\n      }\n    } else {\n      setEmailBody(prev => prev ? prev.replace(/<\\/p>(?![\\s\\S]*<\\/p>)/, `${variable}</p>`) : `<p>${variable}</p>`);\n    }\n  };\n\n  // Insert variable at cursor in email subject\n  const handleInsertSubjectVariable = (variable) => {\n    const input = subjectInputRef.current;\n    if (input) {\n      const start = input.selectionStart || 0;\n      const end = input.selectionEnd || 0;\n      const current = emailSubject || '';\n      const newVal = current.slice(0, start) + variable + current.slice(end);\n      setEmailSubject(newVal);\n      setTimeout(() => {\n        input.focus();\n        input.setSelectionRange(start + variable.length, start + variable.length);\n      }, 0);\n    } else {\n      setEmailSubject(prev => prev + variable);\n    }\n  };\n\n  // Replace variables in text with actual values\n  const replaceVariables = (text, data) => {\n    if (!text || !data) return text;\n    let result = text;\n    VARIABLES.forEach(v => {\n      const field = v.key.replace(/[{}]/g, '');\n      const value = data[field] || '';\n      result = result.split(v.key).join(value);\n    });\n    return result;\n  };\n\n  // ═══════════════════════════════════════════\n  // DATA LOADING\n  // ═══════════════════════════════════════════\n  useEffect(() => { fetchPages(); fetchTemplates(); fetchSentQuotes(); }, []);\n\n  // Initialize email body with signature when loaded\n  useEffect(() => {\n    if (signatureHtml && !emailBody) {\n      setEmailBody(signatureHtml);\n    }\n  }, [signatureHtml]);\n\n  const fetchPages = async () => {\n    try { setLoadingPages(true); const response = await api.get('/devis2/pages'); setAvailablePages(response.data.pages || []); }\n    catch (error) { console.error('Error fetching pages:', error); toast.error('Erreur lors du chargement des pages'); }\n    finally { setLoadingPages(false); }\n  };\n\n  const fetchTemplates = async () => {\n    try { const response = await api.get('/devis2/templates'); setTemplates(response.data.templates || []); }\n    catch (error) { console.error('Error fetching templates:', error); }\n  };\n\n  const fetchSentQuotes = async () => {\n    setLoadingSentQuotes(true);\n    try { const response = await api.get('/devis2/sent'); setSentQuotes(response.data.quotes || []); }\n    catch (error) { console.error('Error fetching sent quotes:', error); }\n    finally { setLoadingSentQuotes(false); }\n  };\n\n  // ═══════════════════════════════════════════\n  // SUIVI OPERATIONS\n  // ═══════════════════════════════════════════\n  const updateQuoteStatus = async (quoteId, newStatus) => {\n    try { await api.put(`/devis2/sent/${quoteId}`, { status: newStatus }); setSentQuotes(prev => prev.map(q => q.id === quoteId ? { ...q, status: newStatus } : q)); toast.success('Statut mis à jour'); }\n    catch (error) { console.error('Error updating status:', error); toast.error('Erreur lors de la mise à jour'); }\n  };\n\n  const addRelance = async () => {\n    if (!selectedQuoteForRelance || !relanceNote.trim()) return;\n    try {\n      const response = await api.post(`/devis2/sent/${selectedQuoteForRelance.id}/relances`, { note: relanceNote });\n      setSentQuotes(prev => prev.map(q => q.id === selectedQuoteForRelance.id ? { ...q, relances: [...(q.relances || []), response.data.relance], status: 'a_relancer' } : q));\n      setShowRelanceDialog(false); setRelanceNote(''); setSelectedQuoteForRelance(null); toast.success('Relance ajoutée');\n    } catch (error) { console.error('Error adding relance:', error); toast.error('Erreur lors de l\\'ajout de la relance'); }\n  };\n\n  const saveNotes = async () => {\n    if (!selectedQuoteForNotes) return;\n    try { await api.put(`/devis2/sent/${selectedQuoteForNotes.id}`, { notes: notesText }); setSentQuotes(prev => prev.map(q => q.id === selectedQuoteForNotes.id ? { ...q, notes: notesText } : q)); setShowNotesDialog(false); setNotesText(''); setSelectedQuoteForNotes(null); toast.success('Notes enregistrées'); }\n    catch (error) { console.error('Error saving notes:', error); toast.error('Erreur lors de l\\'enregistrement'); }\n  };\n\n  const deleteQuote = async (quoteId) => {\n    if (!window.confirm('Supprimer ce devis du suivi ?')) return;\n    try { await api.delete(`/devis2/sent/${quoteId}`); setSentQuotes(prev => prev.filter(q => q.id !== quoteId)); toast.success('Devis supprimé du suivi'); }\n    catch (error) { console.error('Error deleting quote:', error); toast.error('Erreur lors de la suppression'); }\n  };\n\n  const addManualQuote = async () => {\n    if (!manualQuoteForm.recipient_email.trim()) { toast.error('L\\'email du destinataire est requis'); return; }\n    setSavingManualQuote(true);\n    try {\n      let fileData = null, fileName = null;\n      if (manualQuoteFile) {\n        const reader = new FileReader();\n        fileData = await new Promise((resolve, reject) => { reader.onload = () => resolve(reader.result.split(',')[1]); reader.onerror = reject; reader.readAsDataURL(manualQuoteFile); });\n        fileName = manualQuoteFile.name;\n      }\n      const response = await api.post('/devis2/sent/manual', { ...manualQuoteForm, file_data: fileData, file_name: fileName });\n      setSentQuotes(prev => [response.data.quote, ...prev]); setShowAddManualDialog(false); setManualQuoteForm(initialManualQuoteForm); setManualQuoteFile(null); toast.success('Devis ajouté au suivi');\n    } catch (error) { console.error('Error adding manual quote:', error); toast.error('Erreur lors de l\\'ajout'); }\n    finally { setSavingManualQuote(false); }\n  };\n\n  const downloadQuoteFile = async (quoteId, fileName) => {\n    try {\n      const response = await api.get(`/devis2/sent/${quoteId}/file`, { responseType: 'blob' });\n      const url = window.URL.createObjectURL(new Blob([response.data]));\n      const link = document.createElement('a'); link.href = url; link.setAttribute('download', fileName || 'devis.pdf'); document.body.appendChild(link); link.click(); link.remove(); window.URL.revokeObjectURL(url);\n    } catch (error) { console.error('Error downloading file:', error); toast.error('Erreur lors du téléchargement'); }\n  };\n\n  const filteredSentQuotes = useMemo(() => {\n    return sentQuotes.filter(q => {\n      const matchesStatus = statusFilter === 'all' || q.status === statusFilter;\n      const matchesSearch = !searchFilter || q.recipient_email?.toLowerCase().includes(searchFilter.toLowerCase()) || q.recipient_name?.toLowerCase().includes(searchFilter.toLowerCase());\n      return matchesStatus && matchesSearch;\n    });\n  }, [sentQuotes, statusFilter, searchFilter]);\n\n  // ═══════════════════════════════════════════\n  // PAGE MANAGEMENT\n  // ═══════════════════════════════════════════\n  const handlePageToggle = (pageKey) => {\n    setSelectedPages(prev => prev.includes(pageKey) ? prev.filter(k => k !== pageKey) : [...prev, pageKey]);\n    setPdfPreview(null);\n  };\n\n  const getOrderedSelectedPages = () => {\n    const categoryOrder = ['artiste', 'tarif', 'option', 'photos', 'hypnose'];\n    const pagesByCategory = {}; categoryOrder.forEach(cat => { pagesByCategory[cat] = []; });\n    availablePages.forEach(page => { if (selectedPages.includes(page.id)) { const category = page.category || 'artiste'; if (pagesByCategory[category]) { pagesByCategory[category].push(page.id); } else { if (!pagesByCategory['_other']) pagesByCategory['_other'] = []; pagesByCategory['_other'].push(page.id); } } });\n    const orderedPages = []; categoryOrder.forEach(cat => { orderedPages.push(...pagesByCategory[cat]); });\n    if (pagesByCategory['_other']) { orderedPages.push(...pagesByCategory['_other']); }\n    return orderedPages;\n  };\n\n  const movePage = async (pageId, direction) => {\n    const page = availablePages.find(p => p.id === pageId);\n    if (!page) return;\n    const cat = page.category || 'artiste';\n    const pagesInCategory = availablePages.filter(p => (p.category || 'artiste') === cat);\n    const categoryIndex = pagesInCategory.findIndex(p => p.id === pageId);\n    if (categoryIndex === -1) return;\n\n    const targetIndexInCategory = direction === 'up' ? categoryIndex - 1 : categoryIndex + 1;\n    if (targetIndexInCategory < 0 || targetIndexInCategory >= pagesInCategory.length) return;\n\n    const targetPage = pagesInCategory[targetIndexInCategory];\n    const currentIndex = availablePages.findIndex(p => p.id === pageId);\n    const targetIndex = availablePages.findIndex(p => p.id === targetPage.id);\n    if (currentIndex === -1 || targetIndex === -1) return;\n\n    const newPages = [...availablePages];\n    [newPages[currentIndex], newPages[targetIndex]] = [newPages[targetIndex], newPages[currentIndex]];\n\n    try {\n      await api.post('/devis2/pages/reorder', { page_ids: newPages.map(p => p.id) });\n      setAvailablePages(newPages);\n      toast.success('Ordre mis à jour');\n    } catch (error) {\n      console.error('Error reordering pages:', error);\n      toast.error('Erreur lors de la réorganisation');\n    }\n  };\n\n  const openEditPage = (page) => { setEditingPage(page); setPageForm({ label: page.label, category: page.category, is_tarif: page.is_tarif || false }); };\n\n  const savePageEdit = async () => {\n    if (!editingPage || !pageForm.label) { toast.error('Veuillez saisir un nom'); return; }\n    try { await api.put(`/devis2/pages/${editingPage.id}`, pageForm); toast.success('Page mise à jour'); fetchPages(); setEditingPage(null); }\n    catch (error) { console.error('Error updating page:', error); toast.error('Erreur lors de la mise à jour'); }\n  };\n\n  const deletePage = async (pageId) => {\n    if (!window.confirm('Supprimer cette page ? Cette action est irréversible.')) return;\n    try { await api.delete(`/devis2/pages/${pageId}`); toast.success('Page supprimée'); fetchPages(); setSelectedPages(prev => prev.filter(id => id !== pageId)); }\n    catch (error) { console.error('Error deleting page:', error); toast.error('Erreur lors de la suppression'); }\n  };\n\n  const previewPage = async (pageId) => {\n    try { const response = await api.get(`/devis2/pages/${pageId}/preview`); if (response.data.success) { setPagePreviewData(response.data); setShowPagePreview(true); } }\n    catch (error) { console.error('Error previewing page:', error); toast.error('Erreur lors de l\\'aperçu'); }\n  };\n\n  const handleFileSelect = (e) => {\n    const file = e.target.files[0]; if (file) { if (!file.type.startsWith('image/')) { toast.error('Veuillez sélectionner une image (PNG ou JPG)'); return; } setNewPageFile(file); }\n  };\n\n  const uploadNewPage = async () => {\n    if (!newPageFile || !pageForm.label) { toast.error('Veuillez sélectionner un fichier et saisir un nom'); return; }\n    try {\n      setUploadingPage(true);\n      const formData = new FormData(); \n      formData.append('file', newPageFile); \n      formData.append('label', pageForm.label); \n      formData.append('category', pageForm.category); \n      formData.append('is_tarif', pageForm.is_tarif);\n      \n      const data = await api.uploadDevisPage(formData);\n      if (data.success) { \n        toast.success('Page ajoutée avec succès'); \n        fetchPages(); \n        setShowAddPageDialog(false); \n        setNewPageFile(null); \n        setPageForm({ label: '', category: 'options', is_tarif: false }); \n      }\n      else { toast.error(data.detail || 'Erreur lors de l\\'ajout'); }\n    } catch (error) { \n      console.error('Error uploading page:', error); \n      toast.error(error.message || 'Erreur lors de l\\'upload'); \n    }\n    finally { setUploadingPage(false); }\n  };\n\n  const deleteOrphanedPages = async () => {\n    const orphanedPages = availablePages.filter(p => p.exists === false);\n    if (orphanedPages.length === 0) { toast.info('Aucune page orpheline à supprimer'); return; }\n    if (!window.confirm(`Supprimer ${orphanedPages.length} page(s) orpheline(s) ? Cette action est irréversible.`)) return;\n    try { const response = await api.delete('/devis2/pages/orphaned'); if (response.data.success) { toast.success(response.data.message); fetchPages(); } }\n    catch (error) { console.error('Error deleting orphaned pages:', error); toast.error('Erreur lors de la suppression des pages orphelines'); }\n  };\n\n  const orphanedPagesCount = availablePages.filter(p => p.exists === false).length;\n\n  // ═══════════════════════════════════════════\n  // PDF & EMAIL\n  // ═══════════════════════════════════════════\n  const generatePdfPreview = async () => {\n    if (selectedPages.length === 0) { toast.error('Veuillez sélectionner au moins une page'); return; }\n    if (!priceAmount) { toast.error('Veuillez saisir un montant ou texte'); return; }\n    if (!eventDate) { toast.error('Veuillez saisir la date ou l\\'année de l\\'événement'); return; }\n    try {\n      setGeneratingPdf(true);\n      if (pdfBlobUrl) { URL.revokeObjectURL(pdfBlobUrl); setPdfBlobUrl(null); }\n      const orderedSelectedPages = getOrderedSelectedPages();\n      const response = await api.post('/devis2/generate-pdf', { \n        selected_pages: orderedSelectedPages, \n        price_amount: priceAmount || null, \n        price_type: priceType,\n        end_time: endTime,\n        unlimited_time: unlimitedTime\n      });\n      if (response.data.success) {\n        setPdfPreview(response.data.pdf_base64);\n        const byteCharacters = atob(response.data.pdf_base64); const byteNumbers = new Array(byteCharacters.length);\n        for (let i = 0; i < byteCharacters.length; i++) { byteNumbers[i] = byteCharacters.charCodeAt(i); }\n        const byteArray = new Uint8Array(byteNumbers); const blob = new Blob([byteArray], { type: 'application/pdf' });\n        setPdfBlobUrl(URL.createObjectURL(blob)); setShowPreview(true); toast.success('PDF généré avec succès');\n      }\n    } catch (error) { console.error('Error generating PDF:', error); toast.error('Erreur lors de la génération du PDF'); }\n    finally { setGeneratingPdf(false); }\n  };\n\n  const sendEmail = async () => {\n    if (selectedPages.length === 0) { toast.error('Veuillez sélectionner au moins une page'); return; }\n    if (!priceAmount) { toast.error('Veuillez saisir un montant ou texte'); return; }\n    if (!eventDate) { toast.error('Veuillez saisir la date ou l\\'année de l\\'événement'); return; }\n    if (!recipientEmail) { toast.error('Veuillez saisir l\\'email du destinataire'); return; }\n    if (!emailSubject) { toast.error('Veuillez saisir l\\'objet du mail'); return; }\n    try {\n      setSendingEmail(true);\n      const orderedSelectedPages = getOrderedSelectedPages();\n      const formattedEventDate = eventDateType === 'full' ? eventDate.split('-').reverse().join('-') : eventDate;\n      // Build variable data from manual fields + submission data\n      const variableData = {\n        ...(selectedSubmission || {}),\n        date_evenement: formattedEventDate || (selectedSubmission && selectedSubmission.date_evenement) || '',\n        email: recipientEmail || (selectedSubmission && selectedSubmission.email) || '',\n      };\n      const finalSubject = replaceVariables(emailSubject, variableData);\n      const finalBody = replaceVariables(emailBody, variableData);\n      const response = await api.post('/devis2/send-email', { \n        selected_pages: orderedSelectedPages, \n        price_amount: priceAmount || null, \n        price_type: priceType, \n        end_time: endTime,\n        unlimited_time: unlimitedTime,\n        event_date: formattedEventDate, \n        recipient_email: recipientEmail, \n        email_subject: finalSubject, \n        email_body: finalBody \n      });\n      if (response.data.success) { toast.success(response.data.message); setRecipientEmail(''); setEmailSubject(''); setEmailBody(signatureHtml); }\n    } catch (error) { console.error('Error sending email:', error); toast.error(error.response?.data?.detail || 'Erreur lors de l\\'envoi de l\\'email'); }\n    finally { setSendingEmail(false); }\n  };\n\n  // ═══════════════════════════════════════════\n  // TEMPLATE MANAGEMENT\n  // ═══════════════════════════════════════════\n  const openTemplateDialog = (template = null) => {\n    if (template) { setEditingTemplate(template); setTemplateForm({ name: template.name, subject: template.subject, body: template.body, is_default: template.is_default }); }\n    else { setEditingTemplate(null); setTemplateForm({ name: '', subject: emailSubject, body: emailBody, is_default: false }); }\n    setShowTemplateDialog(true);\n  };\n\n  const saveTemplate = async () => {\n    if (!templateForm.name) { toast.error('Veuillez saisir un nom pour le template'); return; }\n    if (!templateForm.subject && !templateForm.body) { toast.error('Le template doit avoir un objet ou un corps de message'); return; }\n    try {\n      setSavingTemplate(true);\n      if (editingTemplate) { await api.put(`/devis2/templates/${editingTemplate.id}`, templateForm); toast.success('Template mis à jour'); }\n      else { await api.post('/devis2/templates', templateForm); toast.success('Template créé'); }\n      fetchTemplates(); setShowTemplateDialog(false);\n    } catch (error) { console.error('Error saving template:', error); toast.error('Erreur lors de l\\'enregistrement'); }\n    finally { setSavingTemplate(false); }\n  };\n\n  const deleteTemplate = async (templateId) => {\n    if (!window.confirm('Supprimer ce template ?')) return;\n    try { await api.delete(`/devis2/templates/${templateId}`); toast.success('Template supprimé'); fetchTemplates(); }\n    catch (error) { console.error('Error deleting template:', error); toast.error('Erreur lors de la suppression'); }\n  };\n\n  const applyTemplate = (template) => { setEmailSubject(template.subject); setEmailBody(template.body); toast.success(`Template \"${template.name}\" appliqué`); };\n\n  // ═══════════════════════════════════════════\n  // RENDER\n  // ═══════════════════════════════════════════\n  return (\n    <div className=\"min-h-screen bg-gradient-to-br from-orange-50 via-white to-amber-50 p-6\">\n      <div className=\"max-w-7xl mx-auto\">\n        {/* Header */}\n        <div className=\"mb-8\">\n          <h1 className=\"text-3xl font-bold text-gray-800 flex items-center gap-3\"><Send className=\"w-8 h-8 text-orange-500\" />Envoi de Devis</h1>\n          <p className=\"text-gray-600 mt-2\">Générez et envoyez des devis PDF personnalisés à vos clients</p>\n        </div>\n\n        {/* Tabs */}\n        <div className=\"flex gap-2 mb-6\">\n          <Button variant={activeTab === 'envoi' ? 'default' : 'outline'} onClick={() => setActiveTab('envoi')} className={activeTab === 'envoi' ? 'bg-orange-500 hover:bg-orange-600' : ''}>\n            <Send className=\"w-4 h-4 mr-2\" />Envoi\n          </Button>\n          <Button variant={activeTab === 'suivi' ? 'default' : 'outline'} onClick={() => { setActiveTab('suivi'); fetchSentQuotes(); }} className={activeTab === 'suivi' ? 'bg-orange-500 hover:bg-orange-600' : ''}>\n            <History className=\"w-4 h-4 mr-2\" />Suivi ({sentQuotes.length})\n          </Button>\n        </div>\n\n        {/* Suivi Tab (composant extrait) */}\n        {activeTab === 'suivi' && (\n          <SuiviTab\n            filteredSentQuotes={filteredSentQuotes} sentQuotes={sentQuotes} loadingSentQuotes={loadingSentQuotes}\n            statusFilter={statusFilter} setStatusFilter={setStatusFilter} searchFilter={searchFilter} setSearchFilter={setSearchFilter}\n            updateQuoteStatus={updateQuoteStatus} setSelectedQuoteForRelance={setSelectedQuoteForRelance}\n            setShowRelanceDialog={setShowRelanceDialog} setSelectedQuoteForNotes={setSelectedQuoteForNotes}\n            setNotesText={setNotesText} setShowNotesDialog={setShowNotesDialog} deleteQuote={deleteQuote}\n            downloadQuoteFile={downloadQuoteFile} setShowAddManualDialog={setShowAddManualDialog}\n          />\n        )}\n\n        {/* Envoi Tab */}\n        {activeTab === 'envoi' && (\n        <div className=\"grid grid-cols-1 lg:grid-cols-2 gap-6\">\n          {/* Left Column - Price & Page Selection */}\n          <div className=\"space-y-6\">\n            {/* Price Configuration */}\n            <Card>\n              <CardHeader className=\"pb-3\"><CardTitle className=\"flex items-center gap-2\"><Euro className=\"w-5 h-5 text-orange-500\" />Configuration du Prix</CardTitle></CardHeader>\n              <CardContent>\n                <div className=\"space-y-4\">\n                  <div className=\"flex gap-4\">\n                    <div className=\"flex-1\">\n                      <Label htmlFor=\"price\">Montant ou texte <span className=\"text-red-500\">*</span></Label>\n                      <Input id=\"price\" type=\"text\" value={priceAmount} onChange={(e) => setPriceAmount(e.target.value)} className={`mt-1 ${!priceAmount ? 'border-red-300' : ''}`} data-testid=\"price-input\" required />\n                      {!priceAmount && <p className=\"text-xs text-red-500 mt-1\">Champ obligatoire</p>}\n                    </div>\n                    <div className=\"w-32\">\n                      <Label>Mention</Label>\n                      <Select value={priceType} onValueChange={setPriceType}>\n                        <SelectTrigger className=\"mt-1\" data-testid=\"price-type-select\"><SelectValue /></SelectTrigger>\n                        <SelectContent><SelectItem value=\"TTC\">TTC</SelectItem><SelectItem value=\"HT\">HT</SelectItem><SelectItem value=\"NONE\">Aucune</SelectItem></SelectContent>\n                      </Select>\n                    </div>\n                  </div>\n                  <div className=\"border-t pt-4\">\n                    <div className=\"grid grid-cols-2 gap-4\">\n                      <div>\n                        <Label>Type de date <span className=\"text-red-500\">*</span></Label>\n                        <Select value={eventDateType} onValueChange={(val) => { setEventDateType(val); setEventDate(''); }}>\n                          <SelectTrigger className=\"mt-1\"><SelectValue /></SelectTrigger>\n                          <SelectContent><SelectItem value=\"full\">Date complète</SelectItem><SelectItem value=\"year\">Année seule</SelectItem></SelectContent>\n                        </Select>\n                      </div>\n                      <div>\n                        <Label htmlFor=\"eventDate\">{eventDateType === 'full' ? \"Date de l'événement\" : \"Année de l'événement\"} <span className=\"text-red-500\">*</span></Label>\n                        {eventDateType === 'full' ? (\n                          <Input id=\"eventDate\" type=\"date\" value={eventDate} onChange={(e) => setEventDate(e.target.value)} className={`mt-1 ${!eventDate ? 'border-red-300' : ''}`} data-testid=\"event-date-input\" required />\n                        ) : (\n                          <Input id=\"eventDate\" type=\"number\" min=\"2024\" max=\"2100\" placeholder=\"2026\" value={eventDate} onChange={(e) => setEventDate(e.target.value)} className={`mt-1 ${!eventDate ? 'border-red-300' : ''}`} data-testid=\"event-year-input\" required />\n                        )}\n                        {!eventDate && <p className=\"text-xs text-red-500 mt-1\">Champ obligatoire</p>}\n                      </div>\n                    </div>\n                  </div>\n                  <div className=\"border-t pt-4\">\n                    <div className=\"flex gap-4 items-center\">\n                      <div className=\"flex-1\">\n                        <Label htmlFor=\"endTime\">Heure de fin</Label>\n                        <Input \n                          id=\"endTime\" \n                          type=\"time\" \n                          value={endTime} \n                          onChange={(e) => setEndTime(e.target.value)} \n                          className=\"mt-1\"\n                          disabled={unlimitedTime}\n                        />\n                      </div>\n                      <div className=\"flex items-center space-x-2 pt-6\">\n                        <Checkbox \n                          id=\"unlimited\" \n                          checked={unlimitedTime} \n                          onCheckedChange={(val) => setUnlimitedTime(!!val)} \n                          data-testid=\"unlimited-checkbox\"\n                        />\n                        <Label htmlFor=\"unlimited\" className=\"cursor-pointer\">Sans limite horaire</Label>\n                      </div>\n                    </div>\n                  </div>\n                </div>\n              </CardContent>\n            </Card>\n\n            {/* Page Selection */}\n            <Card>\n              <CardHeader className=\"pb-3\">\n                <CardTitle className=\"flex items-center justify-between\">\n                  <span className=\"flex items-center gap-2\"><ImageIcon className=\"w-5 h-5 text-orange-500\" />Sélection des Pages</span>\n                  <div className=\"flex gap-2\">\n                    {orphanedPagesCount > 0 && (\n                      <Button size=\"sm\" variant=\"destructive\" onClick={deleteOrphanedPages} className=\"bg-red-500 hover:bg-red-600\" title=\"Supprimer les pages dont les fichiers sont manquants\">\n                        <Trash2 className=\"w-4 h-4 mr-1\" />Supprimer orphelines ({orphanedPagesCount})\n                      </Button>\n                    )}\n                    <Button size=\"sm\" onClick={() => { setPageForm({ label: '', category: 'artiste', is_tarif: false }); setNewPageFile(null); setShowAddPageDialog(true); }} className=\"bg-green-600 hover:bg-green-700\">\n                      <Plus className=\"w-4 h-4 mr-1\" />Ajouter\n                    </Button>\n                  </div>\n                </CardTitle>\n              </CardHeader>\n              <CardContent>\n                {loadingPages ? (\n                  <div className=\"flex items-center justify-center py-8\"><Loader2 className=\"w-6 h-6 animate-spin text-orange-500\" /><span className=\"ml-2\">Chargement...</span></div>\n                ) : (\n                  <div className=\"space-y-4\">\n                    {Object.entries(categoryLabels).map(([categoryKey, categoryLabel]) => {\n                      const pagesInCategory = availablePages.filter(p => (p.category || 'artiste') === categoryKey);\n                      if (pagesInCategory.length === 0) return null;\n                      return (\n                        <div key={categoryKey} className=\"space-y-1.5\">\n                          <h4 className=\"text-sm font-semibold text-gray-700 bg-gray-100 px-2 py-1 rounded\">{categoryLabel}</h4>\n                          {pagesInCategory.map((page, catIndex) => {\n                            const globalIndex = availablePages.findIndex(p => p.id === page.id);\n                            return (\n                              <div key={page.id} className={`flex items-center gap-2 p-2 rounded-lg border transition-colors ml-2 ${selectedPages.includes(page.id || page.key) ? 'bg-orange-50 border-orange-300' : 'bg-gray-50 border-gray-200 hover:bg-gray-100'}`}>\n                                <Checkbox id={page.id || page.key} checked={selectedPages.includes(page.id || page.key)} onCheckedChange={() => handlePageToggle(page.id || page.key)} disabled={page.exists === false} data-testid={`page-checkbox-${page.key}`} />\n                                {page.exists === false && <div className=\"text-red-500\" title=\"Fichier manquant\"><XCircle className=\"w-4 h-4\" /></div>}\n                                <div className=\"flex flex-col gap-0.5\">\n                                  <Button variant=\"ghost\" size=\"sm\" className=\"h-5 w-5 p-0\" onClick={() => movePage(page.id, 'up')} disabled={catIndex === 0}><ChevronUp className=\"w-3 h-3\" /></Button>\n                                  <Button variant=\"ghost\" size=\"sm\" className=\"h-5 w-5 p-0\" onClick={() => movePage(page.id, 'down')} disabled={catIndex === pagesInCategory.length - 1}><ChevronDown className=\"w-3 h-3\" /></Button>\n                                </div>\n                                <div className=\"flex-1 min-w-0\"><p className={`font-medium truncate text-sm ${page.exists === false ? 'text-red-500 line-through' : ''}`}>{page.label}{page.exists === false && <span className=\"text-xs ml-2 text-red-400\">(fichier manquant)</span>}</p></div>\n                                {selectedPages.includes(page.id || page.key) && <CheckCircle className=\"w-4 h-4 text-green-500 flex-shrink-0\" />}\n                                <div className=\"flex gap-0.5 flex-shrink-0\">\n                                  <Button variant=\"ghost\" size=\"sm\" className=\"h-7 w-7 p-0\" onClick={() => previewPage(page.id)} title=\"Aperçu\"><Eye className=\"w-4 h-4 text-blue-500\" /></Button>\n                                  <Button variant=\"ghost\" size=\"sm\" className=\"h-7 w-7 p-0\" onClick={() => openEditPage(page)} title=\"Modifier\"><Edit2 className=\"w-4 h-4 text-gray-500\" /></Button>\n                                  <Button variant=\"ghost\" size=\"sm\" className=\"h-7 w-7 p-0 hover:bg-red-50\" onClick={() => deletePage(page.id)} title=\"Supprimer\"><Trash2 className=\"w-4 h-4 text-red-500\" /></Button>\n                                </div>\n                              </div>\n                            );\n                          })}\n                        </div>\n                      );\n                    })}\n                  </div>\n                )}\n              </CardContent>\n            </Card>\n\n            <Button onClick={generatePdfPreview} disabled={selectedPages.length === 0 || generatingPdf} className=\"w-full bg-orange-500 hover:bg-orange-600 text-white\" size=\"lg\" data-testid=\"generate-preview-btn\">\n              {generatingPdf ? (<><Loader2 className=\"w-5 h-5 mr-2 animate-spin\" />Génération en cours...</>) : (<><Eye className=\"w-5 h-5 mr-2\" />Générer l'Aperçu PDF</>)}\n            </Button>\n          </div>\n\n          {/* Right Column - Email Configuration */}\n          <div className=\"space-y-6\">\n            <Card>\n              <CardHeader>\n                <CardTitle className=\"flex items-center justify-between\">\n                  <span className=\"flex items-center gap-2\"><Mail className=\"w-5 h-5 text-orange-500\" />Configuration Email</span>\n                  <FormSubmissionsSelector onSelect={handleSubmissionSelect} buttonLabel=\"Soumissions\" />\n                </CardTitle>\n              </CardHeader>\n              <CardContent className=\"space-y-4\">\n                {selectedSubmission && (\n                  <div className=\"bg-orange-50 border border-orange-200 rounded-lg p-3 text-sm space-y-1 relative\" data-testid=\"selected-submission-info\">\n                    <button\n                      onClick={handleClearSubmission}\n                      className=\"absolute top-2 right-2 text-red-400 hover:text-red-600 transition-colors\"\n                      title=\"Annuler l'import\"\n                      data-testid=\"clear-submission-btn\"\n                    >\n                      <XCircle className=\"w-4 h-4\" />\n                    </button>\n                    <p className=\"font-semibold text-orange-700 pr-6\">Contact importé : {selectedSubmission.nom || 'Anonyme'}</p>\n                    <div className=\"flex flex-wrap gap-x-4 gap-y-0.5 text-xs text-orange-600\">\n                      {selectedSubmission.email && <span>{selectedSubmission.email}</span>}\n                      {selectedSubmission.telephone && <span>{selectedSubmission.telephone}</span>}\n                      {selectedSubmission.date_evenement && <span>{formatDateDisplay(selectedSubmission.date_evenement)}</span>}\n                    </div>\n                  </div>\n                )}\n                <div><Label htmlFor=\"recipient\">Email du destinataire</Label><Input id=\"recipient\" type=\"email\" value={recipientEmail} onChange={(e) => setRecipientEmail(e.target.value)} className=\"mt-1\" data-testid=\"recipient-email-input\" /></div>\n                <div>\n                  <div className=\"flex items-center justify-between\">\n                    <Label htmlFor=\"subject\">Objet du mail</Label>\n                    <VariableInsertMenu onInsert={handleInsertSubjectVariable} submissionData={selectedSubmission} />\n                  </div>\n                  <Input id=\"subject\" ref={subjectInputRef} value={emailSubject} onChange={(e) => setEmailSubject(e.target.value)} className=\"mt-1\" data-testid=\"email-subject-input\" />\n                </div>\n                <div>\n                  <div className=\"flex items-center justify-between mb-1\">\n                    <Label htmlFor=\"body\">Corps du message</Label>\n                    <VariableInsertMenu onInsert={handleInsertVariable} submissionData={selectedSubmission} />\n                  </div>\n                  <div className=\"mt-1 bg-white rounded-md border\" data-testid=\"email-body-editor\">\n                    <ReactQuill theme=\"snow\" value={emailBody} onChange={setEmailBody} modules={quillModules} formats={quillFormats} style={{ minHeight: '180px' }} />\n                  </div>\n                </div>\n                {selectedPages.length > 0 && eventDate && (\n                  <div className=\"bg-gray-100 border border-gray-300 rounded-lg p-3 mt-4\">\n                    <p className=\"text-sm text-gray-700 flex items-center gap-2\"><FileText className=\"w-4 h-4 text-red-500\" /><strong>Pièce jointe :</strong> Devis_RkeyProd_{eventDateType === 'full' ? eventDate.split('-').reverse().join('') : eventDate}.pdf</p>\n                  </div>\n                )}\n              </CardContent>\n            </Card>\n\n            <Card>\n              <CardHeader>\n                <CardTitle className=\"flex items-center justify-between\">\n                  <span className=\"flex items-center gap-2\"><Settings2 className=\"w-5 h-5 text-orange-500\" />Templates Email</span>\n                  <Button variant=\"outline\" size=\"sm\" onClick={() => openTemplateDialog()} data-testid=\"save-as-template-btn\" disabled={!emailSubject && !emailBody}><Save className=\"w-4 h-4 mr-1\" />Enregistrer comme template</Button>\n                </CardTitle>\n              </CardHeader>\n              <CardContent>\n                {templates.length === 0 ? (\n                  <p className=\"text-gray-500 text-sm text-center py-4\">Aucun template. Créez-en un pour gagner du temps !</p>\n                ) : (\n                  <div className=\"space-y-2\">\n                    {templates.map((template) => (\n                      <div key={template.id} className=\"flex items-center justify-between p-3 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors\">\n                        <div className=\"flex items-center gap-2\">\n                          {template.is_default && <Star className=\"w-4 h-4 text-amber-500 fill-amber-500\" />}\n                          <span className=\"font-medium\">{template.name}</span>\n                        </div>\n                        <div className=\"flex items-center gap-1\">\n                          <Button variant=\"ghost\" size=\"sm\" onClick={() => applyTemplate(template)} className=\"text-green-600 hover:text-green-700 hover:bg-green-50\">Utiliser</Button>\n                          <Button variant=\"ghost\" size=\"sm\" onClick={() => openTemplateDialog(template)}><Edit2 className=\"w-4 h-4\" /></Button>\n                          <Button variant=\"ghost\" size=\"sm\" onClick={() => deleteTemplate(template.id)} className=\"text-red-600 hover:text-red-700 hover:bg-red-50\"><Trash2 className=\"w-4 h-4\" /></Button>\n                        </div>\n                      </div>\n                    ))}\n                  </div>\n                )}\n              </CardContent>\n            </Card>\n\n            <Button onClick={sendEmail} disabled={selectedPages.length === 0 || !recipientEmail || !emailSubject || sendingEmail} className=\"w-full bg-green-600 hover:bg-green-700 text-white\" size=\"lg\" data-testid=\"send-email-btn\">\n              {sendingEmail ? (<><Loader2 className=\"w-5 h-5 mr-2 animate-spin\" />Envoi en cours...</>) : (<><Send className=\"w-5 h-5 mr-2\" />Envoyer le Devis par Email</>)}\n            </Button>\n            <p className=\"text-xs text-gray-500 text-center\">L'email sera envoyé depuis info@rkey-prod.fr avec une copie automatique</p>\n          </div>\n        </div>\n        )}\n\n        {/* Dialogs (composants extraits) */}\n        <PdfPreviewDialog showPreview={showPreview} setShowPreview={setShowPreview} pdfPreview={pdfPreview} pdfBlobUrl={pdfBlobUrl} setPdfBlobUrl={setPdfBlobUrl} numPages={numPages} setNumPages={setNumPages} currentPage={currentPage} setCurrentPage={setCurrentPage} eventDate={eventDate} eventDateType={eventDateType} />\n        <TemplateDialog showTemplateDialog={showTemplateDialog} setShowTemplateDialog={setShowTemplateDialog} editingTemplate={editingTemplate} templateForm={templateForm} setTemplateForm={setTemplateForm} saveTemplate={saveTemplate} savingTemplate={savingTemplate} />\n        <EditPageDialog editingPage={editingPage} setEditingPage={setEditingPage} pageForm={pageForm} setPageForm={setPageForm} savePageEdit={savePageEdit} />\n        <AddPageDialog showAddPageDialog={showAddPageDialog} setShowAddPageDialog={setShowAddPageDialog} pageForm={pageForm} setPageForm={setPageForm} newPageFile={newPageFile} setNewPageFile={setNewPageFile} fileInputRef={fileInputRef} handleFileSelect={handleFileSelect} uploadNewPage={uploadNewPage} uploadingPage={uploadingPage} />\n        <PagePreviewDialog showPagePreview={showPagePreview} setShowPagePreview={setShowPagePreview} pagePreviewData={pagePreviewData} />\n        <RelanceDialog showRelanceDialog={showRelanceDialog} setShowRelanceDialog={setShowRelanceDialog} selectedQuoteForRelance={selectedQuoteForRelance} setSelectedQuoteForRelance={setSelectedQuoteForRelance} relanceNote={relanceNote} setRelanceNote={setRelanceNote} addRelance={addRelance} />\n        <NotesDialog showNotesDialog={showNotesDialog} setShowNotesDialog={setShowNotesDialog} selectedQuoteForNotes={selectedQuoteForNotes} setSelectedQuoteForNotes={setSelectedQuoteForNotes} notesText={notesText} setNotesText={setNotesText} saveNotes={saveNotes} />\n        <ManualQuoteDialog showAddManualDialog={showAddManualDialog} setShowAddManualDialog={setShowAddManualDialog} manualQuoteForm={manualQuoteForm} setManualQuoteForm={setManualQuoteForm} manualQuoteFile={manualQuoteFile} setManualQuoteFile={setManualQuoteFile} manualFileInputRef={manualFileInputRef} addManualQuote={addManualQuote} savingManualQuote={savingManualQuote} initialFormValues={initialManualQuoteForm} />\n      </div>\n    </div>\n  );\n};\n\nexport default DevisEnvoiApp;\n","import React, { useState, useEffect, useRef } from 'react';\nimport { useParams } from 'react-router-dom';\nimport { Users, Music, Clock, Settings, User, Eye, Plus, Shield, MessageSquare, Headphones, Trash2, ArrowUp, ArrowDown, Copy, Check, ChevronDown, ChevronRight, ArrowLeft, Filter, Link as LinkIcon, ExternalLink, Download, RefreshCw, Upload, Search, MapPin, Loader2, Utensils, CheckCircle, XCircle, EyeOff, X, FileText, FileSearch, Bell, Gift, Smartphone, DownloadCloud, Share2, Info, Calendar, Edit3, Sparkles, Mail, Phone, Youtube } from 'lucide-react';\nimport { toast } from 'sonner';\nimport { jsPDF } from 'jspdf';\nimport autoTable from 'jspdf-autotable';\nimport { generateMandatHTML, generateEntrepriseHTML, generateArtisteHTML } from './contracts2/mandatHtmlGenerator';\nimport { isContractDirigeant, calculateContractDepositAmount, calculateContractRemainingBalance } from './contracts2/calculations';\nimport { defaultCompanySettings, musicStyles as availableMusicStyles } from './contracts2/constants';\nimport MyDjLogo from './MyDjLogo';\nimport { Document, Page, pdfjs } from 'react-pdf';\nimport 'react-pdf/dist/esm/Page/AnnotationLayer.css';\nimport 'react-pdf/dist/esm/Page/TextLayer.css';\n\npdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;\n\nimport API_BASE_URL from '../utils/apiUrl';\nconst BACKEND_URL = API_BASE_URL;\n\nconst fixMangledFilenameDisplay = (str) => {\n  if (!str) return '';\n  try {\n    const hasMangled = /([\\u00C0-\\u00DF][\\u0080-\\u00BF]|[\\u00E0-\\u00EF][\\u0080-\\u00BF]{2})/.test(str);\n    if (hasMangled) {\n      const rawBytes = Array.from(str).map(c => c.charCodeAt(0));\n      const decoder = new TextDecoder('utf-8');\n      const decoded = decoder.decode(new Uint8Array(rawBytes));\n      if (!decoded.includes('\\uFFFD')) {\n        return decoded;\n      }\n    }\n    return str;\n  } catch (e) {\n    return str;\n  }\n};\n\nconst getYoutubeEmbedUrl = (url) => {\n  if (!url) return null;\n  let videoId = null;\n  try {\n    const regExp = /^.*(youtu.be\\/|v\\/|u\\/\\w\\/|embed\\/|watch\\?v=|\\&v=)([^#\\&\\?]*).*/;\n    const match = url.match(regExp);\n    if (match && match[2].length === 11) {\n      videoId = match[2];\n    }\n  } catch (e) {\n    console.error(\"Error parsing youtube URL:\", e);\n  }\n  return videoId ? `https://www.youtube.com/embed/${videoId}` : null;\n};\n\nconst DjClientApp = ({ isPublic = false }) => {\n  const { slug } = useParams();\n  \n  // -- Lifted States for Inner Render Functions --\n  const [scheduleCustomItem, setScheduleCustomItem] = useState(\"\");\n  const [clientPhotoUploading, setClientPhotoUploading] = useState(false);\n  const [planningLocalInfo, setPlanningLocalInfo] = useState({});\n  const [docsUploading, setDocsUploading] = useState(false);\n  const [docsUploadCategory, setDocsUploadCategory] = useState(\"Administrative\");\n  const [previewDoc, setPreviewDoc] = useState(null); // { title: string, url: string, type: 'pdf' | 'html' }\n  const [previewBlobUrl, setPreviewBlobUrl] = useState(null);\n  const [loadingPreviewBlob, setLoadingPreviewBlob] = useState(false);\n  const [previewBlobError, setPreviewBlobError] = useState(null);\n  const [previewNumPages, setPreviewNumPages] = useState(null);\n  const [optionsBasket, setOptionsBasket] = useState([]);\n  const [optionsSubmitting, setOptionsSubmitting] = useState(false);\n  const [chatNewMessage, setChatNewMessage] = useState(\"\");\n  const chatContainerRef = useRef(null);\n  const [venueUploading, setVenueUploading] = useState(false);\n  const [djStandaloneExpandedYears, setDjStandaloneExpandedYears] = useState({});\n  const [isEditingClientInfo, setIsEditingClientInfo] = useState(false);\n  const [clientInfoEditData, setClientInfoEditData] = useState({});\n  \n  const SCHEDULE_CATEGORIES = [\n    { title: \"Événements du Repas\", type: 'repas', options: [\"Apéritif\", \"Entrée\", \"Plat\", \"Fromage\", \"Dessert\"] },\n    { title: \"Musique\", type: 'musique', options: [\"Entrée des mariés\", \"Ouverture de bal\", \"Danse de couple\", \"Musique de 80 à début 2000\", \"Musique de 80 à aujourd'hui\"] },\n    { title: \"Animations\", type: 'animations', options: [\"Blind test\", \"Chasse au trésor\", \"Quiz interactif\", \"Show hypnose\", \"Confessionnal\"] }\n  ];\n\n  const [currentRoute, setCurrentRoute] = useState({ view: 'list', role: 'admin', eventId: null, mode: 'dashboard' });\n  const [expandedSections, setExpandedSections] = useState({ past: false }); \n  const [djProfiles, setDjProfiles] = useState([]);\n  const [selectedDjFilter, setSelectedDjFilter] = useState('all');\n  const [searchQuery, setSearchQuery] = useState('');\n\n  const [events, setEvents] = useState([]);\n  const [availableOptions, setAvailableOptions] = useState([]);\n  const [pdfNotes, setPdfNotes] = useState([]);\n  const [isLoadingEvents, setIsLoadingEvents] = useState(true);\n  const [companySettings, setCompanySettings] = useState(defaultCompanySettings);\n\n  // PWA Support States\n  const [deferredPrompt, setDeferredPrompt] = useState(null);\n  const [isStandalone, setIsStandalone] = useState(false);\n  const [showIOSInstallTip, setShowIOSInstallTip] = useState(false);\n  const [notificationPermission, setNotificationPermission] = useState(() => {\n    try {\n      if (typeof window !== 'undefined' && 'Notification' in window) {\n        return Notification.permission;\n      }\n    } catch (e) {\n      console.warn(\"Notification permission check blocked:\", e);\n    }\n    return 'default';\n  });\n  const [lastNotificationCount, setLastNotificationCount] = useState(0);\n  const [dismissedPwa, setDismissedPwa] = useState(() => {\n    try {\n      if (typeof window !== 'undefined' && window.localStorage) {\n        return window.localStorage.getItem('rkey_dismiss_pwa') === 'true';\n      }\n    } catch (e) {\n      console.warn(\"localStorage read blocked in this context:\", e);\n    }\n    return false;\n  });\n\n  const dismissPwaBanner = () => {\n    setDismissedPwa(true);\n    try {\n      if (typeof window !== 'undefined' && window.localStorage) {\n        window.localStorage.setItem('rkey_dismiss_pwa', 'true');\n      }\n    } catch (e) {\n      console.warn(\"localStorage write blocked in this context:\", e);\n    }\n  };\n\n  const installPWA = async () => {\n    if (deferredPrompt) {\n      deferredPrompt.prompt();\n      const { outcome } = await deferredPrompt.userChoice;\n      if (outcome === 'accepted') {\n        setIsStandalone(true);\n        setDeferredPrompt(null);\n        toast.success(\"Installation lancée ! Merci 🎉\");\n      }\n    } else {\n      const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !window.MSStream;\n      if (isIOS) {\n        setShowIOSInstallTip(true);\n      } else {\n        toast.info(\n          \"Pour installer l'application sur votre appareil : cliquez sur l'icône de partage ou les 3 points du navigateur, puis sélectionnez 'Ajouter à l'écran d'accueil' ou 'Installer'.\"\n        );\n      }\n    }\n  };\n\nfunction urlBase64ToUint8Array(base64String) {\n  const padding = '='.repeat((4 - base64String.length % 4) % 4);\n  const base64 = (base64String + padding)\n    .replace(/-/g, '+')\n    .replace(/_/g, '/');\n  const rawData = window.atob(base64);\n  const outputArray = new Uint8Array(rawData.length);\n  for (let i = 0; i < rawData.length; ++i) {\n    outputArray[i] = rawData.charCodeAt(i);\n  }\n  return outputArray;\n}\n\n  const subscribeUserToPush = async (reg) => {\n    try {\n      const res = await fetch(`${BACKEND_URL}/api/push/vapid-public-key`);\n      const { publicKey } = await res.json();\n      const applicationServerKey = urlBase64ToUint8Array(publicKey);\n\n      const subscription = await reg.pushManager.subscribe({\n        userVisibleOnly: true,\n        applicationServerKey\n      });\n\n      await fetch(`${BACKEND_URL}/api/push/subscribe`, {\n        method: 'POST',\n        headers: {\n          'Content-Type': 'application/json',\n          ...(localStorage.getItem('access_token') ? { 'Authorization': `Bearer ${localStorage.getItem('access_token')}` } : {})\n        },\n        body: JSON.stringify({\n          subscription,\n          role: currentRoute.role, // 'admin', 'dj', 'client'\n          eventId: currentRoute.eventId // if viewing a specific event\n        })\n      });\n      console.log('User is subscribed to Web Push backend.');\n    } catch (e) {\n      console.error('Failed to subscribe the user: ', e);\n    }\n  };\n\n  const requestNotificationPermission = async () => {\n    if (!('Notification' in window)) {\n      toast.error(\"Votre navigateur ou appareil ne prend pas en charge les notifications natives.\");\n      return;\n    }\n    try {\n      const permission = await Notification.requestPermission();\n      setNotificationPermission(permission);\n      if (permission === 'granted') {\n        toast.success(\"Notifications push activées avec succès ! 🔔\");\n        if ('serviceWorker' in navigator) {\n          navigator.serviceWorker.ready.then((reg) => {\n            subscribeUserToPush(reg);\n            reg.showNotification(\"Application R'Key Prod\", {\n              body: \"Félicitations ! Vous recevrez désormais les notifications en direct (même l'application fermée). 🎧\",\n              icon: '/favicon.svg',\n              badge: '/favicon.svg'\n            });\n          });\n        } else {\n          new Notification(\"Application R'Key Prod\", {\n            body: \"Félicitations ! Vous recevrez désormais les notifications en direct. 🎧\",\n            icon: '/favicon.svg'\n          });\n        }\n      } else {\n        toast.info(\"Notifications refusées.\");\n      }\n    } catch (e) {\n      console.error(\"Permission request failed\", e);\n    }\n  };\n\n  // Attempt to restore background push notifications automatically if permission previously granted\n  useEffect(() => {\n    try {\n      if (typeof window !== 'undefined' && 'Notification' in window && Notification.permission === 'granted') {\n        if ('serviceWorker' in navigator) {\n          navigator.serviceWorker.ready.then((reg) => {\n            subscribeUserToPush(reg);\n          }).catch(err => console.warn(\"SW ready check rejected:\", err));\n        }\n      }\n    } catch (e) {\n      console.warn(\"Auto background push check failed or blocked:\", e);\n    }\n  }, [currentRoute.role, currentRoute.eventId]);\n\n  useEffect(() => {\n    const handleBeforeInstallPrompt = (e) => {\n      e.preventDefault();\n      setDeferredPrompt(e);\n    };\n\n    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);\n\n    const checkStandalone = () => {\n      if (window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone === true) {\n        setIsStandalone(true);\n      }\n    };\n    checkStandalone();\n    window.addEventListener('resize', checkStandalone);\n\n    return () => {\n      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);\n      window.removeEventListener('resize', checkStandalone);\n    };\n  }, []);\n\n  // Fetch and manage local blob URLs for PDF previews to avoid iframe security/cookie blocks\n  useEffect(() => {\n    let active = true;\n    let urlToRevoke = null;\n\n    if (previewDoc && previewDoc.type === 'pdf') {\n      setLoadingPreviewBlob(true);\n      setPreviewBlobError(null);\n      setPreviewBlobUrl(null);\n      setPreviewNumPages(null);\n\n      fetch(previewDoc.url)\n        .then(async (res) => {\n          if (!res.ok) {\n            throw new Error(`Erreur lors du chargement (HTTP ${res.status})`);\n          }\n          const blob = await res.blob();\n          if (active) {\n            const objectUrl = URL.createObjectURL(blob);\n            urlToRevoke = objectUrl;\n            setPreviewBlobUrl(objectUrl);\n            setLoadingPreviewBlob(false);\n          }\n        })\n        .catch((err) => {\n          console.error(\"Error fetching preview PDF blob:\", err);\n          if (active) {\n            setPreviewBlobError(err.message || \"Impossible de charger le PDF\");\n            setLoadingPreviewBlob(false);\n          }\n        });\n    } else {\n      setPreviewBlobUrl(null);\n      setLoadingPreviewBlob(false);\n      setPreviewBlobError(null);\n      setPreviewNumPages(null);\n    }\n\n    return () => {\n      active = false;\n      if (urlToRevoke) {\n        URL.revokeObjectURL(urlToRevoke);\n      }\n    };\n  }, [previewDoc]);\n\n  // Monitor updates of notifications to trigger local pushes\n  useEffect(() => {\n    const currentUnreadCount = events.reduce((sum, ev) => {\n      const roleNotifs = ev.notifications && ev.notifications[currentRoute.role] \n        ? Object.keys(ev.notifications[currentRoute.role]) \n        : [];\n      return sum + roleNotifs.length;\n    }, 0);\n\n    // Update document title badger\n    if (currentUnreadCount > 0) {\n      document.title = `(${currentUnreadCount}) R'Key Prod App`;\n    } else {\n      document.title = \"R'Key Prod App\";\n    }\n\n    // Trigger local push notification on new updates\n    if (currentUnreadCount > lastNotificationCount) {\n      try {\n        if (typeof window !== 'undefined' && 'Notification' in window && Notification.permission === 'granted') {\n          const msg = `Nouveau message ou modification dans votre portail R'Key Prod !`;\n          let hasServiceWorker = false;\n          try {\n            hasServiceWorker = 'serviceWorker' in navigator;\n          } catch (e) {}\n          if (hasServiceWorker) {\n 